String _friendlyAuthMessage(
  Object error, {
  String fallback = 'Connection problem. Please try again.',
}) {
  final String raw = error.toString();
  final String lower = raw.toLowerCase();
  if (lower.contains('failed host lookup') ||
      lower.contains('name resolution') ||
      lower.contains('dns')) {
    return 'Could not reach login server (DNS). Check internet and retry.';
  }
  if (lower.contains('socketexception') ||
      lower.contains('connection refused') ||
      lower.contains('network is unreachable')) {
    return 'Could not connect to login server. Check internet and retry.';
  }
  if (lower.contains('timeout') || lower.contains('timed out')) {
    return 'Login request timed out. Retry in a moment.';
  }
  if (lower.contains('backend error 4') || lower.contains('backend error 5')) {
    return 'Auth backend is temporarily unavailable. Please try again shortly.';
  }
  return fallback;
}

String _trimTrailingSlash(String raw) {
  return raw.endsWith('/') ? raw.substring(0, raw.length - 1) : raw;
}

String _originFromUrl(String rawUrl) {
  final String raw = rawUrl.trim();
  if (raw.isEmpty) {
    return '';
  }
  final Uri? uri = Uri.tryParse(raw);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) {
    return '';
  }
  final String port = uri.hasPort ? ':${uri.port}' : '';
  return '${uri.scheme}://${uri.host}$port';
}

String _resolveLiveBaseApiUrl() {
  final String explicit = AppConfig.liveClassesApiBaseUrl.trim();
  if (explicit.isNotEmpty) {
    return _trimTrailingSlash(explicit);
  }

  final String aiOrigin = _originFromUrl(RuntimeOverrides.aiEngineUrl);
  if (aiOrigin.isNotEmpty) {
    return _trimTrailingSlash(aiOrigin);
  }

  final String authOrigin = _originFromUrl(RuntimeOverrides.authBackendUrl);
  if (authOrigin.isNotEmpty) {
    return _trimTrailingSlash(authOrigin);
  }

  return 'https://api.example.com';
}

String _resolveLiveTranscriptionWsUrl(String baseApiUrl) {
  final String explicit = AppConfig.liveClassesTranscriptionWsUrl.trim();
  if (explicit.isNotEmpty) {
    return explicit;
  }
  final Uri? uri = Uri.tryParse(baseApiUrl);
  if (uri == null || uri.host.isEmpty) {
    return 'wss://api.example.com/transcription/stream';
  }
  final String scheme = uri.scheme == 'http' ? 'ws' : 'wss';
  return uri
      .replace(scheme: scheme, path: '/transcription/stream', query: '')
      .toString();
}

String _resolveLiveSessionToken() {
  final String configuredSessionToken = AppConfig.liveClassesSessionToken
      .trim();
  if (configuredSessionToken.isNotEmpty) {
    return configuredSessionToken;
  }
  final String configuredJwt = AppConfig.liveClassesJwtAccessToken.trim();
  if (configuredJwt.isNotEmpty) {
    return configuredJwt;
  }
  final String accountId = Session.effectiveAccountId.trim();
  if (accountId.isNotEmpty) {
    return accountId;
  }
  return 'live_session_token_unset';
}

live_models.LiveClassContext _buildLiveClassContext({
  required String role,
  _LiveClassScheduleItem? scheduledClass,
}) {
  final bool isTeacher = role.toLowerCase() == 'teacher';
  final String displayName = Session.effectiveDisplayName.trim().isNotEmpty
      ? Session.effectiveDisplayName.trim()
      : (isTeacher ? 'Teacher' : 'Student');
  final String teacherName = isTeacher
      ? displayName
      : (scheduledClass?.teacherName ??
            AppConfig.liveClassesDefaultTeacherName);
  final String classTitle =
      scheduledClass?.title ?? AppConfig.liveClassesDefaultTitle;
  final String className =
      scheduledClass?.className ?? AppConfig.liveClassesDefaultClassName;
  final String subject =
      scheduledClass?.subject ?? AppConfig.liveClassesDefaultSubject;
  final String topic =
      scheduledClass?.topic ?? AppConfig.liveClassesDefaultTopic;
  final String classId =
      scheduledClass?.classId ?? AppConfig.liveClassesDefaultClassId;
  final String startTime = scheduledClass != null
      ? _formatClassScheduleTime(scheduledClass.startAt)
      : AppConfig.liveClassesDefaultStartTime;
  return live_models.LiveClassContext(
    userId: Session.effectiveAccountId,
    userName: displayName,
    role: role,
    classId: classId,
    sessionToken: _resolveLiveSessionToken(),
    classTitle: classTitle,
    className: className,
    subject: subject,
    topic: topic,
    teacherName: teacherName,
    startTimeLabel: startTime,
  );
}

live_cfg.AppConfig _buildLiveClassesConfig(
  live_models.LiveClassContext contextData,
) {
  final String baseApiUrl = _resolveLiveBaseApiUrl();
  final String ocrEndpoint = AppConfig.liveClassesOcrEndpoint.trim().isNotEmpty
      ? AppConfig.liveClassesOcrEndpoint.trim()
      : '${_trimTrailingSlash(baseApiUrl)}/ocr/frame';
  final String jwtToken = AppConfig.liveClassesJwtAccessToken.trim().isNotEmpty
      ? AppConfig.liveClassesJwtAccessToken.trim()
      : contextData.sessionToken;
  final bool hasConfiguredBackend =
      AppConfig.liveClassesApiBaseUrl.trim().isNotEmpty ||
      AppConfig.aiEngineUrl.trim().isNotEmpty;
  final bool enableMocks =
      !AppConfig.liveClassesEnableRealServices ||
      AppConfig.liveClassesForceMockServices ||
      !hasConfiguredBackend;

  return live_cfg.AppConfig(
    environment: enableMocks ? 'development' : 'production',
    baseApiUrl: baseApiUrl,
    lalacoreBaseUrl: baseApiUrl,
    lalacoreApiKey: AppConfig.aiEngineApiKey,
    zoomSessionId: contextData.classId,
    zoomSessionToken: contextData.sessionToken,
    jwtAccessToken: jwtToken,
    requestSigningSecret: AppConfig.liveClassesRequestSigningSecret.trim(),
    enableMockServices: enableMocks,
    enablePushNotifications: AppConfig.liveClassesEnablePushNotifications,
    transcriptionWsUrl: _resolveLiveTranscriptionWsUrl(baseApiUrl),
    ocrEndpoint: ocrEndpoint,
    quizApiBaseUrl: baseApiUrl,
    recordingApiBaseUrl: baseApiUrl,
    recordingCdnBaseUrl: AppConfig.liveClassesRecordingCdnBaseUrl,
    liveUserId: contextData.userId,
    liveUserName: contextData.userName,
    liveUserRole: contextData.role,
    liveClassTitle: contextData.classTitle,
    liveClassClassName:
        contextData.className ?? AppConfig.liveClassesDefaultClassName,
    liveClassSubject: contextData.subject,
    liveClassTopic: contextData.topic,
    liveClassStartTime:
        contextData.startTimeLabel ?? AppConfig.liveClassesDefaultStartTime,
    liveTeacherName: contextData.teacherName,
    classSessionEndpoint: AppConfig.liveClassesEndpointClassSession,
    classStateEndpoint: AppConfig.liveClassesEndpointClassState,
    classJoinRequestEndpoint: AppConfig.liveClassesEndpointClassJoinRequest,
    classJoinCancelEndpoint: AppConfig.liveClassesEndpointClassJoinCancel,
    classAdmitEndpoint: AppConfig.liveClassesEndpointClassAdmit,
    classRejectEndpoint: AppConfig.liveClassesEndpointClassReject,
    classAdmitAllEndpoint: AppConfig.liveClassesEndpointClassAdmitAll,
    classEventsEndpoint: AppConfig.liveClassesEndpointClassEvents,
    liveTokenEndpoint: AppConfig.liveClassesEndpointLiveToken,
    healthPingEndpoint: AppConfig.liveClassesEndpointHealthPing,
    recordingStartEndpoint: AppConfig.liveClassesEndpointRecordingStart,
    recordingStopEndpoint: AppConfig.liveClassesEndpointRecordingStop,
    recordingProcessEndpoint: AppConfig.liveClassesEndpointRecordingProcess,
    recordingProcessAsyncEndpoint:
        AppConfig.liveClassesEndpointRecordingProcessAsync,
    recordingProcessStatusEndpoint:
        AppConfig.liveClassesEndpointRecordingProcessStatus,
    recordingReplayEndpoint: AppConfig.liveClassesEndpointRecordingReplay,
    quizCreateEndpoint: AppConfig.liveClassesEndpointQuizCreate,
    quizStartEndpoint: AppConfig.liveClassesEndpointQuizStart,
    quizSubmitEndpoint: AppConfig.liveClassesEndpointQuizSubmit,
    quizResultsEndpoint: AppConfig.liveClassesEndpointQuizResults,
