Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();
  await RuntimeOverrides.load();
  if (Platform.isAndroid) {
    await RuntimeOverrides.autoDiscoverBackend();
  }
  await loadThemePreference();

  final SharedPreferences prefs = await SharedPreferences.getInstance();
  final bool isLoggedIn = prefs.containsKey('student_id');
  final String startId = prefs.getString('student_id') ?? '';
  final String accountId = prefs.getString('account_id') ?? '';
  final String chatId = prefs.getString('chat_id') ?? '';
  final bool teacherByIdentity =
      startId.toUpperCase() == 'TEACHER' ||
      accountId.toUpperCase() == 'TEACHER' ||
      chatId.toUpperCase() == 'TEACHER';
  final bool isTeacher =
      (prefs.getBool('is_teacher') ?? false) || teacherByIdentity;
  final String startName = prefs.getString('student_name') ?? '';
  final String email = prefs.getString('user_email') ?? '';
  final String username = prefs.getString('user_username') ?? '';
  final String chatName = prefs.getString('chat_name') ?? '';

  if (isLoggedIn) {
    Session.isTeacher = isTeacher;
    Session.studentId = startId;
    Session.studentName = startName;
    Session.accountId = accountId;
    Session.email = email;
    Session.username = username;
    Session.chatId = chatId;
    Session.chatName = chatName;
    unawaited(
      notificationService
          .initForUser(
            userId: Session.userIdForNotifications,
            role: Session.userRole,
          )
          .timeout(const Duration(seconds: 6), onTimeout: () {}),
    );
  }

  runApp(
    LalaCoreApp(
      isLoggedIn: isLoggedIn,
      isTeacher: isTeacher,
      startId: startId,
      startName: isTeacher
          ? (startName.trim().isEmpty ? 'Admin' : startName)
          : startName,
    ),
  );
}

class LalaCoreApp extends StatelessWidget {
  const LalaCoreApp({
    super.key,
    required this.isLoggedIn,
    required this.isTeacher,
    required this.startId,
    required this.startName,
  });

  final bool isLoggedIn;
  final bool isTeacher;
  final String startId;
  final String startName;

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<ThemeMode>(
      valueListenable: themeNotifier,
      builder: (_, ThemeMode mode, __) {
        return MaterialApp(
          debugShowCheckedModeBanner: false,
          title: 'LalaCore Rebuild',
          themeMode: mode,
          theme: _buildAppTheme(Brightness.light),
          darkTheme: _buildAppTheme(Brightness.dark),
          builder: (BuildContext context, Widget? child) {
            if (child == null) {
              return const SizedBox.shrink();
            }
            return LiquidBackground(child: child);
          },
          home: isLoggedIn
              ? (isTeacher
                    ? const TeacherDashboard()
                    : MenuScreen(studentId: startId, studentName: startName))
              : const AuthScreen(),
        );
      },
    );
  }
}

ThemeData _buildAppTheme(Brightness brightness) {
  final bool isDark = brightness == Brightness.dark;
  final Color seed = isDark ? AppColors.primaryDark : AppColors.primary;
  ColorScheme scheme = ColorScheme.fromSeed(
    seedColor: seed,
    brightness: brightness,
  );
  if (isDark) {
    scheme = scheme.copyWith(
      primary: AppColors.primaryDark,
      secondary: const Color(0xFFA8C0D9),
      tertiary: AppColors.successDark,
      surface: const Color(0xFF131A23),
      onSurface: const Color(0xFFE8EFFA),
    );
  }
  final TextTheme baseText = isDark
      ? GoogleFonts.manropeTextTheme(ThemeData.dark().textTheme)
      : GoogleFonts.manropeTextTheme();

  return ThemeData(
    useMaterial3: true,
    brightness: brightness,
    colorScheme: scheme,
    textTheme: baseText,
    scaffoldBackgroundColor: isDark ? AppColors.bgDark : AppColors.bgLight,
    appBarTheme: AppBarTheme(
      centerTitle: false,
      elevation: 0,
      scrolledUnderElevation: 0,
      backgroundColor: Colors.transparent,
      foregroundColor: isDark ? Colors.white : Colors.black87,
      titleTextStyle: baseText.titleLarge?.copyWith(
        fontWeight: FontWeight.w800,
        color: isDark ? Colors.white : Colors.black87,
      ),
    ),
    pageTransitionsTheme: const PageTransitionsTheme(
      builders: <TargetPlatform, PageTransitionsBuilder>{
        TargetPlatform.android: ZoomPageTransitionsBuilder(),
        TargetPlatform.iOS: CupertinoPageTransitionsBuilder(),
      },
    ),
    snackBarTheme: SnackBarThemeData(
      behavior: SnackBarBehavior.floating,
      backgroundColor: isDark
          ? const Color(0xFF20242C)
          : const Color(0xFF111827),
      contentTextStyle: baseText.bodyMedium?.copyWith(color: Colors.white),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
    ),
    inputDecorationTheme: InputDecorationTheme(
      filled: true,
      fillColor: isDark
          ? Colors.white.withOpacity(0.06)
          : Colors.black.withOpacity(0.03),
      border: OutlineInputBorder(
        borderRadius: BorderRadius.circular(14),
        borderSide: BorderSide(color: scheme.outline.withOpacity(0.22)),
      ),
      enabledBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(14),
        borderSide: BorderSide(color: scheme.outline.withOpacity(0.18)),
      ),
      focusedBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(14),
        borderSide: BorderSide(
          color: (isDark ? AppColors.primaryDark : AppColors.primary)
              .withOpacity(0.72),
        ),
      ),
    ),
    elevatedButtonTheme: ElevatedButtonThemeData(
      style: ElevatedButton.styleFrom(
        elevation: 0,
        minimumSize: const Size(0, 48),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),
      ),
    ),
    outlinedButtonTheme: OutlinedButtonThemeData(
      style: OutlinedButton.styleFrom(
        minimumSize: const Size(0, 48),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),
      ),
    ),
  );
}

class _LiquidTabIndicator extends Decoration {
  const _LiquidTabIndicator({required this.isDark});

  final bool isDark;

  @override
  BoxPainter createBoxPainter([VoidCallback? onChanged]) {
    return _LiquidTabIndicatorPainter(isDark: isDark);
  }
}

class _LiquidTabIndicatorPainter extends BoxPainter {
  _LiquidTabIndicatorPainter({required this.isDark});

  final bool isDark;

  @override
  void paint(Canvas canvas, Offset offset, ImageConfiguration configuration) {
    final Size size = configuration.size ?? Size.zero;
    if (size.isEmpty) {
      return;
    }

    final Rect rect = offset & size;
    final Rect insetRect = rect.deflate(1.4);
    final RRect bubble = RRect.fromRectAndRadius(
      insetRect,
      Radius.circular(insetRect.height * 0.5),
    );
    final Paint basePaint = Paint()
      ..shader = LinearGradient(
        begin: Alignment.topLeft,
        end: Alignment.bottomRight,
        colors: isDark
            ? const <Color>[
                Color(0x34EAF4FF),
                Color(0x2CB9DEFF),
                Color(0x3A7EAFFF),
              ]
            : const <Color>[
                Color(0x92FFFFFF),
                Color(0x86EFF7FF),
                Color(0x7CE2F1FF),
              ],
      ).createShader(insetRect);
    canvas.drawRRect(bubble, basePaint);

    final double highlightWidth = max(22, insetRect.width * 0.62);
    final Rect highlightRect = Rect.fromLTWH(
      insetRect.left + 4,
      insetRect.top + 3,
      min(highlightWidth, insetRect.width - 8),
      max(6, insetRect.height * 0.44),
    );
    final Paint highlightPaint = Paint()
      ..shader = LinearGradient(
        begin: Alignment.topCenter,
        end: Alignment.bottomCenter,
        colors: <Color>[
          Colors.white.withOpacity(isDark ? 0.22 : 0.32),
          Colors.white.withOpacity(0.0),
        ],
      ).createShader(highlightRect);
    canvas.drawRRect(
      RRect.fromRectAndRadius(
        highlightRect,
        Radius.circular(highlightRect.height * 0.8),
      ),
      highlightPaint,
    );

    final Paint borderPaint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = isDark ? 1.0 : 0.9
      ..color = (isDark ? const Color(0xFFDBEEFF) : Colors.white).withOpacity(
        isDark ? 0.22 : 0.34,
      );
    canvas.drawRRect(bubble, borderPaint);

    final Paint glowPaint = Paint()
      ..color = (isDark ? const Color(0xFF8FBFFF) : const Color(0xFFA2CCF5))
          .withOpacity(isDark ? 0.07 : 0.05)
      ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 8);
    canvas.drawRRect(bubble.shift(const Offset(0, 1.0)), glowPaint);
  }
}

class _BottomNavDestination {
  const _BottomNavDestination({required this.icon, required this.label});

  final IconData icon;
  final String label;
}

class _AppleLiquidBottomBar extends StatelessWidget {
  const _AppleLiquidBottomBar({
    required this.selectedIndex,
    required this.onSelected,
    required this.destinations,
    required this.padding,
  });

  final int selectedIndex;
  final ValueChanged<int> onSelected;
  final List<_BottomNavDestination> destinations;
  final EdgeInsets padding;

  @override
  Widget build(BuildContext context) {
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    final bool reducedMotion = shouldUseReducedEffects(context);
    final int count = max(1, destinations.length);
    final int safeIndex = selectedIndex.clamp(0, count - 1);

    return LiquidGlass(
      padding: padding,
      child: LayoutBuilder(
        builder: (BuildContext context, BoxConstraints constraints) {
          final double slotWidth = constraints.maxWidth / count;
          final double bubbleWidth = (slotWidth * 0.92).clamp(70.0, 136.0);
          final double bubbleLeft =
              (slotWidth * safeIndex) + ((slotWidth - bubbleWidth) / 2);

          return SizedBox(
            height: 72,
            child: Stack(
              children: <Widget>[
                AnimatedPositioned(
                  duration: Duration(milliseconds: reducedMotion ? 260 : 500),
                  curve: reducedMotion ? Curves.easeOut : Curves.easeOutCubic,
                  left: bubbleLeft,
                  top: 2,
                  width: bubbleWidth,
                  height: 68,
                  child: IgnorePointer(
                    child: _BottomLiquidDrop(isDark: isDark),
                  ),
                ),
                Row(
                  children: List<Widget>.generate(count, (int index) {
                    final _BottomNavDestination item = destinations[index];
                    return Expanded(
                      child: Center(
                        child: BouncyNavItem(
                          icon: item.icon,
                          label: item.label,
                          isSelected: index == safeIndex,
                          onTap: () => onSelected(index),
                          showSelectionBackground: false,
                          reducedMotion: reducedMotion,
                          selectedColor: isDark
                              ? const Color(0xFFF2F8FF)
                              : const Color(0xFF0E2C49),
                          unselectedColor: isDark
                              ? const Color(0xFF9FB0C7)
                              : const Color(0xFF667085),
                        ),
                      ),
                    );
                  }),
                ),
              ],
            ),
          );
        },
      ),
    );
  }
}

class _BottomLiquidDrop extends StatelessWidget {
  const _BottomLiquidDrop({required this.isDark});

  final bool isDark;

  @override
  Widget build(BuildContext context) {
    return DecoratedBox(
      decoration: BoxDecoration(
        borderRadius: BorderRadius.circular(22),
        gradient: LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: isDark
              ? const <Color>[
                  Color(0x34EAF4FF),
                  Color(0x2CB9DEFF),
                  Color(0x3A7EAFFF),
                ]
              : const <Color>[
                  Color(0x92FFFFFF),
                  Color(0x86EFF7FF),
                  Color(0x7CE2F1FF),
                ],
        ),
        border: Border.all(
          color: (isDark ? const Color(0xFFDBEEFF) : Colors.white).withOpacity(
            isDark ? 0.30 : 0.42,
          ),
        ),
        boxShadow: <BoxShadow>[
          BoxShadow(
            color: (isDark ? const Color(0xFF8FBFFF) : const Color(0xFFA2CCF5))
                .withOpacity(isDark ? 0.11 : 0.09),
            blurRadius: 12,
            offset: const Offset(0, 1),
          ),
        ],
      ),
      child: Align(
        alignment: Alignment.topCenter,
        child: Container(
          margin: const EdgeInsets.fromLTRB(6, 4, 6, 0),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(16),
            gradient: LinearGradient(
              begin: Alignment.topCenter,
              end: Alignment.bottomCenter,
              colors: <Color>[
                Colors.white.withOpacity(isDark ? 0.30 : 0.40),
                Colors.white.withOpacity(0.0),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

