class _AuthScreenState extends State<AuthScreen> {
  static const String _savedAuthEmailKey = 'saved_auth_email';
  static const String _savedAuthPasswordKey = 'saved_auth_password';
  static const String _savedAuthUsernameKey = 'saved_auth_username';

  final TextEditingController _nameCtrl = TextEditingController();
  final TextEditingController _usernameCtrl = TextEditingController();
  final TextEditingController _emailCtrl = TextEditingController();
  final TextEditingController _passCtrl = TextEditingController();
  final LocalAuthentication _localAuth = LocalAuthentication();

  bool _isLogin = true;
  bool _isStudent = true;
  bool _loading = false;
  bool _biometricLoading = false;
  bool _obscurePass = true;

  bool _isValidEmail(String email) {
    return RegExp(r'^[\w\.-]+@[\w\.-]+\.\w+$').hasMatch(email);
  }

  Future<void> _authenticate() async {
    if (_loading) {
      return;
    }
    final String email = _emailCtrl.text.trim();
    final String pass = _passCtrl.text.trim();
    final String name = _nameCtrl.text.trim();
    final String username = _usernameCtrl.text.trim();

    if (!_isValidEmail(email)) {
      _snack('Please enter a valid email');
      return;
    }
    if (!_isLogin && name.isEmpty) {
      _snack('Please enter your name');
      return;
    }
    if (!_isLogin && username.length < 3) {
      _snack('Username must be at least 3 characters');
      return;
    }

    if (pass.length < 4) {
      _snack('Password must be at least 4 characters');
      return;
    }

    setState(() => _loading = true);

    try {
      final String deviceId = await _getOrCreateDeviceId();

      final Map<String, dynamic> data = await backendService
          .authenticate(
            login: _isLogin,
            email: email,
            password: pass,
            name: name,
            username: username,
            deviceId: deviceId,
          )
          .timeout(const Duration(seconds: 20));

      if (_isAuthSuccess(data)) {
        await _handleAuthSuccess(
          data: data,
          fallbackEmail: email,
          fallbackName: name,
          fallbackUsername: username,
          fallbackPassword: pass,
        );
        return;
      }

      final String status = (data['status'] ?? '').toString().toUpperCase();
      switch (status) {
        case 'USER_NOT_FOUND':
          _snack('User not found. Please sign up.');
          break;
        case 'WRONG_PASSWORD':
          _snack('Incorrect password.');
          break;
        case 'USER_EXISTS':
          _snack('Account already exists. Please login.');
          break;
        case 'INVALID_EMAIL':
          _snack('Email format is invalid.');
          break;
        case 'WEAK_PASSWORD':
          _snack('Password is too short.');
          break;
        default:
          _snack(data['message']?.toString() ?? 'Error: $status');
      }
    } catch (e) {
      _snack(
        _friendlyAuthMessage(
          e,
          fallback: 'Unable to login right now. Please retry.',
        ),
      );
    } finally {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  bool _isAuthSuccess(Map<String, dynamic> data) {
    final String status = (data['status'] ?? '').toString().toUpperCase();
    const Set<String> okStatuses = <String>{
      'SUCCESS',
      'OK',
      'LOGIN_SUCCESS',
      'REGISTER_SUCCESS',
      'AUTH_SUCCESS',
    };
    if (data['ok'] == true || okStatuses.contains(status)) {
      return true;
    }
    final bool hasIdentity =
        (data['student_id'] ?? '').toString().trim().isNotEmpty ||
        (data['user_id'] ?? '').toString().trim().isNotEmpty ||
        (data['account_id'] ?? '').toString().trim().isNotEmpty;
    final bool explicitFailure =
        data['ok'] == false ||
        <String>{
          'USER_NOT_FOUND',
          'WRONG_PASSWORD',
          'INVALID_EMAIL',
          'WEAK_PASSWORD',
          'FAILED',
          'ERROR',
        }.contains(status);
    return hasIdentity && !explicitFailure;
  }

  String _fallbackStudentId({required String email, required String username}) {
    final String base =
        (username.trim().isNotEmpty ? username : email.split('@').first)
            .toUpperCase()
            .replaceAll(RegExp(r'[^A-Z0-9]'), '');
    final String head = (base.isEmpty ? 'STUD' : base).padRight(4, 'X');
    int hash = 2166136261;
    for (final int c in email.toLowerCase().codeUnits) {
      hash ^= c;
      hash = (hash * 16777619) & 0x7fffffff;
    }
    final String tail = hash.toRadixString(16).toUpperCase().padLeft(6, '0');
    return '${head.substring(0, 4)}${tail.substring(0, 6)}';
  }

  Future<void> _persistBiometricCredentials({
    required String email,
    required String password,
    required String username,
  }) async {
    if (email.trim().isEmpty || password.trim().isEmpty) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString(_savedAuthEmailKey, email.trim());
    await prefs.setString(_savedAuthPasswordKey, password.trim());
    await prefs.setString(_savedAuthUsernameKey, username.trim());
  }

  Future<void> _clearBiometricCredentials() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove(_savedAuthEmailKey);
    await prefs.remove(_savedAuthPasswordKey);
    await prefs.remove(_savedAuthUsernameKey);
  }

  Future<void> _authenticateWithDeviceSecurity() async {
    if (_loading || _biometricLoading) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final String savedEmail = (prefs.getString(_savedAuthEmailKey) ?? '')
        .trim();
    final String savedPass = (prefs.getString(_savedAuthPasswordKey) ?? '')
        .trim();
    final String savedUsername = (prefs.getString(_savedAuthUsernameKey) ?? '')
        .trim();
    if (savedEmail.isEmpty || savedPass.isEmpty) {
      _snack('Login once with password to enable device unlock.');
      return;
    }

    final bool deviceSupported = await _localAuth.isDeviceSupported();
    final bool canCheckBiometrics = await _localAuth.canCheckBiometrics;
    if (!deviceSupported && !canCheckBiometrics) {
      _snack('No device authentication is available on this phone.');
      return;
    }

    if (mounted) {
      setState(() => _biometricLoading = true);
    }
    try {
      final bool didAuth = await _localAuth.authenticate(
        localizedReason: 'Authenticate to sign in to LalaCore',
        options: const AuthenticationOptions(
          biometricOnly: false,
          stickyAuth: true,
          sensitiveTransaction: true,
          useErrorDialogs: true,
        ),
      );
      if (!didAuth) {
        _snack('Authentication was cancelled.');
        return;
      }

      final String deviceId = await _getOrCreateDeviceId();
      final Map<String, dynamic> data = await backendService
          .authenticate(
            login: true,
            email: savedEmail,
            password: savedPass,
            name: '',
            username: savedUsername,
            deviceId: deviceId,
          )
          .timeout(const Duration(seconds: 20));
      if (_isAuthSuccess(data)) {
        await _handleAuthSuccess(
          data: data,
          fallbackEmail: savedEmail,
          fallbackName: savedEmail.split('@').first,
          fallbackUsername: savedUsername,
          fallbackPassword: savedPass,
        );
        return;
      }
      final String status = (data['status'] ?? '').toString().toUpperCase();
      if (status == 'WRONG_PASSWORD' || status == 'USER_NOT_FOUND') {
        await _clearBiometricCredentials();
        _snack('Saved login expired. Please login with password once.');
        return;
      }
      _snack(
        data['message']?.toString() ?? 'Device authentication login failed',
      );
    } on PlatformException catch (e) {
      _snack(e.message ?? 'Device authentication is unavailable right now.');
    } catch (e) {
      _snack(
        _friendlyAuthMessage(
          e,
          fallback: 'Unable to login with device authentication right now.',
        ),
      );
    } finally {
      if (mounted) {
        setState(() => _biometricLoading = false);
      }
    }
  }

  Future<void> _handleAuthSuccess({
    required Map<String, dynamic> data,
    required String fallbackEmail,
    required String fallbackName,
    required String fallbackUsername,
    required String fallbackPassword,
  }) async {
    final String email = (data['email'] ?? fallbackEmail).toString().trim();
    final String username = (data['username'] ?? fallbackUsername)
        .toString()
        .trim();
    final String id =
        (data['student_id'] ??
                data['user_id'] ??
                data['account_id'] ??
                data['id'] ??
                _fallbackStudentId(email: email, username: username))
            .toString()
            .trim();
    final bool isTeacher = _isTeacherFromAuthPayload(data, resolvedId: id);

    final String niceName =
        (data['name'] ?? fallbackName).toString().trim().isNotEmpty
        ? (data['name'] ?? fallbackName).toString()
        : email.split('@').first;

    await _persistBiometricCredentials(
      email: email,
      password: fallbackPassword,
      username: username,
    );

    await _saveAndGo(
      id,
      niceName,
      isTeacher: isTeacher,
      email: email,
      username: username,
      accountId: (data['account_id'] ?? '').toString(),
      chatId: (data['chat_id'] ?? '').toString(),
      chatName: (data['chat_name'] ?? '').toString(),
    );
  }

  bool _isTeacherFromAuthPayload(
    Map<String, dynamic> data, {
    required String resolvedId,
  }) {
    final String role =
        (data['role'] ??
                data['user_role'] ??
                data['account_role'] ??
                data['profile_role'] ??
                '')
            .toString()
            .trim()
            .toLowerCase();
    if (<String>{'teacher', 'admin', 'administrator'}.contains(role)) {
      return true;
    }

    final dynamic teacherRaw =
        data['is_teacher'] ?? data['teacher'] ?? data['isTeacher'];
    if (teacherRaw is bool && teacherRaw) {
      return true;
    }
    final String teacherFlag = teacherRaw.toString().trim().toLowerCase();
    if (<String>{'1', 'true', 'yes', 'y', 'teacher'}.contains(teacherFlag)) {
      return true;
    }

    final String canonicalId = resolvedId.trim().toUpperCase();
    final String accountId = (data['account_id'] ?? '')
        .toString()
        .trim()
        .toUpperCase();
    final String chatId = (data['chat_id'] ?? '')
        .toString()
        .trim()
        .toUpperCase();
    return canonicalId == 'TEACHER' ||
        accountId == 'TEACHER' ||
        chatId == 'TEACHER';
  }

  Future<String> _getOrCreateDeviceId() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    String id = prefs.getString('device_id') ?? '';
    if (id.isEmpty) {
      id =
          'dev_${DateTime.now().millisecondsSinceEpoch}_${Random().nextInt(99999)}';
      await prefs.setString('device_id', id);
    }
    return id;
  }

  Future<void> _enterTeacherMode() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('student_id', 'TEACHER');
    await prefs.setString('student_name', 'Admin');
    await prefs.setBool('is_teacher', true);
    await prefs.setString('account_id', 'TEACHER');
    await prefs.setString('chat_id', 'TEACHER');
    await prefs.setString('chat_name', 'Teacher');
    await prefs.remove('user_email');
    await prefs.remove('user_username');

    Session.isTeacher = true;
    Session.studentId = 'TEACHER';
    Session.studentName = 'Admin';
    Session.accountId = 'TEACHER';
    Session.email = '';
    Session.username = '';
    Session.chatId = 'TEACHER';
    Session.chatName = 'Teacher';
    unawaited(_runPostLoginWarmups());

    if (!mounted) {
      return;
    }

    Navigator.pushAndRemoveUntil(
      context,
      MaterialPageRoute(builder: (_) => const TeacherDashboard()),
      (Route<dynamic> route) => false,
    );
  }

  Future<void> _saveAndGo(
    String id,
    String name, {
    required bool isTeacher,
    String email = '',
    String username = '',
    String accountId = '',
    String chatId = '',
    String chatName = '',
  }) async {
    final String canonicalId = isTeacher ? 'TEACHER' : id;
    final String canonicalName = isTeacher ? 'Admin' : name;
    final String deviceId = await _getOrCreateDeviceId();
    Map<String, dynamic> identity = <String, dynamic>{};
    try {
      identity = await backendService
          .ensureUserIdentity(
            userId: canonicalId,
            name: canonicalName,
            role: isTeacher ? 'teacher' : 'student',
            email: email,
            username: username,
            chatId: chatId,
            deviceId: deviceId,
            timeout: const Duration(seconds: 8),
          )
          .timeout(const Duration(seconds: 10));
    } catch (_) {}

    final String effectiveAccountId =
        (identity['account_id'] ?? identity['user_id'] ?? accountId)
            .toString()
            .trim()
            .isNotEmpty
        ? (identity['account_id'] ?? identity['user_id'] ?? accountId)
              .toString()
              .trim()
        : canonicalId;
    final String effectiveChatId =
        (identity['chat_id'] ?? chatId).toString().trim().isNotEmpty
        ? (identity['chat_id'] ?? chatId).toString().trim()
        : effectiveAccountId;
    final String effectiveChatName =
        (identity['chat_name'] ?? identity['name'] ?? chatName).toString();
    final String effectiveEmail = (identity['email'] ?? email)
        .toString()
        .trim();
    final String effectiveUsername = (identity['username'] ?? username)
        .toString()
        .trim();

    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('student_id', canonicalId);
    await prefs.setString('student_name', canonicalName);
    await prefs.setBool('is_teacher', isTeacher);
    await prefs.setString('account_id', effectiveAccountId);
    await prefs.setString('chat_id', effectiveChatId);
    await prefs.setString('chat_name', effectiveChatName);
    await prefs.setString('user_email', effectiveEmail);
    await prefs.setString('user_username', effectiveUsername);

    Session.isTeacher = isTeacher;
    Session.studentId = canonicalId;
    Session.studentName = canonicalName;
    Session.accountId = effectiveAccountId;
    Session.email = effectiveEmail;
    Session.username = effectiveUsername;
    Session.chatId = effectiveChatId;
    Session.chatName = effectiveChatName;
    unawaited(_runPostLoginWarmups());

    if (!mounted) {
      return;
    }

    Navigator.pushAndRemoveUntil(
      context,
      MaterialPageRoute(
        builder: (_) => isTeacher
            ? const TeacherDashboard()
            : MenuScreen(studentId: canonicalId, studentName: canonicalName),
      ),
      (Route<dynamic> route) => false,
    );
  }

  Future<void> _runPostLoginWarmups() async {
    try {
      await notificationService
          .initForUser(
            userId: Session.userIdForNotifications,
            role: Session.userRole,
          )
          .timeout(const Duration(seconds: 6));
      await notificationService
          .addAiNotification(
            title: 'Welcome back',
            body: 'Your account is active and synced with LalaCore.',
            type: 'system',
          )
          .timeout(const Duration(seconds: 2));
    } catch (_) {
      // Login flow should not fail if optional sync is slow.
    }
  }

  void _snack(String message) {
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  @override
  void dispose() {
    _nameCtrl.dispose();
    _usernameCtrl.dispose();
    _emailCtrl.dispose();
    _passCtrl.dispose();
    super.dispose();
  }

