class TeacherLockScreen extends StatefulWidget {
  const TeacherLockScreen({
    super.key,
    required this.onBack,
    required this.onTeacherLogin,
  });

  final VoidCallback onBack;
  final Future<void> Function() onTeacherLogin;

  @override
  State<TeacherLockScreen> createState() => _TeacherLockScreenState();
}

class _TeacherLockScreenState extends State<TeacherLockScreen> {
  final TextEditingController _passCtrl = TextEditingController();
  bool _obscure = true;
  bool _loading = false;

  Future<void> _login() async {
    final String entered = _passCtrl.text.trim();
    if (entered.isEmpty) {
      _snack('Enter teacher password');
      return;
    }

    if (entered != AppConfig.teacherPasscode) {
      _snack('Wrong teacher password');
      return;
    }

    setState(() => _loading = true);
    try {
      await widget.onTeacherLogin();
    } finally {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  void _snack(String message) {
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  @override
  void dispose() {
    _passCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Teacher Login'),
        leading: IconButton(
          icon: const Icon(Icons.arrow_back),
          onPressed: widget.onBack,
        ),
      ),
      body: Center(
        child: ConstrainedBox(
          constraints: const BoxConstraints(maxWidth: 520),
          child: Padding(
            padding: const EdgeInsets.all(24),
            child: LiquidGlass(
              padding: const EdgeInsets.all(24),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: <Widget>[
                  const Icon(Icons.school, size: 80),
                  const SizedBox(height: 20),
                  const Text(
