class _ProfileSheet extends StatelessWidget {
  const _ProfileSheet({required this.name, required this.isTeacher});

  final String name;
  final bool isTeacher;

  PerformanceMode _nextMode(PerformanceMode current) {
    return switch (current) {
      PerformanceMode.auto => PerformanceMode.reduced,
      PerformanceMode.reduced => PerformanceMode.full,
      PerformanceMode.full => PerformanceMode.auto,
    };
  }

  Future<void> _logout(BuildContext context) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('student_id');
    await prefs.remove('student_name');
    await prefs.remove('is_teacher');
    await prefs.remove('account_id');
    await prefs.remove('chat_id');
    await prefs.remove('chat_name');
    await prefs.remove('user_email');
    await prefs.remove('user_username');

    Session.isTeacher = false;
    Session.studentId = '';
    Session.studentName = '';
    Session.accountId = '';
    Session.chatId = '';
    Session.chatName = '';
    Session.email = '';
    Session.username = '';

    if (!context.mounted) {
      return;
    }

    Navigator.pushAndRemoveUntil(
      context,
      MaterialPageRoute(builder: (_) => const AuthScreen()),
      (Route<dynamic> route) => false,
    );
