class BackendHealthScreen extends StatefulWidget {
  const BackendHealthScreen({super.key});

  @override
  State<BackendHealthScreen> createState() => _BackendHealthScreenState();
}

class _BackendHealthScreenState extends State<BackendHealthScreen> {
  bool _loading = true;
  Map<String, dynamic> _data = <String, dynamic>{};
  late final TextEditingController _authBackendController;
  late final TextEditingController _aiEngineController;
  late final TextEditingController _aiEngineApiKeyController;
  late final TextEditingController _aiEngineModelController;
  bool _saving = false;
  String _saveNote = '';

  @override
  void initState() {
    super.initState();
    _authBackendController = TextEditingController(
      text: RuntimeOverrides.authBackendUrl,
    );
    _aiEngineController = TextEditingController(
      text: RuntimeOverrides.aiEngineUrl,
    );
    _aiEngineApiKeyController = TextEditingController(
      text: RuntimeOverrides.aiEngineApiKey,
    );
    _aiEngineModelController = TextEditingController(
      text: RuntimeOverrides.aiEngineModel,
    );
    _load();
  }

  @override
  void dispose() {
    _authBackendController.dispose();
    _aiEngineController.dispose();
    _aiEngineApiKeyController.dispose();
    _aiEngineModelController.dispose();
    super.dispose();
  }

  Future<void> _saveOverrides({required bool clear}) async {
    setState(() {
      _saving = true;
      _saveNote = '';
    });
    try {
      final String authUrl = clear
          ? ''
          : _authBackendController.text.trim();
      final String aiUrl = clear ? '' : _aiEngineController.text.trim();
      final String aiKey = clear
          ? ''
          : _aiEngineApiKeyController.text.trim();
      final String aiModel = clear
          ? ''
          : _aiEngineModelController.text.trim();

      await RuntimeOverrides.save(
        authBackendUrl: authUrl,
        authBackendFallbackUrls: authUrl.isNotEmpty ? authUrl : '',
        aiEngineUrl: aiUrl,
        aiEngineApiKey: aiKey,
        aiEngineModel: aiModel,
      );

      _authBackendController.text = RuntimeOverrides.authBackendUrl;
      _aiEngineController.text = RuntimeOverrides.aiEngineUrl;
      _aiEngineApiKeyController.text = RuntimeOverrides.aiEngineApiKey;
      _aiEngineModelController.text = RuntimeOverrides.aiEngineModel;

      setState(() {
        _saveNote = clear
            ? 'Overrides cleared. Using build defaults.'
            : 'Overrides saved. New requests will use these endpoints.';
      });
    } catch (e) {
      setState(() {
        _saveNote = 'Failed to save overrides: $e';
      });
    } finally {
      setState(() => _saving = false);
    }
  }

  Future<void> _load() async {
    setState(() => _loading = true);
    try {
      final Map<String, dynamic> response = await backendService
          .backendDiagnostics();
      if (mounted) {
        setState(() {
          _data = response;
          _loading = false;
        });
      }
    } catch (e) {
      if (mounted) {
        setState(() {
          _data = <String, dynamic>{'ok': false, 'error': e.toString()};
          _loading = false;
        });
      }
    }
  }

  Widget _row(String label, bool ok) {
    return Row(
      children: <Widget>[
        Icon(
          ok ? Icons.check_circle : Icons.cancel,
          color: ok ? Colors.green : Colors.red,
          size: 18,
        ),
        const SizedBox(width: 8),
        Expanded(child: Text(label)),
      ],
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Backend Health'),
        actions: <Widget>[
          IconButton(onPressed: _load, icon: const Icon(Icons.refresh)),
        ],
      ),
      body: _loading
          ? const Center(child: CircularProgressIndicator())
          : ListView(
              padding: const EdgeInsets.all(16),
              children: <Widget>[
                LiquidGlass(
                  padding: const EdgeInsets.all(16),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: <Widget>[
                      Text(
                        _data['ok'] == true
                            ? 'System Healthy'
                            : 'Attention Needed',
                        style: TextStyle(
                          fontSize: 18,
                          fontWeight: FontWeight.bold,
                          color: _data['ok'] == true
                              ? Colors.green
                              : Colors.orange,
                        ),
                      ),
                      const SizedBox(height: 10),
                      _row(
                        'Google Script URL reachable',
                        _data['google_script_reachable'] == true,
                      ),
                      const SizedBox(height: 6),
                      _row(
                        'Master Sheet CSV reachable',
                        _data['master_sheet_reachable'] == true,
                      ),
                      const SizedBox(height: 6),
                      _row(
                        'Apps Script action endpoint reachable',
                        _data['app_script_action_reachable'] == true,
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 12),
                LiquidGlass(
                  padding: const EdgeInsets.all(16),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: <Widget>[
                      const Text(
                        'Wiring',
                        style: TextStyle(fontWeight: FontWeight.bold),
                      ),
                      const SizedBox(height: 8),
                      SelectableText(
                        'Google Script:\n${_data['google_script_url'] ?? AppConfig.googleScriptUrl}',
                      ),
                      const SizedBox(height: 8),
                      SelectableText(
                        'Master Sheet:\n${_data['master_sheet_url'] ?? AppConfig.masterSheetUrl}',
                      ),
                      if (_data['error'] != null) ...<Widget>[
                        const SizedBox(height: 8),
                        Text(
                          'Error: ${_data['error']}',
                          style: const TextStyle(color: Colors.red),
                        ),
                      ],
                    ],
                  ),
                ),
                const SizedBox(height: 12),
                LiquidGlass(
                  padding: const EdgeInsets.all(16),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: <Widget>[
                      const Text(
                        'Runtime Endpoints',
                        style: TextStyle(fontWeight: FontWeight.bold),
                      ),
                      const SizedBox(height: 8),
                      Text(
                        'Effective Auth Backend:\n${RuntimeOverrides.authBackendUrl}',
                      ),
                      const SizedBox(height: 8),
                      TextField(
                        controller: _authBackendController,
                        decoration: const InputDecoration(
                          labelText: 'Auth backend URL',
                          hintText: 'http://192.168.x.y:8000/auth/action',
                        ),
                      ),
                      const SizedBox(height: 8),
                      TextField(
                        controller: _aiEngineController,
                        decoration: const InputDecoration(
                          labelText: 'AI engine URL (optional)',
                          hintText: 'https://your-engine-endpoint',
                        ),
                      ),
                      const SizedBox(height: 8),
                      TextField(
                        controller: _aiEngineApiKeyController,
                        decoration: const InputDecoration(
                          labelText: 'AI engine API key (optional)',
                        ),
                        obscureText: true,
                      ),
                      const SizedBox(height: 8),
                      TextField(
                        controller: _aiEngineModelController,
                        decoration: const InputDecoration(
                          labelText: 'AI engine model (optional)',
                        ),
                      ),
                      const SizedBox(height: 12),
                      Row(
                        children: <Widget>[
                          Expanded(
                            child: ElevatedButton(
                              onPressed: _saving
                                  ? null
                                  : () => _saveOverrides(clear: false),
                              child: Text(
                                _saving ? 'Saving...' : 'Save overrides',
                              ),
                            ),
                          ),
                          const SizedBox(width: 12),
                          OutlinedButton(
                            onPressed: _saving
                                ? null
                                : () => _saveOverrides(clear: true),
                            child: const Text('Clear'),
                          ),
                        ],
                      ),
                      if (_saveNote.isNotEmpty) ...<Widget>[
                        const SizedBox(height: 8),
                        Text(
                          _saveNote,
                          style: TextStyle(
                            color: _saveNote.startsWith('Failed')
                                ? Colors.red
                                : Colors.green,
                          ),
                        ),
                      ],
                      const SizedBox(height: 8),
                      const Text(
                        'Tip: For physical devices, use your laptop LAN IP '
                        'and ensure port 8000 is reachable.',
                        style: TextStyle(color: Colors.grey, fontSize: 12),
                      ),
                    ],
                  ),
                ),
              ],
            ),
    );
  }
}

class NotificationBell extends StatefulWidget {
  const NotificationBell({super.key});

  @override
  State<NotificationBell> createState() => _NotificationBellState();
}

class _NotificationBellState extends State<NotificationBell>
    with WidgetsBindingObserver {
  static const Duration _pollInterval = Duration(seconds: 30);
  Timer? _poll;
  bool _appActive = true;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _syncNow(force: true);
    _startPolling();
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    _stopPolling();
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    final bool active = state == AppLifecycleState.resumed;
    _appActive = active;
    if (active) {
      _syncNow(force: true);
      _startPolling();
    } else {
      _stopPolling();
    }
  }

  void _startPolling() {
    _poll?.cancel();
    if (!_appActive || !mounted) {
      return;
    }
    _poll = Timer.periodic(_pollInterval, (_) => _syncNow());
  }

  void _stopPolling() {
    _poll?.cancel();
    _poll = null;
  }

  void _syncNow({bool force = false}) {
    if (!_appActive && !force) {
      return;
    }
    unawaited(
      notificationService.syncBackendNotifications(
        userId: Session.userIdForNotifications,
        role: Session.userRole,
        force: force,
      ),
    );
  }

  Future<void> _openCenter(BuildContext context) async {
    await Navigator.push(
      context,
      MaterialPageRoute(builder: (_) => const NotificationCenterScreen()),
    );
    await notificationService.syncBackendNotifications(
      userId: Session.userIdForNotifications,
      role: Session.userRole,
      force: true,
    );
  }

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<int>(
      valueListenable: notificationService.unreadCount,
      builder: (_, int unread, __) {
        return GestureDetector(
          onTap: () => _openCenter(context),
          child: Stack(
            children: <Widget>[
              const Padding(
                padding: EdgeInsets.all(10.0),
                child: Icon(Icons.notifications_none_rounded, size: 28),
              ),
              if (unread > 0)
                const Positioned(
                  right: 8,
                  top: 8,
                  child: DecoratedBox(
                    decoration: BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                    ),
                    child: SizedBox(width: 8, height: 8),
                  ),
                ),
            ],
          ),
        );
      },
    );
  }
}

