String _formatNotificationTime(DateTime time) {
  final Duration d = DateTime.now().difference(time);
  if (d.inSeconds < 60) {
    return 'just now';
  }
  if (d.inMinutes < 60) {
    return '${d.inMinutes} min ago';
  }
  if (d.inHours < 24) {
    return '${d.inHours} hr ago';
  }
  if (d.inDays < 7) {
    return '${d.inDays} days ago';
  }
  return '${time.day}/${time.month}/${time.year}';
}

String _lastAiChatIdKey({required String userId, required String accountId}) {
  final String scope = accountId.trim().isNotEmpty ? accountId : userId.trim();
  return 'last_ai_chat_id_$scope';
}

String _aiChatSessionsKey({required String userId, required String accountId}) {
  final String scope = accountId.trim().isNotEmpty ? accountId : userId.trim();
  return 'ai_chat_sessions_$scope';
}

class _AiChatSessionRecord {
  const _AiChatSessionRecord({
    required this.chatId,
    required this.title,
    required this.createdAtMillis,
    required this.updatedAtMillis,
    required this.messageCount,
    required this.aiGeneratedTitle,
    required this.pinned,
    required this.pinnedAtMillis,
  });

  final String chatId;
  final String title;
  final int createdAtMillis;
  final int updatedAtMillis;
  final int messageCount;
  final bool aiGeneratedTitle;
  final bool pinned;
  final int pinnedAtMillis;

  DateTime get createdAt => DateTime.fromMillisecondsSinceEpoch(
    createdAtMillis.clamp(1, 1 << 62).toInt(),
  );
  DateTime get updatedAt => DateTime.fromMillisecondsSinceEpoch(
    updatedAtMillis.clamp(1, 1 << 62).toInt(),
  );

  _AiChatSessionRecord copyWith({
    String? chatId,
    String? title,
    int? createdAtMillis,
    int? updatedAtMillis,
    int? messageCount,
    bool? aiGeneratedTitle,
    bool? pinned,
    int? pinnedAtMillis,
  }) {
    return _AiChatSessionRecord(
      chatId: chatId ?? this.chatId,
      title: title ?? this.title,
      createdAtMillis: createdAtMillis ?? this.createdAtMillis,
      updatedAtMillis: updatedAtMillis ?? this.updatedAtMillis,
      messageCount: messageCount ?? this.messageCount,
      aiGeneratedTitle: aiGeneratedTitle ?? this.aiGeneratedTitle,
      pinned: pinned ?? this.pinned,
      pinnedAtMillis: pinnedAtMillis ?? this.pinnedAtMillis,
    );
  }

  Map<String, dynamic> toJson() => <String, dynamic>{
    'chat_id': chatId,
    'title': title,
    'created_at': createdAtMillis,
    'updated_at': updatedAtMillis,
    'message_count': messageCount,
    'ai_generated_title': aiGeneratedTitle,
    'pinned': pinned,
    'pinned_at': pinnedAtMillis,
  };

  static _AiChatSessionRecord? fromJson(dynamic raw) {
    if (raw is! Map) {
      return null;
    }
    final Map<String, dynamic> map = Map<String, dynamic>.from(raw);
    final String chatId = (map['chat_id'] ?? map['chatId'] ?? '')
        .toString()
        .trim();
    if (chatId.isEmpty) {
      return null;
    }
    final int nowMs = DateTime.now().millisecondsSinceEpoch;
    final int updatedAt = _toSafeSessionMillis(
      map['updated_at'] ?? map['updatedAt'] ?? nowMs,
      fallback: nowMs,
    );
    final int createdAt = _toSafeSessionMillis(
      map['created_at'] ?? map['createdAt'] ?? updatedAt,
      fallback: updatedAt,
    );
    return _AiChatSessionRecord(
      chatId: chatId,
      title: (map['title'] ?? '').toString().trim(),
      createdAtMillis: createdAt,
      updatedAtMillis: updatedAt,
      messageCount: _toSafeSessionInt(
        map['message_count'] ?? map['messageCount'],
      ),
      aiGeneratedTitle: map['ai_generated_title'] == true,
      pinned: map['pinned'] == true,
      pinnedAtMillis: _toSafeSessionMillis(
        map['pinned_at'] ?? map['pinnedAt'] ?? 0,
        fallback: 0,
      ),
    );
  }
}

int _toSafeSessionInt(dynamic raw, {int fallback = 0}) {
  if (raw is int) {
    return raw;
  }
  if (raw is num) {
    return raw.toInt();
  }
  return int.tryParse((raw ?? '').toString()) ?? fallback;
}

int _toSafeSessionMillis(dynamic raw, {required int fallback}) {
  final int parsed = _toSafeSessionInt(raw, fallback: fallback);
  if (parsed < 0) {
    return fallback;
  }
  return parsed;
}

List<_AiChatSessionRecord> _readAiChatSessions({
  required SharedPreferences prefs,
  required String userId,
  required String accountId,
}) {
  final String key = _aiChatSessionsKey(userId: userId, accountId: accountId);
  final String raw = (prefs.getString(key) ?? '').trim();
  if (raw.isEmpty) {
    return <_AiChatSessionRecord>[];
  }
  try {
    final dynamic decoded = jsonDecode(raw);
    if (decoded is! List) {
      return <_AiChatSessionRecord>[];
    }
    final Map<String, _AiChatSessionRecord> deduped =
        <String, _AiChatSessionRecord>{};
    for (final dynamic item in decoded) {
      final _AiChatSessionRecord? record = _AiChatSessionRecord.fromJson(item);
      if (record == null) {
        continue;
      }
      final _AiChatSessionRecord? existing = deduped[record.chatId];
      if (existing == null ||
          record.updatedAtMillis >= existing.updatedAtMillis) {
        deduped[record.chatId] = record;
      }
    }
    final List<_AiChatSessionRecord> out = deduped.values.toList()
      ..sort(
        (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
            b.updatedAtMillis.compareTo(a.updatedAtMillis),
      );
    return out;
  } catch (_) {
    return <_AiChatSessionRecord>[];
  }
}

Future<void> _writeAiChatSessions({
  required SharedPreferences prefs,
  required String userId,
  required String accountId,
  required List<_AiChatSessionRecord> sessions,
}) async {
  final String key = _aiChatSessionsKey(userId: userId, accountId: accountId);
  await prefs.setString(
    key,
    jsonEncode(
      sessions
          .map((_AiChatSessionRecord e) => e.toJson())
          .toList(growable: false),
    ),
  );
}

class _LiveClassScheduleItem {
  const _LiveClassScheduleItem({
    required this.classId,
    required this.title,
    required this.subject,
    required this.topic,
    required this.className,
    required this.teacherName,
    required this.startAt,
    required this.durationMinutes,
    required this.status,
    this.description = '',
  });

  final String classId;
  final String title;
  final String subject;
  final String topic;
  final String className;
  final String teacherName;
  final DateTime startAt;
  final int durationMinutes;
  final String status;
  final String description;

  DateTime get endAt => startAt.add(Duration(minutes: durationMinutes));

  bool get isLive {
    final String normalized = status.trim().toLowerCase();
    if (normalized == 'live') {
      return true;
    }
    final DateTime now = DateTime.now();
    return now.isAfter(startAt) && now.isBefore(endAt);
  }

  bool get isUpcoming {
    final String normalized = status.trim().toLowerCase();
    if (normalized == 'upcoming' || normalized == 'scheduled') {
      return true;
    }
    return DateTime.now().isBefore(startAt);
  }

  bool get isCompleted {
    final String normalized = status.trim().toLowerCase();
    if (normalized == 'completed' || normalized == 'ended') {
      return true;
    }
    return DateTime.now().isAfter(endAt);
  }

  _LiveClassScheduleItem copyWith({
    String? classId,
    String? title,
    String? subject,
    String? topic,
    String? className,
    String? teacherName,
    DateTime? startAt,
    int? durationMinutes,
    String? status,
    String? description,
  }) {
    return _LiveClassScheduleItem(
      classId: classId ?? this.classId,
      title: title ?? this.title,
      subject: subject ?? this.subject,
      topic: topic ?? this.topic,
      className: className ?? this.className,
      teacherName: teacherName ?? this.teacherName,
      startAt: startAt ?? this.startAt,
      durationMinutes: durationMinutes ?? this.durationMinutes,
      status: status ?? this.status,
      description: description ?? this.description,
    );
  }

  Map<String, dynamic> toJson() {
    return <String, dynamic>{
      'class_id': classId,
      'title': title,
      'subject': subject,
      'topic': topic,
      'class_name': className,
      'teacher_name': teacherName,
      'start_time': startAt.toIso8601String(),
      'duration_minutes': durationMinutes,
      'status': status,
      'description': description,
    };
  }

  factory _LiveClassScheduleItem.fromJson(Map<String, dynamic> raw) {
    String firstNonEmpty(List<dynamic> values, {String fallback = ''}) {
      for (final dynamic value in values) {
        final String text = (value ?? '').toString().trim();
        if (text.isNotEmpty) {
          return text;
        }
      }
      return fallback;
    }

    final DateTime now = DateTime.now();
    final String rawStart = firstNonEmpty(<dynamic>[
      raw['start_time'],
      raw['scheduled_at'],
      raw['start_at'],
      raw['time'],
    ], fallback: now.toIso8601String());
    final DateTime startAt = DateTime.tryParse(rawStart) ?? now;
    final int duration =
        int.tryParse(
          firstNonEmpty(<dynamic>[
            raw['duration_minutes'],
            raw['duration'],
            raw['length_minutes'],
          ], fallback: '90'),
        ) ??
        90;
    final String status = firstNonEmpty(<dynamic>[
      raw['status'],
      raw['class_status'],
    ], fallback: startAt.isAfter(now) ? 'upcoming' : 'live');

    return _LiveClassScheduleItem(
      classId: firstNonEmpty(<dynamic>[
        raw['class_id'],
        raw['session_id'],
        raw['id'],
        raw['live_class_id'],
      ], fallback: 'live_${startAt.millisecondsSinceEpoch}'),
      title: firstNonEmpty(<dynamic>[
        raw['title'],
        raw['class_title'],
      ], fallback: AppConfig.liveClassesDefaultTitle),
      subject: firstNonEmpty(<dynamic>[
        raw['subject'],
        raw['class_subject'],
      ], fallback: AppConfig.liveClassesDefaultSubject),
      topic: firstNonEmpty(<dynamic>[
        raw['topic'],
        raw['chapter'],
        raw['concept'],
      ], fallback: AppConfig.liveClassesDefaultTopic),
      className: firstNonEmpty(<dynamic>[
        raw['class_name'],
        raw['class'],
      ], fallback: 'Class 11'),
      teacherName: firstNonEmpty(<dynamic>[
        raw['teacher_name'],
        raw['teacher'],
      ], fallback: AppConfig.liveClassesDefaultTeacherName),
      startAt: startAt,
      durationMinutes: duration,
      status: status,
      description: firstNonEmpty(<dynamic>[raw['description'], raw['notes']]),
    );
  }
}

class _LiveClassScheduleStore {
  static const String _cacheKey = 'live_class_schedule_cache_v1';

  Future<List<_LiveClassScheduleItem>> listSchedule({
    required String viewerRole,
    required String viewerId,
  }) async {
    final Map<String, dynamic> request = <String, dynamic>{
      'user_id': viewerId,
      'viewer_id': viewerId,
      'role': viewerRole,
      'viewer_role': viewerRole,
    };
    final List<Map<String, dynamic>> payloads = <Map<String, dynamic>>[
      <String, dynamic>{'action': 'list_live_class_schedule', ...request},
      <String, dynamic>{'action': 'list_class_schedule', ...request},
      <String, dynamic>{'action': 'get_live_classes', ...request},
      <String, dynamic>{'action': 'get_class_schedule', ...request},
    ];

    Map<String, dynamic>? response;
    try {
      response = await backendService.postActionWithLocalAndScriptFallback(
        payloads,
        localTimeout: const Duration(seconds: 8),
        scriptTimeout: const Duration(seconds: 12),
      );
    } catch (_) {}

    final List<_LiveClassScheduleItem> fromBackend = _parseScheduleList(
      response,
    );
    if (fromBackend.isNotEmpty) {
      await _saveLocal(fromBackend);
      return _sorted(fromBackend);
    }

    final List<_LiveClassScheduleItem> local = await _loadLocal();
    return _sorted(local);
  }

  Future<_LiveClassScheduleItem> scheduleClass({
    required String teacherId,
    required String teacherName,
    required String className,
    required String title,
    required String subject,
    required String topic,
    required DateTime startAt,
    required int durationMinutes,
    String description = '',
  }) async {
    final String classId = 'live_${startAt.millisecondsSinceEpoch}';
    final Map<String, dynamic> request = <String, dynamic>{
      'class_id': classId,
      'teacher_id': teacherId,
      'teacher_name': teacherName,
      'class_name': className,
      'title': title,
      'subject': subject,
      'topic': topic,
      'start_time': startAt.toIso8601String(),
      'duration_minutes': durationMinutes,
      'status': 'upcoming',
      'description': description,
    };
    final List<Map<String, dynamic>> payloads = <Map<String, dynamic>>[
      <String, dynamic>{'action': 'schedule_live_class', ...request},
      <String, dynamic>{'action': 'schedule_class', ...request},
      <String, dynamic>{'action': 'create_live_class', ...request},
      <String, dynamic>{'action': 'create_class_schedule', ...request},
    ];

    _LiveClassScheduleItem output = _LiveClassScheduleItem.fromJson(request);
    try {
      final Map<String, dynamic> response = await backendService
          .postActionWithLocalAndScriptFallback(
            payloads,
            localTimeout: const Duration(seconds: 8),
            scriptTimeout: const Duration(seconds: 12),
          );
      final List<_LiveClassScheduleItem> parsed = _parseScheduleList(response);
      if (parsed.isNotEmpty) {
        output = parsed.first;
      } else if (response.isNotEmpty) {
        final dynamic item =
            response['item'] ??
            response['class'] ??
            response['data'] ??
            response['schedule'];
        if (item is Map) {
          output = _LiveClassScheduleItem.fromJson(
            Map<String, dynamic>.from(item),
          );
        }
      }
    } catch (_) {}

    final List<_LiveClassScheduleItem> local = await _loadLocal();
    final List<_LiveClassScheduleItem> updated = _upsert(local, output);
    await _saveLocal(updated);
    return output;
  }

  Future<_LiveClassScheduleItem> markClassLive(
    _LiveClassScheduleItem item,
  ) async {
    final Map<String, dynamic> request = <String, dynamic>{
      'class_id': item.classId,
      'status': 'live',
      'started_at': DateTime.now().toIso8601String(),
    };
    final List<Map<String, dynamic>> payloads = <Map<String, dynamic>>[
      <String, dynamic>{'action': 'start_live_class', ...request},
      <String, dynamic>{'action': 'mark_class_live', ...request},
      <String, dynamic>{'action': 'update_class_schedule_status', ...request},
    ];
    try {
      await backendService.postActionWithLocalAndScriptFallback(
        payloads,
        localTimeout: const Duration(seconds: 6),
        scriptTimeout: const Duration(seconds: 10),
      );
    } catch (_) {}

    final _LiveClassScheduleItem liveItem = item.copyWith(status: 'live');
    final List<_LiveClassScheduleItem> local = await _loadLocal();
    final List<_LiveClassScheduleItem> updated = _upsert(local, liveItem);
    await _saveLocal(updated);
    return liveItem;
  }

  List<_LiveClassScheduleItem> _parseScheduleList(
    Map<String, dynamic>? source,
  ) {
    if (source == null || source.isEmpty) {
      return <_LiveClassScheduleItem>[];
    }
    dynamic data =
        source['classes'] ??
        source['schedule'] ??
        source['live_classes'] ??
        source['items'] ??
        source['list'] ??
        source['data'];
    if (data is Map) {
      data =
          data['classes'] ??
          data['schedule'] ??
          data['live_classes'] ??
          data['items'] ??
          data['list'] ??
          data['data'];
    }
    if (data is String) {
      try {
        data = jsonDecode(data);
      } catch (_) {
        data = null;
      }
    }
    if (data is! List) {
      return <_LiveClassScheduleItem>[];
    }
    return data
        .whereType<Map>()
        .map(
          (Map raw) =>
              _LiveClassScheduleItem.fromJson(Map<String, dynamic>.from(raw)),
        )
        .toList(growable: false);
  }

  Future<List<_LiveClassScheduleItem>> _loadLocal() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final String raw = (prefs.getString(_cacheKey) ?? '').trim();
    if (raw.isEmpty) {
      return <_LiveClassScheduleItem>[];
    }
    try {
      final dynamic decoded = jsonDecode(raw);
      if (decoded is! List) {
        return <_LiveClassScheduleItem>[];
      }
      return decoded
          .whereType<Map>()
          .map(
            (Map item) => _LiveClassScheduleItem.fromJson(
              Map<String, dynamic>.from(item),
            ),
          )
          .toList(growable: false);
    } catch (_) {
      return <_LiveClassScheduleItem>[];
    }
  }

  Future<void> _saveLocal(List<_LiveClassScheduleItem> items) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString(
      _cacheKey,
      jsonEncode(
        items
            .map((_LiveClassScheduleItem item) => item.toJson())
            .toList(growable: false),
      ),
    );
  }

  List<_LiveClassScheduleItem> _sorted(List<_LiveClassScheduleItem> items) {
    final List<_LiveClassScheduleItem> sorted =
        List<_LiveClassScheduleItem>.from(items);
    sorted.sort(
      (_LiveClassScheduleItem a, _LiveClassScheduleItem b) =>
          a.startAt.compareTo(b.startAt),
    );
    return sorted;
  }

  List<_LiveClassScheduleItem> _upsert(
    List<_LiveClassScheduleItem> items,
    _LiveClassScheduleItem next,
  ) {
    final List<_LiveClassScheduleItem> result =
        List<_LiveClassScheduleItem>.from(items);
    final int existing = result.indexWhere(
      (_LiveClassScheduleItem item) => item.classId == next.classId,
    );
    if (existing == -1) {
      result.add(next);
    } else {
      result[existing] = next;
    }
    return _sorted(result);
  }
}

final _LiveClassScheduleStore _liveClassScheduleStore =
    _LiveClassScheduleStore();

class _LiveClassScheduleEventsBridge {
  _LiveClassScheduleEventsBridge({
    required this.viewerRole,
    required this.viewerId,
    required this.onScheduleChanged,
  });

  final String viewerRole;
  final String viewerId;
  final Future<void> Function() onScheduleChanged;

  WebSocketChannel? _channel;
  StreamSubscription<dynamic>? _subscription;
  Timer? _reconnectTimer;
  bool _disposed = false;

  void start() {
    _connect();
  }

  Future<void> dispose() async {
    _disposed = true;
    _reconnectTimer?.cancel();
    _reconnectTimer = null;
    await _subscription?.cancel();
    _subscription = null;
    await _channel?.sink.close();
    _channel = null;
  }

  void _connect() {
    if (_disposed) {
      return;
    }
    final Uri? uri = _buildUri();
    if (uri == null) {
      return;
    }
    _reconnectTimer?.cancel();
    _reconnectTimer = null;
    unawaited(_subscription?.cancel() ?? Future<void>.value());
    unawaited(_channel?.sink.close() ?? Future<void>.value());
    _subscription = null;
    _channel = null;
    try {
      final WebSocketChannel channel = WebSocketChannel.connect(uri);
      _channel = channel;
      _subscription = channel.stream.listen(
        _handleRawEvent,
        onError: (_) => _scheduleReconnect(),
        onDone: _scheduleReconnect,
        cancelOnError: true,
      );
    } catch (_) {
      _scheduleReconnect();
    }
  }

  void _handleRawEvent(dynamic raw) {
    if (raw is! String) {
      return;
    }
    try {
      final dynamic decoded = jsonDecode(raw);
      if (decoded is! Map) {
        return;
      }
      final Map<String, dynamic> event = Map<String, dynamic>.from(decoded);
      final String type = (event['type'] ?? '').toString().trim();
      if (type.isEmpty || type == 'connected' || type == 'heartbeat') {
        return;
      }
      unawaited(onScheduleChanged());
    } catch (_) {}
  }

  void _scheduleReconnect() {
    if (_disposed || _reconnectTimer != null) {
      return;
    }
    _reconnectTimer = Timer(const Duration(seconds: 3), () {
      _reconnectTimer = null;
      _connect();
    });
  }

  Uri? _buildUri() {
    final String base = _resolveLiveBaseApiUrl().trim();
    if (base.isEmpty || base.contains('api.example.com')) {
      return null;
    }
    final Uri? uri = Uri.tryParse(base);
    if (uri == null || uri.host.isEmpty) {
      return null;
    }
    final String scheme = uri.scheme == 'https' ? 'wss' : 'ws';
    return uri.replace(
      scheme: scheme,
      path: '/app/live_class_schedule/events',
      queryParameters: <String, String>{
        'viewer_role': viewerRole,
        'viewer_id': viewerId,
      },
    );
  }
}

String _formatClassScheduleTime(DateTime value) {
  const List<String> months = <String>[
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  final int hour12 = value.hour % 12 == 0 ? 12 : value.hour % 12;
  final String amPm = value.hour >= 12 ? 'PM' : 'AM';
  final String minute = value.minute.toString().padLeft(2, '0');
  return '${months[value.month - 1]} ${value.day}, ${hour12.toString().padLeft(2, '0')}:$minute $amPm';
}

class MenuScreen extends StatefulWidget {
  const MenuScreen({
    super.key,
    required this.studentId,
    required this.studentName,
  });

  final String studentId;
  final String studentName;

  @override
  State<MenuScreen> createState() => _MenuScreenState();
}

class _MenuScreenState extends State<MenuScreen>
    with SingleTickerProviderStateMixin, WidgetsBindingObserver {
  static const Duration _refreshInterval = Duration(seconds: 30);
  static const Duration _premiumInterval = Duration(minutes: 4);
  late final TabController _topTabs;
  int _bottomIdx = 0;

  bool _loading = true;
  List<QuizItem> _all = <QuizItem>[];
  List<ResultData> _history = <ResultData>[];
  Map<String, bool> _hasAutosave = <String, bool>{};
  bool _fetchInFlight = false;
  bool _fetchQueued = false;
  String _lastMasterCsv = '';
  int _lastNotificationSyncAt = 0;
  int _lastPremiumScanKickoffAt = 0;
  int _lastHistoryFingerprint = 0;
  bool _aiHistoryLoading = false;
  bool _pinnedStackExpanded = false;
  List<_AiChatSessionRecord> _aiChatSessions = <_AiChatSessionRecord>[];
  DateTime? _aiHistoryDateFilter;
  bool _classScheduleLoading = false;
  List<_LiveClassScheduleItem> _classSchedule = <_LiveClassScheduleItem>[];
  String? _studyClassHint;
  String? _studySubjectHint;
  _LiveClassScheduleEventsBridge? _scheduleEventsBridge;

  Timer? _refreshTimer;
  Timer? _premiumSignalTimer;
  bool _appActive = true;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    Session.isTeacher = false;
    Session.studentId = widget.studentId;
    Session.studentName = widget.studentName;

    _topTabs = TabController(length: 3, vsync: this);
    _fetch();
    unawaited(_loadAiChatHistory());
    unawaited(_loadStudentClassSchedule());
    _scheduleEventsBridge = _LiveClassScheduleEventsBridge(
      viewerRole: 'student',
      viewerId: Session.effectiveAccountId,
      onScheduleChanged: () => _loadStudentClassSchedule(quiet: true),
    )..start();
    _startBackgroundPollers();
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    _stopBackgroundPollers();
    unawaited(_scheduleEventsBridge?.dispose() ?? Future<void>.value());
    _scheduleEventsBridge = null;
    _topTabs.dispose();
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    final bool active = state == AppLifecycleState.resumed;
    _appActive = active;
    if (!active) {
      _stopBackgroundPollers();
      return;
    }
    _startBackgroundPollers();
    if (mounted) {
      unawaited(_fetch(quiet: true));
    }
  }

  void _startBackgroundPollers() {
    _stopBackgroundPollers();
    if (!_appActive || !mounted) {
      return;
    }
    _refreshTimer = Timer.periodic(_refreshInterval, (_) => _onRefreshTick());
    _premiumSignalTimer = Timer.periodic(
      _premiumInterval,
      (_) => _onPremiumTick(),
    );
  }

  void _stopBackgroundPollers() {
    _refreshTimer?.cancel();
    _refreshTimer = null;
    _premiumSignalTimer?.cancel();
    _premiumSignalTimer = null;
  }

  void _onRefreshTick() {
    if (!_appActive || !mounted) {
      return;
    }
    if (_bottomIdx <= 1) {
      unawaited(_fetch(quiet: true));
      return;
    }
    if (_bottomIdx == 2) {
      unawaited(_loadStudentClassSchedule(quiet: true));
    }
  }

  void _onPremiumTick() {
    if (!_appActive || !mounted || (_all.isEmpty && _history.isEmpty)) {
      return;
    }
    unawaited(
      _scanPremiumActivitySignals(
        quizzes: _all,
        history: _history,
        force: false,
      ),
    );
  }

  String _todayChatId(String studentName) {
    final DateTime now = DateTime.now();
    final String day =
        '${now.year}-${now.month.toString().padLeft(2, '0')}-${now.day.toString().padLeft(2, '0')}';
    return 'AI_${Session.effectiveAccountId}_$day';
  }

  Future<void> _loadAiChatHistory({bool quiet = false}) async {
    if (!quiet && mounted) {
      setState(() => _aiHistoryLoading = true);
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final List<_AiChatSessionRecord> records = _readAiChatSessions(
      prefs: prefs,
      userId: widget.studentName,
      accountId: Session.effectiveAccountId,
    );
    if (!mounted) {
      return;
    }
    final bool hasPinned = records.any(
      (_AiChatSessionRecord e) => e.pinned && e.messageCount > 0,
    );
    setState(() {
      _aiChatSessions = records;
      if (!hasPinned) {
        _pinnedStackExpanded = false;
      }
      _aiHistoryLoading = false;
    });
  }

  List<_AiChatSessionRecord> _visibleAiChatSessions() {
    final List<_AiChatSessionRecord> sorted =
        List<_AiChatSessionRecord>.from(_aiChatSessions)..sort(
          (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
              b.updatedAtMillis.compareTo(a.updatedAtMillis),
        );
    final DateTime? picked = _aiHistoryDateFilter;
    if (picked != null) {
      return sorted
          .where((_AiChatSessionRecord e) {
            final DateTime t = e.updatedAt;
            return t.year == picked.year &&
                t.month == picked.month &&
                t.day == picked.day &&
                e.messageCount > 0 &&
                !e.pinned;
          })
          .toList(growable: false);
    }
    final DateTime threshold = DateTime.now().subtract(const Duration(days: 7));
    return sorted
        .where(
          (_AiChatSessionRecord e) =>
              !e.updatedAt.isBefore(threshold) &&
              e.messageCount > 0 &&
              !e.pinned,
        )
        .toList(growable: false);
  }

  List<_AiChatSessionRecord> _pinnedAiChatSessions() {
    final List<_AiChatSessionRecord> pinned = _aiChatSessions
        .where(
          (_AiChatSessionRecord e) =>
              e.pinned && e.pinnedAtMillis > 0 && e.messageCount > 0,
        )
        .toList(growable: false);
    pinned.sort(
      (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
          b.pinnedAtMillis.compareTo(a.pinnedAtMillis),
    );
    return pinned;
  }

  Future<void> _saveAiChatRecords(
    List<_AiChatSessionRecord> records, {
    bool collapsePinned = false,
  }) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await _writeAiChatSessions(
      prefs: prefs,
      userId: widget.studentName,
      accountId: Session.effectiveAccountId,
      sessions: records,
    );
    if (!mounted) {
      return;
    }
    setState(() {
      _aiChatSessions = records;
      if (collapsePinned &&
          !records.any((_AiChatSessionRecord e) => e.pinned)) {
        _pinnedStackExpanded = false;
      }
    });
  }

  Future<void> _togglePinned(_AiChatSessionRecord record, bool pinned) async {
    final List<_AiChatSessionRecord> records = List<_AiChatSessionRecord>.from(
      _aiChatSessions,
    );
    final int idx = records.indexWhere(
      (_AiChatSessionRecord e) => e.chatId == record.chatId,
    );
    if (idx < 0) {
      return;
    }
    final int nowMs = DateTime.now().millisecondsSinceEpoch;
    records[idx] = records[idx].copyWith(
      pinned: pinned,
      pinnedAtMillis: pinned ? nowMs : 0,
    );
    records.sort(
      (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
          b.updatedAtMillis.compareTo(a.updatedAtMillis),
    );
    await _saveAiChatRecords(records, collapsePinned: true);
  }

  Future<void> _deleteChatRecord(_AiChatSessionRecord record) async {
    final bool? confirmed = await showDialog<bool>(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: const Text('Delete this AI chat?'),
          content: const Text(
            'This removes the chat from local history and cannot be undone.',
          ),
          actions: <Widget>[
            TextButton(
              onPressed: () => Navigator.pop(context, false),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context, true),
              style: ElevatedButton.styleFrom(backgroundColor: Colors.red),
              child: const Text('Delete'),
            ),
          ],
        );
      },
    );
    if (confirmed != true) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final List<_AiChatSessionRecord> records = _readAiChatSessions(
      prefs: prefs,
      userId: widget.studentName,
      accountId: Session.effectiveAccountId,
    )..removeWhere((_AiChatSessionRecord e) => e.chatId == record.chatId);
    await prefs.remove('ai_chat_${record.chatId}');
    final String lastIdKey = _lastAiChatIdKey(
      userId: widget.studentName,
      accountId: Session.effectiveAccountId,
    );
    if ((prefs.getString(lastIdKey) ?? '').trim() == record.chatId) {
      await prefs.remove(lastIdKey);
    }
    records.sort(
      (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
          b.updatedAtMillis.compareTo(a.updatedAtMillis),
    );
    await _saveAiChatRecords(records, collapsePinned: true);
  }

