  DateTime _parseDate(String raw) {
    if (raw.isEmpty) {
      return DateTime.now().add(const Duration(days: 365));
    }
    if (RegExp(r'^\\d+\$').hasMatch(raw)) {
      final int days = int.tryParse(raw) ?? 0;
      return DateTime(
        1899,
        12,
        30,
      ).add(Duration(days: days, hours: 23, minutes: 59));
    }
    try {
      return DateTime.parse(raw);
    } catch (_) {
      try {
        final List<String> parts = raw.split(RegExp(r'[-/]'));
        if (parts.length == 3) {
          final int p1 = int.parse(parts[0]);
          final int p2 = int.parse(parts[1]);
          final int p3 = int.parse(parts[2]);
          if (p1 > 12) {
            return DateTime(p3, p2, p1, 23, 59, 59);
          }
          return DateTime(p3, p1, p2, 23, 59, 59);
        }
      } catch (_) {}
    }
    return DateTime.now().add(const Duration(days: 7));
  }

  int _resultTimestampFromKey(String key) {
    final RegExpMatch? m = RegExp(r'^res_.+_(\d+)$').firstMatch(key.trim());
    if (m == null) {
      return 0;
    }
    return int.tryParse(m.group(1) ?? '') ?? 0;
  }

  int _historyFingerprint(List<String> keys) {
    int fp = 17;
    for (final String key in keys) {
      fp = (fp * 31 + key.hashCode) & 0x7fffffff;
    }
    return fp;
  }

  List<ResultData> _loadResultHistory(
    SharedPreferences prefs,
    List<String> keys,
  ) {
    return keys
        .map((String key) => prefs.getString(key))
        .whereType<String>()
        .map(
          (String raw) =>
              ResultData.fromJson(jsonDecode(raw) as Map<String, dynamic>),
        )
        .toList();
  }

  Future<void> _scanPremiumActivitySignals({
    required List<QuizItem> quizzes,
    required List<ResultData> history,
    required bool force,
  }) async {
    final int now = DateTime.now().millisecondsSinceEpoch;
    if (!force && now - _lastPremiumScanKickoffAt < 45000) {
      return;
    }
    _lastPremiumScanKickoffAt = now;

    final String accountId = Session.effectiveAccountId.isNotEmpty
        ? Session.effectiveAccountId
        : widget.studentName;
    StudentIntelSnapshot? cachedIntel;
    try {
      cachedIntel = await studentIntelService.load(accountId);
    } catch (_) {}

    await notificationService.runPremiumStudentActivityScan(
      accountId: accountId,
      studentName: widget.studentName,
      quizzes: quizzes,
      history: history,
      intel: cachedIntel,
      force: force,
    );
  }

  Future<void> _fetch({bool quiet = false}) async {
    if (_fetchInFlight) {
      _fetchQueued = true;
      return;
    }
    _fetchInFlight = true;
    if (!quiet && mounted) {
      setState(() => _loading = true);
    }

    try {
      final String masterCsv = await backendService.fetchMasterCsv();
      List<QuizItem> parsed = _all;
      final bool csvChanged = _lastMasterCsv != masterCsv;
      if (csvChanged || _all.isEmpty) {
        final List<List<dynamic>> rows = await parseCsvInBackground(masterCsv);
        parsed = <QuizItem>[];
        for (int i = 1; i < rows.length; i++) {
          final List<dynamic> row = rows[i];
          if (row.length < 3) {
            continue;
          }

          final String id = row[0].toString().trim();
          final String title = row[1].toString().trim();
          final String url = row[2].toString().trim();
          if (id.isEmpty || title.isEmpty || url.isEmpty) {
            continue;
          }

          DateTime deadline = DateTime.now().add(const Duration(days: 7));
          if (row.length > 3 && row[3].toString().trim().isNotEmpty) {
            deadline = _parseDate(row[3].toString().trim());
          }

          String type = 'Exam';
          if (row.length > 4 && row[4].toString().trim().isNotEmpty) {
            type = row[4].toString().trim();
          }
          final bool aiGenerated = type.toLowerCase().contains('ai');

          int duration = 30;
          if (row.length > 5 && row[5].toString().trim().isNotEmpty) {
            duration = int.tryParse(row[5].toString()) ?? 30;
          }
          final bool isUnlimited =
              duration <= 0 ||
              (row.length > 6 &&
                  (row[6].toString().trim().toLowerCase() == 'unlimited' ||
                      row[6].toString().trim().toLowerCase() == 'true'));

          parsed.add(
            QuizItem(
              id: id,
              title: title,
              url: url,
              deadline: deadline,
              type: type,
              durationMinutes: duration,
              isAiGenerated: aiGenerated,
              isUnlimitedTime: isUnlimited,
            ),
          );
        }
        _lastMasterCsv = masterCsv;
      }
      final List<QuizItem> localItems = await localQuizStore.listQuizItems(
        viewerAccountId: Session.effectiveAccountId,
        viewerRole: Session.userRole,
      );
      if (localItems.isNotEmpty) {
        final Map<String, QuizItem> byId = <String, QuizItem>{
          for (final QuizItem q in parsed) q.id: q,
        };
        for (final QuizItem local in localItems) {
          byId.putIfAbsent(local.id, () => local);
        }
        parsed = byId.values.toList()
          ..sort((QuizItem a, QuizItem b) => b.deadline.compareTo(a.deadline));
      }

      final SharedPreferences prefs = await SharedPreferences.getInstance();
      final List<String> resultKeys =
          prefs.getKeys().where((String key) => key.startsWith('res_')).toList()
            ..sort(
              (String a, String b) => _resultTimestampFromKey(
                b,
              ).compareTo(_resultTimestampFromKey(a)),
            );
      final int historyFp = _historyFingerprint(resultKeys);
      final List<ResultData> history =
          (historyFp == _lastHistoryFingerprint && _history.isNotEmpty)
          ? List<ResultData>.from(_history)
          : _loadResultHistory(prefs, resultKeys);

      final Map<String, bool> autosaves = <String, bool>{
        for (final QuizItem item in parsed)
          if (prefs.containsKey('auto_${item.id}')) item.id: true,
      };

      if (mounted) {
        setState(() {
          _all = List<QuizItem>.from(parsed);
          _history = history;
          _lastHistoryFingerprint = historyFp;
          _hasAutosave = autosaves;
          _loading = false;
        });
      }

      await _maybeSyncNotifications(force: !quiet);
      await _scanPremiumActivitySignals(
        quizzes: parsed,
        history: history,
        force: !quiet,
      );
    } catch (_) {
      if (mounted) {
        setState(() => _loading = false);
      }
    } finally {
      _fetchInFlight = false;
      if (_fetchQueued && mounted) {
        _fetchQueued = false;
        unawaited(_fetch(quiet: true));
      }
    }
  }

  Future<void> _maybeSyncNotifications({required bool force}) async {
    if (!_appActive && !force) {
      return;
    }
    final int now = DateTime.now().millisecondsSinceEpoch;
    final int minGapMs = force ? 15000 : 45000;
    if (now - _lastNotificationSyncAt < minGapMs) {
      return;
    }
    _lastNotificationSyncAt = now;
    await notificationService.syncBackendNotifications(
      userId: Session.userIdForNotifications,
      role: Session.userRole,
      force: force,
    );
  }

  Future<void> _onQuizTap(QuizItem item) async {
    if (_hasAutosave[item.id] == true) {
      final bool? resume = await showDialog<bool>(
        context: context,
        builder: (BuildContext context) {
          return AlertDialog(
            title: const Text('Resume Attempt?'),
            content: const Text('Resume where you left off?'),
            actions: <Widget>[
              TextButton(
                onPressed: () => Navigator.pop(context, false),
                child: const Text(
                  'Start New',
                  style: TextStyle(color: Colors.red),
                ),
              ),
              TextButton(
                onPressed: () => Navigator.pop(context, true),
                child: const Text(
                  'Resume',
                  style: TextStyle(fontWeight: FontWeight.bold),
                ),
              ),
            ],
          );
        },
      );

      if (resume == null) {
        return;
      }

      if (!resume) {
        final SharedPreferences prefs = await SharedPreferences.getInstance();
        await prefs.remove('auto_${item.id}');
        if (mounted) {
          setState(() => _hasAutosave.remove(item.id));
        }
      }

      if (!mounted) {
        return;
      }

      await Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => InstructionScreen(
            item: item,
            studentName: widget.studentName,
            isResume: resume,
          ),
        ),
      );
      await _fetch(quiet: true);
      return;
    }

    await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => InstructionScreen(
          item: item,
          studentName: widget.studentName,
          isResume: false,
        ),
      ),
    );
    await _fetch(quiet: true);
  }

