  Widget _buildQuizList(bool missed) {
    final DateTime now = DateTime.now();
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    final String targetType = _bottomIdx == 0 ? 'homework' : 'exam';

    final List<QuizItem> list = _all.where((QuizItem q) {
      final String type = q.type.trim().toLowerCase();
      final bool typeMatch = targetType == 'exam'
          ? (type == 'exam' || type == 'aiexam' || type.contains('ai'))
          : type == targetType;
      final bool isAfter = now.isAfter(
        q.deadline.add(const Duration(minutes: 2)),
      );
      return typeMatch && (missed ? isAfter : !isAfter);
    }).toList();

    if (list.isEmpty) {
      return ListView(
        children: <Widget>[
          SizedBox(height: MediaQuery.of(context).size.height * 0.4),
          Center(child: Text('No ${missed ? 'missed' : 'active'} $targetType')),
        ],
      );
    }

    return ListView.builder(
      padding: const EdgeInsets.all(20),
      itemCount: list.length,
      itemBuilder: (_, int index) {
        final QuizItem item = list[index];
        final List<String> parts = item.title.split('|');
        final String displayTitle = parts.first.trim();
        final String subtitle = parts.length > 1 ? parts[1].trim() : 'General';
        final Duration remaining = item.deadline.difference(now);
        final bool urgent = remaining.inHours <= 24 && !missed;
        final double pressure = (1 - (remaining.inHours / 72)).clamp(0.0, 1.0);
        final String timingLabel = item.isUnlimitedTime
            ? 'Unlimited time • No deadline'
            : '${item.durationMinutes} min • Due: ${item.deadline.day}/${item.deadline.month}';

        return StaggeredList(
          index: index,
          child: Padding(
            padding: const EdgeInsets.only(bottom: 15),
            child: LiquidGlass(
              color:
                  (index % 2 == 0
                          ? AppColors.blueTone(context)
                          : AppColors.tealTone(context))
                      .withOpacity(isDark ? 0.24 : 0.10),
              padding: const EdgeInsets.symmetric(horizontal: 18, vertical: 16),
              onTap: () => _onQuizTap(item),
              child: Column(
                children: <Widget>[
                  Row(
                    children: <Widget>[
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: <Widget>[
                            Text(
                              displayTitle,
                              style: const TextStyle(
                                fontWeight: FontWeight.bold,
                                fontSize: 18,
                              ),
                            ),
                            const SizedBox(height: 4),
                            Text(
                              subtitle,
                              style: TextStyle(
                                fontSize: 12,
                                color: isDark
                                    ? const Color(0xFFB8C5D6)
                                    : Colors.grey,
                              ),
                            ),
                            const SizedBox(height: 4),
                            Text(
                              timingLabel,
                              style: const TextStyle(fontSize: 12),
                            ),
                          ],
                        ),
                      ),
                      Container(
                        padding: const EdgeInsets.all(10),
                        decoration: BoxDecoration(
                          color:
                              (urgent
                                      ? Colors.redAccent
                                      : AppColors.primaryTone(context))
                                  .withOpacity(isDark ? 0.28 : 0.15),
                          shape: BoxShape.circle,
                          boxShadow: urgent
                              ? <BoxShadow>[
                                  BoxShadow(
                                    color: Colors.redAccent.withOpacity(0.35),
                                    blurRadius: 16,
                                    spreadRadius: 1.2,
                                  ),
                                ]
                              : const <BoxShadow>[],
                        ),
                        child: Icon(
                          missed
                              ? Icons.lock_clock
                              : (_hasAutosave[item.id] == true
                                    ? Icons.restore
                                    : Icons.play_arrow),
                          color: urgent
                              ? Colors.redAccent
                              : AppColors.primaryTone(context),
                        ),
                      ),
                    ],
                  ),
                  if (_bottomIdx == 0) ...<Widget>[
                    const SizedBox(height: 10),
                    ClipRRect(
                      borderRadius: BorderRadius.circular(999),
                      child: LinearProgressIndicator(
                        value: pressure,
                        minHeight: 6,
                        backgroundColor: Colors.grey.withOpacity(0.16),
                        color: urgent
                            ? Colors.redAccent
                            : AppColors.primaryTone(context),
                      ),
                    ),
                  ],
                ],
              ),
            ),
          ),
        );
      },
    );
  }

  Widget _buildHistory() {
    final String targetType = _bottomIdx == 0 ? 'homework' : 'exam';
    final List<ResultData> list = _history.where((ResultData h) {
      try {
        final QuizItem q = _all.firstWhere((QuizItem x) => x.id == h.quizId);
        final String type = q.type.trim().toLowerCase();
        if (targetType == 'exam') {
          return type == 'exam' || type == 'aiexam' || type.contains('ai');
        }
        return type == targetType;
      } catch (_) {
        return false;
      }
    }).toList();

    if (list.isEmpty) {
      return const Center(child: Text('No completed items found'));
    }

    return ListView.builder(
      padding: const EdgeInsets.all(20),
      itemCount: list.length,
      itemBuilder: (_, int index) {
        final ResultData item = list[index];
        final QuizItem? quiz = _all
            .where((QuizItem e) => e.id == item.quizId)
            .cast<QuizItem?>()
            .firstOrNull;

        return StaggeredList(
          index: index,
          child: Padding(
            padding: const EdgeInsets.only(bottom: 12),
            child: LiquidGlass(
              padding: const EdgeInsets.symmetric(horizontal: 18, vertical: 16),
              onTap: () {
                if (quiz == null) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    const SnackBar(
                      content: Text(
                        'Quiz details unavailable for this history item.',
                      ),
                    ),
                  );
                  return;
                }
                Navigator.push(
                  context,
                  MaterialPageRoute(
                    builder: (_) => AnalyticsScreen(
                      data: item,
                      studentName: widget.studentName,
                      title: item.quizTitle,
                      item: quiz,
                      aiAvailable: false,
                      aiResult: null,
                    ),
                  ),
                );
              },
              child: Row(
                children: <Widget>[
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: <Widget>[
                        Text(
                          item.quizTitle.split('|').first,
                          style: const TextStyle(
                            fontWeight: FontWeight.bold,
                            fontSize: 16,
                          ),
                        ),
                        const SizedBox(height: 6),
                        Text(
                          'Score: ${item.score.toStringAsFixed(1)} / ${item.maxScore.toStringAsFixed(1)}',
                          style: const TextStyle(
                            fontSize: 13,
                            color: Colors.grey,
                          ),
                        ),
                      ],
                    ),
                  ),
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 14,
                      vertical: 8,
                    ),
                    decoration: BoxDecoration(
                      color: Colors.yellow[700],
                      borderRadius: BorderRadius.circular(20),
                    ),
                    child: const Text(
                      'Review',
                      style: TextStyle(
                        color: Colors.black,
                        fontWeight: FontWeight.bold,
                        fontSize: 12,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        );
      },
    );
  }

  String _formatAiHistoryDate(DateTime dt) {
    final MaterialLocalizations ml = MaterialLocalizations.of(context);
    return ml.formatMediumDate(dt);
  }

  String _formatAiHistoryTime(DateTime dt) {
    final MaterialLocalizations ml = MaterialLocalizations.of(context);
    return ml.formatTimeOfDay(
      TimeOfDay.fromDateTime(dt),
      alwaysUse24HourFormat:
          MediaQuery.maybeOf(context)?.alwaysUse24HourFormat ?? false,
    );
  }

