  Widget _buildPinnedStackPreview(List<_AiChatSessionRecord> pinned) {
    final int previewCount = min(3, pinned.length);
    final double baseHeight = 74;
    final double offset = 11;
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    return GestureDetector(
      behavior: HitTestBehavior.translucent,
      onTap: () => _openAIChatById(pinned.first.chatId),
      onLongPress: () => setState(() => _pinnedStackExpanded = true),
      child: SizedBox(
        height: baseHeight + ((previewCount - 1) * offset),
        child: Stack(
          children: List<Widget>.generate(previewCount, (int i) {
            final int idx = previewCount - i - 1;
            final _AiChatSessionRecord record = pinned[idx];
            return Positioned(
              top: i * offset,
              left: i * 5,
              right: i * 5,
              child: IgnorePointer(
                child: LiquidGlass(
                  borderRadius: BorderRadius.circular(16),
                  color:
                      (i.isEven
                              ? AppColors.blueTone(context)
                              : AppColors.tealTone(context))
                          .withOpacity(isDark ? 0.26 : 0.12),
                  padding: const EdgeInsets.fromLTRB(12, 11, 12, 11),
                  child: Row(
                    children: <Widget>[
                      Icon(
                        Icons.push_pin_rounded,
                        size: 15,
                        color: Theme.of(context).colorScheme.primary,
                      ),
                      const SizedBox(width: 8),
                      Expanded(
                        child: Text(
                          record.title.trim().isEmpty
                              ? 'Pinned AI Chat'
                              : record.title.trim(),
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            fontWeight: FontWeight.w700,
                            fontSize: 13.4,
                          ),
                        ),
                      ),
                      const SizedBox(width: 6),
                      Text(
                        _formatAiHistoryTime(record.updatedAt),
                        style: const TextStyle(fontSize: 11.6),
                      ),
                    ],
                  ),
                ),
              ),
            );
          }),
        ),
      ),
    );
  }

