  List<ResultData> _attemptsForQuiz(String quizId) {
    return _history
        .where((ResultData e) => e.quizId.trim() == quizId.trim())
        .toList(growable: false);
  }

  List<QuizItem> _selfPracticeAiQuizzes() {
    final Map<String, QuizItem> byId = <String, QuizItem>{};
    for (final QuizItem item in _all) {
      final String typeLower = item.type.trim().toLowerCase();
      final bool aiLike = item.isAiGenerated || typeLower.contains('ai');
      if (!aiLike) {
        continue;
      }
      final bool localLike = localQuizStore.isLocalQuizUrl(item.url);
      final bool practiceLike =
          item.isUnlimitedTime ||
          localLike ||
          item.id.startsWith('ai_') ||
          item.id.startsWith('lq_') ||
          typeLower.contains('practice');
      if (!practiceLike) {
        continue;
      }
      byId[item.id] = item;
    }

    final List<QuizItem> out = byId.values.toList();
    int latestAttemptIndex(String quizId) {
      return _history.indexWhere(
        (ResultData r) => r.quizId.trim() == quizId.trim(),
      );
    }

    out.sort((QuizItem a, QuizItem b) {
      final int ai = latestAttemptIndex(a.id);
      final int bi = latestAttemptIndex(b.id);
      if (ai >= 0 && bi >= 0) {
        return ai.compareTo(bi);
      }
      if (ai >= 0) {
        return -1;
      }
      if (bi >= 0) {
        return 1;
      }
      return b.deadline.compareTo(a.deadline);
    });
    return out;
  }

  Future<void> _reattemptAiQuiz(QuizItem item) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('auto_${item.id}');
    if (!mounted) {
      return;
    }
    setState(() => _hasAutosave.remove(item.id));
    await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => InstructionScreen(
          item: item,
          studentName: widget.studentName,
          isResume: false,
        ),
      ),
    );
    if (mounted) {
      await _fetch(quiet: true);
    }
  }

  Future<void> _openAiQuizResults(QuizItem item) async {
    final List<ResultData> attempts = _attemptsForQuiz(item.id);
    if (attempts.isEmpty) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('No past result found for this AI practice quiz.'),
        ),
      );
      return;
    }

    if (attempts.length == 1) {
      await Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => AnalyticsScreen(
            data: attempts.first,
            studentName: widget.studentName,
            title: item.title,
            item: item,
            aiAvailable: false,
            aiResult: null,
          ),
        ),
      );
      return;
    }

    if (!mounted) {
      return;
    }
    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      builder: (BuildContext context) {
        return SafeArea(
          child: Padding(
            padding: const EdgeInsets.fromLTRB(12, 10, 12, 12),
            child: LiquidGlass(
              borderRadius: BorderRadius.circular(22),
              padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: <Widget>[
                  Text(
                    'Past Results • ${item.title.split('|').first}',
                    style: const TextStyle(
                      fontWeight: FontWeight.w800,
                      fontSize: 15,
                    ),
                  ),
                  const SizedBox(height: 8),
                  SizedBox(
                    height: min(
                      420,
                      MediaQuery.of(context).size.height * 0.55,
                    ).toDouble(),
                    child: ListView.separated(
                      itemCount: attempts.length,
                      separatorBuilder: (_, __) => const Divider(height: 1),
                      itemBuilder: (_, int i) {
                        final ResultData result = attempts[i];
                        return ListTile(
                          dense: true,
                          leading: CircleAvatar(
                            radius: 14,
                            child: Text(
                              '${i + 1}',
                              style: const TextStyle(fontSize: 11),
                            ),
                          ),
                          title: Text(
                            'Score ${result.score.toStringAsFixed(1)} / ${result.maxScore.toStringAsFixed(1)}',
                            style: const TextStyle(fontWeight: FontWeight.w700),
                          ),
                          subtitle: Text(
                            'Correct ${result.correct} • Wrong ${result.wrong} • Skipped ${result.skipped}',
                          ),
                          trailing: const Icon(Icons.chevron_right_rounded),
                          onTap: () {
                            Navigator.pop(context);
                            Navigator.push(
                              this.context,
                              MaterialPageRoute(
                                builder: (_) => AnalyticsScreen(
                                  data: result,
                                  studentName: widget.studentName,
                                  title: item.title,
                                  item: item,
                                  aiAvailable: false,
                                  aiResult: null,
                                ),
                              ),
                            );
                          },
                        );
                      },
                    ),
                  ),
                ],
              ),
            ),
          ),
        );
      },
    );
  }

  Widget _buildAiExamHistoryCard(QuizItem item, int index) {
    final ThemeData theme = Theme.of(context);
    final bool isDark = theme.brightness == Brightness.dark;
    final List<ResultData> attempts = _attemptsForQuiz(item.id);
    final ResultData? latest = attempts.firstOrNull;
    final Color tint =
