extension _FirstOrNull<E> on Iterable<E> {
  E? get firstOrNull => isEmpty ? null : first;
}

enum _TeacherActionIconMotion { bookFlip, penWrite }

class _TeacherLiquidActionButton extends StatefulWidget {
  const _TeacherLiquidActionButton({
    required this.label,
    required this.onTap,
    required this.motion,
    required this.tint,
    required this.foreground,
    this.iconOnly = false,
  });

  final String label;
  final Future<void> Function() onTap;
  final _TeacherActionIconMotion motion;
  final Color tint;
  final Color foreground;
  final bool iconOnly;

  @override
  State<_TeacherLiquidActionButton> createState() =>
      _TeacherLiquidActionButtonState();
}

class _TeacherLiquidActionButtonState extends State<_TeacherLiquidActionButton>
    with TickerProviderStateMixin {
  late final AnimationController _pressCtrl;
  late final AnimationController _iconCtrl;
  bool _busy = false;

  @override
  void initState() {
    super.initState();
    _pressCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 210),
      reverseDuration: const Duration(milliseconds: 170),
    );
    _iconCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 420),
    );
  }

  @override
  void dispose() {
    _pressCtrl.dispose();
    _iconCtrl.dispose();
    super.dispose();
  }

  Future<void> _handleTap() async {
    if (_busy) {
      return;
    }
    _busy = true;
    final bool reducedMotion = shouldUseReducedEffects(context);
    if (!reducedMotion) {
      HapticFeedback.selectionClick();
    }
    await _pressCtrl.forward(from: 0);
    await _pressCtrl.reverse();
    await _iconCtrl.forward(from: 0);
    await widget.onTap();
    _busy = false;
  }

  Widget _buildAnimatedIcon({required double t, required bool reducedMotion}) {
    if (widget.motion == _TeacherActionIconMotion.bookFlip) {
      final double eased = Curves.easeInOutCubic.transform(t);
      final double angle = (reducedMotion ? 0.22 : 0.72) * sin(pi * eased);
      final double lift = (reducedMotion ? 1.2 : 2.8) * sin(pi * eased);
      final double frontScale = 1 - (reducedMotion ? 0.03 : 0.08) * eased;
      return SizedBox(
        width: 26,
        height: 26,
        child: Stack(
          alignment: Alignment.center,
          children: <Widget>[
            Transform.translate(
              offset: Offset(0, -lift * 0.3),
              child: Icon(
                Icons.menu_book_rounded,
                size: 21,
                color: widget.foreground.withValues(
                  alpha: 0.24 + (0.18 * eased),
                ),
              ),
            ),
            Transform(
              alignment: Alignment.centerLeft,
              transform: Matrix4.identity()
                ..setEntry(3, 2, 0.002)
                ..rotateY(-angle),
              child: Icon(
                Icons.menu_book_rounded,
                size: 22 * frontScale,
                color: widget.foreground,
              ),
            ),
            Positioned(
              bottom: 3,
              child: Opacity(
                opacity: reducedMotion ? 0.26 : 0.4,
                child: Container(
                  width: 14 + (4 * eased),
                  height: 1.4,
                  decoration: BoxDecoration(
                    color: widget.foreground.withValues(alpha: 0.5),
                    borderRadius: BorderRadius.circular(6),
                  ),
                ),
              ),
            ),
          ],
        ),
      );
    }

    final double eased = Curves.easeOutCubic.transform(t);
    final double sweep = sin(pi * eased);
    final double dx = (reducedMotion ? 2.4 : 6.3) * sweep;
    final double dy = (reducedMotion ? -0.9 : -2.4) * sweep;
    final double angle = -0.42 + (reducedMotion ? 0.15 : 0.34) * sweep;
    final double strokeWidthA = 9 + (reducedMotion ? 5 : 11) * eased;
    final double strokeWidthB =
        2 + (reducedMotion ? 2.6 : 6.3) * max(0, eased - 0.2);
    return SizedBox(
      width: 26,
      height: 26,
      child: Stack(
        alignment: Alignment.center,
        children: <Widget>[
          Positioned(
            left: 2,
            bottom: 5,
            child: Container(
              width: strokeWidthA,
              height: 2.1,
              decoration: BoxDecoration(
                color: widget.foreground.withValues(alpha: 0.84),
                borderRadius: BorderRadius.circular(6),
              ),
            ),
          ),
          Positioned(
            left: 2,
            bottom: 8.4,
            child: Opacity(
              opacity: 0.2 + (0.72 * max(0, eased - 0.18)),
              child: Container(
                width: strokeWidthB,
                height: 1.8,
                decoration: BoxDecoration(
                  color: widget.foreground.withValues(alpha: 0.72),
                  borderRadius: BorderRadius.circular(6),
                ),
              ),
            ),
          ),
          Transform.translate(
            offset: Offset(dx, dy),
            child: Transform.rotate(
              angle: angle,
              child: Icon(
                Icons.edit_note_rounded,
                size: 20,
                color: widget.foreground,
              ),
            ),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final bool reducedMotion = shouldUseReducedEffects(context);
    _pressCtrl.duration = Duration(milliseconds: reducedMotion ? 140 : 210);
    _pressCtrl.reverseDuration = Duration(
      milliseconds: reducedMotion ? 120 : 170,
    );
    _iconCtrl.duration = Duration(milliseconds: reducedMotion ? 250 : 420);

    return AnimatedBuilder(
      animation: Listenable.merge(<Listenable>[_pressCtrl, _iconCtrl]),
      builder: (BuildContext context, _) {
        final double press = Curves.easeOut.transform(_pressCtrl.value);
        final double iconT = Curves.easeOutCubic.transform(_iconCtrl.value);
        final double baseScale = 1 - (reducedMotion ? 0.02 : 0.05) * press;
        final double bounce = reducedMotion
            ? 0
            : 0.012 * sin(pi * Curves.easeOutBack.transform(press));
        final double dy = (reducedMotion ? 0.5 : 1.4) * press;

        return Transform.translate(
          offset: Offset(0, dy),
          child: Transform.scale(
            scale: baseScale + bounce,
            child: LiquidGlass(
              onTap: _handleTap,
              borderRadius: BorderRadius.circular(999),
              color: widget.tint.withValues(alpha: 0.20),
              padding: widget.iconOnly
                  ? const EdgeInsets.all(11)
                  : const EdgeInsets.symmetric(horizontal: 14, vertical: 11),
              child: Tooltip(
                message: widget.label,
                child: Row(
                  mainAxisSize: MainAxisSize.min,
                  children: <Widget>[
                    _buildAnimatedIcon(t: iconT, reducedMotion: reducedMotion),
                    if (!widget.iconOnly) ...<Widget>[
                      const SizedBox(width: 8),
                      Text(
                        widget.label,
                        style: TextStyle(
                          color: widget.foreground,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.1,
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ),
          ),
        );
      },
    );
  }
}

class TeacherDashboard extends StatefulWidget {
  const TeacherDashboard({super.key});

  @override
  State<TeacherDashboard> createState() => _TeacherDashboardState();
}

class _TeacherDashboardState extends State<TeacherDashboard>
    with SingleTickerProviderStateMixin {
  int _idx = 0;
  bool _loading = true;
  late final TabController _statusTabs;

  List<Map<String, dynamic>> _exams = <Map<String, dynamic>>[];
  List<Map<String, dynamic>> _homeworks = <Map<String, dynamic>>[];
  Map<String, List<dynamic>> _studentHistory = <String, List<dynamic>>{};
  bool _teacherScheduleLoading = false;
  List<_LiveClassScheduleItem> _teacherSchedule = <_LiveClassScheduleItem>[];
  bool _fetchInFlight = false;
  bool _fetchQueued = false;
  _LiveClassScheduleEventsBridge? _scheduleEventsBridge;

  @override
  void initState() {
    super.initState();
    _statusTabs = TabController(length: 2, vsync: this);
    Session.isTeacher = true;
    Session.studentId = 'TEACHER';
    Session.studentName = 'Admin';
    Session.accountId = 'TEACHER';
    Session.chatId = 'TEACHER';
    Session.chatName = 'Teacher';
    _fetch();
    unawaited(_loadTeacherClassSchedule());
    _scheduleEventsBridge = _LiveClassScheduleEventsBridge(
      viewerRole: 'teacher',
      viewerId: Session.effectiveAccountId,
      onScheduleChanged: () => _loadTeacherClassSchedule(quiet: true),
    )..start();
  }

  @override
  void dispose() {
    unawaited(_scheduleEventsBridge?.dispose() ?? Future<void>.value());
    _scheduleEventsBridge = null;
    _statusTabs.dispose();
    super.dispose();
  }

  DateTime _parseTeacherDate(String raw, {DateTime? fallback}) {
    final String text = raw.trim();
    final DateTime safeFallback = fallback ?? DateTime.now();
    if (text.isEmpty) {
      return safeFallback;
    }
    final num? serial = num.tryParse(text);
    if (serial != null) {
      final int days = serial.floor();
      return DateTime(1899, 12, 30).add(Duration(days: days));
    }
    return DateTime.tryParse(text) ?? safeFallback;
  }

  DateTime _createdFromResultId(String id, {required DateTime fallback}) {
    final RegExpMatch? m = RegExp(r'(\d{10,13})').firstMatch(id);
    if (m == null) {
      return fallback;
    }
    final int stamp = int.tryParse(m.group(1) ?? '') ?? 0;
    if (stamp <= 0) {
      return fallback;
    }
    final int ms = stamp > 9999999999 ? stamp : stamp * 1000;
    final DateTime parsed = DateTime.fromMillisecondsSinceEpoch(ms);
    if (parsed.year < 2020 || parsed.year > DateTime.now().year + 1) {
      return fallback;
    }
    return parsed;
  }

  DateTime _createdFromMasterRow(
    List<dynamic> row, {
    required String id,
    required DateTime fallback,
  }) {
    if (row.length > 6 && row[6].toString().trim().isNotEmpty) {
      return _parseTeacherDate(row[6].toString(), fallback: fallback);
    }
    return _createdFromResultId(id, fallback: fallback);
  }

  String _resultStudentName(Map<String, dynamic> result) {
    final List<String> candidates = <String>[
      (result['name'] ?? '').toString().trim(),
      (result['student_name'] ?? '').toString().trim(),
      (result['student'] ?? '').toString().trim(),
      (result['studentName'] ?? '').toString().trim(),
      (result['student_name_display'] ?? '').toString().trim(),
      (result['account_id'] ?? '').toString().trim(),
    ];
    return candidates.firstWhere((String e) => e.isNotEmpty, orElse: () => '');
  }

  String _resultStudentId(Map<String, dynamic> result) {
    final List<String> candidates = <String>[
      (result['student_id'] ?? '').toString().trim(),
      (result['studentId'] ?? '').toString().trim(),
      (result['account_id'] ?? '').toString().trim(),
      (result['accountId'] ?? '').toString().trim(),
      (result['user_id'] ?? '').toString().trim(),
      (result['chat_id'] ?? '').toString().trim(),
      (result['email'] ?? '').toString().trim(),
    ];
    return candidates.firstWhere((String e) => e.isNotEmpty, orElse: () => '');
  }

  String _resultTopic(Map<String, dynamic> result) {
    final List<String> candidates = <String>[
      (result['topic'] ?? '').toString().trim(),
      (result['quiz_title'] ?? '').toString().trim(),
      (result['quizTitle'] ?? '').toString().trim(),
      (result['title'] ?? '').toString().trim(),
      (result['quiz'] ?? '').toString().trim(),
    ];
    return candidates.firstWhere((String e) => e.isNotEmpty, orElse: () => '');
  }

  String _topicLookupKey(String value) {
    return value.trim().toLowerCase();
  }

  String _topicFallbackKey(String value) {
    return value.split('|').first.trim().toLowerCase();
  }

  String _assessmentIdKey(String id) => 'id:${id.trim().toLowerCase()}';

  int _resultTimestampFromStorageKey(String key) {
    final RegExpMatch? m = RegExp(r'^res_.+_(\d+)$').firstMatch(key.trim());
    if (m == null) {
      return 0;
    }
    return int.tryParse(m.group(1) ?? '') ?? 0;
  }

  List<Map<String, dynamic>> _loadLocalResultSnapshots(
    SharedPreferences prefs,
  ) {
    final List<String> keys =
        prefs.getKeys().where((String k) => k.startsWith('res_')).toList()
          ..sort(
            (String a, String b) => _resultTimestampFromStorageKey(
              b,
            ).compareTo(_resultTimestampFromStorageKey(a)),
          );
    final List<Map<String, dynamic>> out = <Map<String, dynamic>>[];
    for (final String key in keys) {
      final String? raw = prefs.getString(key);
      if (raw == null || raw.trim().isEmpty) {
        continue;
      }
      try {
        final dynamic decoded = jsonDecode(raw);
        if (decoded is! Map) {
          continue;
        }
        final Map<String, dynamic> row = Map<String, dynamic>.from(decoded);
        final int tsFromKey = _resultTimestampFromStorageKey(key);
        final String quizId = (row['quiz_id'] ?? row['quizId'] ?? '')
            .toString()
            .trim();
        final String title =
            (row['topic'] ?? row['quiz_title'] ?? row['quizTitle'] ?? '')
                .toString()
                .trim();
        final String studentName =
            (row['student_name'] ??
                    row['studentName'] ??
                    row['name'] ??
                    row['student'])
                .toString()
                .trim();
        final String studentId =
            (row['student_id'] ??
                    row['studentId'] ??
                    row['account_id'] ??
                    row['accountId'] ??
                    row['user_id'])
                .toString()
                .trim();
        out.add(<String, dynamic>{
          'id': (row['id'] ?? '').toString(),
          'quiz_id': quizId,
          'topic': title,
          'quiz_title': title,
          'name': studentName,
          'student_name': studentName,
          'student_id': studentId,
          'account_id': studentId,
          'score': row['score'] ?? 0,
          'total': row['total'] ?? row['maxScore'] ?? row['max_score'] ?? 100,
          'max_score':
              row['max_score'] ?? row['maxScore'] ?? row['total'] ?? 100,
          'correct': row['correct'] ?? 0,
          'wrong': row['wrong'] ?? 0,
          'skipped': row['skipped'] ?? 0,
          'submitted_at': (row['submitted_at'] ?? row['savedAt'] ?? '')
              .toString(),
          'ts': row['ts'] ?? row['savedAt'] ?? tsFromKey,
          'type': (row['type'] ?? 'Exam').toString(),
        });
      } catch (_) {}
    }
    return out;
  }

  int _resultSortTs(Map<String, dynamic> result) {
    final dynamic direct = result['ts'] ?? result['timestamp'];
    if (direct is int) {
      return direct > 9999999999 ? direct : direct * 1000;
    }
    if (direct is num) {
      final int v = direct.toInt();
      return v > 9999999999 ? v : v * 1000;
    }
    final List<String> dateKeys = <String>[
      'submitted_at',
      'created_at',
      'date',
      'time',
    ];
    for (final String key in dateKeys) {
      final String raw = (result[key] ?? '').toString().trim();
      if (raw.isEmpty) {
        continue;
      }
      final DateTime? parsed = DateTime.tryParse(raw);
      if (parsed != null) {
        return parsed.millisecondsSinceEpoch;
      }
      final int? asInt = int.tryParse(raw);
      if (asInt != null) {
        return asInt > 9999999999 ? asInt : asInt * 1000;
      }
    }
    return 0;
  }

  DateTime _readItemDate(dynamic raw, DateTime fallback) {
    if (raw is DateTime) {
      return raw;
    }
    return _parseTeacherDate((raw ?? '').toString(), fallback: fallback);
  }

  String _fmtDateTime(DateTime d) {
    final String dd = d.day.toString().padLeft(2, '0');
    final String mm = d.month.toString().padLeft(2, '0');
    final String yy = d.year.toString();
    final String hh = d.hour.toString().padLeft(2, '0');
    final String mi = d.minute.toString().padLeft(2, '0');
    return '$dd/$mm/$yy $hh:$mi';
  }

  double _percentFromResult(dynamic raw) {
    if (raw is! Map) {
      return 0;
    }
    final Map<String, dynamic> row = Map<String, dynamic>.from(raw);
    final double score =
        double.tryParse((row['score'] ?? row['marks'] ?? '').toString()) ?? 0;
    final double total =
        double.tryParse((row['total'] ?? row['max_score'] ?? '').toString()) ??
        0;
    if (total > 0) {
      return ((score / total) * 100).clamp(0.0, 100.0);
    }
    return score.clamp(0.0, 100.0);
  }

  Future<void> _fetch({bool quiet = false}) async {
    if (_fetchInFlight) {
      _fetchQueued = true;
      return;
    }
    _fetchInFlight = true;
    final bool hasWarmData =
        _exams.isNotEmpty ||
        _homeworks.isNotEmpty ||
        _studentHistory.isNotEmpty;
    if (!quiet || !hasWarmData) {
      setState(() => _loading = true);
    }
    try {
      final List<dynamic> fetched = await Future.wait<dynamic>(
        <Future<dynamic>>[
          backendService.fetchMasterCsv(),
          backendService.fetchAllResults(),
        ],
      );
      final String masterCsv = fetched[0] as String;
      final List<dynamic> allResults = List<dynamic>.from(fetched[1] as List);
      final SharedPreferences prefs = await SharedPreferences.getInstance();
      final List<Map<String, dynamic>> localSnapshots =
          _loadLocalResultSnapshots(prefs);
      final List<dynamic> mergedResults = <dynamic>[
        ...localSnapshots,
        ...allResults,
      ];
      final List<List<dynamic>> rows = await parseCsvInBackground(masterCsv);

      final Map<String, Map<String, dynamic>> masterMap =
          <String, Map<String, dynamic>>{};
      for (int i = 1; i < rows.length; i++) {
        final List<dynamic> row = rows[i];
        if (row.length < 2) {
          continue;
        }

        final String title = row[1].toString().trim();
        if (title.isEmpty) {
          continue;
        }

        final String id = row[0].toString().trim();
        DateTime deadline = DateTime.now();
        if (row.length > 3) {
          deadline = _parseTeacherDate(
            row[3].toString(),
            fallback: DateTime.now(),
          );
        }
        final DateTime createdAt = _createdFromMasterRow(
          row,
          id: id,
          fallback: deadline,
        );
        final String type = row.length > 4 ? row[4].toString().trim() : 'Exam';

        final Map<String, dynamic> item = <String, dynamic>{
          'id': id,
          'title': title,
          'date': deadline,
          'deadline': deadline,
          'createdAt': createdAt,
          'type': type,
          'subs': <dynamic>[],
        };
        masterMap[_topicLookupKey(title)] = item;
        masterMap.putIfAbsent(_topicFallbackKey(title), () => item);
        if (id.isNotEmpty) {
          masterMap[_assessmentIdKey(id)] = item;
        }
      }
      final List<QuizItem> localItems = await localQuizStore.listQuizItems(
        viewerAccountId: Session.effectiveAccountId,
        viewerRole: Session.userRole,
      );
      for (final QuizItem item in localItems) {
        final Map<String, dynamic> localRow = <String, dynamic>{
          'id': item.id,
          'title': item.title,
          'date': item.deadline,
          'deadline': item.deadline,
          'createdAt': item.deadline,
          'type': item.type,
          'subs': <dynamic>[],
        };
        masterMap.putIfAbsent(_topicLookupKey(item.title), () => localRow);
        masterMap.putIfAbsent(_topicFallbackKey(item.title), () => localRow);
        if (item.id.trim().isNotEmpty) {
          masterMap.putIfAbsent(_assessmentIdKey(item.id), () => localRow);
        }
      }

      final Map<String, List<dynamic>> byStudent = <String, List<dynamic>>{};
      for (final dynamic raw in mergedResults) {
        final Map<String, dynamic> result = Map<String, dynamic>.from(
          raw as Map,
        );
        final String name = _resultStudentName(result);
        final String studentId = _resultStudentId(result);
        final String studentLabel = name.isNotEmpty
            ? name
            : (studentId.isNotEmpty ? studentId : 'Student');
        if (studentLabel.isNotEmpty) {
          byStudent.putIfAbsent(studentLabel, () => <dynamic>[]).add(result);
        }

        final String topicRaw = _resultTopic(result);
        final String resultQuizId =
            (result['quiz_id'] ?? result['quizId'] ?? '').toString().trim();
        final Map<String, dynamic>? assessment =
            (resultQuizId.isNotEmpty
                ? masterMap[_assessmentIdKey(resultQuizId)]
                : null) ??
            masterMap[_topicLookupKey(topicRaw)] ??
            masterMap[_topicFallbackKey(topicRaw)];
        if (assessment != null) {
          (assessment['subs'] as List<dynamic>).add(result);
        }
      }
      for (final List<dynamic> attempts in byStudent.values) {
        attempts.sort((dynamic a, dynamic b) {
          final Map<String, dynamic> aa = Map<String, dynamic>.from(a as Map);
          final Map<String, dynamic> bb = Map<String, dynamic>.from(b as Map);
          return _resultSortTs(bb).compareTo(_resultSortTs(aa));
        });
      }

      final List<Map<String, dynamic>> tempExams = <Map<String, dynamic>>[];
      final List<Map<String, dynamic>> tempHw = <Map<String, dynamic>>[];

      final Set<Map<String, dynamic>> uniqueAssessments =
          <Map<String, dynamic>>{};
      masterMap.forEach((_, Map<String, dynamic> item) {
        if (!uniqueAssessments.add(item)) {
          return;
        }
        final String type = item['type'].toString().toLowerCase();
        if (type == 'homework') {
          tempHw.add(item);
        } else {
          tempExams.add(item);
        }
      });

      tempExams.sort(
        (Map<String, dynamic> a, Map<String, dynamic> b) => _readItemDate(
          b['deadline'],
          DateTime.now(),
        ).compareTo(_readItemDate(a['deadline'], DateTime.now())),
      );
      tempHw.sort(
        (Map<String, dynamic> a, Map<String, dynamic> b) => _readItemDate(
          b['deadline'],
          DateTime.now(),
        ).compareTo(_readItemDate(a['deadline'], DateTime.now())),
      );

      await notificationService.runTeacherPerformanceScan(
        teacherId: Session.userIdForNotifications,
        exams: tempExams,
        homeworks: tempHw,
        studentHistory: byStudent,
      );

      if (mounted) {
        setState(() {
          _exams = tempExams;
          _homeworks = tempHw;
          _studentHistory = byStudent;
          _loading = false;
        });
      }
    } catch (_) {
      if (mounted) {
        setState(() => _loading = false);
      }
    } finally {
      _fetchInFlight = false;
      if (_fetchQueued && mounted) {
        _fetchQueued = false;
        unawaited(_fetch(quiet: true));
      }
    }
  }

  void _openClassAI() {
    if (_studentHistory.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('No student data available yet')),
      );
      return;
    }

    final List<Map<String, dynamic>> students = _studentHistory.entries
        .map(
          (MapEntry<String, List<dynamic>> e) => <String, dynamic>{
            'name': e.key,
            'history': e.value,
          },
        )
        .toList();

    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => ClassAISummaryScreen(students: students),
      ),
    );
  }

