  Future<void> _loadTeacherClassSchedule({bool quiet = false}) async {
    if (!quiet && mounted) {
      setState(() => _teacherScheduleLoading = true);
    }
    try {
      final List<_LiveClassScheduleItem> schedule =
          await _liveClassScheduleStore.listSchedule(
            viewerRole: 'teacher',
            viewerId: Session.effectiveAccountId,
          );
      if (!mounted) {
        return;
      }
      setState(() {
        _teacherSchedule = schedule;
        _teacherScheduleLoading = false;
      });
    } catch (_) {
      if (mounted) {
        setState(() => _teacherScheduleLoading = false);
      }
    }
  }

  Future<void> _openTeacherLiveClassesModule({
    _LiveClassScheduleItem? scheduledClass,
  }) async {
    final live_models.LiveClassContext contextData = _buildLiveClassContext(
      role: 'teacher',
      scheduledClass: scheduledClass,
    );
    final live_cfg.AppConfig liveConfig = _buildLiveClassesConfig(contextData);
    await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => live_nav.LiveClassFlowBootstrapPage(
          contextOverride: contextData,
          configOverride: liveConfig,
        ),
      ),
    );
  }

  Future<void> _startScheduledClass(_LiveClassScheduleItem item) async {
    final _LiveClassScheduleItem liveClass = await _liveClassScheduleStore
        .markClassLive(item);
    if (mounted) {
      setState(() {
        _teacherSchedule = _teacherSchedule
            .map(
              (_LiveClassScheduleItem each) =>
                  each.classId == liveClass.classId ? liveClass : each,
            )
            .toList(growable: false);
      });
    }
    await _openTeacherLiveClassesModule(scheduledClass: liveClass);
  }

  Future<void> _showScheduleClassSheet() async {
    final TextEditingController titleCtrl = TextEditingController(
      text: 'JEE Live Class',
    );
    final TextEditingController subjectCtrl = TextEditingController(
      text: 'Physics',
    );
    final TextEditingController topicCtrl = TextEditingController(
      text: 'Electrostatics',
    );
    final TextEditingController classCtrl = TextEditingController(
      text: 'Class 11',
    );
    final TextEditingController descriptionCtrl = TextEditingController();
    DateTime selectedDateTime = DateTime.now().add(const Duration(hours: 1));
    int durationMinutes = 90;
    bool saving = false;

    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (BuildContext context) {
        return StatefulBuilder(
          builder:
              (
                BuildContext context,
                void Function(void Function()) setModalState,
              ) {
                Future<void> pickDateTime() async {
                  final DateTime now = DateTime.now();
                  final DateTime? date = await showDatePicker(
                    context: context,
                    initialDate: selectedDateTime,
                    firstDate: now.subtract(const Duration(days: 1)),
                    lastDate: now.add(const Duration(days: 365)),
                  );
                  if (date == null) {
                    return;
                  }
                  final TimeOfDay? time = await showTimePicker(
                    context: context,
                    initialTime: TimeOfDay.fromDateTime(selectedDateTime),
                  );
                  if (time == null) {
                    return;
                  }
                  setModalState(() {
                    selectedDateTime = DateTime(
                      date.year,
                      date.month,
                      date.day,
                      time.hour,
                      time.minute,
                    );
                  });
                }

                Future<void> submit() async {
                  final String title = titleCtrl.text.trim();
                  final String subject = subjectCtrl.text.trim();
                  final String topic = topicCtrl.text.trim();
                  final String className = classCtrl.text.trim();
                  if (title.isEmpty ||
                      subject.isEmpty ||
                      topic.isEmpty ||
                      className.isEmpty) {
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(
                        content: Text('Please fill all required fields'),
                      ),
                    );
                    return;
                  }
                  setModalState(() => saving = true);
                  final _LiveClassScheduleItem item =
                      await _liveClassScheduleStore.scheduleClass(
                        teacherId: Session.effectiveAccountId,
                        teacherName: Session.effectiveDisplayName,
                        className: className,
                        title: title,
                        subject: subject,
                        topic: topic,
                        startAt: selectedDateTime,
                        durationMinutes: durationMinutes,
                        description: descriptionCtrl.text.trim(),
                      );
                  if (!mounted) {
                    return;
                  }
                  Navigator.pop(context);
                  await _loadTeacherClassSchedule(quiet: true);
                  if (!mounted) {
                    return;
                  }
                  ScaffoldMessenger.of(this.context).showSnackBar(
                    SnackBar(
                      content: Text(
                        'Scheduled "${item.title}" for ${_formatClassScheduleTime(item.startAt)}',
                      ),
                    ),
                  );
                }

                return SafeArea(
                  child: Padding(
                    padding: EdgeInsets.only(
                      left: 12,
                      right: 12,
                      bottom: MediaQuery.of(context).viewInsets.bottom + 12,
                    ),
                    child: LiquidGlass(
                      borderRadius: BorderRadius.circular(22),
                      padding: const EdgeInsets.all(16),
                      child: SingleChildScrollView(
                        child: Column(
                          mainAxisSize: MainAxisSize.min,
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: <Widget>[
                            const Text(
                              'Schedule Live Class',
                              style: TextStyle(
                                fontSize: 18,
                                fontWeight: FontWeight.w800,
                              ),
                            ),
                            const SizedBox(height: 12),
                            TextField(
                              controller: titleCtrl,
                              decoration: const InputDecoration(
                                labelText: 'Class Title',
                              ),
                            ),
                            const SizedBox(height: 10),
                            Row(
                              children: <Widget>[
                                Expanded(
                                  child: TextField(
                                    controller: subjectCtrl,
                                    decoration: const InputDecoration(
                                      labelText: 'Subject',
                                    ),
                                  ),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: TextField(
                                    controller: classCtrl,
                                    decoration: const InputDecoration(
                                      labelText: 'Class',
                                    ),
                                  ),
                                ),
                              ],
                            ),
                            const SizedBox(height: 10),
                            TextField(
                              controller: topicCtrl,
                              decoration: const InputDecoration(
                                labelText: 'Topic',
                              ),
                            ),
                            const SizedBox(height: 10),
                            TextField(
                              controller: descriptionCtrl,
                              maxLines: 2,
                              decoration: const InputDecoration(
                                labelText: 'Description (optional)',
                              ),
                            ),
                            const SizedBox(height: 10),
                            ListTile(
                              contentPadding: EdgeInsets.zero,
                              title: const Text('Start Time'),
                              subtitle: Text(
                                _formatClassScheduleTime(selectedDateTime),
                              ),
                              trailing: const Icon(Icons.schedule_rounded),
                              onTap: pickDateTime,
                            ),
                            const SizedBox(height: 6),
                            DropdownButtonFormField<int>(
                              value: durationMinutes,
                              decoration: const InputDecoration(
                                labelText: 'Duration',
                              ),
                              items: const <int>[45, 60, 75, 90, 120]
                                  .map(
                                    (int value) => DropdownMenuItem<int>(
                                      value: value,
                                      child: Text('$value min'),
                                    ),
                                  )
                                  .toList(),
                              onChanged: (int? value) {
                                if (value == null) {
                                  return;
                                }
                                setModalState(() => durationMinutes = value);
                              },
                            ),
                            const SizedBox(height: 14),
                            Row(
                              children: <Widget>[
                                Expanded(
                                  child: OutlinedButton(
                                    onPressed: saving
                                        ? null
                                        : () => Navigator.pop(context),
                                    child: const Text('Cancel'),
                                  ),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: FilledButton.icon(
                                    onPressed: saving ? null : submit,
                                    icon: saving
                                        ? const SizedBox(
                                            width: 14,
                                            height: 14,
                                            child: CircularProgressIndicator(
                                              strokeWidth: 2,
                                            ),
                                          )
                                        : const Icon(Icons.check_rounded),
                                    label: Text(
                                      saving ? 'Saving...' : 'Schedule',
                                    ),
                                  ),
                                ),
                              ],
                            ),
                          ],
                        ),
                      ),
                    ),
                  ),
                );
              },
        );
      },
    );
    titleCtrl.dispose();
    subjectCtrl.dispose();
    topicCtrl.dispose();
    classCtrl.dispose();
    descriptionCtrl.dispose();
  }

  Widget _buildTeacherStatusChip(_LiveClassScheduleItem item) {
