            borderRadius: BorderRadius.circular(999),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: <Widget>[
                _TeacherLiquidActionButton(
                  label: 'Add Study Material',
                  iconOnly: true,
                  motion: _TeacherActionIconMotion.bookFlip,
                  tint: const Color(0xFFFFF2B2),
                  foreground: const Color(0xFF7A5A00),
                  onTap: _openTeacherAddMaterial,
                ),
                const SizedBox(width: 10),
                _TeacherLiquidActionButton(
                  label: 'Create Quiz',
                  iconOnly: true,
                  motion: _TeacherActionIconMotion.penWrite,
                  tint: const Color(0xFFCBE9FF),
                  foreground: const Color(0xFF12537A),
                  onTap: _openTeacherCreateQuiz,
                ),
              ],
            ),
          ),
        ),
      ),
      body:
          (_loading &&
              _exams.isEmpty &&
              _homeworks.isEmpty &&
              _studentHistory.isEmpty)
          ? const Center(child: CircularProgressIndicator())
          : Padding(
              padding: const EdgeInsets.all(12),
              child: () {
                if (_idx == 0) {
                  return _glassPage(_buildResultTabs(_exams, label: 'exam'));
                }
                if (_idx == 1) {
                  return _glassPage(
                    _buildResultTabs(_homeworks, label: 'homework'),
                  );
                }
                if (_idx == 2) {
                  return _buildTeacherClassesHub();
                }
                if (_idx == 3) {
                  return _glassPage(
                    const StudyMaterialScreen(
                      studentName: 'Admin',
                      enableAiActions: false,
                    ),
                  );
                }
                if (_idx == 4) {
                  return _glassPage(_buildStudentList());
                }
                return const SizedBox.shrink();
              }(),
            ),
      bottomNavigationBar: _AppleLiquidBottomBar(
        selectedIndex: _idx,
        onSelected: (int index) {
          setState(() => _idx = index);
          if (index <= 1) {
            unawaited(_fetch(quiet: true));
          } else if (index == 2) {
            unawaited(_loadTeacherClassSchedule(quiet: true));
          }
        },
        padding: const EdgeInsets.only(
          left: 20,
          right: 20,
          top: 10,
          bottom: 25,
        ),
        destinations: const <_BottomNavDestination>[
          _BottomNavDestination(icon: Icons.timer, label: 'Exams'),
          _BottomNavDestination(icon: Icons.book, label: 'Homeworks'),
          _BottomNavDestination(icon: Icons.live_tv, label: 'Classes'),
          _BottomNavDestination(icon: Icons.menu_book, label: 'Study'),
          _BottomNavDestination(
            icon: Icons.insights,
            label: 'Student Analytics',
          ),
        ],
      ),
    );
  }

  Widget _buildResultTabs(
    List<Map<String, dynamic>> items, {
    required String label,
  }) {
    return TabBarView(
      controller: _statusTabs,
      children: <Widget>[
        _buildResultList(items, deadlinePassed: false, label: label),
        _buildResultList(items, deadlinePassed: true, label: label),
      ],
    );
  }

  Widget _buildResultList(
    List<Map<String, dynamic>> items, {
    required bool deadlinePassed,
    required String label,
  }) {
    final DateTime now = DateTime.now();
    final List<Map<String, dynamic>> filtered = items.where((
      Map<String, dynamic> item,
    ) {
      final DateTime deadline = _readItemDate(item['deadline'], now);
      final bool passed = now.isAfter(deadline.add(const Duration(minutes: 2)));
      return deadlinePassed ? passed : !passed;
    }).toList();

    if (filtered.isEmpty) {
      final String state = deadlinePassed ? 'deadline passed' : 'active';
      return Center(child: Text('No $state $label items'));
    }

    return ListView.builder(
      padding: const EdgeInsets.all(20),
      itemCount: filtered.length,
      itemBuilder: (_, int index) {
        final Map<String, dynamic> item = filtered[index];
        final DateTime deadline = _readItemDate(
          item['deadline'],
          DateTime.now(),
        );
        final DateTime createdAt = _readItemDate(item['createdAt'], deadline);
        final String dateMeta =
            'Created: ${_fmtDateTime(createdAt)}  •  Deadline: ${_fmtDateTime(deadline)}';

        return StaggeredList(
          index: index,
          child: Padding(
            padding: const EdgeInsets.only(bottom: 15),
            child: LiquidGlass(
              padding: const EdgeInsets.all(16),
              onTap: () => Navigator.push(
                context,
                MaterialPageRoute(
                  builder: (_) => TeacherResultDetail(
                    topic: item['title'].toString(),
                    date: _fmtDateTime(deadline),
                    submissions: item['subs'] as List<dynamic>,
                  ),
                ),
              ),
              child: Row(
                children: <Widget>[
                  Container(
                    padding: const EdgeInsets.all(12),
                    decoration: BoxDecoration(
                      color: AppColors.primary.withOpacity(0.15),
                      borderRadius: BorderRadius.circular(14),
                    ),
                    child: Text(
                      '${(item['subs'] as List<dynamic>).length}',
                      style: const TextStyle(
                        fontWeight: FontWeight.bold,
                        fontSize: 18,
                        color: AppColors.primary,
                      ),
                    ),
                  ),
                  const SizedBox(width: 15),
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: <Widget>[
                        Text(
                          item['title'].toString(),
                          style: const TextStyle(
                            fontWeight: FontWeight.bold,
                            fontSize: 16,
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          dateMeta,
                          style: const TextStyle(
                            color: Colors.grey,
                            fontSize: 12,
                          ),
                        ),
                      ],
                    ),
                  ),
                  const Icon(
                    Icons.arrow_forward_ios,
                    size: 14,
                    color: Colors.grey,
                  ),
                ],
              ),
            ),
          ),
        );
      },
    );
  }

  Widget _buildStudentList() {
    final List<String> names = _studentHistory.keys.toList()..sort();
    if (names.isEmpty) {
      return const Center(child: Text('No student submissions yet'));
    }

    return ListView(
      padding: const EdgeInsets.all(20),
      children: <Widget>[
        LiquidGlass(
          padding: const EdgeInsets.all(14),
          child: Row(
            children: <Widget>[
              const Expanded(
                child: Text(
                  'Class-level AI overview is available in Student Analytics.',
                  style: TextStyle(fontSize: 13.5),
                ),
              ),
              const SizedBox(width: 10),
              ElevatedButton.icon(
                onPressed: _openClassAI,
                icon: const Icon(Icons.psychology, size: 16),
                label: const Text('Open'),
              ),
            ],
          ),
        ),
        const SizedBox(height: 12),
        ...List<Widget>.generate(names.length, (int i) {
          final String name = names[i];
          final List<dynamic> history = _studentHistory[name]!;
          final double avg =
              history
                  .map((dynamic e) => _percentFromResult(e))
                  .reduce((double a, double b) => a + b) /
              history.length;

          return StaggeredList(
            index: i,
            child: Padding(
              padding: const EdgeInsets.only(bottom: 12),
              child: LiquidGlass(
                padding: const EdgeInsets.all(16),
                onTap: () => Navigator.push(
                  context,
                  MaterialPageRoute(
                    builder: (_) =>
                        TeacherStudentProfile(name: name, history: history),
                  ),
                ),
                child: Row(
                  children: <Widget>[
                    CircleAvatar(
                      backgroundColor: AppColors.primary.withOpacity(0.15),
                      child: Text(
                        name[0],
                        style: const TextStyle(
                          color: AppColors.primary,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                    ),
                    const SizedBox(width: 15),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          Text(
                            name,
                            style: const TextStyle(fontWeight: FontWeight.bold),
                          ),
                          Text(
                            '${history.length} Quizzes',
                            style: const TextStyle(
                              color: Colors.grey,
                              fontSize: 12,
                            ),
                          ),
                        ],
                      ),
                    ),
                    Text(
                      '${avg.toStringAsFixed(1)}%',
                      style: const TextStyle(
                        fontWeight: FontWeight.bold,
                        color: AppColors.primary,
                      ),
                    ),
                  ],
                ),
              ),
            ),
          );
        }),
      ],
    );
  }
}

class TeacherResultDetail extends StatelessWidget {
  const TeacherResultDetail({
    super.key,
    required this.topic,
    required this.date,
    required this.submissions,
  });

  final String topic;
  final String date;
  final List<dynamic> submissions;

  @override
  Widget build(BuildContext context) {
    submissions.sort((dynamic a, dynamic b) {
      final double sA =
          double.tryParse((a as Map<String, dynamic>)['score'].toString()) ?? 0;
      final double sB =
          double.tryParse((b as Map<String, dynamic>)['score'].toString()) ?? 0;
      return sB.compareTo(sA);
    });

    final List<double> scores = submissions
        .map(
          (dynamic e) =>
              double.tryParse(
                (e as Map<String, dynamic>)['score'].toString(),
              ) ??
              0,
        )
        .toList();

    final double avg = scores.isEmpty
        ? 0
        : scores.reduce((double a, double b) => a + b) / scores.length;
    final int low = scores.where((double s) => s < 30).length;
    final int mid = scores.where((double s) => s >= 30 && s < 70).length;
    final int high = scores.where((double s) => s >= 70).length;

    return Scaffold(
      appBar: AppBar(title: Text(topic)),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(20),
        child: Column(
          children: <Widget>[
            LiquidGlass(
              padding: const EdgeInsets.all(20),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.spaceAround,
                children: <Widget>[
                  _stat('Submitted', '${submissions.length}', Colors.blue),
                  _stat('Avg Score', avg.toStringAsFixed(1), Colors.orange),
                  _stat(
                    'Highest',
                    scores.isNotEmpty ? scores.first.toStringAsFixed(0) : '0',
                    Colors.green,
                  ),
                ],
              ),
            ),
            const SizedBox(height: 30),
            const Text(
              'Score Distribution',
              style: TextStyle(fontWeight: FontWeight.bold, fontSize: 18),
            ),
            const SizedBox(height: 15),
            SizedBox(
              height: 120,
              child: Row(
                crossAxisAlignment: CrossAxisAlignment.end,
                children: <Widget>[
                  _bar(low, Colors.red, 'Low (<30%)'),
                  _bar(mid, Colors.orange, 'Avg (30–70%)'),
                  _bar(high, Colors.green, 'High (>70%)'),
                ],
              ),
            ),
            const SizedBox(height: 30),
            const Align(
              alignment: Alignment.centerLeft,
              child: Text(
                'Leaderboard',
                style: TextStyle(fontWeight: FontWeight.bold, fontSize: 18),
              ),
            ),
            const SizedBox(height: 10),
            ...List<Widget>.generate(submissions.length, (int i) {
              final Map<String, dynamic> row =
                  submissions[i] as Map<String, dynamic>;
              return Padding(
                padding: const EdgeInsets.only(bottom: 10),
                child: LiquidGlass(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 20,
                    vertical: 15,
                  ),
                  child: Row(
                    children: <Widget>[
                      Text(
                        '#${i + 1}',
                        style: const TextStyle(
                          fontWeight: FontWeight.bold,
                          fontSize: 16,
                          color: AppColors.primary,
                        ),
                      ),
                      const SizedBox(width: 15),
                      Expanded(
                        child: Text(
                          row['name'].toString(),
                          style: const TextStyle(fontWeight: FontWeight.bold),
                        ),
                      ),
                      Text(
                        '${row['score']} / ${row['total']}',
                        style: const TextStyle(fontWeight: FontWeight.bold),
                      ),
                    ],
                  ),
                ),
              );
            }),
          ],
        ),
      ),
    );
  }

  Widget _stat(String label, String value, Color color) {
    return Column(
      children: <Widget>[
        Text(
          value,
          style: TextStyle(
            fontSize: 24,
            fontWeight: FontWeight.bold,
            color: color,
          ),
        ),
        Text(label, style: const TextStyle(fontSize: 12, color: Colors.grey)),
      ],
    );
  }

  Widget _bar(int value, Color color, String label) {
    return Expanded(
      child: Column(
        mainAxisAlignment: MainAxisAlignment.end,
        children: <Widget>[
          Container(
            height: (value * 20.0 + 10).clamp(10.0, 100.0),
            width: 30,
            decoration: BoxDecoration(
              color: color.withOpacity(0.8),
              borderRadius: BorderRadius.circular(8),
            ),
          ),
          const SizedBox(height: 5),
          Text(
            label,
            style: const TextStyle(fontSize: 10, fontWeight: FontWeight.bold),
          ),
          Text(
            '$value',
            style: TextStyle(
              fontSize: 12,
              color: color,
              fontWeight: FontWeight.bold,
            ),
          ),
        ],
      ),
    );
  }
}

class ClassAISummaryScreen extends StatefulWidget {
  const ClassAISummaryScreen({super.key, required this.students});

  final List<Map<String, dynamic>> students;

  @override
  State<ClassAISummaryScreen> createState() => _ClassAISummaryScreenState();
}

class _ClassAISummaryScreenState extends State<ClassAISummaryScreen> {
  bool _loading = true;
  Map<String, dynamic>? _data;

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() => _loading = true);
    try {
      final Map<String, dynamic> res = await aiService.classSummary(
        widget.students,
      );
      if (res['ok'] == true) {
        setState(() {
          _data = Map<String, dynamic>.from(
            res['data'] as Map? ?? <String, dynamic>{},
          );
          _loading = false;
        });
        await notificationService.addAiNotification(
          title: 'Class AI Overview Ready',
          body: 'New class-level insights and action plan generated.',
          type: 'ai',
        );
        return;
      }
    } catch (_) {}

    setState(() {
      _loading = false;
      _data = null;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Class AI Overview'),
        actions: <Widget>[
          IconButton(icon: const Icon(Icons.refresh), onPressed: _load),
        ],
      ),
      body: _loading
          ? const Center(child: CircularProgressIndicator())
          : _data == null
          ? const Center(child: Text('AI not available'))
          : ListView(
              padding: const EdgeInsets.all(20),
              children: <Widget>[
                LiquidGlass(
                  padding: const EdgeInsets.all(24),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: <Widget>[
                      const Text(
                        'Class AI Overview',
                        style: TextStyle(
                          fontSize: 22,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                      const SizedBox(height: 12),
                      Text(
                        (_data!['summary'] ?? '').toString(),
                        style: const TextStyle(fontSize: 15, height: 1.4),
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 20),
                _listCard(
                  'Key Insights',
                  (_data!['insights'] ?? <dynamic>[]) as List<dynamic>,
                ),
                const SizedBox(height: 20),
                _listCard(
                  'Action Plan',
                  (_data!['actions'] ?? <dynamic>[]) as List<dynamic>,
                ),
              ],
            ),
    );
  }

  Widget _listCard(String title, List<dynamic> list) {
    return LiquidGlass(
      padding: const EdgeInsets.all(16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Text(
            title,
            style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
          ),
          const SizedBox(height: 8),
          ...list.map((dynamic e) => Text('• $e')),
        ],
      ),
    );
  }
}

class TeacherStudentProfile extends StatefulWidget {
  const TeacherStudentProfile({
    super.key,
    required this.name,
    required this.history,
  });

  final String name;
  final List<dynamic> history;

  @override
  State<TeacherStudentProfile> createState() => _TeacherStudentProfileState();
}

class _TeacherStudentProfileState extends State<TeacherStudentProfile> {
  Map<String, dynamic>? _ai;
  bool _loadingAI = true;

  @override
  void initState() {
    super.initState();
    _loadAI();
  }

  Future<void> _loadAI({bool force = false}) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final String key = 'ai_teacher_${widget.name.hashCode}';

    if (!force) {
      final String? cached = prefs.getString(key);
      if (cached != null) {
        setState(() {
          _ai = jsonDecode(cached) as Map<String, dynamic>;
          _loadingAI = false;
        });
        return;
      }
    }

    setState(() => _loadingAI = true);
    try {
      final Map<String, dynamic> response = await aiService.studentProfile(
        widget.history,
      );
      if (response['ok'] == true && response['profile'] != null) {
        _ai = Map<String, dynamic>.from(response['profile'] as Map);
        await prefs.setString(key, jsonEncode(_ai));
      } else {
        _ai = <String, dynamic>{
          'summary': 'AI analysis not available right now.',
          'action_plan': <String>[],
          'weekly_plan': <String>[],
        };
      }
    } catch (_) {
      _ai = <String, dynamic>{
        'summary': 'AI analysis not available right now.',
        'action_plan': <String>[],
        'weekly_plan': <String>[],
      };
    }

    if (mounted) {
      setState(() => _loadingAI = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    final List<dynamic> history = widget.history;
    if (history.isEmpty) {
      return Scaffold(
        appBar: AppBar(title: Text(widget.name)),
        body: const Center(child: Text('No history found')),
      );
    }

    final List<Map<String, dynamic>> analysis = history.map((dynamic raw) {
      final Map<String, dynamic> h = Map<String, dynamic>.from(raw as Map);
      final double s = double.tryParse(h['score'].toString()) ?? 0;
      final double t = double.tryParse(h['total'].toString()) ?? 1;
      return <String, dynamic>{
        'topic': h['topic'],
        'pct': (s / t) * 100,
        'score': s,
        'total': t,
      };
    }).toList();

    analysis.sort(
      (Map<String, dynamic> a, Map<String, dynamic> b) =>
          (a['pct'] as double).compareTo(b['pct'] as double),
    );

    final List<FlSpot> spots = <FlSpot>[];
    for (int i = 0; i < analysis.length; i++) {
      spots.add(FlSpot(i.toDouble(), (analysis[i]['pct'] as double)));
    }

    final double avg =
        analysis
            .map((Map<String, dynamic> e) => e['pct'] as double)
            .reduce((double a, double b) => a + b) /
        analysis.length;
    final double best = analysis
        .map((Map<String, dynamic> e) => e['pct'] as double)
        .reduce((double a, double b) => a > b ? a : b);
    final double worst = analysis
        .map((Map<String, dynamic> e) => e['pct'] as double)
        .reduce((double a, double b) => a < b ? a : b);

    return Scaffold(
      appBar: AppBar(
        title: Text(widget.name),
        actions: <Widget>[
          IconButton(
            icon: const Icon(Icons.refresh),
            onPressed: () => _loadAI(force: true),
          ),
        ],
      ),
      body: ListView(
        padding: const EdgeInsets.all(20),
        children: <Widget>[
          if (_loadingAI)
            LiquidGlass(
              padding: const EdgeInsets.all(20),
              child: const Row(
                children: <Widget>[
                  CircularProgressIndicator(strokeWidth: 2),
                  SizedBox(width: 12),
                  Text('AI is analyzing student...'),
                ],
              ),
            )
          else if (_ai != null)
            LiquidGlass(
              padding: const EdgeInsets.all(20),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text(
                    'AI Coach Summary',
                    style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
                  ),
                  const SizedBox(height: 10),
                  Text((_ai!['summary'] ?? '').toString()),
                  const SizedBox(height: 12),
                  const Text(
                    'Action Plan',
                    style: TextStyle(fontWeight: FontWeight.bold),
                  ),
                  ...((_ai!['action_plan'] ?? <dynamic>[]) as List<dynamic>)
                      .map((dynamic e) => Text('• $e')),
                  const SizedBox(height: 12),
                  const Text(
                    'Weekly Plan',
                    style: TextStyle(fontWeight: FontWeight.bold),
                  ),
                  ...((_ai!['weekly_plan'] ?? <dynamic>[]) as List<dynamic>)
                      .map((dynamic e) => Text('• $e')),
                ],
              ),
            ),
          const SizedBox(height: 20),
          LiquidGlass(
            padding: const EdgeInsets.all(20),
            child: Column(
              children: <Widget>[
                CircleAvatar(
                  radius: 40,
                  backgroundColor: AppColors.primary.withOpacity(0.15),
                  child: Text(
                    widget.name[0].toUpperCase(),
                    style: const TextStyle(
                      fontSize: 36,
                      fontWeight: FontWeight.bold,
                      color: AppColors.primary,
                    ),
                  ),
                ),
                const SizedBox(height: 10),
                Text(
                  widget.name,
                  style: const TextStyle(
                    fontSize: 24,
                    fontWeight: FontWeight.bold,
                  ),
                ),
                Text(
                  '${history.length} Tests Attempted',
                  style: const TextStyle(color: Colors.grey),
                ),
              ],
            ),
          ),
          const SizedBox(height: 20),
          Row(
            children: <Widget>[
              _miniStat('AVG', avg, Colors.blue),
              const SizedBox(width: 12),
              _miniStat('BEST', best, Colors.green),
              const SizedBox(width: 12),
              _miniStat('WORST', worst, Colors.red),
            ],
          ),
          const SizedBox(height: 24),
          const Text(
            'Performance Trend',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
          ),
          const SizedBox(height: 12),
          LiquidGlass(
            padding: const EdgeInsets.all(12),
            child: SizedBox(
              height: 220,
              child: LineChart(
                LineChartData(
                  gridData: const FlGridData(show: false),
                  titlesData: const FlTitlesData(show: false),
                  borderData: FlBorderData(show: false),
                  lineBarsData: <LineChartBarData>[
                    LineChartBarData(
                      spots: spots,
                      isCurved: true,
                      color: AppColors.primary,
                      barWidth: 4,
                      dotData: const FlDotData(show: true),
                      belowBarData: BarAreaData(
                        show: true,
                        color: AppColors.primary.withOpacity(0.15),
                      ),
                    ),
                  ],
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _miniStat(String label, double value, Color color) {
    return Expanded(
      child: LiquidGlass(
        padding: const EdgeInsets.all(14),
        child: Column(
          children: <Widget>[
            Text(
              '${value.toStringAsFixed(1)}%',
              style: TextStyle(
                fontSize: 22,
                fontWeight: FontWeight.bold,
                color: color,
              ),
            ),
            const SizedBox(height: 4),
            Text(label, style: const TextStyle(color: Colors.grey)),
          ],
        ),
      ),
    );
  }
}

