  ];

  void _setAiGenerationStage(int stage, {String? label, String detail = ''}) {
    if (!mounted) {
      return;
    }
    final int clamped = stage.clamp(1, _aiGenerationStages.length);
    setState(() {
      _aiGenerationStage = clamped;
      _aiPreparingProgressTotal = _aiGenerationStages.length;
      _aiPreparingProgressCurrent = clamped;
      _aiPreparingLabel = label ?? _aiGenerationStages[clamped - 1];
      _aiPreparingDetail = detail;
    });
  }

  void _startAiThinkingTicker() {
    _aiThinkingTimer?.cancel();
    _aiThinkingMessageIndex = 0;
    _aiThinkingTimer = Timer.periodic(const Duration(milliseconds: 1350), (
      Timer timer,
    ) {
      if (!mounted || !_aiGenerating) {
        timer.cancel();
        return;
      }
      setState(() {
        _aiThinkingMessageIndex =
            (_aiThinkingMessageIndex + 1) % _aiThinkingMessages.length;
      });
    });
  }

  void _stopAiThinkingTicker() {
    _aiThinkingTimer?.cancel();
    _aiThinkingTimer = null;
    _aiThinkingMessageIndex = 0;
  }

  Future<void> _enforceMinimumAiLoading(DateTime startedAt) async {
    final Duration elapsed = DateTime.now().difference(startedAt);
    if (elapsed < _minAiLoadingDuration) {
      await Future<void>.delayed(_minAiLoadingDuration - elapsed);
    }
  }

