  Future<void> _pickImage(bool camera) async {
    final XFile? f = await ImagePicker().pickImage(
      source: camera ? ImageSource.camera : ImageSource.gallery,
      imageQuality: 60,
      maxWidth: 1280,
    );
    if (f == null) {
      return;
    }
    final Uint8List bytes = await f.readAsBytes();
    setState(() => _img = 'data:image/jpeg;base64,${base64Encode(bytes)}');
  }

  String _normalizeSubPartName(String raw) {
    final String cleaned = raw.trim().replaceAll(RegExp(r'\s+'), ' ');
    return cleaned;
  }

  String _defaultSubPartName(int index) {
    if (index < 0) {
      return 'Part A';
    }
    if (index < 26) {
      final int code = 'A'.codeUnitAt(0) + index;
      return 'Part ${String.fromCharCode(code)}';
    }
    return 'Part ${index + 1}';
  }

  List<String> _resolvedSubParts() {
    final List<String> out = <String>[];
    final Set<String> seenLower = <String>{};
    for (final String candidate in <String>[
      ..._quizSubParts,
      ..._questions.map((QuizQuestion q) => q.subPart),
    ]) {
      final String normalized = _normalizeSubPartName(candidate);
      if (normalized.isEmpty) {
        continue;
      }
      final String key = normalized.toLowerCase();
      if (seenLower.add(key)) {
        out.add(normalized);
      }
    }
    return out;
  }

  void _registerSubPart(String raw) {
    final String normalized = _normalizeSubPartName(raw);
    if (normalized.isEmpty) {
      return;
    }
    final Set<String> lower = _quizSubParts
        .map((String e) => e.trim().toLowerCase())
        .toSet();
    if (lower.contains(normalized.toLowerCase())) {
      return;
    }
    _quizSubParts = <String>[..._quizSubParts, normalized];
  }

  String _inferImageMimeType(String fileName) {
    final String lower = fileName.toLowerCase();
    if (lower.endsWith('.png')) {
      return 'image/png';
    }
    if (lower.endsWith('.webp')) {
      return 'image/webp';
    }
    if (lower.endsWith('.heic')) {
      return 'image/heic';
    }
    if (lower.endsWith('.heif')) {
      return 'image/heif';
    }
    return 'image/jpeg';
  }

  String _toImageDataUrl(_PaperImportImage image) {
    return 'data:${image.mimeType};base64,${base64Encode(image.bytes)}';
  }

  String _fileStem(String fileName) {
    final String trimmed = fileName.trim();
    if (trimmed.isEmpty) {
      return 'paper';
    }
    final int dot = trimmed.lastIndexOf('.');
    if (dot <= 0) {
      return trimmed;
    }
    return trimmed.substring(0, dot);
  }

  String _compactImportLabel(String raw, {int maxChars = 38}) {
    final String cleaned = raw.trim().replaceAll(RegExp(r'\s+'), ' ');
    if (cleaned.isEmpty) {
      return 'untitled';
    }
    if (cleaned.length <= maxChars) {
      return cleaned;
    }
    return '${cleaned.substring(0, maxChars - 1)}…';
  }

  String _paperImportFormatLabel(_PaperImportImage image) {
    switch (image.sourceKind) {
      case 'pdf':
        return 'PDF';
      case 'camera':
        return 'Camera';
      case 'gallery':
        return 'Gallery';
      default:
        final String lowerMime = image.mimeType.toLowerCase();
        if (lowerMime.contains('heic') || lowerMime.contains('heif')) {
          return 'HEIC';
        }
        if (lowerMime.contains('webp')) {
          return 'WEBP';
        }
        return 'Image';
    }
  }

  String _paperImportSourceName(_PaperImportImage image) {
    final String preferred = image.sourceName.trim().isNotEmpty
        ? image.sourceName
        : image.fileName;
    return _compactImportLabel(preferred);
  }

  Future<List<_PaperImportImage>> _pdfToPaperImages({
    required Uint8List pdfBytes,
    required String fileName,
  }) async {
    final List<_PaperImportImage> pages = <_PaperImportImage>[];
    final String stem = _fileStem(fileName);
    int pageNumber = 0;
    await for (final PdfRaster raster in Printing.raster(pdfBytes, dpi: 220)) {
      pageNumber++;
      final Uint8List png = await raster.toPng();
      if (png.isEmpty) {
        continue;
      }
      pages.add(
        _PaperImportImage(
          bytes: png,
          fileName: '${stem}_page_$pageNumber.png',
          mimeType: 'image/png',
          sourceKind: 'pdf',
          sourceName: fileName,
        ),
      );
      if (pages.length >= _maxPdfPagesPerImport) {
        break;
      }
    }
    return pages;
  }

  Future<List<_PaperImportImage>> _pickPaperFromCamera() async {
    final XFile? image = await ImagePicker().pickImage(
      source: ImageSource.camera,
      imageQuality: 95,
      maxWidth: 2200,
    );
    if (image == null) {
      return <_PaperImportImage>[];
    }
    final Uint8List bytes = await image.readAsBytes();
    return <_PaperImportImage>[
      _PaperImportImage(
        bytes: bytes,
        fileName: image.name.trim().isEmpty
            ? 'camera_${DateTime.now().millisecondsSinceEpoch}.jpg'
            : image.name,
        mimeType: _inferImageMimeType(image.name),
        sourceKind: 'camera',
        sourceName: 'Camera capture',
      ),
    ];
  }

  Future<List<_PaperImportImage>> _pickPaperFromGallery() async {
    final List<XFile> images = await ImagePicker().pickMultiImage(
      imageQuality: 95,
      maxWidth: 2200,
    );
    final List<_PaperImportImage> out = <_PaperImportImage>[];
    for (final XFile image in images) {
      final Uint8List bytes = await image.readAsBytes();
      out.add(
        _PaperImportImage(
          bytes: bytes,
          fileName: image.name.trim().isEmpty
              ? 'gallery_${out.length + 1}.jpg'
              : image.name,
          mimeType: _inferImageMimeType(image.name),
          sourceKind: 'gallery',
          sourceName: image.name,
        ),
      );
    }
    return out;
  }

  Future<List<_PaperImportImage>> _pickPaperFromFiles() async {
    final FilePickerResult? result = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      allowMultiple: true,
      withData: true,
      allowedExtensions: <String>[
        'jpg',
        'jpeg',
        'png',
        'webp',
        'heic',
        'heif',
        'pdf',
      ],
    );
    if (result == null) {
      return <_PaperImportImage>[];
    }
    final List<_PaperImportImage> out = <_PaperImportImage>[];
    for (final PlatformFile file in result.files) {
      Uint8List? bytes = file.bytes;
      if (bytes == null && (file.path ?? '').trim().isNotEmpty) {
        try {
          bytes = await File(file.path!).readAsBytes();
        } catch (_) {
          bytes = null;
        }
      }
      if (bytes == null || bytes.isEmpty) {
        continue;
      }
      final String name = file.name.trim().isEmpty
          ? 'page_${out.length + 1}.jpg'
          : file.name;
      final String lowerName = name.toLowerCase();
      if (lowerName.endsWith('.pdf')) {
        try {
          final List<_PaperImportImage> pages = await _pdfToPaperImages(
            pdfBytes: bytes,
            fileName: name,
          );
          out.addAll(pages);
        } catch (_) {}
        continue;
      }
      out.add(
        _PaperImportImage(
          bytes: bytes,
          fileName: name,
          mimeType: _inferImageMimeType(name),
          sourceKind: 'file_image',
          sourceName: name,
        ),
      );
    }
    return out;
  }

  Future<List<_PaperImportImage>> _pickPaperImportImages() async {
    final String? source = await showModalBottomSheet<String>(
      context: context,
      builder: (BuildContext context) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              ListTile(
                leading: const Icon(Icons.camera_alt_rounded),
                title: const Text('Capture With Camera'),
                subtitle: const Text('Take one photo of question paper'),
                onTap: () => Navigator.pop(context, 'camera'),
              ),
              ListTile(
                leading: const Icon(Icons.photo_library_rounded),
                title: const Text('Pick From Gallery'),
                subtitle: const Text('Select one or multiple pages'),
                onTap: () => Navigator.pop(context, 'gallery'),
              ),
              ListTile(
                leading: const Icon(Icons.upload_file_rounded),
                title: const Text('Pick From Files'),
                subtitle: const Text('Import PDF/image files'),
                onTap: () => Navigator.pop(context, 'files'),
              ),
            ],
          ),
        );
      },
    );
    if (source == null) {
      return <_PaperImportImage>[];
    }
    if (source == 'camera') {
      return _pickPaperFromCamera();
    }
    if (source == 'gallery') {
      return _pickPaperFromGallery();
    }
    return _pickPaperFromFiles();
  }

  Future<List<String>?> _collectSubPartAssignments(
    List<_PaperImportImage> images,
  ) async {
    final List<String> knownParts = _resolvedSubParts();
    final List<TextEditingController> ctrls =
        List<TextEditingController>.generate(images.length, (int i) {
          final String fallback = knownParts.isNotEmpty
              ? knownParts[min(i, knownParts.length - 1)]
              : _defaultSubPartName(i);
          return TextEditingController(text: fallback);
        });
    bool submit = false;
    await showDialog<void>(
      context: context,
      builder: (BuildContext context) {
        return StatefulBuilder(
          builder:
              (
                BuildContext context,
                void Function(void Function()) setDialogState,
              ) {
                return AlertDialog(
                  title: const Text('Assign Sub-Parts'),
                  content: SizedBox(
                    width: 460,
                    child: SingleChildScrollView(
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: <Widget>[
                          const Align(
                            alignment: Alignment.centerLeft,
                            child: Text(
                              'Name each page/section before AI extraction.',
                            ),
                          ),
                          const SizedBox(height: 10),
                          ...List<Widget>.generate(images.length, (int i) {
                            final _PaperImportImage page = images[i];
                            return Padding(
                              padding: const EdgeInsets.only(bottom: 10),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: <Widget>[
                                  Text(
                                    'Page ${i + 1}: ${page.fileName}',
                                    style: const TextStyle(
                                      fontWeight: FontWeight.w700,
                                      fontSize: 12,
                                    ),
                                  ),
                                  const SizedBox(height: 6),
                                  TextField(
                                    controller: ctrls[i],
                                    decoration: const InputDecoration(
                                      labelText: 'Sub-part name',
                                      hintText: 'Part A / Section 1',
                                    ),
                                  ),
                                ],
                              ),
                            );
                          }),
                          if (knownParts.isNotEmpty) ...<Widget>[
                            const SizedBox(height: 4),
                            Align(
                              alignment: Alignment.centerLeft,
                              child: Wrap(
                                spacing: 6,
                                runSpacing: 6,
                                children: knownParts
                                    .map(
                                      (String part) => ActionChip(
                                        label: Text(part),
                                        onPressed: () {
                                          setDialogState(() {
                                            for (final TextEditingController c
                                                in ctrls) {
                                              c.text = part;
                                            }
                                          });
                                        },
                                      ),
                                    )
                                    .toList(),
                              ),
                            ),
                          ],
                        ],
                      ),
                    ),
                  ),
                  actions: <Widget>[
                    TextButton(
                      onPressed: () => Navigator.pop(context),
                      child: const Text('Cancel'),
                    ),
                    ElevatedButton(
                      onPressed: () {
                        submit = true;
                        Navigator.pop(context);
                      },
                      child: const Text('Continue'),
                    ),
                  ],
                );
              },
        );
      },
    );
    final List<String>? out = submit
        ? List<String>.generate(images.length, (int i) {
            final String normalized = _normalizeSubPartName(ctrls[i].text);
            return normalized.isEmpty ? _defaultSubPartName(i) : normalized;
          })
        : null;
    for (final TextEditingController c in ctrls) {
      c.dispose();
    }
    return out;
  }

