  Map<String, dynamic> _toMap(dynamic raw) {
    if (raw is Map<String, dynamic>) {
      return raw;
    }
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return <String, dynamic>{};
  }

  List<String> _toStringList(dynamic raw) {
    if (raw is List) {
      return raw
          .map((dynamic e) => e.toString().trim())
          .where((String e) => e.isNotEmpty)
          .toList();
    }
    if (raw is String) {
      final String txt = raw.trim();
      if (txt.isEmpty) {
        return <String>[];
      }
      return txt
          .split(RegExp(r'[,|\n;/]+'))
          .map((String e) => e.trim())
          .where((String e) => e.isNotEmpty)
          .toList();
    }
    return <String>[];
  }

  int _findMatchingBrace(String text, int openIndex) {
    if (openIndex < 0 || openIndex >= text.length || text[openIndex] != '{') {
      return -1;
    }
    int depth = 0;
    bool inString = false;
    bool escaped = false;
    for (int i = openIndex; i < text.length; i++) {
      final String ch = text[i];
      if (inString) {
        if (escaped) {
          escaped = false;
          continue;
        }
        if (ch == r'\') {
          escaped = true;
          continue;
        }
        if (ch == '"') {
          inString = false;
        }
        continue;
      }
      if (ch == '"') {
        inString = true;
        continue;
      }
      if (ch == '{') {
        depth++;
        continue;
      }
      if (ch == '}') {
        depth--;
        if (depth == 0) {
          return i;
        }
      }
    }
    return -1;
  }

  List<Map<String, dynamic>> _extractJsonMapsFromMixedText(String text) {
    final List<Map<String, dynamic>> maps = <Map<String, dynamic>>[];
    for (int i = 0; i < text.length; i++) {
      if (text[i] != '{') {
        continue;
      }
      final int end = _findMatchingBrace(text, i);
      if (end <= i) {
        continue;
      }
      final String segment = text.substring(i, end + 1).trim();
      if (segment.length < 2) {
        continue;
      }
      try {
        final dynamic decoded = jsonDecode(segment);
        if (decoded is Map<String, dynamic>) {
          maps.add(decoded);
        } else if (decoded is Map) {
          maps.add(Map<String, dynamic>.from(decoded));
        }
      } catch (_) {}
    }
    return maps;
  }

  int _jsonMapQualityScore(Map<String, dynamic> map) {
    int score = 0;
    final dynamic rawQuestions =
        map['questions'] ??
        map['questions_json'] ??
        map['lc_iie_questions'] ??
        map['lc_iie_output'];
    if (rawQuestions is List) {
      final int len = rawQuestions.length;
      score += len * 12;
      if (len > 1) {
        score += 20;
      }
      if (rawQuestions.isNotEmpty) {
        final dynamic first = rawQuestions.first;
        if (first is Map) {
          final String qText =
              (first['question_text'] ?? first['question'] ?? '')
                  .toString()
                  .toLowerCase();
          if (qText.isNotEmpty && !qText.contains('string')) {
            score += 8;
          }
        }
      }
    }
    final String quizId = (map['quiz_id'] ?? map['id'] ?? '').toString().trim();
    if (quizId.isNotEmpty) {
      score += 6;
    }
    if (map.containsKey('title') || map.containsKey('quiz_title')) {
      score += 2;
    }
    return score;
  }

  Map<String, dynamic>? _tryDecodeJsonAsMap(String raw) {
    String text = raw.trim();
    if (text.isEmpty) {
      return null;
    }
    if (text.startsWith('```')) {
      text = text.replaceFirst(RegExp(r'^```[a-zA-Z]*\s*'), '');
      text = text.replaceFirst(RegExp(r'```$'), '').trim();
    }
    dynamic decoded;
    try {
      decoded = jsonDecode(text);
    } catch (_) {
      decoded = null;
    }
    if (decoded is Map<String, dynamic>) {
      return decoded;
    }
    if (decoded is Map) {
      return Map<String, dynamic>.from(decoded);
    }
    if (decoded is List) {
      return <String, dynamic>{'questions': decoded};
    }

    final int braceStart = text.indexOf('{');
    final int braceEnd = text.lastIndexOf('}');
    if (braceStart >= 0 && braceEnd > braceStart) {
      final String segment = text.substring(braceStart, braceEnd + 1);
      try {
        final dynamic mapDecoded = jsonDecode(segment);
        if (mapDecoded is Map<String, dynamic>) {
          return mapDecoded;
        }
        if (mapDecoded is Map) {
          return Map<String, dynamic>.from(mapDecoded);
        }
      } catch (_) {}
    }

    final int listStart = text.indexOf('[');
    final int listEnd = text.lastIndexOf(']');
    if (listStart >= 0 && listEnd > listStart) {
      final String segment = text.substring(listStart, listEnd + 1);
      try {
        final dynamic listDecoded = jsonDecode(segment);
        if (listDecoded is List) {
          return <String, dynamic>{'questions': listDecoded};
        }
      } catch (_) {}
    }

    final List<Map<String, dynamic>> extracted = _extractJsonMapsFromMixedText(
      text,
    );
    if (extracted.isNotEmpty) {
      Map<String, dynamic> best = extracted.first;
      int bestScore = _jsonMapQualityScore(best);
      for (int i = 1; i < extracted.length; i++) {
        final int score = _jsonMapQualityScore(extracted[i]);
        if (score > bestScore) {
          bestScore = score;
          best = extracted[i];
        }
      }
      return best;
    }
    return null;
  }

  Map<String, dynamic> _extractPaperPayloadFromResponse(
    Map<String, dynamic> response,
  ) {
    final List<dynamic> candidates = <dynamic>[
      response['lc_iie_questions'],
      response['lc_iie_output'],
      response['paper'],
      response['data'],
      _toMap(response['ocr_data'])['lc_iie_questions'],
      _toMap(response['ocr_data'])['lc_iie_output'],
      _toMap(response['ocr_data'])['questions'],
      response['raw'],
      response['answer'],
      response['explanation'],
      '${response['answer'] ?? ''}\n${response['explanation'] ?? ''}',
      _toMap(response['raw'])['output'],
      _toMap(response['raw'])['answer'],
      _toMap(response['raw'])['content'],
      _toMap(_toMap(response['raw'])['data'])['output'],
      _toMap(_toMap(response['raw'])['data'])['answer'],
    ];

    for (final dynamic candidate in candidates) {
      if (candidate == null) {
        continue;
      }
      if (candidate is Map) {
        final Map<String, dynamic> map = candidate is Map<String, dynamic>
            ? candidate
            : Map<String, dynamic>.from(candidate);
        if (map['questions'] is List ||
            map['lc_iie_questions'] is List ||
            map['lc_iie_output'] is List ||
            map['sections'] is List ||
            map['sub_parts'] is List ||
            map['parts'] is List ||
            map['question_text'] != null ||
            map['statement'] != null) {
          return map;
        }
      }
      if (candidate is String) {
        final Map<String, dynamic>? map = _tryDecodeJsonAsMap(candidate);
        if (map == null) {
          continue;
        }
        if (map['questions'] is List ||
            map['lc_iie_questions'] is List ||
            map['lc_iie_output'] is List ||
            map['sections'] is List ||
            map['sub_parts'] is List ||
            map['parts'] is List ||
            map['question_text'] != null ||
            map['statement'] != null) {
          return map;
        }
      }
      if (candidate is List) {
        return <String, dynamic>{'questions': candidate};
      }
    }
    return <String, dynamic>{};
  }

  String _defaultQuestionSection() {
    if (_selectedChapters.isNotEmpty) {
      return _selectedChapters.join(', ');
    }
    return 'General';
  }

  double? _toDoubleOrNull(dynamic raw) {
    if (raw == null) {
      return null;
    }
    if (raw is num) {
      return raw.toDouble();
    }
    final String text = raw.toString().trim();
    if (text.isEmpty) {
      return null;
    }
    final double? direct = double.tryParse(text);
    if (direct != null) {
      return direct;
    }
    final Match? m = RegExp(r'-?\d+(?:\.\d+)?').firstMatch(text);
    if (m == null) {
      return null;
    }
    return double.tryParse(m.group(0)!);
  }

  Map<String, double?> _extractMarks(dynamic raw) {
    if (raw is Map) {
      final Map<String, dynamic> map = Map<String, dynamic>.from(raw);
      final double? pos =
          _toDoubleOrNull(map['positive']) ??
          _toDoubleOrNull(map['pos']) ??
          _toDoubleOrNull(map['mark']) ??
          _toDoubleOrNull(map['marks']) ??
          _toDoubleOrNull(map['max']);
      final double? neg =
          _toDoubleOrNull(map['negative']) ??
          _toDoubleOrNull(map['neg']) ??
          _toDoubleOrNull(map['negative_mark']) ??
          _toDoubleOrNull(map['minus']);
      return <String, double?>{'pos': pos, 'neg': neg};
    }
    if (raw is num) {
      return <String, double?>{'pos': raw.toDouble(), 'neg': null};
    }
    final String text = (raw ?? '').toString().trim();
    if (text.isEmpty) {
      return <String, double?>{'pos': null, 'neg': null};
    }
    final Iterable<Match> nums = RegExp(r'[+-]?\d+(?:\.\d+)?').allMatches(text);
    final List<double> parsed = nums
        .map((Match m) => double.tryParse(m.group(0) ?? ''))
        .whereType<double>()
        .toList();
    if (parsed.isEmpty) {
      return <String, double?>{'pos': null, 'neg': null};
    }
    final double pos = parsed.first.abs();
    double? neg;
    if (parsed.length > 1) {
      neg = parsed[1].abs();
    } else if (text.contains('-')) {
      neg = parsed.first.abs();
    }
    return <String, double?>{'pos': pos, 'neg': neg};
  }

  List<String> _extractOptionsFromPaperMap(Map<String, dynamic> q) {
    final dynamic rawOptions =
        q['options'] ?? q['choices'] ?? q['option_list'] ?? q['latex_options'];
    if (rawOptions is List) {
      return rawOptions
          .map((dynamic e) => e.toString().trim())
          .where((String e) => e.isNotEmpty)
          .toList();
    }
    if (rawOptions is Map) {
      final List<String> keys =
          rawOptions.keys.map((dynamic e) => e.toString()).toList()..sort();
      return keys
          .map((String k) => (rawOptions[k] ?? '').toString().trim())
          .where((String e) => e.isNotEmpty)
          .toList();
    }
    final List<String> keyed =
        <String>[
              'option_a',
              'option_b',
              'option_c',
              'option_d',
              'option_1',
              'option_2',
              'option_3',
              'option_4',
              'a',
              'b',
              'c',
              'd',
            ]
            .map((String k) => (q[k] ?? '').toString().trim())
            .where((String e) => e.isNotEmpty)
            .toList();
    if (keyed.isNotEmpty) {
      return keyed;
    }
    return <String>[];
  }

  String _normalizeImportedQuestionType(
    Map<String, dynamic> q,
    List<String> options,
    List<String> answers,
  ) {
    final String raw = (q['question_type'] ?? q['type'] ?? '')
        .toString()
        .trim()
        .toUpperCase();
    if (raw.contains('MCQ_MULTI') || raw.contains('MULTI')) {
      return 'MULTI';
    }
    if (raw.contains('INTEGER') ||
        raw.contains('NUMERICAL') ||
        raw.contains('NUM')) {
      return 'NUMERICAL';
    }
    if (raw.contains('SUBJECTIVE') || raw.contains('DESCRIPTIVE')) {
      return 'NUMERICAL';
    }
    if (raw.contains('MULTI') || raw.contains('MULTIPLE')) {
      return 'MULTI';
    }
    if (raw.contains('NUM') ||
        raw.contains('INTEGER') ||
        raw.contains('DESCRIPTIVE') ||
        raw.contains('SHORT')) {
      return 'NUMERICAL';
    }
    if (raw.contains('MCQ') || raw.contains('SINGLE')) {
      return 'MCQ';
    }
    if (options.isEmpty) {
      return 'NUMERICAL';
    }
    if (answers.length > 1) {
      return 'MULTI';
    }
    return 'MCQ';
  }

  QuizQuestion? _toQuizQuestionFromPaperMap(
    Map<String, dynamic> raw, {
    required String fallbackSubPart,
  }) {
    String text =
        (raw['statement'] ??
                raw['question_text'] ??
                raw['latex_statement'] ??
                raw['question'] ??
                raw['text'] ??
                raw['statement'] ??
                raw['prompt'] ??
                '')
            .toString()
            .trim();
    final String number =
        (raw['number'] ?? raw['question_id'] ?? raw['q_no'] ?? raw['id'] ?? '')
            .toString()
            .trim();
    if (number.isNotEmpty &&
        text.isNotEmpty &&
        !text.toLowerCase().startsWith(number.toLowerCase())) {
      text = '$number. $text';
    }
    if (text.isEmpty) {
      return null;
    }

    List<String> options = _extractOptionsFromPaperMap(raw);
    List<String> answers = _extractAiCorrectAnswers(raw, options);
    if (answers.isEmpty) {
      answers = _toStringList(
        raw['correct_answers'] ??
            raw['correct_answer'] ??
            raw['answer'] ??
            raw['final_answer'] ??
            raw['solution'],
      );
      if (options.isNotEmpty) {
        final Set<String> matched = <String>{};
        for (final String answer in answers) {
          final String low = answer.trim().toLowerCase();
          if (low.isEmpty) {
            continue;
          }
          if (RegExp(r'^[a-d1-4]$').hasMatch(low)) {
            final int idx = low.codeUnitAt(0) >= 49
                ? int.parse(low) - 1
                : low.codeUnitAt(0) - 97;
            if (idx >= 0 && idx < options.length) {
              matched.add(options[idx]);
            }
          } else {
            for (final String option in options) {
              if (option.trim().toLowerCase() == low) {
                matched.add(option);
              }
            }
          }
        }
        if (matched.isNotEmpty) {
          answers = matched.toList();
        }
      }
    }

    String type = _normalizeImportedQuestionType(raw, options, answers);
    if (type != 'NUMERICAL') {
      while (options.length < 4) {
        options.add('Option ${options.length + 1}');
      }
      if (options.length > 4) {
        options = options.take(4).toList();
      }
      if (answers.isEmpty) {
        answers = <String>[options.first];
      } else {
        answers = answers
            .where((String a) => options.any((String o) => o == a))
            .toList();
        if (answers.isEmpty) {
          answers = <String>[options.first];
        }
      }
      if (type == 'MCQ' && answers.length > 1) {
        answers = <String>[answers.first];
      }
    } else {
      options = <String>['', '', '', ''];
      final String numericAnswer = answers.isNotEmpty
          ? answers.first
          : (raw['answer'] ?? raw['final_answer'] ?? '').toString().trim();
      answers = <String>[numericAnswer.isEmpty ? '0' : numericAnswer];
    }

    final Map<String, double?> marks = _extractMarks(
      raw['marks'] ?? raw['marking'] ?? raw['mark_scheme'],
    );
    final double pos =
        marks['pos'] ??
        _toDoubleOrNull(raw['positive_mark']) ??
        _toDoubleOrNull(raw['pos_mark']) ??
        _toDoubleOrNull(raw['mark']) ??
        4;
    final double neg =
        marks['neg'] ??
        _toDoubleOrNull(raw['negative_mark']) ??
        _toDoubleOrNull(raw['neg_mark']) ??
        1;

    final String chapterSection = (raw['chapter'] ?? raw['section'] ?? '')
        .toString()
        .trim();
    final String section = chapterSection.isEmpty
        ? _defaultQuestionSection()
        : chapterSection;

    final String explicitSubPart = _normalizeSubPartName(
      (raw['part_name'] ?? raw['sub_part'] ?? raw['section_name'] ?? '')
          .toString(),
    );
    final String subPart = explicitSubPart.isEmpty
        ? _normalizeSubPartName(fallbackSubPart)
        : explicitSubPart;
    final String solution = _normalizeAiLatexText(
      (raw['solution'] ??
              _toMap(raw['proof_layers'])['level_0'] ??
              raw['solution_explanation'] ??
              raw['_solution_explanation'] ??
              '')
          .toString(),
    );
    final int difficultyLevel = _extractAiDifficultyLevel(raw);
    final String difficultyLabel = _extractAiDifficultyLabel(
      raw,
      level: difficultyLevel,
    );
    final double confidenceScore = _extractAiConfidenceScore(raw);
    final double adaptiveScore = _extractAiAdaptiveScore(raw);

    return QuizQuestion(
      text: text,
      image: '',
      type: type,
      options: options,
      correct: answers,
      section: section,
      subPart: subPart,
      pos: max(0, pos),
      neg: max(0, neg),
      solution: solution,
      difficultyLabel: difficultyLabel,
      confidenceScore: confidenceScore,
      adaptiveScore: adaptiveScore,
    );
  }

  List<QuizQuestion> _fallbackQuestionsFromText(
    String rawText, {
    required String fallbackSubPart,
  }) {
    String cleanLine(String raw) {
      String text = raw.trim().replaceAll(RegExp(r'\s+'), ' ');
      text = text.replaceAll(
        RegExp(r'\[JEE[^\]]*\]', caseSensitive: false),
        '',
      );
      text = text.replaceAll(RegExp(r'\bMCR\d+\b', caseSensitive: false), '');
      text = text.replaceAll(RegExp(r'\s+'), ' ').trim();
      return text;
    }

    bool looksLikeQuestionStart(String line) {
      return RegExp(
        r'^(?:q(?:uestion)?\s*)?\d+\s*[\).:]\s+',
        caseSensitive: false,
      ).hasMatch(line);
    }

    String stripQuestionPrefix(String line) {
      return line
          .replaceFirst(
            RegExp(
              r'^(?:q(?:uestion)?\s*)?\d+\s*[\).:]\s*',
              caseSensitive: false,
            ),
            '',
          )
          .trim();
    }

    List<String> inlineOptions(String line) {
      final List<String> out = <String>[];
      final RegExp pattern = RegExp(
        r'\((?:[1-4]|[A-Da-d])\)\s*([^()]+?)(?=\s*\((?:[1-4]|[A-Da-d])\)|$)',
      );
      for (final Match m in pattern.allMatches(line)) {
        final String option = cleanLine(m.group(1) ?? '');
        if (option.isNotEmpty) {
          out.add(option);
        }
      }
      return out;
    }

    bool looksLikeStandaloneOption(String line) {
      return RegExp(r'^\(?([1-4]|[A-Da-d])\)?[\).:-]?\s+').hasMatch(line);
    }

    String stripStandaloneOption(String line) {
      return cleanLine(
        line.replaceFirst(RegExp(r'^\(?([1-4]|[A-Da-d])\)?[\).:-]?\s*'), ''),
      );
    }

    final List<String> lines = rawText
        .split('\n')
        .map(cleanLine)
        .where((String e) => e.isNotEmpty)
        .toList();
    if (lines.isEmpty) {
      return <QuizQuestion>[];
    }

    final List<Map<String, dynamic>> parsedBlocks = <Map<String, dynamic>>[];
    Map<String, dynamic>? current;

    void flushCurrent() {
      if (current == null) {
        return;
      }
      final List<String> textParts =
          current!['text_parts'] as List<String>? ?? <String>[];
      if (textParts.any((String e) => e.trim().isNotEmpty)) {
        parsedBlocks.add(current!);
      }
    }

    for (final String line in lines) {
      if (looksLikeQuestionStart(line)) {
        flushCurrent();
        current = <String, dynamic>{
          'text_parts': <String>[stripQuestionPrefix(line)],
          'options': <String>[],
        };
        continue;
      }
      if (current == null) {
        continue;
      }

      final List<String> manyOptions = inlineOptions(line);
      if (manyOptions.length >= 2) {
        (current['options'] as List<String>).addAll(manyOptions);
        continue;
      }

      if (looksLikeStandaloneOption(line)) {
        final String option = stripStandaloneOption(line);
        if (option.isNotEmpty) {
          (current['options'] as List<String>).add(option);
        }
        continue;
      }

      final bool metadataOnly =
          RegExp(r'^\[[^\]]+\]$').hasMatch(line) ||
          RegExp(r'^[A-Z]{2,}\d+$').hasMatch(line) ||
          RegExp(r'^\[\s*\d+\s*\]$').hasMatch(line) ||
          line.toLowerCase().contains('www.');
      if (metadataOnly) {
        continue;
      }
      (current['text_parts'] as List<String>).add(line);
    }
    flushCurrent();

    final List<QuizQuestion> out = <QuizQuestion>[];
    for (int i = 0; i < parsedBlocks.length; i++) {
      final Map<String, dynamic> block = parsedBlocks[i];
      final String text = cleanLine(
        (block['text_parts'] as List<String>? ?? <String>[]).join(' '),
      );
      if (text.isEmpty) {
        continue;
      }
      final List<String> optionSource =
          (block['options'] as List<String>? ?? <String>[])
              .map(cleanLine)
              .where((String e) => e.isNotEmpty)
              .toList();
      final List<String> options = <String>[];
      final Set<String> seen = <String>{};
      for (final String option in optionSource) {
        final String key = option.toLowerCase();
        if (seen.add(key)) {
          options.add(option);
        }
      }
      if (options.length > 4) {
        options.removeRange(4, options.length);
      }

      final bool isMcq = options.isNotEmpty;
      final List<String> finalOptions = isMcq
          ? <String>[...options]
          : <String>['', '', '', ''];
      if (isMcq) {
        while (finalOptions.length < 4) {
          finalOptions.add('Option ${finalOptions.length + 1}');
        }
      }

      out.add(
        QuizQuestion(
          text: text,
          image: '',
          type: isMcq ? 'MCQ' : 'NUMERICAL',
          options: finalOptions,
          correct: <String>[isMcq ? finalOptions.first : '0'],
          section: _defaultQuestionSection(),
          subPart: _normalizeSubPartName(fallbackSubPart),
          pos: 4,
          neg: 1,
        ),
      );
    }
    return out;
  }

  List<QuizQuestion> _quizQuestionsFromPaperPayload(
    Map<String, dynamic> payload, {
    required String fallbackSubPart,
  }) {
    final List<QuizQuestion> out = <QuizQuestion>[];
    final String payloadPart = _normalizeSubPartName(
      (payload['part_name'] ??
              payload['sub_part'] ??
              payload['section_name'] ??
              '')
          .toString(),
    );
    final String resolvedFallback = payloadPart.isEmpty
        ? fallbackSubPart
        : payloadPart;

    void addList(dynamic rawList, String subPart) {
      if (rawList is! List) {
        return;
      }
      for (final dynamic item in rawList) {
        if (item is! Map) {
          continue;
        }
        final QuizQuestion? parsed = _toQuizQuestionFromPaperMap(
          Map<String, dynamic>.from(item),
          fallbackSubPart: subPart,
        );
        if (parsed != null) {
          out.add(parsed);
        }
      }
    }

    final dynamic sections =
        payload['sections'] ?? payload['sub_parts'] ?? payload['parts'];
    if (sections is List) {
      for (final dynamic section in sections) {
        if (section is! Map) {
          continue;
        }
        final Map<String, dynamic> map = Map<String, dynamic>.from(section);
        final String sectionPart = _normalizeSubPartName(
          (map['name'] ?? map['part_name'] ?? map['sub_part'] ?? '').toString(),
        );
        addList(
          map['questions'] ?? map['items'] ?? map['question_list'],
          sectionPart.isEmpty ? resolvedFallback : sectionPart,
        );
      }
    }

    addList(
      payload['questions'] ??
          payload['lc_iie_questions'] ??
          payload['lc_iie_output'] ??
          payload['items'] ??
          payload['question_list'] ??
          payload['extracted_questions'],
      resolvedFallback,
    );

    if (out.isEmpty &&
        (payload['question_text'] != null || payload['statement'] != null)) {
      final QuizQuestion? single = _toQuizQuestionFromPaperMap(
        payload,
        fallbackSubPart: resolvedFallback,
      );
      if (single != null) {
        out.add(single);
      }
    }

    return out;
  }

  Future<_PaperImportPageResult> _extractPaperPage({
    required _PaperImportImage image,
    required String assignedSubPart,
    required int pageIndex,
    required int totalPages,
  }) async {
    String prompt = _paperImportPrompt(
      subPart: assignedSubPart,
      pageIndex: pageIndex,
      totalPages: totalPages,
    );
    try {
      final String chapterHint = _selectedChapters.isEmpty
          ? assignedSubPart
          : _selectedChapters.first;
      final String query =
          '$_selectedSubject $chapterHint $assignedSubPart JEE question answer solution';
      final Map<String, dynamic> webVerify = await backendService
          .lc9WebVerifyQuery(query: query, maxRows: 4)
          .timeout(const Duration(seconds: 6));
      final List<dynamic> rows = webVerify['rows'] is List
          ? webVerify['rows'] as List<dynamic>
          : const <dynamic>[];
      if (rows.isNotEmpty) {
        final List<String> lines = <String>[];
        for (int i = 0; i < rows.length; i++) {
          final dynamic row = rows[i];
          if (row is! Map) {
            continue;
          }
          final String title = (row['title'] ?? '').toString().trim();
          final String url = (row['url'] ?? '').toString().trim();
          if (title.isEmpty && url.isEmpty) {
            continue;
          }
          lines.add('${i + 1}. $title $url'.trim());
        }
        if (lines.isNotEmpty) {
          prompt =
              '$prompt\n\nServer-side cached web verification hints:\n${lines.join('\n')}';
        }
      }
    } catch (_) {}
    final String dataUrl = _toImageDataUrl(image);
    Map<String, dynamic> response = <String, dynamic>{};
    try {
      response = await aiService.sendChat(
        prompt: prompt,
        userId: Session.effectiveAccountId,
        chatId:
            'paper_import_${DateTime.now().millisecondsSinceEpoch}_$pageIndex',
        function: 'quiz_paper_ocr_extract',
        responseStyle: 'structured_json',
        enablePersona: false,
        card: <String, dynamic>{
          'task': 'paper_to_quiz',
          'assessment_type': _assessmentType,
          'sub_part': assignedSubPart,
          'strict_ocr': true,
          'handwritten_hint': true,
          'ocr_multi_pass': 3,
          'web_verification_required': true,
          'android_web_verification': true,
        },
        base64Image: dataUrl,
      );
    } catch (_) {
      response = <String, dynamic>{};
    }

    Map<String, dynamic> payload = _extractPaperPayloadFromResponse(response);
    List<QuizQuestion> questions = _quizQuestionsFromPaperPayload(
      payload,
      fallbackSubPart: assignedSubPart,
    );

    if (questions.isEmpty) {
      try {
        final Map<String, dynamic> retry = await aiService.sendChat(
          prompt: _paperImportRetryPrompt(
            subPart: assignedSubPart,
            pageIndex: pageIndex,
            totalPages: totalPages,
          ),
          userId: Session.effectiveAccountId,
          chatId:
              'paper_import_retry_${DateTime.now().millisecondsSinceEpoch}_$pageIndex',
          function: 'quiz_paper_ocr_extract',
          responseStyle: 'strict_json',
          enablePersona: false,
          card: <String, dynamic>{
            'task': 'paper_to_quiz',
            'assessment_type': _assessmentType,
            'sub_part': assignedSubPart,
            'strict_ocr': true,
            'handwritten_hint': true,
            'ocr_multi_pass': 4,
            'json_only': true,
            'web_verification_required': true,
            'android_web_verification': true,
          },
          base64Image: dataUrl,
        );
        payload = _extractPaperPayloadFromResponse(retry);
        questions = _quizQuestionsFromPaperPayload(
          payload,
          fallbackSubPart: assignedSubPart,
        );
        if (response.isEmpty) {
          response = retry;
        }
      } catch (_) {}
    }

    if (questions.isEmpty) {
      final String plain = <String>[
        (response['answer'] ?? '').toString(),
        (response['explanation'] ?? '').toString(),
      ].where((String e) => e.trim().isNotEmpty).join('\n');
      questions = _fallbackQuestionsFromText(
        plain,
        fallbackSubPart: assignedSubPart,
      );
    }

    final String title =
        (payload['title'] ??
                payload['assessment_title'] ??
                payload['exam_name'] ??
                payload['homework_name'] ??
                payload['paper_name'] ??
                '')
            .toString()
            .trim();
    final String payloadPart = _normalizeSubPartName(
      (payload['part_name'] ?? payload['sub_part'] ?? '').toString(),
    );
    return _PaperImportPageResult(
      title: title,
      subPart: payloadPart.isEmpty ? assignedSubPart : payloadPart,
      questions: questions,
    );
  }

  Future<void> _openSubPartManager() async {
    final List<String> seed = _resolvedSubParts();
    final List<String> draft = List<String>.from(seed);
    final TextEditingController addCtrl = TextEditingController();
    bool saved = false;
    await showDialog<void>(
      context: context,
      builder: (BuildContext context) {
        return StatefulBuilder(
          builder:
              (
                BuildContext context,
                void Function(void Function()) setDialogState,
              ) {
                return AlertDialog(
                  title: const Text('Manage Sub-Parts'),
                  content: SizedBox(
                    width: 420,
                    child: SingleChildScrollView(
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          TextField(
                            controller: addCtrl,
                            decoration: const InputDecoration(
                              labelText: 'New sub-part',
                              hintText: 'Part A / Section I',
                            ),
                            onSubmitted: (_) {
                              final String normalized = _normalizeSubPartName(
                                addCtrl.text,
                              );
                              if (normalized.isEmpty) {
                                return;
                              }
                              final bool exists = draft.any(
                                (String e) =>
                                    e.trim().toLowerCase() ==
                                    normalized.toLowerCase(),
                              );
                              if (exists) {
                                return;
                              }
                              setDialogState(() {
                                draft.add(normalized);
                                addCtrl.clear();
                              });
                            },
                          ),
                          const SizedBox(height: 10),
                          ElevatedButton.icon(
                            onPressed: () {
                              final String normalized = _normalizeSubPartName(
                                addCtrl.text,
                              );
                              if (normalized.isEmpty) {
                                return;
                              }
                              final bool exists = draft.any(
                                (String e) =>
                                    e.trim().toLowerCase() ==
                                    normalized.toLowerCase(),
                              );
                              if (exists) {
                                return;
                              }
                              setDialogState(() {
                                draft.add(normalized);
                                addCtrl.clear();
                              });
                            },
                            icon: const Icon(Icons.add_rounded),
                            label: const Text('Add'),
                          ),
                          const SizedBox(height: 10),
                          if (draft.isEmpty)
                            const Text(
                              'No sub-parts added yet.',
                              style: TextStyle(color: Colors.grey),
                            )
                          else
                            Wrap(
                              spacing: 8,
                              runSpacing: 8,
                              children: draft
                                  .map(
                                    (String part) => InputChip(
                                      label: Text(part),
                                      onDeleted: () {
                                        setDialogState(() {
                                          draft.remove(part);
                                        });
                                      },
                                    ),
                                  )
                                  .toList(),
                            ),
                        ],
                      ),
                    ),
                  ),
                  actions: <Widget>[
                    TextButton(
                      onPressed: () => Navigator.pop(context),
                      child: const Text('Cancel'),
                    ),
                    ElevatedButton(
                      onPressed: () {
                        saved = true;
                        Navigator.pop(context);
                      },
                      child: const Text('Save'),
                    ),
                  ],
                );
              },
        );
      },
    );
    addCtrl.dispose();
    if (!saved || !mounted) {
      return;
    }
    setState(() {
      _quizSubParts = draft
          .map(_normalizeSubPartName)
          .where((String e) => e.isNotEmpty)
          .toList();
    });
  }

  QuizQuestion? _toQuizQuestionFromImportedJson(Map<String, dynamic> raw) {
    ImportedQuestion imported;
    try {
      imported = ImportedQuestion.fromJson(raw);
    } catch (_) {
      return null;
    }
    if (imported.questionText.trim().isEmpty) {
      return null;
    }

    final List<ImportOption> sourceOptions = List<ImportOption>.from(
      imported.options,
    )..sort((ImportOption a, ImportOption b) => a.label.compareTo(b.label));
    final Map<String, String> labelToText = <String, String>{
      for (final ImportOption option in sourceOptions)
        option.label.toUpperCase(): option.text.trim(),
    };

    String type = 'MCQ';
    List<String> options = sourceOptions
        .map((ImportOption e) => e.text.trim())
        .where((String e) => e.isNotEmpty)
        .toList();
    List<String> correct = <String>[];

    if (imported.type == ImportedQuestionType.numerical) {
      type = 'NUMERICAL';
      options = <String>['', '', '', ''];
      final String value = (imported.correctAnswer.numerical ?? '').trim();
      correct = <String>[value.isEmpty ? '0' : value];
    } else if (imported.type == ImportedQuestionType.mcqMulti) {
      type = 'MULTI';
      while (options.length < 2) {
        options.add('Option ${options.length + 1}');
      }
      correct = imported.correctAnswer.multiple
          .map((String e) => e.trim().toUpperCase())
          .map((String label) => labelToText[label] ?? '')
          .where((String e) => e.isNotEmpty)
          .toSet()
          .toList();
      if (correct.isEmpty && options.isNotEmpty) {
        correct = <String>[options.first];
      }
    } else {
      while (options.length < 2) {
        options.add('Option ${options.length + 1}');
      }
      final String label = (imported.correctAnswer.single ?? '')
          .trim()
          .toUpperCase();
      final String single =
          labelToText[label] ?? (options.isEmpty ? '' : options.first);
      correct = <String>[single];
    }

    final String chosenSubPart = _resolvedSubParts().isNotEmpty
        ? _resolvedSubParts().first
        : _defaultSubPartName(0);
    return QuizQuestion(
      text: imported.questionText.trim(),
      image: '',
      type: type,
      options: options,
      correct: correct,
      section: imported.chapter.trim().isNotEmpty
          ? imported.chapter.trim()
          : _defaultQuestionSection(),
      subPart: _normalizeSubPartName(chosenSubPart),
      pos: 4,
      neg: 1,
    );
  }

  Future<void> _openStructuredImportScreen() async {
    final dynamic result = await Navigator.of(context).push<dynamic>(
      MaterialPageRoute(
        builder: (_) => TeacherImportQuestionsScreen(
          importService: teacherQuestionImportService,
          backendService: backendService,
          initialSubject: _selectedSubject,
          initialChapter: _selectedChapters.isEmpty
              ? ''
              : _selectedChapters.join(', '),
          initialDifficulty: 'Hard',
        ),
      ),
    );
    if (!mounted || result == null) {
      return;
    }
    if (result is! List) {
      _snack('Invalid import payload returned.', isError: true);
      return;
    }
    final List<QuizQuestion> imported = <QuizQuestion>[];
    for (final dynamic row in result) {
      if (row is! Map) {
        continue;
      }
      final QuizQuestion? parsed = _toQuizQuestionFromImportedJson(
        Map<String, dynamic>.from(row),
      );
      if (parsed != null) {
        imported.add(parsed);
      }
    }
    if (imported.isEmpty) {
      _snack('No valid structured questions were returned.', isError: true);
      return;
    }
    setState(() {
      _questions = <QuizQuestion>[..._questions, ...imported];
      if (_selectedIndex < 0) {
        _selectedIndex = 0;
      } else {
        _selectedIndex = _questions.length - imported.length;
      }
      _hasAiDraftQuestions = true;
      _activeAiUiSpec = _normalizeAiUiSpec(<String, dynamic>{});
      _activeStudentAdaptiveData = <String, dynamic>{
        'mastery_status': <String, dynamic>{},
        'recommendations': <dynamic>[],
        'performance_trends': <String, dynamic>{},
      };
    });
    _snack(
      'Imported ${imported.length} structured question(s). Review and publish.',
      isError: false,
    );
  }

  Future<void> _importQuestionPaperWithAi() async {
    if (widget.selfPracticeMode || Session.userRole != 'teacher') {
      _snack(
        'Only teachers can import question papers into quiz drafts.',
        isError: true,
      );
      return;
    }
    if (_loading) {
      return;
    }

    final List<_PaperImportImage> images = await _pickPaperImportImages();
    if (images.isEmpty) {
      return;
    }
    final List<String>? partAssignments = await _collectSubPartAssignments(
      images,
    );
    if (partAssignments == null || partAssignments.isEmpty) {
      return;
    }

    setState(() {
      _loading = true;
      _aiGenerating = true;
      _paperImportInFlight = true;
      _aiPreparingLabel = 'Importing question paper';
      _aiPreparingDetail = 'Scanning pages and preparing extraction.';
      _aiGenerationStage = 0;
      _aiPreparingProgressCurrent = 0;
      _aiPreparingProgressTotal = images.length;
    });
    _aiPreparingCtrl
      ..stop()
      ..value = 0;
    if (!isLikelyWidgetTestMode()) {
      _aiPreparingCtrl.repeat();
    }

    String inferredTitle = '';
    final List<QuizQuestion> imported = <QuizQuestion>[];
    int extractedPages = 0;
    try {
      for (int i = 0; i < images.length; i++) {
        if (!mounted) {
          break;
        }
        final _PaperImportImage currentImage = images[i];
        final String formatLabel = _paperImportFormatLabel(currentImage);
        final String sourceLabel = _paperImportSourceName(currentImage);
        setState(() {
          _aiPreparingProgressCurrent = i + 1;
          _aiPreparingLabel = 'Importing $formatLabel page';
          _aiPreparingDetail =
              'Processing page ${i + 1}/${images.length} • $sourceLabel';
        });
        final _PaperImportPageResult page = await _extractPaperPage(
          image: currentImage,
          assignedSubPart: partAssignments[min(i, partAssignments.length - 1)],
          pageIndex: i + 1,
          totalPages: images.length,
        );
        if (page.title.isNotEmpty && inferredTitle.isEmpty) {
          inferredTitle = page.title;
        }
        if (page.subPart.trim().isNotEmpty) {
          _registerSubPart(page.subPart);
        }
        if (page.questions.isNotEmpty) {
          extractedPages++;
          imported.addAll(page.questions);
          for (final QuizQuestion q in page.questions) {
            _registerSubPart(q.subPart);
          }
        }
      }

      if (imported.isEmpty) {
        _snack(
          'Could not extract valid questions from the uploaded paper.',
          isError: true,
        );
        return;
      }

      if (!mounted) {
        return;
      }
      setState(() {
        final int oldCount = _questions.length;
        _questions = <QuizQuestion>[..._questions, ...imported];
        if (_selectedIndex < 0) {
          _selectedIndex = 0;
        } else if (oldCount < _questions.length) {
          _selectedIndex = oldCount;
        }
        if (_title.text.trim().isEmpty && inferredTitle.isNotEmpty) {
          _title.text = inferredTitle;
        }
        _hasAiDraftQuestions = true;
        _activeAiUiSpec = _normalizeAiUiSpec(<String, dynamic>{});
        _activeStudentAdaptiveData = <String, dynamic>{
          'mastery_status': <String, dynamic>{},
          'recommendations': <dynamic>[],
          'performance_trends': <String, dynamic>{},
        };
      });
      _snack(
        'Imported ${imported.length} question(s) from $extractedPages page(s). Review, edit and publish.',
        isError: false,
      );
    } catch (e) {
      _snack('Question paper import failed: $e', isError: true);
    } finally {
      _aiPreparingCtrl
        ..stop()
        ..value = 0;
      if (mounted) {
        setState(() {
          _loading = false;
          _aiGenerating = false;
          _paperImportInFlight = false;
          _aiGenerationStage = 0;
          _aiPreparingLabel = 'Preparing question';
          _aiPreparingDetail = '';
          _aiPreparingProgressCurrent = 0;
          _aiPreparingProgressTotal = 0;
        });
      }
    }
  }

  bool get _useUnlimitedSelfPracticeTime =>
      widget.selfPracticeMode && _selfPracticeUnlimitedTime;

  DateTime _effectiveDeadlineForQuiz() {
    if (widget.selfPracticeMode) {
      return _selfPracticeDeadline();
    }
    return _deadline;
  }

  int _resolvedDurationMinutes(int fallback) {
    if (_useUnlimitedSelfPracticeTime) {
      return 0;
    }
    return max(1, int.tryParse(_durationCtrl.text.trim()) ?? fallback);
  }

  Future<void> _pickDeadlineDate() async {
    final DateTime now = DateTime.now();
    final DateTime? picked = await showDatePicker(
      context: context,
      initialDate: _deadline.isBefore(now) ? now : _deadline,
      firstDate: now.subtract(const Duration(days: 1)),
      lastDate: now.add(const Duration(days: 365 * 3)),
    );
    if (picked == null) {
      return;
    }
    setState(() {
      _deadline = DateTime(
        picked.year,
        picked.month,
        picked.day,
        _deadline.hour,
        _deadline.minute,
      );
    });
  }

  Future<void> _pickDeadlineTime() async {
    final TimeOfDay? picked = await showTimePicker(
      context: context,
      initialTime: TimeOfDay(hour: _deadline.hour, minute: _deadline.minute),
    );
    if (picked == null) {
      return;
    }
    setState(() {
      _deadline = DateTime(
        _deadline.year,
        _deadline.month,
        _deadline.day,
        picked.hour,
        picked.minute,
      );
    });
  }

  String _deadlineLabel() {
    final String dd = _deadline.day.toString().padLeft(2, '0');
    final String mm = _deadline.month.toString().padLeft(2, '0');
    final String yyyy = _deadline.year.toString();
    final String hh = _deadline.hour.toString().padLeft(2, '0');
    final String min = _deadline.minute.toString().padLeft(2, '0');
    return '$dd/$mm/$yyyy $hh:$min';
  }

  Future<List<Map<String, dynamic>>> _buildQuestionPayloads() async {
    final List<Map<String, dynamic>> out = <Map<String, dynamic>>[];
    final int stamp = DateTime.now().millisecondsSinceEpoch;
    for (int i = 0; i < _questions.length; i++) {
      final QuizQuestion q = _questions[i];
      String imageValue = q.image.trim();
      if (imageValue.startsWith('data:image')) {
        final String lower = imageValue.toLowerCase();
        final String ext = lower.startsWith('data:image/png')
            ? 'png'
            : (lower.startsWith('data:image/webp') ? 'webp' : 'jpg');
        final String uploaded = await backendService.uploadFileData(
          fileName: 'quiz_q_${stamp}_${i + 1}.$ext',
          dataUrl: imageValue,
        );
        if (uploaded.trim().isNotEmpty) {
          imageValue = uploaded.trim();
        }
      }
      out.add(<String, dynamic>{
        'text': q.text,
        'image': imageValue,
        'type': q.type,
        'options': q.options,
        'correct': q.correct.join(','),
        'solution': q.solution,
        'solution_explanation': q.solution,
        'section': q.section,
        'sub_part': q.subPart,
        'subpart': q.subPart,
        'posMark': q.pos,
        'negMark': q.neg,
        'difficulty': q.difficultyLabel,
        'confidence_score': q.confidenceScore,
        'adaptive_score': q.adaptiveScore,
      });
    }
    return out;
  }

  List<String> _splitTags(String raw) {
    return raw
        .split(',')
        .map((String e) => e.trim())
        .where((String e) => e.isNotEmpty)
        .toList();
  }

  String _normalizeChapterKey(String raw) {
    final String lower = raw.toLowerCase().replaceAll('&', 'and');
    return lower.replaceAll(RegExp(r'[^a-z0-9]+'), ' ').trim();
  }

