          'hybridization',
          'oxidation state',
          'mechanism',
          'rate expression',
        ],
        'biology': <String>[
          'pathway',
          'regulation',
          'inheritance pattern',
          'diagram based',
          'assertion reason',
        ],
      };

  Set<String> _chapterSignalsFor(String rawChapter) {
    final String key = _normalizeChapterKey(rawChapter);
    if (key.isEmpty) {
      return <String>{};
    }
    final Set<String> tokens = key
        .split(RegExp(r'[^a-z0-9]+'))
        .map((String e) => e.trim())
        .where((String e) => e.length >= 4)
        .where((String e) => !_scopeStopWords.contains(e))
        .toSet();
    _chapterSignalOverrides.forEach((String chapterKey, List<String> signals) {
      final bool match =
          key == chapterKey ||
          key.contains(chapterKey) ||
          chapterKey.contains(key);
      if (!match) {
        return;
      }
      tokens.addAll(
        signals
            .map((String e) => e.toLowerCase().trim())
            .where((String e) => e.isNotEmpty),
      );
    });
    return tokens;
  }

  Set<String> _scopeSignals({
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final Set<String> out = <String>{};
    for (final String chapter in chapters) {
      out.addAll(_chapterSignalsFor(chapter));
    }
    for (final String subtopic in subtopics) {
      out.addAll(_chapterSignalsFor(subtopic));
    }
    if (out.length < 4) {
      final String subjectKey = subject.trim().toLowerCase();
      final List<String> baseline =
          _subjectSignalBaselines[subjectKey] ??
          _subjectSignalBaselines.entries
              .firstWhere(
                (MapEntry<String, List<String>> e) =>
                    subjectKey.contains(e.key),
                orElse: () =>
                    const MapEntry<String, List<String>>('', <String>[]),
              )
              .value;
      out.addAll(baseline);
    }
    return out;
  }

  Map<String, List<String>> _chapterSignalLock({
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final Map<String, List<String>> out = <String, List<String>>{};
    for (final String chapter in chapters) {
      final List<String> signals = _chapterSignalsFor(chapter).toList()..sort();
      if (signals.isNotEmpty) {
        out[chapter] = signals.take(8).toList();
      }
    }
    if (out.isEmpty) {
      final Set<String> fallback = _scopeSignals(
        subject: subject,
        chapters: chapters,
        subtopics: subtopics,
      );
      if (fallback.isNotEmpty) {
        out['general_scope'] = fallback.take(8).toList();
      }
    }
    return out;
  }

  List<String> _chapterHardDirectives({
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final List<String> directives = <String>[];
    final Set<String> seen = <String>{};
    for (final String chapter in <String>[...chapters, ...subtopics]) {
      final String name = chapter.trim();
      if (name.isEmpty || !seen.add(name.toLowerCase())) {
        continue;
      }
      final List<String> anchors = _chapterSignalsFor(name).take(5).toList();
      if (anchors.isEmpty) {
        continue;
      }
      directives.add(
        '- Chapter lock "$name": include at least one question using signals like ${anchors.join(', ')}.',
      );
    }
    if (directives.isEmpty) {
      final List<String> fallback = _scopeSignals(
        subject: subject,
        chapters: chapters,
        subtopics: subtopics,
      ).take(6).toList();
      if (fallback.isNotEmpty) {
        directives.add(
          '- Scope lock: include signals like ${fallback.join(', ')} across the set.',
        );
      }
    }
    return directives;
  }

  List<String> _expandedHardSubtopics({
    required String subject,
    required List<String> chapters,
    required List<String> requestedSubtopics,
    int limit = 28,
  }) {
    final Set<String> out = <String>{};
    for (final String s in requestedSubtopics) {
      final String trimmed = s.trim();
      if (trimmed.isNotEmpty) {
        out.add(trimmed);
      }
    }
    for (final String chapter in chapters) {
      final String chapterName = chapter.trim();
      if (chapterName.isEmpty) {
        continue;
      }
      out.add(chapterName);
      final List<String> anchors = _chapterSignalsFor(chapterName).toList()
        ..sort();
      for (final String anchor in anchors.take(6)) {
        out.add('$chapterName :: $anchor');
      }
    }
    final List<String> subjectAnchors =
        _subjectSignalBaselines[subject.trim().toLowerCase()] ??
        _subjectSignalBaselines.entries
            .firstWhere(
              (MapEntry<String, List<String>> e) =>
                  subject.toLowerCase().contains(e.key),
              orElse: () =>
                  const MapEntry<String, List<String>>('', <String>[]),
            )
            .value;
    for (final String signal in subjectAnchors) {
      out.add('Subject Anchor :: $signal');
    }
    return out.take(max(6, limit)).toList();
  }

  String _inferSubjectFromChapters({
    required String selectedClass,
    required List<String> chapters,
  }) {
    final List<String> scopedClasses = selectedClass == 'Class 11+12'
        ? <String>['Class 11', 'Class 12']
        : <String>[selectedClass];
    final List<String> normalizedInput = chapters
        .map(_normalizeChapterKey)
        .where((String e) => e.isNotEmpty)
        .toList();
    if (normalizedInput.isEmpty) {
      return 'Mathematics';
    }

    final Map<String, int> scores = <String, int>{};
    for (final String className in scopedClasses) {
      final Map<String, List<String>> bySubject =
          syllabusByClassAndSubject[className] ?? <String, List<String>>{};
      bySubject.forEach((String subject, List<String> chapterList) {
        final Set<String> normalizedCatalog = chapterList
            .map(_normalizeChapterKey)
            .where((String e) => e.isNotEmpty)
            .toSet();
        int score = 0;
        for (final String chapter in normalizedInput) {
          if (normalizedCatalog.contains(chapter)) {
            score++;
          }
        }
        if (score > 0) {
          scores[subject] = (scores[subject] ?? 0) + score;
        }
      });
    }

    if (scores.isEmpty) {
      return 'Mathematics';
    }
    final List<MapEntry<String, int>> ranked = scores.entries.toList()
      ..sort(
        (MapEntry<String, int> a, MapEntry<String, int> b) =>
            b.value.compareTo(a.value),
      );
    return ranked.first.key;
  }

  List<Question> _draftQuestionsAsExamQuestions() {
    return _questions.map((QuizQuestion q) {
      final String section = q.section.trim().isEmpty
          ? 'General'
          : q.section.trim();
      final String subPart = q.subPart.trim();
      return Question(
        text: q.text,
        imageUrl: q.image,
        type: q.type,
        section: section,
        posMark: q.pos,
        negMark: q.neg,
        options: List<String>.from(q.options),
        correctAnswers: List<String>.from(q.correct),
        solution: q.solution,
        concept: subPart.isEmpty ? section : '$section | $subPart',
        difficultyLabel: q.difficultyLabel,
        confidenceScore: q.confidenceScore,
        adaptiveScore: q.adaptiveScore,
      );
    }).toList();
  }

  bool _isQuestionLikelyTooEasy(Question q) {
    final String text = q.text.trim().toLowerCase();
    if (text.isEmpty) {
      return true;
    }
    final String solution = q.solution.trim().toLowerCase();
    final String difficultyBag = '${q.difficultyLabel} ${q.concept}'
        .trim()
        .toLowerCase();
    final int reasoningSteps = _reasoningStepCount(q.solution);
    final bool hardProfileRequested =
        _aiDifficulty >= 5 || (_aiPreferPyq && _aiDifficulty >= 4);
    final bool distanceTemplate = _isDistanceOnlyTemplate(text);
    final bool veryShort = text.length < 48;
    final bool singleStepMath = RegExp(
      r'(\d+\s*[x*]\s*\d+|\d+\s*[+\-]\s*\d+)',
    ).hasMatch(text);
    final bool hasReasoningCue =
        text.contains('solve') ||
        text.contains('larger root') ||
        text.contains('ratio') ||
        text.contains('choose') ||
        text.contains('term') ||
        text.contains('prove') ||
        text.contains('hence') ||
        text.contains('show that') ||
        text.contains('distinct') ||
        text.contains('locus') ||
        text.contains('parameter') ||
        text.contains('equation') ||
        text.contains('evaluate') ||
        text.contains('integral') ||
        text.contains('determinant');
    final bool hasConstraintCue =
        text.contains('at least') ||
        text.contains('at most') ||
        text.contains('exactly') ||
        text.contains('distinct') ||
        text.contains('without repetition') ||
        text.contains('if and only if') ||
        text.contains('subject to') ||
        text.contains('maximum') ||
        text.contains('minimum');
    final bool advancedSignal = RegExp(
      r'\b(case|constraint|non[- ]routine|eliminate|prove|hence|therefore|transform|substitution|piecewise|inequality)\b',
    ).hasMatch('$text $solution');
    final bool explicitlyBasic =
        difficultyBag.contains('basic') ||
        difficultyBag.contains('easy') ||
        difficultyBag.contains('difficulty l1') ||
        difficultyBag.contains('difficulty l2');
    final bool placeholderOption = q.options
        .map((String e) => e.trim().toLowerCase())
        .any((String e) => e.startsWith('option '));
    final bool trivialOptionBand = _looksOptionBandTrivial(q.options);
    final int wordCount = text
        .split(RegExp(r'\s+'))
        .where((String token) => token.trim().isNotEmpty)
        .length;
    final bool shallowReasoning = reasoningSteps < 2;
    final bool ultraShallowHard =
        hardProfileRequested && reasoningSteps < 3 && wordCount < 16;
    if (placeholderOption) {
      return true;
    }
    if (distanceTemplate) {
      return true;
    }
    if (singleStepMath && !hasReasoningCue && !hasConstraintCue) {
      return true;
    }
    if (explicitlyBasic && !advancedSignal) {
      return true;
    }
    if (trivialOptionBand && !advancedSignal) {
      return true;
    }
    if ((shallowReasoning || ultraShallowHard) &&
        !advancedSignal &&
        !hasConstraintCue) {
      return true;
    }
    if (veryShort && wordCount < 10 && !hasReasoningCue && !hasConstraintCue) {
      return true;
    }
    return false;
  }

  bool _quizLikelyTooEasy(List<Question> questions) {
    if (questions.isEmpty) {
      return true;
    }
    final int weak = questions.where(_isQuestionLikelyTooEasy).length;
    final bool hardProfileRequested =
        _aiDifficulty >= 5 || (_aiPreferPyq && _aiDifficulty >= 4);
    final double avgHardness =
        questions
            .map(_estimatedQuestionHardnessScore)
            .fold<double>(0.0, (double a, double b) => a + b) /
        questions.length;
    final int advancedLike = questions
        .where((Question q) => _estimatedQuestionHardnessScore(q) >= 4.0)
        .length;
    if (hardProfileRequested) {
      if (avgHardness < 2.85) {
        return true;
      }
      if (advancedLike < max(1, (questions.length * 0.20).round())) {
        return true;
      }
    }
    return weak >= max(2, (questions.length * 0.45).round());
  }

  bool _isDistanceOnlyTemplate(String text) {
    final bool hasPointPair = RegExp(
      r'\ba\s*\([^)]*\)\s*and\s*b\s*\([^)]*\)',
      caseSensitive: false,
    ).hasMatch(text);
    final bool asksAbSquared =
        text.contains('ab^2') ||
        text.contains(r'ab$^2$') ||
        text.contains('ab2') ||
        RegExp(r'\bfind\s+ab', caseSensitive: false).hasMatch(text);
    final bool hasCircleSignal = _containsCircleSignals(text);
    return hasPointPair && asksAbSquared && !hasCircleSignal;
  }

  bool _containsCircleSignals(String text) {
    const List<String> circleSignals = <String>[
      'circle',
      'radius',
      'diameter',
      'tangent',
      'normal',
      'chord',
      'director circle',
      'x^2 + y^2',
      'x2 + y2',
      'pair of tangents',
      'family of circles',
    ];
    return circleSignals.any(text.contains);
  }

  bool _looksOptionBandTrivial(List<String> options) {
    final List<String> cleaned = options
        .map((String e) => e.trim())
        .where((String e) => e.isNotEmpty)
        .toList();
    if (cleaned.length < 4) {
      return false;
    }
    final List<int> numeric = <int>[];
    for (final String option in cleaned) {
      final String normalized = option
          .replaceAll(RegExp(r'[\$\\,]'), '')
          .trim();
      final int? value = int.tryParse(normalized);
      if (value == null) {
        return false;
      }
      numeric.add(value);
    }
    numeric.sort();
    int consecutive = 1;
    for (int i = 1; i < numeric.length; i++) {
      if (numeric[i] - numeric[i - 1] <= 2) {
        consecutive++;
      }
    }
    return consecutive >= 3;
  }

  double _estimatedQuestionHardnessScore(Question q) {
    final String bag =
        '${q.text} ${q.solution} ${q.concept} ${q.difficultyLabel}'
            .toLowerCase();
    final Match? marker = RegExp(
      r'difficulty\s*l?\s*([1-5])',
      caseSensitive: false,
    ).firstMatch(bag);
    if (marker != null) {
      final int? parsed = int.tryParse(marker.group(1) ?? '');
      if (parsed != null) {
        return parsed.toDouble();
      }
    }
    final String label = q.difficultyLabel.toLowerCase();
    if (label.contains('advanced') || label.contains('hard')) {
      return 4.2;
    }
    if (label.contains('main') || label.contains('moderate')) {
      return 3.1;
    }
    if (label.contains('basic') || label.contains('easy')) {
      return 1.8;
    }
    int signal = 0;
    if (RegExp(
      r'\b(case|constraint|eliminate|prove|hence|therefore)\b',
    ).hasMatch(bag)) {
      signal += 2;
    }
    if (_reasoningStepCount(q.solution) >= 3) {
      signal += 1;
    }
    if (RegExp(
      r'\\int|\\sum|determinant|matrix|vector|probability|binomial',
    ).hasMatch(bag)) {
      signal += 1;
    }
    if (signal >= 4) {
      return 4.6;
    }
    if (signal == 3) {
      return 4.0;
    }
    if (signal == 2) {
      return 3.4;
    }
    if (signal == 1) {
      return 2.8;
    }
    return 2.3;
  }

  bool _isBinomialScope({
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final String bag = <String>[
      subject,
      ...chapters,
      ...subtopics,
    ].join(' ').toLowerCase();
    final bool explicit =
        bag.contains('binomial') ||
        bag.contains(r'\binom') ||
        bag.contains('ncr') ||
        bag.contains('(1+x)^') ||
        bag.contains('(a+b)^') ||
        bag.contains('(x+y)^');
    final bool coeffScope =
        bag.contains('coefficient') &&
        (bag.contains('term') || bag.contains('expansion'));
    return explicit || coeffScope;
  }

  bool _questionMatchesRequestedScope(
    Question q, {
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final String rawText = q.text.trim();
    if (rawText.isEmpty) {
      return false;
    }
    final bool templateScaffold = RegExp(
      r"^\s*(for chapter|in)\s*'[^']+'",
      caseSensitive: false,
    ).hasMatch(rawText);
    final String textWithoutScaffold = rawText
        .replaceFirst(
          RegExp(
            r"^\s*(for chapter|in)\s*'[^']+'\s*,?\s*",
            caseSensitive: false,
          ),
          '',
        )
        .replaceAll(RegExp(r"\(trap:\s*[^)]*\)", caseSensitive: false), '')
        .trim()
        .toLowerCase();
    final String bag = textWithoutScaffold;

    if (_isBinomialScope(
      subject: subject,
      chapters: chapters,
      subtopics: subtopics,
    )) {
      const List<String> binomialMarkers = <String>[
        'coefficient',
        'expansion',
        'general term',
        'middle term',
        'greatest coefficient',
        'constant term',
        r'\binom',
        'ncr',
        '(1+x)^',
        '(a+b)^',
        '(x+y)^',
      ];
      final bool hasBinomialSignal = binomialMarkers.any(bag.contains);
      final bool derivativeOnly =
          (rawText.toLowerCase().contains("f'(1)") ||
              rawText.toLowerCase().contains('f(x)=') ||
              rawText.toLowerCase().contains('derivative') ||
              rawText.toLowerCase().contains('d/dx')) &&
          !bag.contains('coefficient') &&
          !bag.contains('expansion');
      return hasBinomialSignal && !derivativeOnly;
    }

    final String scopeBag = <String>[
      subject,
      ...chapters,
      ...subtopics,
    ].join(' ').toLowerCase();
    final Set<String> explicitScopeTokens = <String>[...chapters, ...subtopics]
        .map(_normalizeChapterKey)
        .where((String e) => e.isNotEmpty)
        .expand((String e) => e.split(RegExp(r'[^a-z0-9]+')))
        .map((String e) => e.trim())
        .where((String e) => e.length >= 4)
        .where((String e) => !_scopeStopWords.contains(e))
        .toSet();
    if (explicitScopeTokens.isEmpty) {
      return true;
    }
    final Set<String> scopeTokens = _scopeSignals(
      subject: subject,
      chapters: chapters,
      subtopics: subtopics,
    );
    if (scopeTokens.isEmpty) {
      return true;
    }
    final int hits = scopeTokens.where(bag.contains).length;
    bool domainGuardApplied = false;
    if (scopeBag.contains('trigon')) {
      domainGuardApplied = true;
      if (!<String>[
        'sin',
        'cos',
        'tan',
        'cot',
        'sec',
        'cosec',
        'trigon',
      ].any(bag.contains)) {
        return false;
      }
    }
    if (scopeBag.contains('probability') || scopeBag.contains('statistics')) {
      domainGuardApplied = true;
      if (!<String>[
        'probability',
        'random',
        'coin',
        'dice',
        'mean',
        'variance',
      ].any(bag.contains)) {
        return false;
      }
    }
    if (scopeBag.contains('matrix') || scopeBag.contains('determinant')) {
      domainGuardApplied = true;
      if (!<String>[
        'matrix',
        'determinant',
        'adjoint',
        'inverse',
        'rank',
      ].any(bag.contains)) {
        return false;
      }
    }
    if (scopeBag.contains('vector') ||
        scopeBag.contains('3d geometry') ||
        scopeBag.contains('three dimensional')) {
      domainGuardApplied = true;
      if (!<String>[
        'vector',
        'dot',
        'cross',
        'line',
        'plane',
        'direction ratio',
      ].any(bag.contains)) {
        return false;
      }
    }
    if (<String>[
      'calculus',
      'limit',
      'continuity',
      'derivative',
      'integral',
      'differential',
    ].any(scopeBag.contains)) {
      domainGuardApplied = true;
      if (!<String>[
        'limit',
        'derivative',
        'integral',
        'd/dx',
        r'\int',
        'differentiat',
      ].any(bag.contains)) {
        return false;
      }
    }
    if (scopeBag.contains('circle') ||
        scopeBag.contains('conic') ||
        scopeTokens.contains('circle') ||
        scopeTokens.contains('tangent') ||
        scopeTokens.contains('chord') ||
        scopeTokens.contains('radius') ||
        scopeTokens.contains('diameter')) {
      domainGuardApplied = true;
      final bool hasCircleSignal = _containsCircleSignals(bag);
      if (!hasCircleSignal) {
        return false;
      }
      if (_isDistanceOnlyTemplate(bag)) {
        return false;
      }
    }
    if (domainGuardApplied) {
      return true;
    }
    if (hits == 0) {
      return false;
    }
    if (templateScaffold && hits <= 1 && scopeTokens.length >= 2) {
      return false;
    }
    return true;
  }

  bool _quizLikelyOutOfScope(
    List<Question> questions, {
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    if (questions.isEmpty) {
      return true;
    }
    final int mismatched = questions
        .where(
          (Question q) => !_questionMatchesRequestedScope(
            q,
            subject: subject,
            chapters: chapters,
            subtopics: subtopics,
          ),
        )
        .length;
    return mismatched >= max(2, (questions.length * 0.4).round());
  }

  bool _quizLikelyLowAuthoringQuality(List<Question> questions) {
    if (questions.isEmpty) {
      return true;
    }
    bool templated(Question q) {
      final String text = q.text.toLowerCase();
      return text.startsWith("for chapter '") ||
          text.startsWith("in '") ||
          text.contains('(trap: avoid') ||
          (text.contains("f(x)=") && text.contains("f'(1)")) ||
          _isDistanceOnlyTemplate(text);
    }

    final int templatedCount = questions.where(templated).length;
    if (templatedCount >= max(2, (questions.length * 0.5).round())) {
      return true;
    }
    return _quizLikelyLowVariety(questions);
  }

  String _questionSkeleton(String text) {
    String out = text.toLowerCase();
    out = out.replaceAll(RegExp(r'\$[^$]*\$'), ' M ');
    out = out.replaceAll(RegExp(r'\([^)]*\)'), '()');
    out = out.replaceAll(RegExp(r'-?\d+(?:\.\d+)?'), '#');
    out = out.replaceAll(RegExp(r'\s+'), ' ').trim();
    return out;
  }

  bool _quizLikelyLowVariety(List<Question> questions) {
    if (questions.length < 4) {
      return false;
    }
    final Map<String, int> skeletonCount = <String, int>{};
    int distanceTemplateCount = 0;
    final Map<String, int> openingCount = <String, int>{};
    final Map<String, int> techniqueCount = <String, int>{};
    final List<Set<String>> tokenSets = <Set<String>>[];
    for (final Question q in questions) {
      final String text = q.text.trim().toLowerCase();
      final String key = _questionSkeleton(text);
      if (key.isNotEmpty) {
        skeletonCount[key] = (skeletonCount[key] ?? 0) + 1;
      }
      final String opening = _openingFingerprint(text);
      if (opening.isNotEmpty) {
        openingCount[opening] = (openingCount[opening] ?? 0) + 1;
      }
      final String technique = _questionTechniqueBucket(
        '${q.text} ${q.solution} ${q.concept}',
      );
      techniqueCount[technique] = (techniqueCount[technique] ?? 0) + 1;
      tokenSets.add(_tokenSetForVariety(text));
      if (_isDistanceOnlyTemplate(text)) {
        distanceTemplateCount++;
      }
    }

    final int maxSkeletonRepeat = skeletonCount.values.isEmpty
        ? 0
        : skeletonCount.values.reduce(max);
    if (maxSkeletonRepeat >= max(2, (questions.length * 0.35).round())) {
      return true;
    }
    if (distanceTemplateCount >= max(2, (questions.length * 0.35).round())) {
      return true;
    }
    final int dominantOpening = openingCount.values.isEmpty
        ? 0
        : openingCount.values.reduce(max);
    if (dominantOpening >= max(3, (questions.length * 0.5).round())) {
      return true;
    }
    if (questions.length >= 6 &&
        techniqueCount.keys.length <
            max(3, (questions.length * 0.35).round())) {
      return true;
    }
    int similarPairs = 0;
    int pairCount = 0;
    for (int i = 0; i < tokenSets.length; i++) {
      for (int j = i + 1; j < tokenSets.length; j++) {
        pairCount++;
        if (_jaccardSimilarity(tokenSets[i], tokenSets[j]) >= 0.85) {
          similarPairs++;
        }
      }
    }
    if (pairCount >= 6 && (similarPairs / pairCount) >= 0.55) {
      return true;
    }

    final Map<String, int> typeCounts = <String, int>{};
    for (final Question q in questions) {
      final String type = q.type.trim().toUpperCase();
      typeCounts[type] = (typeCounts[type] ?? 0) + 1;
    }
    final int dominantType = typeCounts.values.isEmpty
        ? 0
        : typeCounts.values.reduce(max);
    if (questions.length >= 8 &&
        dominantType >= max(6, (questions.length * 0.8).round())) {
      return true;
    }
    return false;
  }

  String _openingFingerprint(String text) {
    final List<String> tokens = text
        .replaceAll(RegExp(r'[^a-z0-9 ]+'), ' ')
        .split(RegExp(r'\s+'))
        .map((String t) => t.trim())
        .where((String t) => t.length >= 3)
        .take(7)
        .toList();
    return tokens.join(' ');
  }

  String _questionTechniqueBucket(String text) {
    final String bag = text.toLowerCase();
    if (RegExp(r'\\int|integral|d/dx|derivative|limit').hasMatch(bag)) {
      return 'calculus';
    }
    if (RegExp(
      r'probability|random|coin|dice|binomial distribution',
    ).hasMatch(bag)) {
      return 'probability';
    }
    if (RegExp(r'matrix|determinant|adjoint|rank').hasMatch(bag)) {
      return 'matrix';
    }
    if (RegExp(r'vector|dot|cross|line|plane').hasMatch(bag)) {
      return 'vector3d';
    }
    if (RegExp(
      r'circle|conic|parabola|ellipse|hyperbola|tangent',
    ).hasMatch(bag)) {
      return 'coordinate_geometry';
    }
    if (RegExp(r'coefficient|expansion|ncr|binomial|term').hasMatch(bag)) {
      return 'binomial';
    }
    if (RegExp(
      r'case|constraint|at least|at most|without repetition',
    ).hasMatch(bag)) {
      return 'combinatorics';
    }
    return 'general';
  }

  Set<String> _tokenSetForVariety(String text) {
    return text
        .replaceAll(RegExp(r'\$[^$]*\$'), ' ')
        .replaceAll(RegExp(r'[^a-z0-9 ]+'), ' ')
        .split(RegExp(r'\s+'))
        .map((String token) => token.trim())
        .where((String token) => token.length >= 4)
        .where((String token) => !_scopeStopWords.contains(token))
        .toSet();
  }

  double _jaccardSimilarity(Set<String> a, Set<String> b) {
    if (a.isEmpty || b.isEmpty) {
      return 0.0;
    }
    final Set<String> intersection = a.intersection(b);
    final Set<String> union = a.union(b);
    if (union.isEmpty) {
      return 0.0;
    }
    return intersection.length / union.length;
  }

  bool _hasChapterCoverage(
    List<Question> questions,
    List<String> chapters, {
    required String subject,
  }) {
    final List<String> normalizedChapters = chapters
        .map((String e) => e.trim().toLowerCase())
        .where((String e) => e.isNotEmpty)
        .toList();
    if (normalizedChapters.length <= 1) {
      return true;
    }

    int covered = 0;
    for (final String chapter in normalizedChapters) {
      final Set<String> tokens = _chapterSignalsFor(chapter);
      if (tokens.isEmpty) {
        covered++;
        continue;
      }
      final bool hit = questions.any((Question q) {
        final String bag = '${q.text} ${q.concept} ${q.solution}'.toLowerCase();
        return tokens.any(bag.contains);
      });
      if (hit) {
        covered++;
      }
    }

    if (questions.length >= normalizedChapters.length) {
      return covered == normalizedChapters.length;
    }
    return covered >= max(1, (normalizedChapters.length * 0.7).round());
  }

  bool _passesTeacherAuthoringContract(
    List<Question> questions, {
    required int expectedCount,
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    if (questions.length != expectedCount) {
      return false;
    }
    if (_quizLikelyOutOfScope(
      questions,
      subject: subject,
      chapters: chapters,
      subtopics: subtopics,
    )) {
      return false;
    }
    if (_quizLikelyTooEasy(questions) ||
        _quizLikelyLowAuthoringQuality(questions) ||
        _quizLikelyLowVariety(questions)) {
      return false;
    }
    if (!_hasChapterCoverage(questions, chapters, subject: subject)) {
      return false;
    }

    int mcq = 0;
    int multi = 0;
    int numerical = 0;
    for (final Question q in questions) {
      final String type = q.type.toUpperCase();
      if (type == 'MCQ') {
        mcq++;
      } else if (type == 'MULTI') {
        multi++;
      } else if (type == 'NUMERICAL') {
        numerical++;
      }
      if (q.correctAnswers.isEmpty) {
        return false;
      }
      if (type != 'NUMERICAL' && q.options.length != 4) {
        return false;
      }
      if (type == 'MCQ' && q.correctAnswers.length != 1) {
        return false;
      }
      if (type == 'MULTI' && q.correctAnswers.length < 2) {
        return false;
      }
      if (type == 'NUMERICAL') {
        final int? value = int.tryParse(q.correctAnswers.first.trim());
        if (value == null || value < 0 || value > 9) {
          return false;
        }
      }
      if (_reasoningStepCount(q.solution) < 2) {
        return false;
      }
    }

    if (!_hasRequiredTypeMix(
      questions,
      expectedCount: expectedCount,
      mcq: mcq,
      multi: multi,
      numerical: numerical,
    )) {
      return false;
    }

    if (expectedCount >= 8) {
      final int minPerType = max(1, (expectedCount * 0.2).round());
      if (multi < minPerType || numerical < minPerType || mcq < minPerType) {
        return false;
      }
    }
    return true;
  }

  Map<String, int> _expectedTypeDistribution(int total) {
    final int safeTotal = total <= 0 ? 1 : total;
    final int numerical = (safeTotal * 0.4).round();
    final int mcq = (safeTotal * 0.3).round();
    final int multi = safeTotal - numerical - mcq;
    return <String, int>{
      'MCQ': mcq.clamp(0, safeTotal),
      'MULTI': multi.clamp(0, safeTotal),
      'NUMERICAL': numerical.clamp(0, safeTotal),
    };
  }

  bool _hasRequiredTypeMix(
    List<Question> questions, {
    required int expectedCount,
    int? mcq,
    int? multi,
    int? numerical,
  }) {
    int computedMcq = 0;
    int computedMulti = 0;
    int computedNumerical = 0;
    if (mcq == null || multi == null || numerical == null) {
      for (final Question q in questions) {
        final String type = q.type.toUpperCase();
        if (type == 'MCQ') {
          computedMcq++;
        } else if (type == 'MULTI') {
          computedMulti++;
        } else if (type == 'NUMERICAL') {
          computedNumerical++;
        }
      }
    }
    final int cMcq = mcq ?? computedMcq;
    final int cMulti = multi ?? computedMulti;
    final int cNumerical = numerical ?? computedNumerical;
    final int distinctTypes = <int>[
      cMcq,
      cMulti,
      cNumerical,
    ].where((int count) => count > 0).length;
    if (expectedCount <= 1) {
      return true;
    }
    if (expectedCount == 2) {
      return distinctTypes >= 2;
    }
    if (expectedCount <= 4) {
      return cMcq >= 1 && cMulti >= 1 && cNumerical >= 1;
    }
    return cMcq >= 1 && cMulti >= 1 && cNumerical >= 1;
  }

  DateTime _selfPracticeDeadline() {
    return DateTime.now().add(const Duration(days: 365 * 50));
  }

  String _quizCsvFallbackUrl(String quizId) {
    final String raw = AppConfig.authBackendUrl.trim();
    if (raw.isEmpty) {
      return 'ai://$quizId';
    }
    try {
      final Uri uri = Uri.parse(raw);
      final String host = uri.host.trim();
      if (uri.scheme.isEmpty || host.isEmpty) {
        return 'ai://$quizId';
      }
      final String port = uri.hasPort ? ':${uri.port}' : '';
      return '${uri.scheme}://$host$port/app/quiz/$quizId.csv';
    } catch (_) {
      return 'ai://$quizId';
    }
  }

  String _normalizeAiLatexText(String raw) {
    final String text = raw.replaceAll('\r', '\n').trim();
    if (text.isEmpty) {
      return '';
    }
    final String compact = text
        .split('\n')
        .map((String line) => line.trim())
        .where((String line) => line.isNotEmpty)
        .join(' ');
    if (compact.isEmpty) {
      return '';
    }
    final String repaired = _repairLikelyIndexedRadiusSymbols(compact);
    final String normalized = normalizeUniversalLatex(repaired).trim();
    return _repairRadiusIndexAfterLatexNormalization(normalized);
  }

  String _repairLikelyIndexedRadiusSymbols(String text) {
    String out = text;
    out = out
        .replaceAll('r¹', 'r1')
        .replaceAll('r²', 'r2')
        .replaceAll('r₁', 'r1')
        .replaceAll('r₂', 'r2');
    out = out.replaceAllMapped(
      RegExp(r'(?<![A-Za-z0-9_\\^])r([12])(?![0-9])', caseSensitive: false),
      (Match m) => 'r_${m.group(1)}',
    );
    return out;
  }

  String _repairRadiusIndexAfterLatexNormalization(String text) {
    String out = text;
    final bool hasIndexedOne = RegExp(r'r_\{?1\}?').hasMatch(out);
    final bool hasIndexedTwo = RegExp(r'r_\{?2\}?').hasMatch(out);
    if (hasIndexedOne && !hasIndexedTwo) {
      out = out.replaceAllMapped(RegExp(r'r\^\{?2\}?'), (Match m) => 'r_{2}');
    }
    return out;
  }

  String _normalizeAiOptionText(String raw) {
    String out = raw.trim();
    if (out.isEmpty) {
      return '';
    }
    out = out.replaceFirst(RegExp(r'^\s*[-*]\s*'), '');
    out = out.replaceFirst(RegExp(r'^\s*\(?[A-Da-d1-4]\)?[.)\-:]\s*'), '');
    out = out.replaceFirst(RegExp(r'^\s*[A-Da-d]\s*\]\s*'), '');
    return _normalizeAiLatexText(out);
  }

  String _normalizeAiQuestionType(dynamic rawType) {
    final String normalized = rawType.toString().trim().toLowerCase();
    final bool singleCorrectSignal =
        normalized.contains('single correct') ||
        normalized.contains('single answer') ||
        normalized.contains('mcq_single') ||
        normalized == 'single';
    final bool multiSignal =
        normalized == 'multi' ||
        normalized == 'mcq_multi' ||
        normalized == 'multicorrect' ||
        normalized == 'multi_correct' ||
        normalized == 'multi-correct' ||
        normalized == 'multiple' ||
        normalized == 'multiple_correct' ||
        normalized == 'multiple correct' ||
        normalized == 'multiple_choice_multiple_answer' ||
        normalized == 'msq' ||
        normalized == 'mcma' ||
        normalized == 'select_all_that_apply' ||
        normalized.contains('multiple correct') ||
        normalized.contains('multi correct') ||
        normalized.contains('select all') ||
        (normalized.contains('multiple') && !singleCorrectSignal);
    if (multiSignal) {
      return 'MULTI';
    }
    if (normalized == 'numerical' ||
        normalized == 'num' ||
        normalized == 'integer' ||
        normalized == 'integer_type' ||
        normalized == 'integer type' ||
        normalized == 'numerical answer type' ||
        normalized == 'nat' ||
        normalized == 'non_mcq' ||
        normalized.contains('numerical') ||
        normalized.contains('integer') ||
        normalized.contains('numeric')) {
      return 'NUMERICAL';
    }
    return 'MCQ';
  }

  String _sanitizeNumericalAnswer(dynamic ans) {
    if (ans is num) {
      if (ans >= 0 && ans <= 9 && ans == ans.roundToDouble()) {
        return ans.toInt().toString();
      }
    }
    if (ans is String) {
      final String trimmed = ans.trim();
      final int? parsed = int.tryParse(trimmed);
      if (parsed != null && parsed >= 0 && parsed <= 9) {
        return parsed.toString();
      }
    }
    throw const FormatException('Invalid numerical answer. Regenerate.');
  }

  String _extractSanitizedNumericalAnswer(
    Map<String, dynamic> q,
    Map<String, dynamic> hiddenGrading,
  ) {
    final dynamic rawCandidate =
        q['correct_answer'] ??
        q['numerical_answer'] ??
        q['correct_numerical'] ??
        q['answer'] ??
        q['correct_answers'] ??
        hiddenGrading['correct_answer'] ??
        hiddenGrading['numerical_answer'] ??
        hiddenGrading['correct_numerical'] ??
        hiddenGrading['answer'] ??
        hiddenGrading['correct_answers'];
    if (rawCandidate is List && rawCandidate.isNotEmpty) {
      return _sanitizeNumericalAnswer(rawCandidate.first);
    }
    return _sanitizeNumericalAnswer(rawCandidate);
  }

  int _extractAiDifficultyLevel(Map<String, dynamic> q) {
    final dynamic raw =
        q['difficulty'] ?? q['difficulty_level'] ?? q['difficulty_estimate'];
    if (raw is num) {
      final int level = raw.toInt();
      if (level >= 1 && level <= 5) {
        return level;
      }
    }
    if (raw is String) {
      final int? level = int.tryParse(raw.trim());
      if (level != null && level >= 1 && level <= 5) {
        return level;
      }
    }
    return 0;
  }

  String _difficultyLabelForLevel(int level) {
    if (level <= 2) {
      return 'Basic';
    }
    if (level == 3) {
      return 'Main';
    }
    if (level >= 4) {
      return 'Advanced';
    }
    return '';
  }

  String _extractAiDifficultyLabel(
    Map<String, dynamic> q, {
    required int level,
  }) {
    final dynamic raw =
        q['difficulty_label'] ??
        q['difficulty'] ??
        q['difficulty_stage_label'] ??
        q['difficulty_estimate'];
    if (raw is String) {
      final String text = raw.trim();
      if (text.isNotEmpty) {
        final int? parsed = int.tryParse(text);
        if (parsed == null) {
          return text;
        }
      }
    }
    if (raw is num) {
      return _difficultyLabelForLevel(raw.toInt());
    }
    if (level > 0) {
      return _difficultyLabelForLevel(level);
    }
    return '';
  }

  double _extractAiConfidenceScore(Map<String, dynamic> q) {
    final dynamic raw =
        q['confidence_score'] ?? q['confidence'] ?? q['score_confidence'];
    if (raw is num) {
      return raw.toDouble().clamp(0.0, 1.0);
    }
    final String text = raw.toString().trim().toLowerCase();
    if (text.isEmpty) {
      return -1;
    }
    final double? numeric = double.tryParse(text.replaceAll('%', ''));
    if (numeric != null) {
      if (text.contains('%')) {
        return (numeric / 100).clamp(0.0, 1.0);
      }
      return numeric.clamp(0.0, 1.0);
    }
    if (text == 'high') {
      return 0.82;
    }
    if (text == 'medium' || text == 'moderate') {
      return 0.58;
    }
    if (text == 'low') {
      return 0.32;
    }
    return -1;
  }

  double _extractAiAdaptiveScore(Map<String, dynamic> q) {
    final dynamic raw =
        q['adaptive_score'] ?? q['adaptive'] ?? q['mastery_fit'];
    if (raw is num) {
      return raw.toDouble().clamp(0.0, 1.0);
    }
    final String text = raw.toString().trim();
    if (text.isEmpty) {
      return -1;
    }
    final double? parsed = double.tryParse(text);
    if (parsed == null) {
      return -1;
    }
    return parsed.clamp(0.0, 1.0);
  }

