  int _reasoningStepCount(String solution) {
    final String text = solution.trim();
    if (text.isEmpty) {
      return 0;
    }
    final int explicit = RegExp(
      r'(step\s*\d+\s*:|^\s*\d+\s*[.)])',
      caseSensitive: false,
      multiLine: true,
    ).allMatches(text).length;
    if (explicit > 0) {
      return explicit;
    }
    final List<String> sentences = text
        .split(RegExp(r'(?<=[.!?])\s+'))
        .map((String e) => e.trim())
        .where((String e) => e.isNotEmpty)
        .toList();
    return sentences.length;
  }

  bool _hasStrictDifficultyCoverage(List<Question> questions) {
    if (questions.length < 5) {
      return true;
    }
    final Set<int> seen = <int>{};
    final RegExp marker = RegExp(
      r'\bdifficulty\s*L?\s*([1-5])\b',
      caseSensitive: false,
    );
    for (final Question q in questions) {
      final Iterable<Match> matches = marker.allMatches(q.concept);
      for (final Match m in matches) {
        final int? level = int.tryParse(m.group(1) ?? '');
        if (level != null) {
          seen.add(level);
        }
      }
    }
    return seen.length == 5;
  }

  bool _matchesCustomPracticeDistribution(List<Question> questions) {
    if (questions.isEmpty) {
      return false;
    }
    final int total = questions.length;
    final Map<String, int> expected = _expectedTypeDistribution(total);
    final int expectedNumerical = expected['NUMERICAL'] ?? 0;
    final int expectedMcq = expected['MCQ'] ?? 0;
    final int expectedMulti = expected['MULTI'] ?? 0;
    final int numerical = questions
        .where((Question q) => q.type.toUpperCase() == 'NUMERICAL')
        .length;
    final int mcq = questions
        .where((Question q) => q.type.toUpperCase() == 'MCQ')
        .length;
    final int multi = questions
        .where((Question q) => q.type.toUpperCase() == 'MULTI')
        .length;
    return numerical == expectedNumerical &&
        mcq == expectedMcq &&
        multi == expectedMulti;
  }

  bool _passesCustomPracticeContract(
    List<Question> questions, {
    required int expectedCount,
  }) {
    if (questions.length != expectedCount) {
      return false;
    }
    if (!_matchesCustomPracticeDistribution(questions)) {
      return false;
    }
    if (!_hasStrictDifficultyCoverage(questions)) {
      return false;
    }
    for (final Question q in questions) {
      if (_reasoningStepCount(q.solution) < 2) {
        return false;
      }
      if (q.type.toUpperCase() == 'MULTI' && q.correctAnswers.length < 2) {
        return false;
      }
      if (q.type.toUpperCase() == 'NUMERICAL') {
        if (q.correctAnswers.isEmpty) {
          return false;
        }
        final int? value = int.tryParse(q.correctAnswers.first.trim());
        if (value == null || value < 0 || value > 9) {
          return false;
        }
      }
    }
    return true;
  }

  List<String> _normalizeAiOptions(dynamic rawOptions) {
    if (rawOptions is Map) {
      final Map<String, dynamic> map = Map<String, dynamic>.from(rawOptions);
      final List<String> keys =
          map.keys.map((dynamic e) => e.toString()).toList()..sort();
      final List<String> out = <String>[];
      for (final String key in keys) {
        final String cleaned = _normalizeAiOptionText(
          (map[key] ?? '').toString(),
        );
        if (cleaned.isNotEmpty) {
          out.add(cleaned);
        }
      }
      return out.take(4).toList();
    }
    if (rawOptions is! List) {
      return <String>[];
    }
    final List<String> out = <String>[];
    final Set<String> seen = <String>{};
    for (final dynamic entry in rawOptions) {
      final String cleaned = _normalizeAiOptionText(entry.toString());
      if (cleaned.isEmpty) {
        continue;
      }
      final String key = cleaned.toLowerCase();
      if (seen.contains(key)) {
        continue;
      }
      seen.add(key);
      out.add(cleaned);
      if (out.length >= 4) {
        break;
      }
    }
    return out;
  }

  List<String> _extractAiCorrectAnswers(
    Map<String, dynamic> payload,
    List<String> options,
  ) {
    final Set<String> out = <String>{};
    final Map<String, dynamic> hiddenGrading = payload['grading_key'] is Map
        ? Map<String, dynamic>.from(payload['grading_key'] as Map)
        : <String, dynamic>{};

    void addByLetter(String letter) {
      final String upper = letter.trim().toUpperCase();
      if (upper.isEmpty) {
        return;
      }
      if (upper == '1' || upper == '2' || upper == '3' || upper == '4') {
        final int idx = int.parse(upper) - 1;
        if (idx >= 0 && idx < options.length) {
          out.add(options[idx]);
        }
        return;
      }
      if (!RegExp(r'^[A-D]$').hasMatch(upper)) {
        return;
      }
      final int idx = upper.codeUnitAt(0) - 65;
      if (idx >= 0 && idx < options.length) {
        out.add(options[idx]);
      }
    }

    void addByIndex(dynamic rawIndex) {
      final int? idx = rawIndex is int
          ? rawIndex
          : int.tryParse(rawIndex.toString().trim());
      if (idx == null) {
        return;
      }
      final int normalized = (idx >= 1 && idx <= 4) ? idx - 1 : idx;
      if (normalized >= 0 && normalized < options.length) {
        out.add(options[normalized]);
      }
    }

    void addByExactOption(String text) {
      final String cleaned = _normalizeAiOptionText(text);
      if (cleaned.isEmpty) {
        return;
      }
      for (final String option in options) {
        if (_normalizeAiOptionText(option).toLowerCase() ==
            cleaned.toLowerCase()) {
          out.add(option);
        }
      }
    }

    void addFromToken(String token) {
      final String cleaned = _normalizeAiOptionText(token);
      if (cleaned.isEmpty) {
        return;
      }
      if (RegExp(r'^[A-Da-d1-4]$').hasMatch(cleaned)) {
        addByLetter(cleaned);
        return;
      }
      if (RegExp(r'^\d+$').hasMatch(cleaned)) {
        final int? numeric = int.tryParse(cleaned);
        if (numeric != null && numeric >= 1 && numeric <= 4) {
          addByIndex(cleaned);
          return;
        }
        addByExactOption(cleaned);
        return;
      }
      addByExactOption(cleaned);
    }

    final String rawLetter =
        (payload['correct_option'] ??
                payload['correctOption'] ??
                payload['answer_key'] ??
                payload['_correct_option'] ??
                hiddenGrading['correct_option'] ??
                '')
            .toString()
            .trim();
    if (rawLetter.isNotEmpty) {
      for (final String token in rawLetter.split(RegExp(r'[^A-Za-z0-9]+'))) {
        addFromToken(token);
      }
    }

    final dynamic rawAnswers =
        payload['correct_answers'] ??
        payload['correctAnswers'] ??
        payload['correct_answer'] ??
        payload['answer'] ??
        payload['_correct_answers'] ??
        hiddenGrading['correct_answers'] ??
        hiddenGrading['answer'];
    if (rawAnswers is List) {
      for (final dynamic entry in rawAnswers) {
        addFromToken(entry.toString());
      }
    } else if (rawAnswers is Map) {
      final Map<String, dynamic> answerMap = Map<String, dynamic>.from(
        rawAnswers,
      );
      answerMap.forEach((String key, dynamic value) {
        if (value is bool && value) {
          addFromToken(key);
          return;
        }
        if (value is num && value.toInt() == 1) {
          addFromToken(key);
          return;
        }
        if (value is String && value.trim().toLowerCase() == 'true') {
          addFromToken(key);
          return;
        }
      });
      final dynamic labelList =
          answerMap['labels'] ??
          answerMap['options'] ??
          answerMap['choices'] ??
          answerMap['answers'] ??
          answerMap['correct_options'] ??
          answerMap['correct'];
      if (labelList is List) {
        for (final dynamic entry in labelList) {
          addFromToken(entry.toString());
        }
      }
      final dynamic indexList =
          answerMap['indices'] ??
          answerMap['index'] ??
          answerMap['answer_indices'] ??
          answerMap['correct_option_indexes'];
      if (indexList is List) {
        for (final dynamic entry in indexList) {
          addByIndex(entry);
        }
      }
    } else {
      final String answerText = _normalizeAiOptionText(
        (rawAnswers ?? '').toString(),
      );
      if (answerText.isNotEmpty) {
        if (RegExp(r'^[A-Da-d]{2,4}$').hasMatch(answerText)) {
          for (final int code in answerText.toUpperCase().codeUnits) {
            addByLetter(String.fromCharCode(code));
          }
        }
        for (final String token in answerText.split(RegExp(r'[,/|&;]+'))) {
          addFromToken(token);
        }
      }
    }

    final dynamic indexSource =
        payload['correct_option_indexes'] ??
        payload['correct_indices'] ??
        hiddenGrading['correct_option_indexes'] ??
        hiddenGrading['correct_indices'];
    if (indexSource is List) {
      for (final dynamic entry in indexSource) {
        addByIndex(entry);
      }
    }

    return out.toList();
  }

  String _flattenSolutionPayload(dynamic raw) {
    if (raw is String) {
      return raw;
    }
    if (raw is Map) {
      final Map<String, dynamic> map = Map<String, dynamic>.from(raw);
      final List<String> chunks = <String>[
        (map['core_idea'] ?? map['level_0'] ?? '').toString().trim(),
        (map['intuition'] ?? _toMap(map['level_1'])['intuition'] ?? '')
            .toString()
            .trim(),
      ].where((String e) => e.isNotEmpty).toList();

      final dynamic formal =
          map['formal_derivation'] ??
          _toMap(map['level_2'])['formal_derivation'];
      if (formal is List) {
        for (final dynamic step in formal) {
          if (step is Map) {
            final Map<String, dynamic> s = Map<String, dynamic>.from(step);
            final String stepText =
                (s['step'] ?? s['equation'] ?? s['justification'] ?? '')
                    .toString()
                    .trim();
            if (stepText.isNotEmpty) {
              chunks.add(stepText);
            }
          } else {
            final String txt = step.toString().trim();
            if (txt.isNotEmpty) {
              chunks.add(txt);
            }
          }
        }
      }
      final String shortcut = (map['shortcut'] ?? map['shortcut_mode'] ?? '')
          .toString()
          .trim();
      if (shortcut.isNotEmpty) {
        chunks.add(shortcut);
      }
      return chunks.join('\n');
    }
    return raw.toString();
  }

  List<Question> _parseAiQuestions(
    dynamic raw, {
    required bool includeAnswers,
  }) {
    if (raw is! List) {
      return <Question>[];
    }
    final List<Question> out = <Question>[];
    for (int i = 0; i < raw.length; i++) {
      final dynamic item = raw[i];
      if (item is! Map) {
        continue;
      }
      final Map<String, dynamic> q = Map<String, dynamic>.from(item);
      final Map<String, dynamic> hiddenGrading = q['grading_key'] is Map
          ? Map<String, dynamic>.from(q['grading_key'] as Map)
          : <String, dynamic>{};
      final String text = _normalizeAiLatexText(
        (q['question'] ??
                q['statement'] ??
                q['question_text'] ??
                q['latex_statement'] ??
                '')
            .toString(),
      );
      String type = _normalizeAiQuestionType(q['type'] ?? q['question_type']);
      final List<String> options = _normalizeAiOptions(q['options']);
      if (type != 'NUMERICAL' && options.length != 4) {
        continue;
      }
      if (type == 'NUMERICAL') {
        while (options.length < 4) {
          options.add('');
        }
      }
      final List<String> tags = (q['concept_tags'] is List)
          ? (q['concept_tags'] as List<dynamic>)
                .map((dynamic e) => _normalizeAiLatexText(e.toString()))
                .where((String e) => e.isNotEmpty)
                .toList()
          : <String>[];
      String sourceOrigin = (q['source_origin'] ?? q['origin'] ?? '')
          .toString()
          .trim();
      String sourceStub =
          (q['source_stub'] ?? q['source_url'] ?? q['reference'] ?? '')
              .toString()
              .trim();
      if (sourceOrigin.isEmpty &&
          ((q['citations'] is List && (q['citations'] as List).isNotEmpty) ||
              (q['web_sources'] is List &&
                  (q['web_sources'] as List).isNotEmpty))) {
        sourceOrigin = 'web_pyq';
      }
      if (sourceStub.isEmpty) {
        final dynamic firstCitation =
            (q['citations'] is List && (q['citations'] as List).isNotEmpty)
            ? (q['citations'] as List).first
            : (q['web_sources'] is List &&
                  (q['web_sources'] as List).isNotEmpty)
            ? (q['web_sources'] as List).first
            : null;
        if (firstCitation != null) {
          sourceStub = firstCitation.toString().trim();
        }
      }
      final int difficultyLevel = _extractAiDifficultyLevel(q);
      final String difficultyLabel = _extractAiDifficultyLabel(
        q,
        level: difficultyLevel,
      );
      final double confidenceScore = _extractAiConfidenceScore(q);
      final double adaptiveScore = _extractAiAdaptiveScore(q);
      if (difficultyLevel > 0) {
        tags.insert(0, 'Difficulty L$difficultyLevel');
      }
      if (difficultyLabel.isNotEmpty &&
          !tags.any(
            (String tag) =>
                tag.toLowerCase().trim() == difficultyLabel.toLowerCase(),
          )) {
        tags.insert(0, difficultyLabel);
      }
      if (sourceOrigin.isNotEmpty) {
        tags.add('Source: $sourceOrigin');
      }
      if (sourceStub.isNotEmpty) {
        tags.add('Reference: $sourceStub');
      }
      final List<String> correctAnswers;
      if (!includeAnswers) {
        correctAnswers = const <String>[];
      } else if (type == 'NUMERICAL') {
        final String aqieAnswer = (q['correct_answer'] ?? '').toString().trim();
        if (aqieAnswer.isNotEmpty) {
          correctAnswers = <String>[aqieAnswer];
        } else {
          try {
            correctAnswers = <String>[
              _extractSanitizedNumericalAnswer(q, hiddenGrading),
            ];
          } catch (_) {
            continue;
          }
        }
      } else {
        final String aqieAnswer = (q['correct_answer'] ?? '').toString().trim();
        List<String> parsedAnswers = _extractAiCorrectAnswers(q, options);
        if (parsedAnswers.isEmpty && aqieAnswer.isNotEmpty) {
          parsedAnswers = <String>[aqieAnswer];
        }
        correctAnswers = parsedAnswers
            .map((String e) => _normalizeAiOptionText(e))
            .where((String e) => e.isNotEmpty)
            .toSet()
            .toList();
      }
      if (text.isEmpty) {
        continue;
      }
      if (includeAnswers && correctAnswers.isEmpty) {
        continue;
      }
      String solution = includeAnswers
          ? _normalizeAiLatexText(
              _flattenSolutionPayload(
                q['solution'] ??
                    q['proof_layers'] ??
                    q['solution_explanation'] ??
                    q['_solution_explanation'] ??
                    hiddenGrading['solution_explanation'] ??
                    hiddenGrading['solution'] ??
                    '',
              ),
            )
          : '';
      if (includeAnswers &&
          sourceStub.isNotEmpty &&
          !solution.toLowerCase().contains(sourceStub.toLowerCase())) {
        solution = solution.trim().isEmpty
            ? 'Reference: $sourceStub'
            : '$solution\nReference: $sourceStub';
      }
      out.add(
        Question(
          text: text,
          imageUrl: '',
          type: type,
          section: tags.isEmpty ? 'General' : tags.join(', '),
          posMark: 4,
          negMark: 1,
          options: options,
          // Answer keys are retained for scoring/analytics; UI can still hide them.
          correctAnswers: correctAnswers,
          solution: solution,
          concept: tags.join(', '),
          difficultyLabel: difficultyLabel,
          confidenceScore: confidenceScore,
          adaptiveScore: adaptiveScore,
        ),
      );
    }
    return out;
  }

  List<dynamic> _listFromUnknown(dynamic raw) {
    if (raw is List) {
      return raw;
    }
    if (raw is String) {
      final String text = raw.trim();
      if (text.isEmpty) {
        return <dynamic>[];
      }
      try {
        final dynamic decoded = jsonDecode(text);
        if (decoded is List) {
          return decoded;
        }
        if (decoded is Map) {
          final Map<String, dynamic> map = Map<String, dynamic>.from(decoded);
          final dynamic nested =
              map['questions'] ??
              map['questions_json'] ??
              map['quiz_questions'] ??
              map['aqie_questions'] ??
              map['lc_iie_questions'] ??
              map['items'];
          if (nested == null && map['lc_aqie'] is Map) {
            return _listFromUnknown(
              _toMap(map['lc_aqie'])['questions'] ??
                  _toMap(map['lc_aqie'])['questions_json'],
            );
          }
          if (nested is List) {
            return nested;
          }
        }
      } catch (_) {}
    }
    if (raw is Map) {
      final dynamic nested =
          raw['questions'] ??
          raw['questions_json'] ??
          raw['quiz_questions'] ??
          raw['aqie_questions'] ??
          raw['lc_iie_questions'] ??
          raw['items'];
      if (nested == null && raw['lc_aqie'] is Map) {
        return _listFromUnknown(
          _toMap(raw['lc_aqie'])['questions'] ??
              _toMap(raw['lc_aqie'])['questions_json'],
        );
      }
      if (nested is List) {
        return nested;
      }
      if (nested is String) {
        return _listFromUnknown(nested);
      }
    }
    return <dynamic>[];
  }

  List<dynamic> _extractAiQuestionRawList(Map<String, dynamic> response) {
    final List<dynamic> direct = _listFromUnknown(
      response['questions_json'] ??
          response['questions'] ??
          response['aqie_questions'] ??
          response['quiz_questions'] ??
          _toMap(response['lc_aqie'])['questions'] ??
          response['items'],
    );
    if (direct.isNotEmpty) {
      return direct;
    }
    final Map<String, dynamic> data = _toMap(response['data']);
    final List<dynamic> fromData = _listFromUnknown(
      data['questions_json'] ??
          data['questions'] ??
          data['aqie_questions'] ??
          data['quiz_questions'] ??
          _toMap(data['lc_aqie'])['questions'] ??
          data['items'],
    );
    if (fromData.isNotEmpty) {
      return fromData;
    }
    final Map<String, dynamic> raw = _toMap(response['raw']);
    final List<dynamic> fromRaw = _listFromUnknown(
      raw['questions_json'] ??
          raw['questions'] ??
          raw['aqie_questions'] ??
          raw['quiz_questions'] ??
          _toMap(raw['lc_aqie'])['questions'] ??
          raw['items'],
    );
    if (fromRaw.isNotEmpty) {
      return fromRaw;
    }
    final Map<String, dynamic>? decodedAnswer = _tryDecodeJsonAsMap(
      (response['answer'] ?? '').toString(),
    );
    if (decodedAnswer != null) {
      final List<dynamic> fromAnswer = _listFromUnknown(
        decodedAnswer['questions'] ??
            decodedAnswer['questions_json'] ??
            decodedAnswer['aqie_questions'] ??
            decodedAnswer['quiz_questions'],
      );
      if (fromAnswer.isNotEmpty) {
        return fromAnswer;
      }
    }
    final List<String> candidateTexts = <String>[
      (response['answer'] ?? '').toString(),
      (response['final_answer'] ?? '').toString(),
      (response['reasoning'] ?? '').toString(),
      (response['explanation'] ?? '').toString(),
      (data['answer'] ?? '').toString(),
      (data['final_answer'] ?? '').toString(),
      (data['reasoning'] ?? '').toString(),
      (data['explanation'] ?? '').toString(),
      (raw['answer'] ?? '').toString(),
      (raw['final_answer'] ?? '').toString(),
      (raw['reasoning'] ?? '').toString(),
      (raw['output'] ?? '').toString(),
      (raw['content'] ?? '').toString(),
      (raw['text'] ?? '').toString(),
    ];
    for (final String text in candidateTexts) {
      if (text.trim().isEmpty) {
        continue;
      }
      final Map<String, dynamic>? map = _tryDecodeJsonAsMap(text);
      if (map != null) {
        final List<dynamic> parsed = _listFromUnknown(
          map['questions'] ??
              map['questions_json'] ??
              map['aqie_questions'] ??
              map['quiz_questions'] ??
              map['items'],
        );
        if (parsed.isNotEmpty) {
          return parsed;
        }
      }
      final List<Map<String, dynamic>> embeddedMaps =
          _extractJsonMapsFromMixedText(text);
      for (final Map<String, dynamic> embedded in embeddedMaps) {
        final List<dynamic> parsed = _listFromUnknown(
          embedded['questions'] ??
              embedded['questions_json'] ??
              embedded['aqie_questions'] ??
              embedded['quiz_questions'] ??
              embedded['items'],
        );
        if (parsed.isNotEmpty) {
          return parsed;
        }
      }
    }
    return <dynamic>[];
  }

  String _extractAiFailureReason(Map<String, dynamic> response) {
    final List<String> chunks = <String>[
      (response['status'] ?? '').toString().trim(),
      (response['message'] ?? '').toString().trim(),
      (response['error'] ?? '').toString().trim(),
      (_toMap(response['data'])['message'] ?? '').toString().trim(),
      (_toMap(response['raw'])['message'] ?? '').toString().trim(),
      (_toMap(response['raw'])['error'] ?? '').toString().trim(),
    ].where((String e) => e.isNotEmpty).toList();
    if (chunks.isEmpty) {
      return 'backend response did not include usable questions';
    }
    return chunks.join(' | ');
  }

  Future<Map<String, dynamic>> _generateAiQuizFallbackViaEngine({
    required Map<String, dynamic> payload,
    required int attempt,
  }) async {
    final List<String> chapters =
        (payload['chapters'] as List<dynamic>? ?? <dynamic>[])
            .map((dynamic e) => e.toString().trim())
            .where((String e) => e.isNotEmpty)
            .toList();
    final List<String> subtopics =
        (payload['subtopics'] as List<dynamic>? ?? <dynamic>[])
            .map((dynamic e) => e.toString().trim())
            .where((String e) => e.isNotEmpty)
            .toList();
    final int requestedCount =
        (payload['question_count'] as num?)?.toInt() ?? 10;
    final int requestedDifficulty =
        (payload['difficulty'] as num?)?.toInt() ?? 5;
    final String requestedClass = (payload['class'] ?? _selectedClass)
        .toString()
        .trim();
    final String requestedSubject = (payload['subject'] ?? _selectedSubject)
        .toString()
        .trim();
    final String difficultyLabel = _aiHardnessLabel(_aiDifficulty);
    final String role = (payload['role'] ?? Session.userRole).toString();
    final bool includeAnswers =
        (payload['include_answer_key'] as bool?) ?? true;
    final bool preferPyq = (payload['pyq_focus'] as bool?) ?? _aiPreferPyq;
    final bool ultraHard =
        _aiDifficulty >= 5 ||
        requestedDifficulty >= 7 ||
        ((payload['ultra_hard_mode'] as bool?) ?? false);
    final bool binomialScope = _isBinomialScope(
      subject: requestedSubject,
      chapters: chapters,
      subtopics: subtopics,
    );
    final int expectedNumerical = (requestedCount * 0.4).round();
    final int expectedMcq = (requestedCount * 0.3).round();
    final int expectedMulti = requestedCount - expectedNumerical - expectedMcq;
    final Map<String, dynamic> signalLockRaw =
        payload['chapter_signal_lock'] is Map
        ? Map<String, dynamic>.from(payload['chapter_signal_lock'] as Map)
        : <String, dynamic>{};
    final Map<String, List<String>> chapterSignalLock = signalLockRaw.map(
      (String key, dynamic value) => MapEntry<String, List<String>>(
        key,
        value is List
            ? value
                  .map((dynamic e) => e.toString().trim())
                  .where((String e) => e.isNotEmpty)
                  .toList()
            : <String>[],
      ),
    );
    final List<String> chapterHardDirectives = _chapterHardDirectives(
      subject: requestedSubject,
      chapters: chapters,
      subtopics: subtopics,
    );

    final String prompt = <String>[
      'Use LC-AQIE (LalaCore AI Quiz Intelligence Engine) and return strict JSON only.',
      'Role: $role',
      'Class: ${requestedClass.isEmpty ? 'Class 11/12' : requestedClass}',
      'Subject: ${requestedSubject.isEmpty ? 'Mathematics' : requestedSubject}',
      'Difficulty profile: $difficultyLabel',
      'Difficulty level (numeric): $requestedDifficulty',
      'Question count: $requestedCount',
      'Chapters: ${chapters.isEmpty ? 'General' : chapters.join(', ')}',
      'Subtopics: ${subtopics.isEmpty ? 'General' : subtopics.join(', ')}',
      if (preferPyq)
        'Priority: Use previous-year-question style framing and trap patterns without copying exact copyrighted text.',
      if (preferPyq)
        'PYQ web scope lock: search only for PYQs matching requested subject/chapter/subtopic. Do not use unrelated chapter PYQs.',
      'Web research directive: if web retrieval tools are available, fetch hard PYQ-style references for the requested chapter, then synthesize NEW questions (do not copy verbatim).',
      'Attempt index: $attempt',
      'Output contract (must follow exactly):',
      '{',
      '  "quiz_metadata": {',
      '    "title": "string",',
      '    "mode": "TEACHER | STUDENT",',
      '    "duration_minutes": 0,',
      '    "total_marks": 0,',
      '    "shuffle_questions": true,',
      '    "difficulty_mix": "Basic | Main | Advanced | Mixed"',
      '  },',
      '  "source_policy": {',
      '    "mode": "pyq_related_web_only | hybrid",',
      '    "scope_verified": true,',
      '    "fallback_used": false',
      '  },',
      '  "questions": [',
      '    {',
      '      "id": 1,',
      '      "type": "MCQ | MULTI | Integer",',
      '      "statement": "string",',
      '      "latex_statement": "string",',
      '      "source_origin": "web_pyq | synthesized",',
      '      "source_stub": "short citation or blank",',
      '      "options": {"A":"...","B":"...","C":"...","D":"..."},',
      '      "correct_answer": "single digit integer OR option letters",',
      '      "solution": {',
      '        "core_idea": "string",',
      '        "formal_derivation": [],',
      '        "intuition": "string",',
      '        "shortcut": "string",',
      '        "diagrams": {"mermaid":"","matplotlib_code":"","ascii":""}',
      '      },',
      '      "verification": {"numeric_pass": true, "symbolic_pass": true, "dimension_pass": true},',
      '      "confidence_score": 0.0,',
      '      "difficulty": "Basic | Main | Advanced",',
      '      "adaptive_score": 0.0',
      '    }',
      '  ],',
      '  "ui_spec": {},',
      '  "student_adaptive_data": {"mastery_status": {}, "recommendations": [], "performance_trends": {}}',
      '}',
      'Strict rules:',
      '- Return ONLY valid JSON.',
      '- No markdown, no code fences, no commentary.',
      '- Keep question_text exam-style and concise. Do not start with filler like "For chapter...".',
      '- Keep wording natural and classroom-ready for UI cards.',
      '- Diversity lock: each question must follow a different solving pattern; avoid stem rewrites of the same template.',
      '- Diversity lock: avoid repeating the same first 7 words across questions.',
      '- Math notation support: use LaTeX for mathematical expressions in question and solution.',
      '- Wrap mathematical expressions in \$...\$ and keep plain text outside math mode.',
      '- Keep LaTeX concise and renderer-safe (avoid custom macros).',
      '- No LaTeX in correct_answer.',
      '- For numerical type: correct_answer must be one integer from 0 to 9.',
      '- Numerical correct_answer cannot be negative, decimal, fraction, expression, or text.',
      '- For MULTI type: correct_answer must contain at least two distinct options from A/B/C/D.',
      if (preferPyq)
        '- In PYQ mode, every question must be either web_pyq from related scope or a harder synthesized variant of that same scope.',
      if (preferPyq)
        '- If source_origin is web_pyq, include source_stub and ensure correct_answer is explicitly validated in solution.',
      '- Each solution must include at least ${ultraHard ? 3 : 2} reasoning steps.',
      '- Use explicit structure in solutions: "Step 1", "Step 2", ${ultraHard ? '"Step 3", ' : ''}then final result.',
      '- If a question is solvable in less than two reasoning steps, regenerate internally.',
      '- Distribution must be exact: numerical=$expectedNumerical, mcq=$expectedMcq, multi=$expectedMulti.',
      '- Ensure type variety. Never return only one question type.',
      '- Set difficulty field as integer 1-5 for every question (not just labels).',
      if (chapters.length > 1 && requestedCount >= chapters.length)
        '- Chapter coverage lock: every selected chapter must appear in at least one question.',
      if (chapters.length == 1 && subtopics.length > 1)
        '- Subtopic coverage lock: spread questions across the listed subtopics, avoid repeating one template.',
      if (subtopics.length >= 6)
        '- Diversification lock: cover at least 6 distinct subtopics/signals from the provided subtopic list.',
      if (chapterHardDirectives.isNotEmpty) ...<String>[
        '- Chapter anchor lock (must satisfy):',
        ...chapterHardDirectives,
      ],
      if (requestedCount >= 5)
        '- Each difficulty level 1,2,3,4,5 must appear at least once.',
      if (ultraHard) ...<String>[
        '- Hardness lock: questions must be JEE Advanced hard, non-routine, and trap-driven.',
        '- Ban direct single-formula plug-in questions.',
        '- At least 60% questions must require case analysis, hidden constraint handling, or transformation trick.',
        '- Avoid repeated stems/templates across questions.',
      ],
      if (preferPyq)
        '- If suitable related PYQs are unavailable, fallback must generate ultra-hard original questions in the same chapter scope.',
      if (binomialScope) ...<String>[
        '- Topic lock: every question MUST be directly from Binomial Theorem.',
        '- Allowed binomial patterns: coefficient extraction, general term, middle term, constant term, greatest coefficient, binomial identities.',
        '- Forbidden in this scope: derivative/integration/coordinate-geometry templates.',
      ],
      '- Difficulty calibration:',
      '  Level 1: conceptual but needs 2-3 reasoning steps.',
      '  Level 2: multi-step with trap possibility.',
      '  Level 3: multi-concept integration with manipulation.',
      '  Level 4: deep conceptual application and elimination/identity transformation.',
      '  Level 5: true JEE Advanced with hidden constraint and case/symmetry/substitution trick.',
      '- Forbidden: direct formula plug-in, board-level trivial questions.',
      if (!includeAnswers)
        '- If answer key is disallowed, regenerate with empty correct_answer.',
      'Internal self-check before output:',
      '1) Validate numerical answers are 0-9 integers.',
      '2) Validate difficulty tags match complexity.',
      if (preferPyq)
        '3) Validate PYQ web scope relevance for every web_pyq source.',
      if (preferPyq)
        '4) Validate answer key consistency for web_pyq sourced items.',
      '${preferPyq ? '5' : '3'}) Validate strict JSON validity.',
      '${preferPyq ? '6' : '4'}) Validate no text outside JSON.',
      'If any check fails, regenerate internally and return ONLY final valid JSON.',
    ].join('\n');

    final Map<String, dynamic> response = await aiService.sendChat(
      prompt: prompt,
      userId: Session.effectiveAccountId,
      chatId:
          'ai_quiz_fallback_${DateTime.now().millisecondsSinceEpoch}_$attempt',
      function: 'ai_generate_quiz',
      responseStyle: 'structured_json',
      enablePersona: false,
      card: <String, dynamic>{
        'surface': widget.selfPracticeMode
            ? 'student_ai_quiz_fallback'
            : 'teacher_ai_quiz_fallback',
        'question_count': requestedCount,
        'difficulty': requestedDifficulty,
        'pyq_focus': preferPyq,
        'pyq_web_only_mode': preferPyq,
        'pyq_answer_retrieval_required': preferPyq,
        'fallback_ultra_hard_required': true,
        'web_research_enabled': true,
        'web_scope': '${chapters.join(", ")} ${subtopics.join(", ")}'.trim(),
        'chapter_signal_lock': chapterSignalLock,
      },
    );

    final List<dynamic> extracted = _extractAiQuestionRawList(response);
    final Map<String, dynamic> uiSpec = _extractAiUiSpec(response);
    final Map<String, dynamic> studentAdaptive = _extractAiStudentAdaptiveData(
      response,
    );
    if (extracted.isNotEmpty) {
      return <String, dynamic>{
        'ok': true,
        'status': 'SUCCESS',
        'quiz_id':
            'ai_engine_${DateTime.now().millisecondsSinceEpoch}_$attempt',
        'questions_json': extracted,
        'ui_spec': uiSpec,
        'student_adaptive_data': studentAdaptive,
        'source': 'ai_engine_fallback',
      };
    }

    final Map<String, dynamic> responseRaw = _toMap(response['raw']);
    final Map<String, dynamic> responseData = _toMap(response['data']);
    final List<String> candidateTexts = <String>[
      (response['answer'] ?? '').toString(),
      (response['final_answer'] ?? '').toString(),
      (response['reasoning'] ?? '').toString(),
      (response['explanation'] ?? '').toString(),
      (responseData['answer'] ?? '').toString(),
      (responseData['final_answer'] ?? '').toString(),
      (responseData['reasoning'] ?? '').toString(),
      (responseData['explanation'] ?? '').toString(),
      (responseRaw['answer'] ?? '').toString(),
      (responseRaw['final_answer'] ?? '').toString(),
      (responseRaw['reasoning'] ?? '').toString(),
      (responseRaw['output'] ?? '').toString(),
      (responseRaw['content'] ?? '').toString(),
      (responseRaw['text'] ?? '').toString(),
    ];
    for (final String text in candidateTexts) {
      final Map<String, dynamic>? map = _tryDecodeJsonAsMap(text);
      if (map == null) {
        continue;
      }
      final List<dynamic> parsed = _listFromUnknown(
        map['questions'] ?? map['questions_json'] ?? map['quiz_questions'],
      );
      if (parsed.isNotEmpty) {
        return <String, dynamic>{
          'ok': true,
          'status': 'SUCCESS',
          'quiz_id':
              'ai_engine_${DateTime.now().millisecondsSinceEpoch}_$attempt',
          'questions_json': parsed,
          'ui_spec': _extractAiUiSpec(map),
          'student_adaptive_data': _extractAiStudentAdaptiveData(map),
          'source': 'ai_engine_fallback',
        };
      }
    }
    final String repairInput = candidateTexts
        .map((String text) => text.trim())
        .where((String text) => text.isNotEmpty)
        .take(3)
        .join('\n\n');
    if (repairInput.isNotEmpty) {
      final Map<String, dynamic> repairedResponse = await aiService.sendChat(
        prompt: <String>[
          'Transform the following quiz content into strict JSON only.',
          'Return a single JSON object with key "questions" (array).',
          'Each question item must contain: type, difficulty, question/question_text, options (if MCQ/MULTI), correct_answer, solution.',
          'Allowed types: MCQ, MULTI, INTEGER.',
          'No markdown, no backticks, no commentary.',
          'Input content:',
          repairInput,
        ].join('\n'),
        userId: Session.effectiveAccountId,
        chatId:
            'ai_quiz_json_repair_${DateTime.now().millisecondsSinceEpoch}_$attempt',
        function: 'ai_generate_quiz',
        responseStyle: 'structured_json',
        enablePersona: false,
        card: const <String, dynamic>{
          'surface': 'teacher_ai_quiz_json_repair',
          'json_repair': true,
        },
      );
      final List<dynamic> repaired = _extractAiQuestionRawList(
        repairedResponse,
      );
      if (repaired.isNotEmpty) {
        return <String, dynamic>{
          'ok': true,
          'status': 'SUCCESS',
          'quiz_id':
              'ai_engine_${DateTime.now().millisecondsSinceEpoch}_${attempt}_repair',
          'questions_json': repaired,
          'ui_spec': _extractAiUiSpec(repairedResponse),
          'student_adaptive_data': _extractAiStudentAdaptiveData(
            repairedResponse,
          ),
          'source': 'ai_engine_fallback_json_repair',
        };
      }
    }
    final List<Map<String, dynamic>> emergencyQuestions =
        _buildEmergencyFallbackQuizQuestions(
          requestedCount: requestedCount,
          subject: requestedSubject,
          chapters: chapters,
          subtopics: subtopics,
          preferPyq: preferPyq,
        );
    if (emergencyQuestions.isNotEmpty) {
      return <String, dynamic>{
        'ok': true,
        'status': 'SUCCESS',
        'quiz_id':
            'ai_engine_${DateTime.now().millisecondsSinceEpoch}_${attempt}_emergency',
        'questions_json': emergencyQuestions,
        'ui_spec': const <String, dynamic>{},
        'student_adaptive_data': const <String, dynamic>{
          'mastery_status': <String, dynamic>{},
          'recommendations': <dynamic>[
            'Network fallback used. Review and optionally regenerate when backend is reachable.',
          ],
          'performance_trends': <String, dynamic>{},
        },
        'source': 'local_emergency_quiz_fallback',
      };
    }
    throw Exception('AI engine fallback did not return structured questions.');
  }

  List<Map<String, dynamic>> _buildEmergencyFallbackQuizQuestions({
    required int requestedCount,
    required String subject,
    required List<String> chapters,
    required List<String> subtopics,
    required bool preferPyq,
  }) {
    final int count = requestedCount <= 0 ? 1 : requestedCount;
    final List<String> focus = <String>[
      ...chapters.map((String e) => e.trim()),
      ...subtopics.map((String e) => e.trim()),
    ].where((String e) => e.isNotEmpty).toSet().toList(growable: false);
    final List<String> scopedTopics = focus.isEmpty
        ? <String>['Core $subject']
        : focus;
    final List<String> typePlan = _targetTypePlanForCount(count);
    final List<Map<String, dynamic>> out = <Map<String, dynamic>>[];
    for (int i = 0; i < count; i++) {
      final String type = typePlan[i];
      final int difficulty = (i % 5) + 1;
      final String topic = scopedTopics[i % scopedTopics.length];
      final String sourceOrigin = preferPyq
          ? 'synthesized_pyq_variant'
          : 'synthesized';
      if (type == 'NUMERICAL') {
        final int value = (i * 3 + 7) % 10;
        out.add(<String, dynamic>{
          'type': 'INTEGER',
          'difficulty': difficulty,
          'question_text':
              'In $topic, evaluate a constrained final digit after applying a non-routine transformation chain with one hidden parity condition.',
          'correct_answer': value.toString(),
          'solution': <String>[
            'Step 1: Convert the expression into a parity-modulo form tied to $topic.',
            'Step 2: Apply hidden-constraint filtering and eliminate invalid branches.',
            'Step 3: Evaluate the surviving branch and reduce to a single digit.',
          ].join(' '),
          'source_origin': sourceOrigin,
          'source_stub': 'offline_fallback_scope_locked',
        });
        continue;
      }

      final Map<String, String> options = <String, String>{
        'A': 'Boundary-case overcount is ignored',
        'B': 'Symmetry-aware filtered result',
        'C': 'Naive direct substitution',
        'D': 'Sign-flipped intermediate value',
      };
      final dynamic correct = type == 'MULTI' ? <String>['B', 'D'] : 'B';
      out.add(<String, dynamic>{
        'type': type == 'MULTI' ? 'MCQ_MULTI' : 'MCQ',
        'difficulty': difficulty,
        'question_text':
            'For $topic in $subject, choose the valid statement(s) under a trap-heavy setup with case-split and elimination logic.',
        'options': options,
        'correct_answer': correct,
        'solution': <String>[
          'Step 1: Identify hidden assumptions and rewrite the setup in invariant form.',
          'Step 2: Perform case-split and reject branches violating the scope constraints.',
          'Step 3: Verify the surviving option set against consistency conditions.',
        ].join(' '),
        'source_origin': sourceOrigin,
        'source_stub': 'offline_fallback_scope_locked',
      });
    }
    return out;
  }

  List<QuizQuestion> _toDraftQuizQuestions(List<Question> source) {
    return source.map((Question q) {
      String type = q.type.trim().toUpperCase();
      if (type.isEmpty) {
        type = 'MCQ';
      }
      if (type != 'MCQ' && type != 'MULTI' && type != 'NUMERICAL') {
        type = 'MCQ';
      }

      final List<String> options = List<String>.from(q.options);
      while (options.length < 4) {
        options.add('Option ${options.length + 1}');
      }

      List<String> correct = q.correctAnswers
          .map((String e) => e.trim())
          .where((String e) => e.isNotEmpty)
          .toList();
      if (type == 'NUMERICAL') {
        if (correct.isEmpty) {
          correct = <String>['0'];
        }
      } else if (correct.isEmpty) {
        correct = <String>[options.first];
      }

      return QuizQuestion(
        text: q.text.trim(),
        image: q.imageUrl.trim(),
        type: type,
        options: options.take(4).toList(),
        correct: correct,
        section: q.section.trim().isEmpty ? 'General' : q.section.trim(),
        subPart: '',
        pos: q.posMark,
        neg: q.negMark,
        solution: q.solution.trim(),
        difficultyLabel: q.difficultyLabel,
        confidenceScore: q.confidenceScore,
        adaptiveScore: q.adaptiveScore,
      );
    }).toList();
  }

  String _preparingSuffix() {
    final int suffixCount = 1 + (_aiPreparingCtrl.value * 3).floor();
    final int clampedSuffix = suffixCount < 1
        ? 1
        : (suffixCount > 4 ? 4 : suffixCount);
    return List<String>.filled(clampedSuffix, '_').join();
  }

  String _preparingLabelWithProgress(String suffix) {
    final String base = _aiPreparingLabel.trim().isEmpty
        ? 'Preparing'
        : _aiPreparingLabel.trim();
    if (_aiPreparingProgressTotal <= 0) {
      return '$base $suffix';
    }
    final int current = _aiPreparingProgressCurrent.clamp(
      0,
      _aiPreparingProgressTotal,
    );
    return 'Stage $current/$_aiPreparingProgressTotal • $base $suffix'.trim();
  }

