  String _targetTypeForShardIndex(int index) {
    const List<String> cycle = <String>['MCQ', 'MULTI', 'NUMERICAL'];
    return cycle[index % cycle.length];
  }

  List<String> _targetTypePlanForCount(int questionCount) {
    final int safeCount = questionCount <= 0 ? 1 : questionCount;
    final Map<String, int> remaining = _expectedTypeDistribution(safeCount);
    final List<String> plan = <String>[];
    const List<String> order = <String>['MCQ', 'MULTI', 'NUMERICAL'];
    while (plan.length < safeCount) {
      bool addedInRound = false;
      for (final String type in order) {
        final int count = remaining[type] ?? 0;
        if (count <= 0) {
          continue;
        }
        plan.add(type);
        remaining[type] = count - 1;
        addedInRound = true;
        if (plan.length >= safeCount) {
          break;
        }
      }
      if (!addedInRound) {
        plan.add(_targetTypeForShardIndex(plan.length));
      }
    }
    return plan;
  }

  List<List<String>> _buildQuestionShardSubtopicPlans({
    required int questionCount,
    required List<String> chapters,
    required List<String> subtopics,
  }) {
    final List<String> pool = <String>[
      ...subtopics,
      ...chapters,
    ].map((String e) => e.trim()).where((String e) => e.isNotEmpty).toList();
    final List<String> uniquePool = <String>[];
    final Set<String> seen = <String>{};
    for (final String item in pool) {
      final String key = item.toLowerCase();
      if (seen.add(key)) {
        uniquePool.add(item);
      }
    }
    if (uniquePool.isEmpty) {
      uniquePool.add('General');
    }
    final List<List<String>> plans = <List<String>>[];
    final int offset = max(1, questionCount ~/ 2).toInt();
    for (int i = 0; i < questionCount; i++) {
      final String primary = uniquePool[i % uniquePool.length];
      final String secondary = uniquePool[(i + offset) % uniquePool.length];
      final String chapter = chapters.isEmpty
          ? uniquePool[i % uniquePool.length]
          : chapters[i % chapters.length];
      final List<String> shard = <String>[chapter, primary];
      if (secondary.toLowerCase() != primary.toLowerCase()) {
        shard.add(secondary);
      }
      final List<String> normalized = <String>[];
      final Set<String> shardSeen = <String>{};
      for (final String token in shard) {
        final String t = token.trim();
        if (t.isEmpty) {
          continue;
        }
        final String key = t.toLowerCase();
        if (shardSeen.add(key)) {
          normalized.add(t);
        }
      }
      plans.add(normalized);
    }
    return plans;
  }

  bool _hasAnyWebSourceSignal(Map<String, dynamic> generated, dynamic rawList) {
    final List<dynamic> rawQuestions = rawList is List ? rawList : <dynamic>[];
    bool hasSignalInMap(Map<String, dynamic> map) {
      final String sourceOrigin =
          (map['source_origin'] ?? map['origin'] ?? map['source'] ?? '')
              .toString()
              .toLowerCase()
              .trim();
      final String sourceStub =
          (map['source_stub'] ??
                  map['source_url'] ??
                  map['source_link'] ??
                  map['reference'] ??
                  '')
              .toString()
              .trim();
      final bool hasCitationList =
          (map['citations'] is List &&
              (map['citations'] as List<dynamic>).isNotEmpty) ||
          (map['web_sources'] is List &&
              (map['web_sources'] as List<dynamic>).isNotEmpty);
      final bool hasPyqTag =
          (map['concept_tags'] is List) &&
          (map['concept_tags'] as List<dynamic>).any(
            (dynamic tag) => tag.toString().toLowerCase().contains('pyq'),
          );
      return sourceOrigin.contains('web') ||
          sourceOrigin.contains('pyq') ||
          sourceOrigin.contains('internet') ||
          sourceStub.isNotEmpty ||
          hasCitationList ||
          hasPyqTag;
    }

    for (final dynamic row in rawQuestions) {
      if (row is Map && hasSignalInMap(Map<String, dynamic>.from(row))) {
        return true;
      }
    }
    final Map<String, dynamic> web = _toMap(generated['web_retrieval']);
    if ((web['citations'] is List &&
            (web['citations'] as List<dynamic>).isNotEmpty) ||
        (web['matches'] is List &&
            (web['matches'] as List<dynamic>).isNotEmpty) ||
        (web['results'] is List &&
            (web['results'] as List<dynamic>).isNotEmpty)) {
      return true;
    }
    if (generated['citations'] is List &&
        (generated['citations'] as List<dynamic>).isNotEmpty) {
      return true;
    }
    final Map<String, dynamic> raw = _toMap(generated['raw']);
    final Map<String, dynamic> rawWeb = _toMap(raw['web_retrieval']);
    if ((rawWeb['citations'] is List &&
            (rawWeb['citations'] as List<dynamic>).isNotEmpty) ||
        (rawWeb['matches'] is List &&
            (rawWeb['matches'] as List<dynamic>).isNotEmpty)) {
      return true;
    }
    final Map<String, dynamic> sourcePolicy = _toMap(
      generated['source_policy'],
    );
    final bool scopeVerified = sourcePolicy['scope_verified'] == true;
    if (scopeVerified && sourcePolicy.isNotEmpty) {
      return true;
    }
    return false;
  }

  bool _isShardQuestionAcceptable(
    Question q, {
    required String targetType,
    required String subject,
    required List<String> chapters,
    required List<String> scopeSubtopics,
  }) {
    final String normalizedType = q.type.trim().toUpperCase();
    if (!_questionMatchesRequestedScope(
      q,
      subject: subject,
      chapters: chapters,
      subtopics: scopeSubtopics,
    )) {
      return false;
    }
    if (_isQuestionLikelyTooEasy(q)) {
      return false;
    }
    if (q.correctAnswers.isEmpty) {
      return false;
    }
    if (normalizedType != targetType) {
      return false;
    }
    if (normalizedType == 'NUMERICAL') {
      final int? value = int.tryParse(q.correctAnswers.first.trim());
      if (value == null || value < 0 || value > 9) {
        return false;
      }
    } else {
      if (q.options.length != 4) {
        return false;
      }
      if (normalizedType == 'MCQ' && q.correctAnswers.length != 1) {
        return false;
      }
      if (normalizedType == 'MULTI' && q.correctAnswers.length < 2) {
        return false;
      }
    }
    if (_reasoningStepCount(q.solution) < 2) {
      return false;
    }
    return true;
  }

  Future<_AiQuestionShardResult> _generateSingleQuestionShard({
    required int shardIndex,
    required String targetType,
    required List<String> shardSubtopics,
    required Map<String, dynamic> basePayload,
    required String subject,
    required List<String> chapters,
    required List<String> scopeSubtopics,
    required bool preferPyq,
    void Function(_AiQuestionShardProgress progress)? onQuestionShardProgress,
  }) async {
    void push({
      required String state,
      required String detail,
      Question? question,
      String source = '',
    }) {
      onQuestionShardProgress?.call(
        _AiQuestionShardProgress(
          index: shardIndex,
          state: state,
          detail: detail,
          targetType: targetType,
          source: source,
          subtopics: shardSubtopics,
          question: question,
        ),
      );
    }

    push(state: 'queued', detail: 'Queued for generation.');
    final int maxAttempts = preferPyq ? 4 : 3;
    String lastError = 'no usable candidate';
    Map<String, dynamic> lastResponse = <String, dynamic>{};
    for (int attempt = 0; attempt < maxAttempts; attempt++) {
      final int tunedDifficulty = max(
        ((basePayload['difficulty'] as int?) ?? 5),
        6 + attempt,
      );
      final Map<String, dynamic> payload = <String, dynamic>{
        ...basePayload,
        'question_count': 1,
        'difficulty': tunedDifficulty,
        'retry_index': attempt + 1,
        'subtopics': shardSubtopics,
        'target_subtopic': shardSubtopics.isEmpty ? '' : shardSubtopics.first,
        'forced_question_type': targetType,
        'target_question_type': targetType,
        'type_distribution_lock': <String, int>{targetType: 1},
        'question_slot': shardIndex + 1,
        'strict_topic_lock': true,
        'allow_web_search': true,
        'web_research_enabled': true,
        'search_hard_pyq': preferPyq,
        'pyq_mode': preferPyq ? 'strict_related_web' : 'hybrid',
        'pyq_web_only_mode': preferPyq,
        'pyq_answer_retrieval_required': preferPyq,
        'fallback_ultra_hard_required': true,
        'web_scope_subject': subject,
        'web_scope_chapters': chapters,
        'web_scope_subtopics': shardSubtopics,
      };
      push(
        state: 'generating',
        detail: 'Generating (attempt ${attempt + 1}/$maxAttempts)...',
      );
      try {
        Map<String, dynamic> generated = await backendService
            .generateAiQuiz(payload)
            .timeout(Duration(seconds: attempt == 0 ? 20 : 28));
        String source = 'backend';
        List<dynamic> rawQuestions = _extractAiQuestionRawList(generated);
        final bool backendOk = backendService.isSuccessfulResponse(generated);
        if (rawQuestions.isEmpty || !backendOk) {
          generated = await _generateAiQuizFallbackViaEngine(
            payload: payload,
            attempt: attempt + 1,
          );
          source = 'ai_engine_fallback';
          rawQuestions = _extractAiQuestionRawList(generated);
        }
        for (int pass = 0; pass < 2; pass++) {
          if (rawQuestions.isEmpty) {
            lastError = 'empty response payload';
            lastResponse = generated;
            break;
          }
          final bool hasWebSignal = _hasAnyWebSourceSignal(
            generated,
            rawQuestions,
          );
          if (preferPyq && !hasWebSignal && pass == 0) {
            generated = await _generateAiQuizFallbackViaEngine(
              payload: payload,
              attempt: attempt + 1,
            );
            source = 'ai_engine_fallback';
            rawQuestions = _extractAiQuestionRawList(generated);
            continue;
          }
          if (preferPyq && !hasWebSignal) {
            generated = <String, dynamic>{
              ...generated,
              'source_policy': <String, dynamic>{
                ..._toMap(generated['source_policy']),
                'mode': 'pyq_scope_locked_synthesized',
                'scope_verified': true,
                'fallback_used': true,
              },
              'pyq_warning':
                  'Web citations unavailable in this shard; using strict chapter/subtopic-locked synthesized PYQ variant.',
            };
          }
          final List<Question> parsed = _parseAiQuestions(
            rawQuestions,
            includeAnswers: true,
          );
          if (parsed.isEmpty) {
            lastError = 'parsed shard questions were empty';
            lastResponse = generated;
            if (pass == 0 && source == 'backend') {
              generated = await _generateAiQuizFallbackViaEngine(
                payload: payload,
                attempt: attempt + 1,
              );
              source = 'ai_engine_fallback';
              rawQuestions = _extractAiQuestionRawList(generated);
              continue;
            }
            break;
          }
          final List<Question> filtered = parsed
              .where(
                (Question q) => _isShardQuestionAcceptable(
                  q,
                  targetType: targetType,
                  subject: subject,
                  chapters: chapters,
                  scopeSubtopics: scopeSubtopics,
                ),
              )
              .toList();
          if (filtered.isEmpty) {
            lastError = 'no acceptable candidate for shard';
            lastResponse = generated;
            if (pass == 0 && source == 'backend') {
              generated = await _generateAiQuizFallbackViaEngine(
                payload: payload,
                attempt: attempt + 1,
              );
              source = 'ai_engine_fallback';
              rawQuestions = _extractAiQuestionRawList(generated);
              continue;
            }
            break;
          }
          filtered.sort((Question a, Question b) {
            final int stepCmp = _reasoningStepCount(
              b.solution,
            ).compareTo(_reasoningStepCount(a.solution));
            if (stepCmp != 0) {
              return stepCmp;
            }
            return b.text.length.compareTo(a.text.length);
          });
          final Question winner = filtered.first;
          push(
            state: 'done',
            detail: 'Completed.',
            question: winner,
            source: source,
          );
          return _AiQuestionShardResult(
            index: shardIndex,
            targetType: targetType,
            subtopics: shardSubtopics,
            question: winner,
            response: generated,
            source: source,
            error: '',
          );
        }
      } catch (e) {
        lastError = e.toString();
      }
    }
    push(state: 'failed', detail: lastError);
    return _AiQuestionShardResult(
      index: shardIndex,
      targetType: targetType,
      subtopics: shardSubtopics,
      source: 'failed',
      response: lastResponse,
      error: lastError,
    );
  }

  Future<_AiQuestionShardAggregateResult?> _tryGenerateShardedQuestionSet({
    required Map<String, dynamic> basePayload,
    required String subject,
    required List<String> chapters,
    required List<String> scopeSubtopics,
    required List<String> generationSubtopics,
    required void Function(int stage, String detail) emit,
    void Function(_AiQuestionShardProgress progress)? onQuestionShardProgress,
  }) async {
    final int requestedCount = _aiQuestionCount;
    if (requestedCount <= 1) {
      return null;
    }
    emit(
      2,
      'Parallel shard mode: generating $requestedCount independent questions.',
    );
    final bool preferPyq = (basePayload['pyq_focus'] as bool?) ?? _aiPreferPyq;
    final List<String> targetTypePlan = _targetTypePlanForCount(requestedCount);
    final List<List<String>> plans = _buildQuestionShardSubtopicPlans(
      questionCount: requestedCount,
      chapters: chapters,
      subtopics: generationSubtopics,
    );
    final Map<int, _AiQuestionShardResult> successByIndex =
        <int, _AiQuestionShardResult>{};
    const int maxRounds = 3;
    for (int round = 0; round < maxRounds; round++) {
      final List<int> pending = List<int>.generate(
        requestedCount,
        (int i) => i,
      ).where((int i) => !successByIndex.containsKey(i)).toList();
      if (pending.isEmpty) {
        break;
      }
      if (round > 0) {
        emit(
          3,
          'Shard retry round ${round + 1}/$maxRounds for ${pending.length} pending question(s).',
        );
      }
      final List<Future<_AiQuestionShardResult>> jobs = pending.map((int i) {
        final String targetType = targetTypePlan[i];
        onQuestionShardProgress?.call(
          _AiQuestionShardProgress(
            index: i,
            state: 'queued',
            detail: round == 0
                ? 'Awaiting worker...'
                : 'Retry round ${round + 1}/$maxRounds',
            targetType: targetType,
            subtopics: plans[i],
          ),
        );
        return _generateSingleQuestionShard(
          shardIndex: i,
          targetType: targetType,
          shardSubtopics: plans[i],
          basePayload: basePayload,
          subject: subject,
          chapters: chapters,
          scopeSubtopics: scopeSubtopics,
          preferPyq: preferPyq,
          onQuestionShardProgress: onQuestionShardProgress,
        );
      }).toList();
      final List<_AiQuestionShardResult> roundResults = await Future.wait(jobs);
      for (final _AiQuestionShardResult row in roundResults) {
        if (row.question != null) {
          successByIndex[row.index] = row;
        }
      }
    }
    final List<_AiQuestionShardResult> success = successByIndex.values.toList()
      ..sort((a, b) => a.index.compareTo(b.index));
    if (success.length != requestedCount) {
      return null;
    }
    final List<Question> questions = success
        .map((r) => r.question!)
        .where((Question q) => q.text.trim().isNotEmpty)
        .toList();
    if (questions.length != requestedCount) {
      return null;
    }
    final Set<String> uniqueSkeletons = <String>{};
    final List<Question> deduped = <Question>[];
    for (final Question q in questions) {
      final String key = _questionSkeleton(q.text.toLowerCase());
      if (key.isNotEmpty && !uniqueSkeletons.add(key)) {
        continue;
      }
      deduped.add(q);
    }
    if (deduped.length != requestedCount) {
      return null;
    }
    if (_quizLikelyOutOfScope(
      deduped,
      subject: subject,
      chapters: chapters,
      subtopics: scopeSubtopics,
    )) {
      return null;
    }
    if (_quizLikelyLowAuthoringQuality(deduped) ||
        _quizLikelyLowVariety(deduped) ||
        _quizLikelyTooEasy(deduped)) {
      return null;
    }
    if (widget.selfPracticeMode &&
        !_passesCustomPracticeContract(
          deduped,
          expectedCount: requestedCount,
        )) {
      return null;
    }
    if (!widget.selfPracticeMode &&
        !_passesTeacherAuthoringContract(
          deduped,
          expectedCount: requestedCount,
          subject: subject,
          chapters: chapters,
          subtopics: scopeSubtopics,
        )) {
      return null;
    }
    final Map<String, dynamic> response = success
        .firstWhere(
          (_AiQuestionShardResult r) => r.response.isNotEmpty,
          orElse: () => const _AiQuestionShardResult(
            index: 0,
            targetType: '',
            subtopics: <String>[],
            source: 'parallel_sharded',
            error: '',
          ),
        )
        .response;
    return _AiQuestionShardAggregateResult(
      questions: deduped,
      response: response,
      warnings: const <String>[
        'Parallel shard mode used: questions were generated independently and merged.',
      ],
    );
  }

  Future<_AiQuizGenerationData> _generateAiQuizForStudio({
    required int hardnessBoost,
    required void Function(_AiGenerationProgress progress) onProgress,
    void Function(_AiQuestionShardProgress progress)? onQuestionShardProgress,
  }) async {
    if (!widget.selfPracticeMode && Session.userRole != 'teacher') {
      throw Exception('Only teachers can generate publishable quiz drafts.');
    }
    final List<String> effectiveChapters = _selectedChapters.isEmpty
        ? <String>[
            _title.text.trim().isNotEmpty ? _title.text.trim() : 'General',
          ]
        : List<String>.from(_selectedChapters);
    final String inferredSubject = _selectedSubject.trim().isNotEmpty
        ? _selectedSubject.trim()
        : _inferSubjectFromChapters(
            selectedClass: _selectedClass,
            chapters: effectiveChapters,
          );
    final String subject = inferredSubject.isEmpty
        ? 'Mathematics'
        : inferredSubject;
    final String quizTitle = _title.text.trim().isEmpty
        ? 'AI Quiz • $subject'
        : _title.text.trim();
    final List<String> scopeSubtopics = _aiSubtopics.isNotEmpty
        ? List<String>.from(_aiSubtopics)
        : List<String>.from(effectiveChapters);
    final List<String> generationSubtopics = _expandedHardSubtopics(
      subject: subject,
      chapters: effectiveChapters,
      requestedSubtopics: scopeSubtopics,
    );
    final Map<String, List<String>> chapterSignalLock = _chapterSignalLock(
      subject: subject,
      chapters: effectiveChapters,
      subtopics: scopeSubtopics,
    );
    final Map<String, dynamic> hardness = _hardnessProfile(_aiDifficulty);
    final int baseDifficulty =
        (hardness['difficulty'] as int?) ?? _aiDifficulty;
    final int effectiveDifficulty = widget.selfPracticeMode
        ? max(baseDifficulty + hardnessBoost, 5)
        : max(1, baseDifficulty + hardnessBoost);
    final int duration = _resolvedDurationMinutes(
      max(20, _aiQuestionCount * 2),
    );
    final DateTime effectiveDeadline = _effectiveDeadlineForQuiz();
    final Map<String, int> expectedTypeCounts = _expectedTypeDistribution(
      _aiQuestionCount,
    );
    final Map<String, dynamic> basePayload = <String, dynamic>{
      'title': quizTitle,
      'subject': subject,
      'chapters': effectiveChapters,
      'subtopics': generationSubtopics,
      'difficulty': effectiveDifficulty,
      'difficulty_stage': _aiDifficulty,
      'difficulty_stage_label': _aiHardnessLabel(_aiDifficulty),
      'question_count': _aiQuestionCount,
      'trap_intensity': hardness['trap_intensity'] ?? _aiTrapIntensity,
      'weakness_mode': true,
      'cross_concept': true,
      'class': _selectedClass,
      'type': _assessmentType,
      'duration': duration,
      'deadline': effectiveDeadline.toIso8601String(),
      'user_id': Session.effectiveAccountId,
      'student_id': Session.studentId,
      'role': Session.userRole,
      'request_role': Session.userRole,
      'self_practice_mode': widget.selfPracticeMode,
      'authoring_mode': !widget.selfPracticeMode,
      'include_answer_key': true,
      'include_solutions': true,
      'time_mode': _useUnlimitedSelfPracticeTime ? 'unlimited' : 'timed',
      'unlimited_time_mode': _useUnlimitedSelfPracticeTime,
      'enforce_difficulty': true,
      'avoid_easy_questions': true,
      'reasoning_depth': hardness['reasoning_depth'] ?? 'high',
      'strict_hard_mode': hardness['strict_hard_mode'] ?? true,
      'target_level': hardness['target_level'] ?? 'advanced',
      'pyq_focus': _aiPreferPyq,
      'prefer_pyq': _aiPreferPyq,
      'use_pyq_patterns': _aiPreferPyq,
      'prefer_previous_year_questions': _aiPreferPyq,
      'pyq_weight': _aiPreferPyq ? 0.75 : 0.35,
      'exam_patterns': _aiPreferPyq
          ? <String>['JEE Main', 'JEE Advanced', 'NEET']
          : <String>[],
      'prefer_local_only': false,
      'minimum_exam_level': 'jee_main',
      'allow_web_search': true,
      'web_research_enabled': true,
      'search_hard_pyq': true,
      'pyq_mode': _aiPreferPyq ? 'strict_related_web' : 'hybrid',
      'pyq_web_only_mode': _aiPreferPyq,
      'pyq_answer_retrieval_required': _aiPreferPyq,
      'fallback_ultra_hard_required': true,
      'web_scope_subject': subject,
      'web_scope_chapters': effectiveChapters,
      'web_scope_subtopics': generationSubtopics,
      'require_type_variety': true,
      'enforce_type_distribution': true,
      'disallow_single_type_set': true,
      'required_type_counts': expectedTypeCounts,
      'type_distribution_lock': expectedTypeCounts,
      'require_mcq_count': expectedTypeCounts['MCQ'],
      'require_multi_count': expectedTypeCounts['MULTI'],
      'require_numerical_count': expectedTypeCounts['NUMERICAL'],
      'chapter_coverage_required': true,
      'chapter_signal_lock': chapterSignalLock,
    };
    void emit(int stage, String detail) {
      final int clamped = stage.clamp(1, _aiGenerationStages.length);
      onProgress(
        _AiGenerationProgress(
          stage: clamped,
          label: _aiGenerationStages[clamped - 1],
          detail: detail,
        ),
      );
    }

    emit(
      1,
      'Using ${_aiHardnessLabel(_aiDifficulty)} with $_aiQuestionCount question(s).',
    );

    Map<String, dynamic> response = <String, dynamic>{};
    String quizId = '';
    List<Question> questions = <Question>[];
    final List<String> failures = <String>[];
    final List<String> warnings = <String>[];
    List<Question> relaxedCandidate = <Question>[];
    String relaxedReason = '';
    final bool ultraHardRequested =
        _aiDifficulty >= 5 || hardnessBoost > 0 || _aiPreferPyq;

    final int maxAttempts = ultraHardRequested ? 7 : 5;
    final bool preferLalacoreOnly =
        (basePayload['prefer_local_only'] as bool?) ?? false;
    final _AiQuestionShardAggregateResult? sharded =
        await _tryGenerateShardedQuestionSet(
          basePayload: basePayload,
          subject: subject,
          chapters: effectiveChapters,
          scopeSubtopics: scopeSubtopics,
          generationSubtopics: generationSubtopics,
          emit: emit,
          onQuestionShardProgress: onQuestionShardProgress,
        );
    if (sharded != null) {
      response = Map<String, dynamic>.from(sharded.response);
      questions = List<Question>.from(sharded.questions);
      warnings.addAll(sharded.warnings);
      if (_aiPreferPyq &&
          !_hasAnyWebSourceSignal(
            response,
            _extractAiQuestionRawList(response),
          )) {
        warnings.add(
          'PYQ mode fallback used without explicit web citations; generated set is synthesized but chapter-locked.',
        );
      }
    } else if (onQuestionShardProgress != null && _aiQuestionCount > 1) {
      warnings.add(
        'Parallel shard mode could not satisfy strict validation; retried with unified generation.',
      );
    }
    Future<Map<String, dynamic>?> tryEngineFallback({
      required Map<String, dynamic> payload,
      required int attempt,
      required String detail,
    }) async {
      emit(3, detail);
      try {
        final Map<String, dynamic> generated =
            await _generateAiQuizFallbackViaEngine(
              payload: payload,
              attempt: attempt + 1,
            );
        final List<dynamic> rawQuestions = _extractAiQuestionRawList(generated);
        if (rawQuestions.isEmpty) {
          failures.add('fallback returned empty question payload');
          return null;
        }
        emit(
          4,
          'Validating answer keys, options, and hardness quality checks.',
        );
        final List<Question> parsed = _parseAiQuestions(
          rawQuestions,
          includeAnswers: true,
        );
        if (parsed.isEmpty) {
          failures.add('fallback parsed questions were empty');
          return null;
        }
        if (_quizLikelyOutOfScope(
          parsed,
          subject: subject,
          chapters: effectiveChapters,
          subtopics: scopeSubtopics,
        )) {
          failures.add('fallback topic relevance validation failed');
          return null;
        }
        final bool lowQuality = _quizLikelyLowAuthoringQuality(parsed);
        if (lowQuality && attempt < maxAttempts - 1) {
          failures.add(
            'fallback question wording quality rejected (template-like)',
          );
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason =
                'strict wording-quality filter rejected template-heavy output';
          }
          return null;
        }
        if (_quizLikelyLowVariety(parsed) && attempt < maxAttempts - 1) {
          failures.add('fallback rejected due to low variety/repetition');
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict variety filter rejected repetitive output';
          }
          return null;
        }
        if (_quizLikelyTooEasy(parsed)) {
          failures.add('fallback set too easy after strict validation');
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict hardness filter rejected all attempts';
          }
          return null;
        }
        if (widget.selfPracticeMode &&
            !_passesCustomPracticeContract(
              parsed,
              expectedCount: _aiQuestionCount,
            )) {
          failures.add('fallback custom practice contract validation failed');
          if (relaxedCandidate.isEmpty ||
              parsed.length > relaxedCandidate.length) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict distribution/difficulty contract mismatch';
          }
          return null;
        }
        if (!widget.selfPracticeMode &&
            !_passesTeacherAuthoringContract(
              parsed,
              expectedCount: _aiQuestionCount,
              subject: subject,
              chapters: effectiveChapters,
              subtopics: scopeSubtopics,
            )) {
          failures.add('fallback teacher contract validation failed');
          if (relaxedCandidate.isEmpty ||
              parsed.length > relaxedCandidate.length) {
            relaxedCandidate = parsed;
            relaxedReason =
                'strict teacher authoring contract mismatch (chapter lock/type spread).';
          }
          return null;
        }
        return <String, dynamic>{
          'generated': generated,
          'parsed': parsed,
          'quiz_id': (generated['quiz_id'] ?? generated['id'] ?? '')
              .toString()
              .trim(),
        };
      } catch (fallbackError) {
        failures.add('fallback: $fallbackError');
        return null;
      }
    }

    for (
      int attempt = 0;
      attempt < maxAttempts && questions.isEmpty;
      attempt++
    ) {
      final bool allowEngineFallback =
          !preferLalacoreOnly &&
          (ultraHardRequested ? attempt >= 1 : attempt >= maxAttempts - 2);
      final int tunedDifficulty = max(effectiveDifficulty, 5 + attempt);
      final Map<String, dynamic> payload = <String, dynamic>{
        ...basePayload,
        'difficulty': tunedDifficulty,
        'trap_intensity': attempt >= 2
            ? 'extreme'
            : (hardness['trap_intensity'] ?? 'high'),
        'weakness_mode': true,
        'cross_concept': true,
        'strict_hard_mode': true,
        'target_level': hardness['target_level'] ?? 'advanced',
        'retry_index': attempt + 1,
        'require_answer_key': true,
        'hardness_pass': attempt + 1,
        'ultra_hard_mode': ultraHardRequested,
        'minimum_reasoning_steps': ultraHardRequested ? 3 : 2,
        'require_non_routine': ultraHardRequested,
        'strict_topic_lock': true,
        'prefer_local_only': preferLalacoreOnly,
        'allow_web_search': true,
        'web_research_enabled': true,
        'search_hard_pyq': true,
        'pyq_mode': _aiPreferPyq ? 'strict_related_web' : 'hybrid',
        'pyq_web_only_mode': _aiPreferPyq,
        'pyq_answer_retrieval_required': _aiPreferPyq,
        'fallback_ultra_hard_required': true,
        'web_scope_subject': subject,
        'web_scope_chapters': effectiveChapters,
        'web_scope_subtopics': generationSubtopics,
        'require_type_variety': true,
        'chapter_coverage_required': true,
        'chapter_signal_lock': chapterSignalLock,
      };
      emit(
        2,
        _aiPreferPyq
            ? 'Applying PYQ-style trap blueprint (pass ${attempt + 1}/$maxAttempts).'
            : 'Building hard blueprint (pass ${attempt + 1}/$maxAttempts).',
      );
      emit(
        3,
        'Generating hard set (pass ${attempt + 1}/$maxAttempts, difficulty $tunedDifficulty).',
      );
      try {
        Map<String, dynamic> generated = await backendService
            .generateAiQuiz(payload)
            .timeout(
              Duration(
                seconds: attempt == 0
                    ? (ultraHardRequested ? 45 : 30)
                    : (ultraHardRequested ? 58 : 36),
              ),
            );
        List<dynamic> rawQuestions = _extractAiQuestionRawList(generated);
        if (rawQuestions.isEmpty) {
          if (!backendService.isSuccessfulResponse(generated)) {
            failures.add(_extractAiFailureReason(generated));
          } else {
            failures.add(
              'backend returned success without structured questions',
            );
          }
          if (allowEngineFallback) {
            emit(
              3,
              'Backend rejected request, trying AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            try {
              generated = await _generateAiQuizFallbackViaEngine(
                payload: payload,
                attempt: attempt + 1,
              );
              rawQuestions = _extractAiQuestionRawList(generated);
            } catch (fallbackError) {
              failures.add('fallback: $fallbackError');
            }
          } else {
            final String status = (generated['status'] ?? '')
                .toString()
                .trim()
                .toUpperCase();
            if (status == 'LOCAL_UNAVAILABLE') {
              failures.add('local lalacore backend unavailable');
              final Map<String, dynamic>? upgraded = await tryEngineFallback(
                payload: payload,
                attempt: attempt,
                detail:
                    'Local backend unavailable, switching to AI fallback (pass ${attempt + 1}/$maxAttempts).',
              );
              if (upgraded != null) {
                response = upgraded['generated'] as Map<String, dynamic>;
                questions = upgraded['parsed'] as List<Question>;
                quizId = (upgraded['quiz_id'] ?? '').toString().trim();
                break;
              }
            }
          }
        }
        if (rawQuestions.isEmpty) {
          failures.add('no valid questions found in response');
          continue;
        }
        emit(
          4,
          'Validating answer keys, options, and hardness quality checks.',
        );
        final List<Question> parsed = _parseAiQuestions(
          rawQuestions,
          includeAnswers: true,
        );
        if (parsed.isEmpty) {
          failures.add('parsed questions were empty');
          continue;
        }
        final bool outOfScope = _quizLikelyOutOfScope(
          parsed,
          subject: subject,
          chapters: effectiveChapters,
          subtopics: scopeSubtopics,
        );
        if (outOfScope) {
          failures.add('topic relevance validation failed');
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Improving topic alignment via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        final bool lowQuality = _quizLikelyLowAuthoringQuality(parsed);
        if (lowQuality && attempt < maxAttempts - 1) {
          failures.add('question wording quality rejected (template-like)');
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason =
                'strict wording-quality filter rejected template-heavy output';
          }
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Improving question intelligence via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        if (_quizLikelyLowVariety(parsed) && attempt < maxAttempts - 1) {
          failures.add('set rejected due to low variety/repetition');
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict variety filter rejected repetitive output';
          }
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Expanding question-type and pattern variety via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        if (_quizLikelyTooEasy(parsed)) {
          failures.add('set too easy after strict validation');
          if (relaxedCandidate.isEmpty) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict hardness filter rejected all attempts';
          }
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Raising difficulty via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        if (widget.selfPracticeMode &&
            !_passesCustomPracticeContract(
              parsed,
              expectedCount: _aiQuestionCount,
            )) {
          failures.add('custom practice contract validation failed');
          if (relaxedCandidate.isEmpty ||
              parsed.length > relaxedCandidate.length) {
            relaxedCandidate = parsed;
            relaxedReason = 'strict distribution/difficulty contract mismatch';
          }
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Fixing distribution + answer-key contract via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        if (!widget.selfPracticeMode &&
            !_passesTeacherAuthoringContract(
              parsed,
              expectedCount: _aiQuestionCount,
              subject: subject,
              chapters: effectiveChapters,
              subtopics: scopeSubtopics,
            )) {
          failures.add('teacher authoring contract validation failed');
          if (relaxedCandidate.isEmpty ||
              parsed.length > relaxedCandidate.length) {
            relaxedCandidate = parsed;
            relaxedReason =
                'strict teacher authoring contract mismatch (chapter lock/type spread).';
          }
          if (allowEngineFallback) {
            final Map<String, dynamic>? upgraded = await tryEngineFallback(
              payload: payload,
              attempt: attempt,
              detail:
                  'Applying strict teacher contract (type variety + chapter lock + hardness) via AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
            );
            if (upgraded != null) {
              response = upgraded['generated'] as Map<String, dynamic>;
              questions = upgraded['parsed'] as List<Question>;
              quizId = (upgraded['quiz_id'] ?? '').toString().trim();
              break;
            }
          }
          continue;
        }
        response = generated;
        questions = parsed;
        quizId = (generated['quiz_id'] ?? generated['id'] ?? '')
            .toString()
            .trim();
        break;
      } catch (e) {
        failures.add('backend: $e');
        if (allowEngineFallback) {
          final Map<String, dynamic>? upgraded = await tryEngineFallback(
            payload: payload,
            attempt: attempt,
            detail:
                'Primary request failed, trying AI engine fallback (pass ${attempt + 1}/$maxAttempts).',
          );
          if (upgraded != null) {
            response = upgraded['generated'] as Map<String, dynamic>;
            questions = upgraded['parsed'] as List<Question>;
            quizId = (upgraded['quiz_id'] ?? '').toString().trim();
            break;
          }
        }
      }
    }

    if (questions.isEmpty && relaxedCandidate.isNotEmpty) {
      final bool canUseRelaxed = widget.selfPracticeMode
          ? _passesCustomPracticeContract(
              relaxedCandidate,
              expectedCount: _aiQuestionCount,
            )
          : _hasRequiredTypeMix(
              relaxedCandidate,
              expectedCount: _aiQuestionCount,
            );
      if (canUseRelaxed) {
        questions = relaxedCandidate;
        warnings.add(
          widget.selfPracticeMode
              ? (relaxedReason.isEmpty
                    ? 'Generated using relaxed validation fallback.'
                    : 'Generated using relaxed validation fallback: $relaxedReason.')
              : (relaxedReason.isEmpty
                    ? 'Strict hard filters were partially relaxed; review/edit this teacher draft before publish.'
                    : 'Strict hard filters were partially relaxed ($relaxedReason); review/edit this teacher draft before publish.'),
        );
        emit(4, warnings.last);
      } else {
        failures.add(
          'relaxed fallback rejected (missing required type mix or hardness).',
        );
      }
    }

    if (questions.isEmpty) {
      final String reason = failures.isEmpty
          ? 'Unknown generation error.'
          : failures.last;
      throw Exception(
        'AI could not generate a valid hard quiz right now. $reason',
      );
    }
    final Map<String, dynamic> sourcePolicy = _toMap(response['source_policy']);
    final bool responseFallbackUsed = sourcePolicy['fallback_used'] == true;
    final String responseSource = (response['source'] ?? '').toString().trim();
    if (responseSource == 'local_emergency_quiz_fallback') {
      warnings.add(
        'Emergency local fallback was used to complete this quiz. Review or regenerate when the backend is healthy.',
      );
    } else if (responseFallbackUsed) {
      warnings.add(
        'Fallback generation was used for part of this quiz. Review the set before relying on it.',
      );
    }
    if (_aiPreferPyq &&
        !_hasAnyWebSourceSignal(
          response,
          _extractAiQuestionRawList(response),
        )) {
      warnings.add(
        'PYQ web references were unavailable in this run; answers are synthesized under strict chapter lock.',
      );
    }
    if (quizId.isEmpty) {
      quizId = 'ai_runtime_${DateTime.now().millisecondsSinceEpoch}';
    }
    emit(5, 'Finalizing quiz package and preparing delivery.');
    final Map<String, dynamic> uiSpec = _extractAiUiSpec(response);
    final Map<String, dynamic> studentAdaptiveData =
        _extractAiStudentAdaptiveData(response);

    final String quizUrl = (response['quiz_url'] ?? response['url'] ?? '')
        .toString()
        .trim();
    final QuizItem item = QuizItem(
      id: quizId,
      title: quizTitle,
      url: quizUrl.isEmpty ? _quizCsvFallbackUrl(quizId) : quizUrl,
      deadline: effectiveDeadline,
      type: 'AIExam',
      durationMinutes: duration,
      isAiGenerated: true,
      isUnlimitedTime: _useUnlimitedSelfPracticeTime,
      uiSpec: uiSpec,
      studentAdaptiveData: studentAdaptiveData,
    );
    return _AiQuizGenerationData(
      questions: questions,
      quizItem: item,
      quizTitle: quizTitle,
      quizId: quizId,
      warnings: warnings,
      uiSpec: uiSpec,
      studentAdaptiveData: studentAdaptiveData,
    );
  }

  Future<void> _generateAiQuiz() async {
    if (_loading) {
      return;
    }
    final DateTime generationStartedAt = DateTime.now();
    setState(() {
      _loading = true;
      _aiGenerating = true;
      _aiGenerationStage = 1;
      _aiPreparingLabel = _aiGenerationStages.first;
      _aiPreparingDetail =
          'Locking scope, class, and hardness profile before generation.';
      _aiPreparingProgressCurrent = 1;
      _aiPreparingProgressTotal = _aiGenerationStages.length;
    });
    _aiPreparingCtrl
      ..stop()
      ..value = 0;
    if (!isLikelyWidgetTestMode()) {
      _aiPreparingCtrl.repeat();
    }
    _startAiThinkingTicker();
    _setAiGenerationStage(
      1,
      detail:
          'Using ${_aiHardnessLabel(_aiDifficulty)} with ${_aiQuestionCount.toString()} question(s).',
    );
    try {
      final _AiQuizGenerationData generated = await _generateAiQuizForStudio(
        hardnessBoost: 0,
        onProgress: (_AiGenerationProgress progress) {
          _setAiGenerationStage(
            progress.stage,
            label: progress.label,
            detail: progress.detail,
          );
        },
      );
      if (generated.warnings.isNotEmpty) {
        _snack(generated.warnings.first, isError: false);
      }
      await _enforceMinimumAiLoading(generationStartedAt);

      if (!widget.selfPracticeMode) {
        final List<QuizQuestion> drafted = _toDraftQuizQuestions(
          generated.questions,
        );
        if (mounted) {
          setState(() {
            _questions = drafted;
            _selectedIndex = drafted.isEmpty ? -1 : 0;
            _hasAiDraftQuestions = drafted.isNotEmpty;
            _activeAiUiSpec = Map<String, dynamic>.from(generated.uiSpec);
            _activeStudentAdaptiveData = Map<String, dynamic>.from(
              generated.studentAdaptiveData,
            );
            if (_title.text.trim().isEmpty) {
              _title.text = generated.quizTitle;
            }
          });
        }
        _snack(
          'AI hard draft ready. Review answer key cards, edit, then publish.',
          isError: false,
        );
        return;
      }

      final QuizItem playItem = generated.quizItem;

      await localQuizStore.saveQuiz(
        item: playItem,
        questions: generated.questions,
        ownerAccountId: Session.effectiveAccountId,
        ownerRole: Session.userRole,
        visibility: 'private',
      );

      if (!mounted) {
        return;
      }
      _snack(
        'AI hard quiz generated. Redirecting to practice exam...',
        isError: false,
      );
      await Navigator.pushReplacement(
        context,
        MaterialPageRoute(
          builder: (_) => ExamScreen(
            questions: generated.questions,
            item: playItem,
            studentName: Session.effectiveDisplayName,
            isResume: false,
          ),
        ),
      );
    } catch (e) {
      await _enforceMinimumAiLoading(generationStartedAt);
      _snack('AI generation failed: $e', isError: true);
    } finally {
      _stopAiThinkingTicker();
      if (mounted) {
        _aiPreparingCtrl
          ..stop()
          ..value = 0;
        setState(() {
          _loading = false;
          _aiGenerating = false;
          _aiGenerationStage = 0;
          _aiPreparingLabel = 'Preparing question';
          _aiPreparingDetail = '';
          _aiPreparingProgressCurrent = 0;
          _aiPreparingProgressTotal = 0;
        });
      }
    }
  }

  Future<void> _openAiGeneratorDialog() async {
    int draftDifficulty = _aiDifficulty;
    int draftCount = _aiQuestionCount;
    bool draftWeakness = _aiWeaknessMode;
    bool draftCrossConcept = _aiCrossConcept;
    bool draftPyqFocus = _aiPreferPyq;
    String draftClass = _selectedClass;
    String draftSubject = _selectedSubject.trim().isEmpty
        ? _inferSubjectFromChapters(
            selectedClass: _selectedClass,
            chapters: _selectedChapters,
          )
        : _selectedSubject;
    List<String> draftChapters = List<String>.from(_selectedChapters);
    List<String> draftSubtopics = _aiSubtopics.isNotEmpty
        ? List<String>.from(_aiSubtopics)
        : List<String>.from(_selectedChapters);
    final TextEditingController subtopicsCtrl = TextEditingController(
      text: draftSubtopics.join(', '),
    );
    final bool? run = await showDialog<bool>(
      context: context,
      builder: (BuildContext context) {
        return StatefulBuilder(
          builder: (BuildContext context, void Function(void Function()) setDraft) {
            final Map<String, dynamic> profile = _hardnessProfile(
              draftDifficulty,
            );
            return AlertDialog(
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(20),
              ),
              titlePadding: const EdgeInsets.fromLTRB(20, 18, 20, 0),
              contentPadding: const EdgeInsets.fromLTRB(20, 14, 20, 0),
              actionsPadding: const EdgeInsets.fromLTRB(12, 6, 12, 12),
              title: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text('AI Quiz Generator'),
                  const SizedBox(height: 4),
                  Text(
                    widget.selfPracticeMode
                        ? 'Student hard practice mode'
                        : 'Teacher hard draft mode',
                    style: const TextStyle(fontSize: 12, color: Colors.grey),
                  ),
                ],
              ),
              content: SingleChildScrollView(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: <Widget>[
                    const Text(
                      'Hardness Profile',
                      style: TextStyle(fontWeight: FontWeight.w700),
                    ),
                    const SizedBox(height: 8),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: List<Widget>.generate(5, (int i) {
                        final int level = i + 1;
                        final bool selected = draftDifficulty == level;
                        return ChoiceChip(
                          selected: selected,
                          label: Text('S$level'),
                          onSelected: (_) =>
                              setDraft(() => draftDifficulty = level),
                        );
                      }),
                    ),
                    const SizedBox(height: 8),
                    Container(
                      width: double.infinity,
                      padding: const EdgeInsets.all(12),
                      decoration: BoxDecoration(
                        color: AppColors.primary.withOpacity(0.08),
                        borderRadius: BorderRadius.circular(12),
                        border: Border.all(
                          color: AppColors.primary.withOpacity(0.22),
                        ),
                      ),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          Text(
                            _aiHardnessLabel(draftDifficulty),
                            style: const TextStyle(
                              fontSize: 13,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            _aiHardnessDescription(draftDifficulty),
                            style: const TextStyle(
                              fontSize: 12,
                              color: Colors.grey,
                            ),
                          ),
                          const SizedBox(height: 6),
                          Text(
                            'Target: ${profile['target_level']}',
                            style: const TextStyle(
                              fontSize: 12,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ],
                      ),
                    ),
                    const SizedBox(height: 12),
                    Text(
                      'Questions: $draftCount',
                      style: const TextStyle(fontWeight: FontWeight.w700),
                    ),
                    Slider(
                      min: 5,
                      max: 40,
                      divisions: 35,
                      value: draftCount.toDouble(),
                      onChanged: (double v) =>
                          setDraft(() => draftCount = v.round()),
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: <Widget>[
                        Expanded(
                          child: OutlinedButton.icon(
                            onPressed: () async {
                              final Map<String, dynamic>? result =
                                  await showClassChapterPicker(
                                    context,
                                    currentClass: draftClass == 'Class 11+12'
                                        ? '11 + 12'
                                        : draftClass,
                                    currentSubject: draftSubject,
                                    currentChapters: draftChapters,
                                  );
                              if (result == null) {
                                return;
                              }
                              setDraft(() {
                                final String selected =
                                    (result['class'] ?? 'Class 11').toString();
                                draftClass = selected == '11 + 12'
                                    ? 'Class 11+12'
                                    : selected;
                                draftSubject =
                                    (result['subject'] ?? draftSubject)
                                        .toString()
                                        .trim();
                                draftChapters = List<String>.from(
                                  result['chapters'] as List<dynamic>,
                                );
                                if (subtopicsCtrl.text.trim().isEmpty) {
                                  draftSubtopics = List<String>.from(
                                    draftChapters,
                                  );
                                  subtopicsCtrl.text = draftSubtopics.join(
                                    ', ',
                                  );
                                }
                              });
                            },
                            icon: const Icon(Icons.menu_book_rounded),
                            label: Text(
                              draftChapters.isEmpty
                                  ? 'Select Chapters'
                                  : '${draftChapters.length} chapter(s)',
                            ),
                          ),
                        ),
                      ],
                    ),
                    if (draftChapters.isNotEmpty) ...<Widget>[
                      const SizedBox(height: 8),
                      Align(
                        alignment: Alignment.centerLeft,
                        child: Wrap(
                          spacing: 6,
                          runSpacing: 6,
                          children: draftChapters
                              .map((String e) => Chip(label: Text(e)))
                              .toList(),
                        ),
                      ),
                    ],
                    const SizedBox(height: 8),
                    TextField(
                      controller: subtopicsCtrl,
                      minLines: 1,
                      maxLines: 2,
                      onChanged: (String value) {
                        draftSubtopics = _splitTags(value);
                      },
                      decoration: const InputDecoration(
                        labelText: 'Subtopics (comma separated)',
                      ),
                    ),
                    const SizedBox(height: 8),
                    SwitchListTile.adaptive(
                      contentPadding: EdgeInsets.zero,
                      title: const Text('PYQ Focus'),
                      subtitle: const Text(
                        'Prefer previous-year-question style patterns and traps.',
                      ),
                      value: draftPyqFocus,
                      onChanged: (bool v) => setDraft(() => draftPyqFocus = v),
                    ),
                    SwitchListTile.adaptive(
                      contentPadding: EdgeInsets.zero,
                      title: const Text('Weakness Mode'),
                      value: draftWeakness,
                      onChanged: (bool v) => setDraft(() => draftWeakness = v),
                    ),
                    SwitchListTile.adaptive(
                      contentPadding: EdgeInsets.zero,
                      title: const Text('Cross Concept'),
                      value: draftCrossConcept,
                      onChanged: (bool v) =>
                          setDraft(() => draftCrossConcept = v),
                    ),
                  ],
                ),
              ),
              actions: <Widget>[
                TextButton(
                  onPressed: () => Navigator.pop(context, false),
                  child: const Text('Cancel'),
                ),
                ElevatedButton(
                  onPressed: () => Navigator.pop(context, true),
                  child: const Text('Generate Hard Quiz'),
                ),
              ],
            );
          },
        );
      },
    );
    final List<String> resolvedSubtopics = _splitTags(
      subtopicsCtrl.text.trim(),
    );
    subtopicsCtrl.dispose();
    if (run != true || !mounted) {
      return;
    }
    setState(() {
      _aiDifficulty = draftDifficulty;
      _aiQuestionCount = draftCount;
      _aiTrapIntensity =
          (_hardnessProfile(draftDifficulty)['trap_intensity'] ?? 'high')
              .toString();
      _aiWeaknessMode = draftWeakness;
      _aiCrossConcept = draftCrossConcept;
      _aiPreferPyq = draftPyqFocus;
      _selectedClass = draftClass;
      _selectedSubject = draftSubject;
      _selectedChapters = List<String>.from(draftChapters);
      _aiSubtopics = resolvedSubtopics;
    });
    await _generateAiQuiz();
  }

  Future<void> _openAiGenerationStudio() async {
    if (!mounted) {
      return;
    }
    final _AiGenerationStudioResult? result = await Navigator.of(context)
        .push<_AiGenerationStudioResult>(
          MaterialPageRoute<_AiGenerationStudioResult>(
            builder: (_) => _AiGenerationStudioScreen(
              selfPracticeMode: widget.selfPracticeMode,
              teacherMode:
                  !widget.selfPracticeMode && Session.userRole == 'teacher',
              initialDifficulty: _aiDifficulty,
              initialQuestionCount: _aiQuestionCount,
              generate:
                  ({
                    required int hardnessBoost,
                    required void Function(_AiGenerationProgress progress)
                    onProgress,
                    void Function(_AiQuestionShardProgress progress)?
                    onQuestionShardProgress,
                  }) => _generateAiQuizForStudio(
                    hardnessBoost: hardnessBoost,
                    onProgress: onProgress,
                    onQuestionShardProgress: onQuestionShardProgress,
                  ),
            ),
          ),
        );
    if (!mounted || result == null) {
      return;
    }

    if (!widget.selfPracticeMode) {
      final List<QuizQuestion> drafted = _toDraftQuizQuestions(
        result.questions,
      );
      setState(() {
        _questions = drafted;
        _selectedIndex = drafted.isEmpty ? -1 : 0;
        _hasAiDraftQuestions = drafted.isNotEmpty;
        _activeAiUiSpec = Map<String, dynamic>.from(result.data.uiSpec);
        _activeStudentAdaptiveData = Map<String, dynamic>.from(
          result.data.studentAdaptiveData,
        );
        if (_title.text.trim().isEmpty) {
          _title.text = result.data.quizTitle;
        }
      });
    }

    if (result.data.warnings.isNotEmpty) {
      _snack(result.data.warnings.first, isError: false);
    }

    if (result.action == _AiGenerationAction.publish) {
      await _publishQuiz();
      return;
    }
    if (result.action == _AiGenerationAction.startExam) {
      await localQuizStore.saveQuiz(
        item: result.data.quizItem,
        questions: result.questions,
        ownerAccountId: Session.effectiveAccountId,
        ownerRole: Session.userRole,
        visibility: 'private',
      );
      if (!mounted) {
        return;
      }
      await Navigator.pushReplacement(
        context,
        MaterialPageRoute(
          builder: (_) => ExamScreen(
            questions: result.questions,
            item: result.data.quizItem,
            studentName: Session.effectiveDisplayName,
            isResume: false,
          ),
        ),
      );
      return;
    }

    if (!widget.selfPracticeMode && _questions.isNotEmpty) {
      _snack(
        'AI draft ready. Swipe right on cards to edit, then publish.',
        isError: false,
      );
    }
  }

  Future<void> _publishQuiz() async {
    if (widget.selfPracticeMode || Session.userRole != 'teacher') {
      _snack(
        'Students can generate practice quizzes and attempt them only.',
        isError: true,
      );
      return;
    }
    if (_title.text.trim().isEmpty || _questions.isEmpty) {
      _snack('Title and questions are required', isError: true);
      return;
    }

    final bool? ok = await showDialog<bool>(
      context: context,
      builder: (BuildContext context) => AlertDialog(
        title: Text(
          widget.selfPracticeMode
              ? 'Start Practice Quiz?'
              : 'Publish $_assessmentType?',
        ),
        content: Text(
          widget.selfPracticeMode
              ? "Create '${_title.text.trim()}' and start attempt now."
              : "Confirm upload of '${_title.text.trim()}' ($_assessmentType) to server.",
        ),
        actions: <Widget>[
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Cancel'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.pop(context, true),
            child: Text(widget.selfPracticeMode ? 'Start' : 'Publish'),
          ),
        ],
      ),
    );

    if (ok != true) {
      return;
    }

    setState(() => _loading = true);
    try {
      final int duration = max(
        1,
        int.tryParse(_durationCtrl.text.trim()) ?? (_questions.length * 2),
      );
      final List<Map<String, dynamic>> questionPayload =
          await _buildQuestionPayloads();
      final List<Question> runtimeQuestions = _draftQuestionsAsExamQuestions();
      final Map<String, dynamic> payload = <String, dynamic>{
        'title': _title.text.trim(),
        'deadline': _deadline.toIso8601String(),
        'type': _assessmentType,
        'duration': duration,
        'class': _selectedClass,
        'chapters': _selectedChapters.join(', '),
        'questions': questionPayload,
        'role': Session.userRole,
      };
      bool backendSaved = false;
      String quizId = '';
      String quizUrl = '';
      try {
        final Map<String, dynamic> response = await backendService
            .createQuiz(payload)
            .timeout(const Duration(seconds: 9));
        backendSaved = backendService.isSuccessfulResponse(response);
        quizId = (response['id'] ?? response['quiz_id'] ?? '')
            .toString()
            .trim();
        quizUrl = (response['url'] ?? response['quiz_url'] ?? '')
            .toString()
            .trim();
      } catch (_) {
        backendSaved = false;
      }
      if (quizId.isEmpty) {
        quizId = 'lq_${DateTime.now().millisecondsSinceEpoch}';
      }
      if (quizUrl.isEmpty) {
        quizUrl = localQuizStore.localQuizUrl(quizId);
      }
      final QuizItem item = QuizItem(
        id: quizId,
        title: _title.text.trim(),
        url: quizUrl,
        deadline: _deadline,
        type: _assessmentType,
        durationMinutes: duration,
        isAiGenerated: _hasAiDraftQuestions,
        uiSpec: _hasAiDraftQuestions
            ? Map<String, dynamic>.from(_activeAiUiSpec)
            : <String, dynamic>{},
        studentAdaptiveData: _hasAiDraftQuestions
            ? Map<String, dynamic>.from(_activeStudentAdaptiveData)
            : <String, dynamic>{},
      );
      await localQuizStore.saveQuiz(
        item: item,
        questions: runtimeQuestions,
        ownerAccountId: Session.effectiveAccountId,
        ownerRole: Session.userRole,
        visibility: 'published',
      );

      if (!mounted) {
        return;
      }

      showSuccessBurst(context);
      _snack(
        backendSaved
            ? 'Quiz published successfully'
            : 'Backend unavailable. Quiz saved locally.',
        isError: false,
      );
      await notificationService.addAiNotification(
        title: widget.selfPracticeMode
            ? 'Practice Quiz Ready'
            : 'Quiz Published',
        body: widget.selfPracticeMode
            ? '${_title.text.trim()} is ready for your attempt.'
            : '${_title.text.trim()} is live for students.',
        type: 'system',
      );
      if (widget.selfPracticeMode) {
        await Navigator.pushReplacement(
          context,
          MaterialPageRoute(
            builder: (_) => InstructionScreen(
              item: item,
              studentName: Session.effectiveDisplayName,
              isResume: false,
            ),
          ),
        );
      } else {
        Navigator.pop(context);
      }
    } catch (e) {
      _snack('Publish failed: $e', isError: true);
    } finally {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  void _snack(String message, {required bool isError}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _deleteQuestion(int index) {
    setState(() {
      _questions.removeAt(index);
      if (_questions.isEmpty) {
        _selectedIndex = -1;
      } else if (_selectedIndex >= _questions.length) {
        _selectedIndex = _questions.length - 1;
      }
    });

    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(
        content: Text('Question deleted'),
        backgroundColor: Colors.red,
      ),
    );
  }

  void _duplicateQuestion(int index) {
    if (index < 0 || index >= _questions.length) {
      return;
    }
    final QuizQuestion q = _questions[index];
    final QuizQuestion clone = QuizQuestion(
      text: q.text,
      image: q.image,
      type: q.type,
      options: List<String>.from(q.options),
      correct: List<String>.from(q.correct),
      section: q.section,
      subPart: q.subPart,
      pos: q.pos,
      neg: q.neg,
      solution: q.solution,
      difficultyLabel: q.difficultyLabel,
      confidenceScore: q.confidenceScore,
      adaptiveScore: q.adaptiveScore,
    );
    setState(() {
      final int insertAt = index + 1;
      _questions.insert(insertAt, clone);
      _selectedIndex = insertAt;
    });
    _snack('Question duplicated', isError: false);
  }

  void _moveQuestionByDelta(int index, int delta) {
    if (index < 0 || index >= _questions.length) {
      return;
    }
    final int target = index + delta;
    if (target < 0 || target >= _questions.length || target == index) {
      return;
    }
    setState(() {
      final QuizQuestion item = _questions.removeAt(index);
      _questions.insert(target, item);
      _selectedIndex = target;
    });
  }

  void _openQuestionSheet({int? editIndex}) {
    _editingIndex = editIndex;
    List<String> modalChapters = <String>[];
    final TextEditingController subPartCtrl = TextEditingController();
    final List<String> partSuggestions = _resolvedSubParts();

    if (editIndex != null) {
      final QuizQuestion q = _questions[editIndex];
      _qTextCtrl.text = q.text;
      _img = q.image;
      _qType = q.type;
      subPartCtrl.text = q.subPart;
      modalChapters = q.section
          .split(',')
          .map((String e) => e.trim())
          .where((String e) => e.isNotEmpty)
          .toList();
      _posCtrl.text = q.pos.toString();
      _negCtrl.text = q.neg.toString();
      for (int i = 0; i < 4; i++) {
        _optCtrls[i].text = i < q.options.length ? q.options[i] : '';
      }
      _numCtrl.text = q.type == 'NUMERICAL' ? q.correct.first : '';
      if (q.type == 'MCQ') {
        _mcqCorrect = q.options.indexOf(q.correct.first);
      }
      if (q.type == 'MULTI') {
        _multiCorrect = q.correct
            .map((String e) => q.options.indexOf(e))
            .toList();
      }
    } else {
      _qTextCtrl.clear();
      _numCtrl.clear();
      _img = '';
      _qType = 'MCQ';
      _mcqCorrect = 0;
      _multiCorrect.clear();
      modalChapters = List<String>.from(_selectedChapters);
      subPartCtrl.text = partSuggestions.isNotEmpty
          ? partSuggestions.first
          : _defaultSubPartName(0);
      _posCtrl.text = '4';
      _negCtrl.text = '1';
      for (final TextEditingController c in _optCtrls) {
        c.clear();
      }
    }

    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      builder: (BuildContext c) {
        return StatefulBuilder(
          builder:
              (
                BuildContext context,
                void Function(void Function()) setModalState,
              ) {
                return Padding(
                  padding: EdgeInsets.only(
                    bottom: MediaQuery.of(c).viewInsets.bottom,
                    left: 16,
                    right: 16,
                    top: 16,
                  ),
                  child: SingleChildScrollView(
                    child: Column(
                      children: <Widget>[
                        Text(
                          editIndex == null ? 'Add Question' : 'Edit Question',
                          style: const TextStyle(
                            fontSize: 18,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                        const SizedBox(height: 12),
                        TextField(
                          key: const ValueKey<String>('quiz_question_text'),
                          controller: _qTextCtrl,
                          maxLines: 3,
                          decoration: const InputDecoration(
                            labelText: 'Question',
                          ),
                        ),
                        const SizedBox(height: 8),
                        Align(
                          alignment: Alignment.centerLeft,
                          child: TextButton.icon(
                            onPressed: () async {
                              final Map<String, dynamic>? result =
                                  await showClassChapterPicker(
                                    context,
                                    currentClass:
                                        _selectedClass == 'Class 11+12'
                                        ? '11 + 12'
                                        : _selectedClass,
                                    currentSubject: _selectedSubject,
                                    currentChapters: modalChapters,
                                  );
                              if (result == null) {
                                return;
                              }
                              setModalState(() {
                                final String selected =
                                    (result['class'] ?? 'Class 11').toString();
                                _selectedClass = selected == '11 + 12'
                                    ? 'Class 11+12'
                                    : selected;
                                _selectedSubject =
                                    (result['subject'] ?? _selectedSubject)
                                        .toString()
                                        .trim();
                                modalChapters = List<String>.from(
                                  result['chapters'] as List<dynamic>,
                                );
                              });
                              setState(() {});
                            },
                            icon: const Icon(Icons.menu_book),
                            label: Text(
                              modalChapters.isEmpty
                                  ? 'Select chapters'
                                  : '${modalChapters.length} chapter(s) selected',
                            ),
                          ),
                        ),
                        if (modalChapters.isNotEmpty)
                          Align(
                            alignment: Alignment.centerLeft,
                            child: Wrap(
                              spacing: 6,
                              runSpacing: 6,
                              children: modalChapters
                                  .map(
                                    (String e) => Chip(
                                      label: Text(
                                        e,
                                        style: const TextStyle(fontSize: 11),
                                      ),
                                    ),
                                  )
                                  .toList(),
                            ),
                          ),
                        const SizedBox(height: 8),
                        TextField(
                          key: const ValueKey<String>('quiz_question_subpart'),
                          controller: subPartCtrl,
                          decoration: const InputDecoration(
                            labelText: 'Sub-part (optional)',
                            hintText: 'Part A / Section 1',
                          ),
                        ),
                        if (partSuggestions.isNotEmpty) ...<Widget>[
                          const SizedBox(height: 6),
                          Align(
                            alignment: Alignment.centerLeft,
                            child: Wrap(
                              spacing: 6,
                              runSpacing: 6,
                              children: partSuggestions
                                  .map(
                                    (String part) => ActionChip(
                                      label: Text(part),
                                      onPressed: () => setModalState(
                                        () => subPartCtrl.text = part,
                                      ),
                                    ),
                                  )
                                  .toList(),
                            ),
                          ),
                        ],
                        const SizedBox(height: 10),
                        if (_img.isEmpty)
                          Row(
                            children: <Widget>[
                              ElevatedButton.icon(
                                onPressed: () => _pickImage(true),
                                icon: const Icon(Icons.camera_alt),
                                label: const Text('Camera'),
                              ),
                              const SizedBox(width: 10),
                              ElevatedButton.icon(
                                onPressed: () => _pickImage(false),
                                icon: const Icon(Icons.image),
                                label: const Text('Gallery'),
                              ),
                            ],
                          )
                        else
                          Column(
                            children: <Widget>[
                              Padding(
                                padding: const EdgeInsets.all(8.0),
                                child: SmartImage(_img, height: 160),
                              ),
                              Row(
                                children: <Widget>[
                                  Expanded(
                                    child: OutlinedButton.icon(
                                      icon: const Icon(Icons.refresh),
                                      label: const Text('Replace'),
                                      onPressed: () => _pickImage(false),
                                    ),
                                  ),
                                  const SizedBox(width: 8),
                                  Expanded(
                                    child: OutlinedButton.icon(
                                      icon: const Icon(
                                        Icons.delete,
                                        color: Colors.red,
                                      ),
                                      label: const Text('Remove'),
                                      onPressed: () =>
                                          setModalState(() => _img = ''),
                                    ),
                                  ),
                                ],
                              ),
                            ],
                          ),
                        const SizedBox(height: 10),
                        DropdownButtonFormField<String>(
                          value: _qType,
                          items: const <DropdownMenuItem<String>>[
                            DropdownMenuItem(
                              value: 'MCQ',
                              child: Text('Single Correct (MCQ)'),
                            ),
                            DropdownMenuItem(
                              value: 'MULTI',
                              child: Text('Multi Correct'),
                            ),
                            DropdownMenuItem(
                              value: 'NUMERICAL',
                              child: Text('Numerical'),
                            ),
                          ],
                          onChanged: (String? v) {
                            if (v == null) {
                              return;
                            }
                            setModalState(() => _qType = v);
                          },
                        ),
                        const SizedBox(height: 10),
                        Row(
                          children: <Widget>[
                            Expanded(
                              child: TextField(
                                key: const ValueKey<String>(
                                  'quiz_question_pos',
                                ),
                                controller: _posCtrl,
                                keyboardType:
                                    const TextInputType.numberWithOptions(
                                      decimal: true,
                                    ),
                                decoration: const InputDecoration(
                                  labelText: 'Positive Mark',
                                ),
                              ),
                            ),
                            const SizedBox(width: 10),
                            Expanded(
                              child: TextField(
                                key: const ValueKey<String>(
                                  'quiz_question_neg',
                                ),
                                controller: _negCtrl,
                                keyboardType:
                                    const TextInputType.numberWithOptions(
                                      decimal: true,
                                    ),
                                decoration: const InputDecoration(
                                  labelText: 'Negative Mark',
                                ),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 10),
                        if (_qType == 'NUMERICAL')
                          TextField(
                            key: const ValueKey<String>('quiz_question_num'),
                            controller: _numCtrl,
                            decoration: const InputDecoration(
                              labelText: 'Correct Answer',
                            ),
                          )
                        else
                          Column(
                            children: List<Widget>.generate(4, (int i) {
                              return Row(
                                children: <Widget>[
                                  Expanded(
                                    child: TextField(
                                      key: ValueKey<String>(
                                        'quiz_question_option_$i',
                                      ),
                                      controller: _optCtrls[i],
                                      decoration: InputDecoration(
                                        labelText: 'Option ${i + 1}',
                                      ),
                                    ),
                                  ),
                                  if (_qType == 'MCQ')
                                    Radio<int>(
                                      value: i,
                                      groupValue: _mcqCorrect,
                                      onChanged: (int? v) => setModalState(
                                        () => _mcqCorrect = v ?? 0,
                                      ),
                                    ),
                                  if (_qType == 'MULTI')
                                    Checkbox(
                                      value: _multiCorrect.contains(i),
                                      onChanged: (bool? v) {
                                        setModalState(() {
                                          if (v == true) {
                                            _multiCorrect.add(i);
                                          } else {
                                            _multiCorrect.remove(i);
                                          }
                                        });
                                      },
                                    ),
                                ],
                              );
                            }),
                          ),
                        const SizedBox(height: 16),
                        ElevatedButton(
                          onPressed: () {
                            if (_qTextCtrl.text.trim().isEmpty) {
                              return;
                            }
                            final List<String> options = _optCtrls
                                .map((TextEditingController e) => e.text.trim())
                                .toList();

                            if (_qType != 'NUMERICAL' &&
                                options.any((String e) => e.isEmpty)) {
                              ScaffoldMessenger.of(context).showSnackBar(
                                const SnackBar(
                                  content: Text('All options must be filled'),
                                ),
                              );
                              return;
                            }

                            List<String> correct = <String>[];
                            if (_qType == 'NUMERICAL') {
                              if (_numCtrl.text.trim().isEmpty) {
                                return;
                              }
                              correct = <String>[_numCtrl.text.trim()];
                            } else if (_qType == 'MCQ') {
                              correct = <String>[options[_mcqCorrect]];
                            } else {
                              if (_multiCorrect.isEmpty) {
                                ScaffoldMessenger.of(context).showSnackBar(
                                  const SnackBar(
                                    content: Text(
                                      'Select at least one correct option',
                                    ),
                                  ),
                                );
                                return;
                              }
                              correct = _multiCorrect
                                  .map((int i) => options[i])
                                  .toList();
                            }

                            final QuizQuestion newQ = QuizQuestion(
                              solution:
                                  (_editingIndex != null &&
                                      _editingIndex! >= 0 &&
                                      _editingIndex! < _questions.length)
                                  ? _questions[_editingIndex!].solution
                                  : '',
                              difficultyLabel:
                                  (_editingIndex != null &&
                                      _editingIndex! >= 0 &&
                                      _editingIndex! < _questions.length)
                                  ? _questions[_editingIndex!].difficultyLabel
                                  : '',
                              confidenceScore:
                                  (_editingIndex != null &&
                                      _editingIndex! >= 0 &&
                                      _editingIndex! < _questions.length)
                                  ? _questions[_editingIndex!].confidenceScore
                                  : -1,
                              adaptiveScore:
                                  (_editingIndex != null &&
                                      _editingIndex! >= 0 &&
                                      _editingIndex! < _questions.length)
                                  ? _questions[_editingIndex!].adaptiveScore
                                  : -1,
                              text: _qTextCtrl.text.trim(),
                              image: _img,
                              type: _qType,
                              options: options,
                              correct: correct,
                              section: modalChapters.isEmpty
                                  ? _defaultQuestionSection()
                                  : modalChapters.join(', '),
                              subPart: _normalizeSubPartName(subPartCtrl.text),
                              pos: double.tryParse(_posCtrl.text) ?? 4,
                              neg: double.tryParse(_negCtrl.text) ?? 1,
                            );

                            setState(() {
                              if (newQ.subPart.trim().isNotEmpty) {
                                _registerSubPart(newQ.subPart);
                              }
                              if (_editingIndex == null) {
                                _questions.add(newQ);
                                _selectedIndex = _questions.length - 1;
                              } else {
                                _questions[_editingIndex!] = newQ;
                                _selectedIndex = _editingIndex!;
                              }
                            });

                            Navigator.pop(c);
                            ScaffoldMessenger.of(context).showSnackBar(
                              SnackBar(
                                content: Text(
                                  _editingIndex == null
                                      ? 'Question added'
                                      : 'Question updated',
                                ),
                                backgroundColor: Colors.green,
                              ),
                            );
                          },
                          child: const Text('Save Question'),
                        ),
                        const SizedBox(height: 20),
                      ],
                    ),
                  ),
                );
              },
        );
      },
    ).whenComplete(subPartCtrl.dispose);
  }

  String _densityLabel(PerformanceMode mode) {
    switch (mode) {
      case PerformanceMode.reduced:
        return 'Reduced';
      case PerformanceMode.auto:
        return 'Auto';
      case PerformanceMode.full:
        return 'Full';
    }
  }

  bool _isReducedComposer(double width, PerformanceMode mode) {
    switch (mode) {
      case PerformanceMode.reduced:
        return true;
      case PerformanceMode.full:
        return false;
      case PerformanceMode.auto:
        return width < 1020;
    }
  }

  bool _isFullComposer(double width, PerformanceMode mode) {
    switch (mode) {
      case PerformanceMode.reduced:
        return false;
      case PerformanceMode.full:
        return true;
      case PerformanceMode.auto:
        return width >= 1320;
    }
  }

  Future<Map<String, List<String>>> _loadDynamicChapterMapForPicker({
    required String subjectHint,
  }) async {
    final String subject = subjectHint.trim();
    try {
      final Map<String, List<String>> chapterMap = await backendService
          .lc9ListImportChapters(
            subject: subject,
            minCount: 2,
            includeGeneric: false,
          );
      if (chapterMap.isNotEmpty) {
        return chapterMap;
      }
    } catch (_) {}
    if (subject.isEmpty) {
      return <String, List<String>>{};
    }
    try {
      return await backendService.lc9ListImportChapters(
        subject: '',
        minCount: 2,
        includeGeneric: false,
      );
    } catch (_) {
      return <String, List<String>>{};
    }
  }

  Future<void> _pickQuizChapters() async {
    final Map<String, List<String>> dynamicChapterMap =
        await _loadDynamicChapterMapForPicker(subjectHint: _selectedSubject);
    if (!mounted) {
      return;
    }
    final Map<String, dynamic>? result = await showClassChapterPicker(
      context,
      currentClass: _selectedClass == 'Class 11+12'
          ? '11 + 12'
          : _selectedClass,
      currentSubject: _selectedSubject,
      currentChapters: _selectedChapters,
      dynamicChaptersBySubject: dynamicChapterMap,
    );
    if (result == null) {
      return;
    }
    setState(() {
      final String selected = (result['class'] ?? 'Class 11').toString();
      _selectedClass = selected == '11 + 12' ? 'Class 11+12' : selected;
      _selectedChapters = List<String>.from(
        result['chapters'] as List<dynamic>,
      );
      final String selectedSubject = (result['subject'] ?? '')
          .toString()
          .trim();
      _selectedSubject = selectedSubject.isEmpty
          ? _inferSubjectFromChapters(
              selectedClass: _selectedClass,
              chapters: _selectedChapters,
            )
          : selectedSubject;
      if (_aiSubtopics.isEmpty) {
        _aiSubtopics = List<String>.from(_selectedChapters);
      }
    });
  }

  Widget _buildDensityModeCard({
    required PerformanceMode mode,
    required bool reducedLayout,
    required bool fullLayout,
  }) {
    final Color tone = reducedLayout
        ? Colors.orange
        : (fullLayout ? AppColors.primary : Colors.blueGrey);
    return LiquidGlass(
      padding: EdgeInsets.symmetric(
        horizontal: reducedLayout ? 10 : 14,
        vertical: reducedLayout ? 10 : 12,
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Row(
            children: <Widget>[
              Icon(Icons.tune_rounded, color: tone),
              const SizedBox(width: 8),
              Expanded(
                child: Text(
                  'Composer Layout',
                  style: TextStyle(
                    fontWeight: FontWeight.w800,
                    fontSize: reducedLayout ? 13 : 15,
                  ),
                ),
              ),
              Text(
                _densityLabel(mode),
                style: TextStyle(
                  color: tone,
                  fontWeight: FontWeight.w700,
                  fontSize: reducedLayout ? 11 : 12,
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: PerformanceMode.values.map((PerformanceMode candidate) {
              final bool selected = candidate == mode;
              return ChoiceChip(
                label: Text(_densityLabel(candidate)),
                selected: selected,
                onSelected: (bool value) {
                  if (!value) {
                    return;
                  }
                  unawaited(setPerformanceMode(candidate));
                },
              );
            }).toList(),
          ),
          const SizedBox(height: 6),
          const Text(
            'Synced with Profile Performance mode.',
            style: TextStyle(fontSize: 11, color: Colors.grey),
          ),
        ],
      ),
    );
  }

