  List<AnswerKeyCardPayload> _buildDraftAnswerKeyCards(
    List<Question> questions,
  ) {
    return List<AnswerKeyCardPayload>.generate(questions.length, (int i) {
      final Question q = questions[i];
      final List<String> opts = q.options
          .asMap()
          .entries
          .map(
            (MapEntry<int, String> e) =>
                '${String.fromCharCode(65 + e.key)}) ${e.value}',
          )
          .toList();
      return AnswerKeyCardPayload(
        heroTag: 'draft_${DateTime.now().millisecondsSinceEpoch}_$i',
        questionIndex: i,
        questionText: q.text,
        options: opts,
        correctAnswer: q.correctAnswers.isEmpty
            ? 'Not available'
            : q.correctAnswers.join(', '),
        studentAnswer: 'Draft (not attempted)',
        solution: q.solution,
        concept: q.concept,
        marksDelta: 0,
        statusLabel: 'DRAFT',
        statusColor: AppColors.primary,
        imageUrl: q.imageUrl,
      );
    });
  }

  Future<void> _askAiForDraftQuestion({
    required int index,
    required Question question,
    required AnswerKeyCardPayload payload,
  }) async {
    final String prompt =
        '''
You are reviewing a draft exam question before final publish.

Question:
${question.text}

Options:
A) ${question.options.elementAtOrNull(0) ?? ''}
B) ${question.options.elementAtOrNull(1) ?? ''}
C) ${question.options.elementAtOrNull(2) ?? ''}
D) ${question.options.elementAtOrNull(3) ?? ''}

Draft Correct Answer: ${question.correctAnswers.join(', ')}
Draft Solution: ${question.solution.trim().isEmpty ? 'Not provided.' : question.solution.trim()}

Tasks:
1) Verify if answer key is correct.
2) Detect ambiguity / multiple-correct risk.
3) Improve this into JEE-hard level if needed.
4) Provide final polished answer + concise solution.
''';

    await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => AIChatScreen(
          userId: Session.effectiveDisplayName,
          chatId:
              'AI_${Session.effectiveAccountId}_draft_${DateTime.now().millisecondsSinceEpoch}',
          chatFunction: 'aks_answer_review',
          showPersonaBanner: true,
          heroTag: payload.heroTag,
          heroCard: payload.toCardMap(),
          initialPrompt: prompt,
          contextCard: <String, dynamic>{
            'surface': 'create_quiz_draft_review',
            'question_index': index,
            'answer_key_card': payload.toCardMap(),
          },
        ),
      ),
    );
  }

  Future<void> _sendDraftToTeacher({
    required int index,
    required Question question,
    required AnswerKeyCardPayload payload,
  }) async {
    final TextEditingController doubtCtrl = TextEditingController();
    await showDialog<void>(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: const Text('Send Draft to Teacher'),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              Text(
                question.text,
                maxLines: 3,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(fontSize: 12, color: Colors.grey),
              ),
              const SizedBox(height: 10),
              TextField(
                controller: doubtCtrl,
                minLines: 2,
                maxLines: 4,
                decoration: const InputDecoration(
                  hintText: 'What should teacher review here?',
                  border: OutlineInputBorder(),
                ),
              ),
            ],
          ),
          actions: <Widget>[
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Send'),
            ),
          ],
        );
      },
    );

    final String doubt = doubtCtrl.text.trim();
    doubtCtrl.dispose();
    if (doubt.isEmpty || !mounted) {
      return;
    }

    try {
      await backendService.enqueueTeacherReview(<String, dynamic>{
        'quiz_id': 'draft_${DateTime.now().millisecondsSinceEpoch}',
        'question_id': index + 1,
        'question_index': index,
        'student_answer': 'Draft review request',
        'correct_answer': question.correctAnswers.join(', '),
        'student_id': Session.effectiveAccountId,
        'message': doubt,
        'timestamp': DateTime.now().millisecondsSinceEpoch,
      });
    } catch (_) {}

    try {
      final ChatThreadSummary thread = await chatService.raiseDoubtFromQuestion(
        quizId: 'draft_${DateTime.now().millisecondsSinceEpoch}',
        quizTitle: _title.text.trim().isEmpty ? 'AI Draft Quiz' : _title.text,
        questionText: question.text,
        myUserId: Session.effectiveChatId,
        myName: Session.effectiveDisplayName,
        initialMessage: doubt,
        imageUrl: question.imageUrl,
        card: payload.toCardMap(),
      );
      if (!mounted) {
        return;
      }
      await Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => ChatThreadScreen(
            thread: thread,
            myUserId: Session.effectiveChatId,
            myName: Session.effectiveDisplayName,
            role: Session.userRole,
            chatService: chatService,
          ),
        ),
      );
    } catch (e) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Failed to send: $e')));
    }
  }

  Future<void> _openDraftAnswerKeyPreview() async {
    final List<Question> draftQuestions = _draftQuestionsAsExamQuestions();
    if (draftQuestions.isEmpty) {
      _snack('Generate questions first to preview answer keys.', isError: true);
      return;
    }
    final List<AnswerKeyCardPayload> cards = _buildDraftAnswerKeyCards(
      draftQuestions,
    );
    await Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => _DraftAnswerKeyPreviewScreen(
          title: _title.text.trim().isEmpty ? 'AI Draft Quiz' : _title.text,
          cards: cards,
          canEdit: Session.userRole == 'teacher',
          onEditQuestion: (int index) async {
            _openQuestionSheet(editIndex: index);
          },
          onAskAi: (int index) async {
            await _askAiForDraftQuestion(
              index: index,
              question: draftQuestions[index],
              payload: cards[index],
            );
          },
          onSendToTeacher: (int index) async {
            await _sendDraftToTeacher(
              index: index,
              question: draftQuestions[index],
              payload: cards[index],
            );
          },
        ),
      ),
    );
  }

  Widget _buildSelectedQuestionCard({required bool reducedLayout}) {
    if (widget.selfPracticeMode ||
        _selectedIndex < 0 ||
        _questions.isEmpty ||
        _selectedIndex >= _questions.length) {
      return const SizedBox.shrink();
    }
    final QuizQuestion current = _questions[_selectedIndex];
    final bool hasSolution = current.solution.trim().isNotEmpty;
    final bool canMoveLeft = _selectedIndex > 0;
    final bool canMoveRight = _selectedIndex < (_questions.length - 1);
    final int optionCount = current.options
        .where((String e) => e.trim().isNotEmpty)
        .length;

    Widget infoChip({
      required IconData icon,
      required String label,
      required Color color,
    }) {
      return Container(
        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
        decoration: BoxDecoration(
          color: color.withOpacity(0.10),
          borderRadius: BorderRadius.circular(999),
          border: Border.all(color: color.withOpacity(0.35)),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: <Widget>[
            Icon(icon, size: 14, color: color),
            const SizedBox(width: 6),
            Text(
              label,
              style: TextStyle(
                fontSize: 12,
                fontWeight: FontWeight.w700,
                color: color,
              ),
            ),
          ],
        ),
      );
    }

    return LiquidGlass(
      padding: EdgeInsets.all(reducedLayout ? 12 : 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          SmartText(
            'Q${_selectedIndex + 1}. ${current.text}',
            style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 16),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              infoChip(
                icon: Icons.tune_rounded,
                label: current.type,
                color: AppColors.primary,
              ),
              infoChip(
                icon: Icons.category_outlined,
                label: current.section.isEmpty ? 'General' : current.section,
                color: Colors.teal.shade700,
              ),
              infoChip(
                icon: Icons.radio_button_checked_rounded,
                label: current.type == 'NUMERICAL'
                    ? 'Numerical'
                    : '$optionCount option${optionCount == 1 ? '' : 's'}',
                color: Colors.indigo.shade700,
              ),
            ],
          ),
          if (current.subPart.trim().isNotEmpty)
            Padding(
              padding: const EdgeInsets.only(top: 8),
              child: Text('Sub-part: ${current.subPart}'),
            ),
          if (current.type == 'NUMERICAL' &&
              current.correct.isNotEmpty) ...<Widget>[
            const SizedBox(height: 10),
            const Text(
              'Answer',
              style: TextStyle(fontWeight: FontWeight.w700, fontSize: 13),
            ),
            const SizedBox(height: 4),
            SmartText(current.correct.first),
          ] else if (current.options.any(
            (String e) => e.trim().isNotEmpty,
          )) ...<Widget>[
            const SizedBox(height: 10),
            const Text(
              'Options',
              style: TextStyle(fontWeight: FontWeight.w700, fontSize: 13),
            ),
            const SizedBox(height: 4),
            ...current.options.asMap().entries.map((MapEntry<int, String> e) {
              final String option = e.value.trim();
              if (option.isEmpty) {
                return const SizedBox.shrink();
              }
              final String label = String.fromCharCode(65 + e.key);
              return Padding(
                padding: const EdgeInsets.only(bottom: 4),
                child: SmartText('$label) $option'),
              );
            }),
            if (current.correct.isNotEmpty) ...<Widget>[
              const SizedBox(height: 2),
              const Text(
                'Correct Answer',
                style: TextStyle(fontWeight: FontWeight.w700, fontSize: 13),
              ),
              const SizedBox(height: 4),
              SmartText(current.correct.join(', ')),
            ],
          ],
          if (hasSolution) ...<Widget>[
            const SizedBox(height: 10),
            const Text(
              'Draft Solution',
              style: TextStyle(fontWeight: FontWeight.w700, fontSize: 13),
            ),
            const SizedBox(height: 4),
            Container(
              width: double.infinity,
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.80),
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.black12),
              ),
              child: SmartText(current.solution.trim()),
            ),
          ],
          const SizedBox(height: 12),
          Row(
            children: <Widget>[
              Expanded(
                child: ElevatedButton.icon(
                  onPressed: () =>
                      _openQuestionSheet(editIndex: _selectedIndex),
                  icon: const Icon(Icons.edit_note_rounded),
                  label: const Text('Edit This Question'),
                ),
              ),
              const SizedBox(width: 8),
              OutlinedButton.icon(
                onPressed: () => _duplicateQuestion(_selectedIndex),
                icon: const Icon(Icons.copy_all_rounded),
                label: const Text('Duplicate'),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Row(
            children: <Widget>[
              Expanded(
                child: OutlinedButton.icon(
                  onPressed: canMoveLeft
                      ? () => _moveQuestionByDelta(_selectedIndex, -1)
                      : null,
                  icon: const Icon(Icons.arrow_back_rounded),
                  label: const Text('Move Left'),
                ),
              ),
              const SizedBox(width: 8),
              Expanded(
                child: OutlinedButton.icon(
                  onPressed: canMoveRight
                      ? () => _moveQuestionByDelta(_selectedIndex, 1)
                      : null,
                  icon: const Icon(Icons.arrow_forward_rounded),
                  label: const Text('Move Right'),
                ),
              ),
              const SizedBox(width: 8),
              OutlinedButton.icon(
                onPressed: _questions.isNotEmpty
                    ? () => _deleteQuestion(_selectedIndex)
                    : null,
                icon: const Icon(Icons.delete_outline_rounded),
                label: const Text('Delete'),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _buildQuestionPalette({required bool reducedLayout}) {
    if (widget.selfPracticeMode || _questions.isEmpty) {
      return const SizedBox.shrink();
    }
    return SizedBox(
      height: reducedLayout ? 82 : 92,
      child: ReorderableListView.builder(
        scrollDirection: Axis.horizontal,
        itemCount: _questions.length,
        onReorder: (int oldIndex, int newIndex) {
          setState(() {
            if (newIndex > oldIndex) {
              newIndex--;
            }
            final QuizQuestion item = _questions.removeAt(oldIndex);
            _questions.insert(newIndex, item);
            if (_selectedIndex == oldIndex) {
              _selectedIndex = newIndex;
            }
          });
        },
        itemBuilder: (_, int i) {
          final bool selected = i == _selectedIndex;
          return GestureDetector(
            key: ValueKey<String>('q$i'),
            onTap: () => setState(() => _selectedIndex = i),
            onLongPress: () => _deleteQuestion(i),
            child: Container(
              width: reducedLayout ? 52 : 56,
              margin: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: selected ? AppColors.primary : Colors.grey.shade300,
                shape: BoxShape.circle,
              ),
              child: Center(
                child: Text(
                  '${i + 1}',
                  style: TextStyle(
                    color: selected ? Colors.white : Colors.black,
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ),
            ),
          );
        },
      ),
    );
  }

  @override
  void dispose() {
    _aiPreparingCtrl.dispose();
    _aiThinkingTimer?.cancel();
    _title.dispose();
    _durationCtrl.dispose();
    _qTextCtrl.dispose();
    _numCtrl.dispose();
    _posCtrl.dispose();
    _negCtrl.dispose();
    for (final TextEditingController c in _optCtrls) {
      c.dispose();
    }
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(
          widget.selfPracticeMode ? 'AI Practice Quiz' : 'Create Quiz',
        ),
        actions: <Widget>[
          Padding(
            padding: const EdgeInsets.only(right: 12),
            child: _loading
                ? (_aiGenerating
                      ? _buildAiPreparingChip()
                      : const Padding(
                          padding: EdgeInsets.all(12),
                          child: SizedBox(
                            width: 20,
                            height: 20,
                            child: CircularProgressIndicator(strokeWidth: 2),
                          ),
                        ))
                : (!widget.selfPracticeMode
                      ? IconButton(
                          icon: const Icon(
                            Icons.check_circle,
                            color: AppColors.primary,
                            size: 32,
                          ),
                          onPressed: _publishQuiz,
                          tooltip: 'Publish Quiz',
                        )
                      : const SizedBox.shrink()),
          ),
        ],
      ),
      body: ValueListenableBuilder<PerformanceMode>(
        valueListenable: performanceModeNotifier,
        builder: (_, PerformanceMode perfMode, __) {
          return LayoutBuilder(
            builder: (BuildContext context, BoxConstraints constraints) {
              final bool reducedLayout = _isReducedComposer(
                constraints.maxWidth,
                perfMode,
              );
              final bool fullLayout = _isFullComposer(
                constraints.maxWidth,
                perfMode,
              );
              final double gap = reducedLayout ? 10 : 14;
              final EdgeInsets pad = EdgeInsets.all(reducedLayout ? 14 : 20);
              final List<String> subParts = _resolvedSubParts();

              return Stack(
                children: <Widget>[
                  Column(
                    children: <Widget>[
                      Expanded(
                        child: SingleChildScrollView(
                          padding: pad,
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: <Widget>[
                              _buildDensityModeCard(
                                mode: perfMode,
                                reducedLayout: reducedLayout,
                                fullLayout: fullLayout,
                              ),
                              SizedBox(height: gap),
                              _buildComposerOverviewCard(
                                reducedLayout: reducedLayout,
                                fullLayout: fullLayout,
                              ),
                              SizedBox(height: gap),
                              _buildSetupCard(
                                reducedLayout: reducedLayout,
                                fullLayout: fullLayout,
                              ),
                              SizedBox(height: gap),
                              _buildActionCard(reducedLayout: reducedLayout),
                              if (_aiGenerating &&
                                  !_paperImportInFlight) ...<Widget>[
                                SizedBox(height: gap),
                                _buildAiPreparingBanner(),
                              ],
                              if (!widget.selfPracticeMode &&
                                  !_aiGenerating &&
                                  subParts.isNotEmpty) ...<Widget>[
                                SizedBox(height: gap),
                                LiquidGlass(
                                  padding: EdgeInsets.symmetric(
                                    horizontal: reducedLayout ? 10 : 12,
                                    vertical: reducedLayout ? 8 : 10,
                                  ),
                                  child: Wrap(
                                    spacing: 6,
                                    runSpacing: 6,
                                    children: subParts
                                        .map(
                                          (String e) =>
                                              Chip(label: Text('Sub-part: $e')),
                                        )
                                        .toList(),
                                  ),
                                ),
                              ],
                              SizedBox(height: gap + 2),
                              _buildSelectedQuestionCard(
                                reducedLayout: reducedLayout,
                              ),
                            ],
                          ),
                        ),
                      ),
                      _buildQuestionPalette(reducedLayout: reducedLayout),
                    ],
                  ),
                  _buildPaperImportLoadingOverlay(),
                  _buildCustomPracticeLoadingOverlay(),
                ],
              );
            },
          );
        },
      ),
    );
  }
}

class _AiGenerationStudioScreen extends StatefulWidget {
  const _AiGenerationStudioScreen({
    required this.selfPracticeMode,
    required this.teacherMode,
    required this.initialDifficulty,
    required this.initialQuestionCount,
    required this.generate,
  });

  final bool selfPracticeMode;
  final bool teacherMode;
  final int initialDifficulty;
  final int initialQuestionCount;
  final Future<_AiQuizGenerationData> Function({
    required int hardnessBoost,
    required void Function(_AiGenerationProgress progress) onProgress,
    void Function(_AiQuestionShardProgress progress)? onQuestionShardProgress,
  })
  generate;

  @override
  State<_AiGenerationStudioScreen> createState() =>
      _AiGenerationStudioScreenState();
}

class _AiGenerationStudioScreenState extends State<_AiGenerationStudioScreen> {
  int _hardnessBoost = 0;
  bool _loading = true;
  int _stage = 1;
  String _stageLabel = 'Scope & Constraints';
  String _stageDetail = 'Preparing AI generation pipeline...';
  String _error = '';
  int _visibleCards = 0;
  int _runId = 0;
  int _cardSeed = DateTime.now().millisecondsSinceEpoch;
  List<_AiQuestionShardProgress> _questionShards = <_AiQuestionShardProgress>[];
  _AiQuizGenerationData? _data;
  List<Question> _questions = <Question>[];

  @override
  void initState() {
    super.initState();
    unawaited(_runGeneration());
  }

  Future<void> _runGeneration({bool harder = false}) async {
    final int runId = ++_runId;
    setState(() {
      if (harder) {
        _hardnessBoost += 1;
      }
      _loading = true;
      _error = '';
      _visibleCards = 0;
      _stage = 1;
      _stageLabel = 'Scope & Constraints';
      _stageDetail = 'Preparing AI generation pipeline...';
      _data = null;
      _questions = <Question>[];
      _questionShards = List<_AiQuestionShardProgress>.generate(
        widget.initialQuestionCount,
        (int i) => _AiQuestionShardProgress(
          index: i,
          state: 'queued',
          detail: 'Awaiting worker...',
          targetType: const <String>['MCQ', 'MULTI', 'NUMERICAL'][i % 3],
        ),
      );
      _cardSeed = DateTime.now().millisecondsSinceEpoch;
    });
    try {
      final _AiQuizGenerationData generated = await widget.generate(
        hardnessBoost: _hardnessBoost,
        onProgress: (_AiGenerationProgress p) {
          if (!mounted || runId != _runId) {
            return;
          }
          setState(() {
            _stage = p.stage;
            _stageLabel = p.label;
            _stageDetail = p.detail;
          });
        },
        onQuestionShardProgress: (_AiQuestionShardProgress p) {
          if (!mounted || runId != _runId) {
            return;
          }
          setState(() {
            if (p.index < 0) {
              return;
            }
            while (_questionShards.length <= p.index) {
              final int i = _questionShards.length;
              _questionShards.add(
                _AiQuestionShardProgress(
                  index: i,
                  state: 'queued',
                  detail: 'Awaiting worker...',
                  targetType: const <String>[
                    'MCQ',
                    'MULTI',
                    'NUMERICAL',
                  ][i % 3],
                ),
              );
            }
            _questionShards[p.index] = p;
            final String detail = p.detail.trim();
            if (detail.isNotEmpty) {
              _stage = max(_stage, 3);
              _stageLabel = 'Parallel Question Workers';
              _stageDetail = 'Q${p.index + 1}: $detail';
            }
          });
        },
      );
      if (!mounted || runId != _runId) {
        return;
      }
      setState(() {
        _loading = false;
        _data = generated;
        _questions = List<Question>.from(generated.questions);
      });
      await _revealCardsSequentially(runId);
    } catch (e) {
      if (!mounted || runId != _runId) {
        return;
      }
      setState(() {
        _loading = false;
        _error = e.toString();
      });
    }
  }

  Future<void> _revealCardsSequentially(int runId) async {
    for (int i = 0; i < _questions.length; i++) {
      if (!mounted || runId != _runId) {
        return;
      }
      await Future<void>.delayed(const Duration(milliseconds: 160));
      if (!mounted || runId != _runId) {
        return;
      }
      setState(() => _visibleCards = i + 1);
    }
  }

  String _difficultyLabel() {
    final int level = (widget.initialDifficulty + _hardnessBoost).clamp(1, 9);
    return 'L$level';
  }

  List<String> _optionRows(Question q) {
    if (q.type.toUpperCase() == 'NUMERICAL') {
      return const <String>[];
    }
    final List<String> rows = <String>[];
    for (int i = 0; i < q.options.length; i++) {
      final String option = q.options[i].trim();
      if (option.isEmpty) {
        continue;
      }
      rows.add('${String.fromCharCode(65 + i)}) $option');
    }
    return rows;
  }

  AnswerKeyCardPayload _teacherPayload(Question q, int i) {
    final List<String> options = _optionRows(q);
    final Map<String, String> optionToLabel = <String, String>{};
    for (int idx = 0; idx < q.options.length; idx++) {
      final String token = q.options[idx].trim();
      if (token.isEmpty) {
        continue;
      }
      optionToLabel[token.toLowerCase()] = String.fromCharCode(65 + idx);
    }
    String formattedAnswer = 'Not available';
    if (q.correctAnswers.isNotEmpty) {
      if (q.type.toUpperCase() == 'NUMERICAL') {
        formattedAnswer = q.correctAnswers.first;
      } else {
        final List<String> parts = <String>[];
        for (final String answer in q.correctAnswers) {
          final String token = answer.trim();
          if (token.isEmpty) {
            continue;
          }
          final String? label = optionToLabel[token.toLowerCase()];
          if (label == null) {
            parts.add(token);
          } else {
            parts.add('$label) $token');
          }
        }
        formattedAnswer = parts.isEmpty
            ? q.correctAnswers.join(', ')
            : parts.join(' | ');
      }
    }
    return AnswerKeyCardPayload(
      heroTag: 'ai_studio_${_cardSeed}_$i',
      questionIndex: i,
      questionText: q.text,
      options: options,
      correctAnswer: formattedAnswer,
      studentAnswer: 'Draft',
      solution: q.solution,
      concept: q.concept,
      marksDelta: 0,
      statusLabel:
          'DRAFT • +${q.posMark.toStringAsFixed(q.posMark % 1 == 0 ? 0 : 1)} / -${q.negMark.toStringAsFixed(q.negMark % 1 == 0 ? 0 : 1)}',
      statusColor: AppColors.primary,
      imageUrl: q.imageUrl,
    );
  }

  List<String> _parseCorrectAnswersFromInput(
    String rawInput,
    List<String> options,
    String type,
    List<String> fallback,
  ) {
    final String upperType = type.toUpperCase();
    if (upperType == 'NUMERICAL') {
      final String cleaned = rawInput.trim();
      if (cleaned.isEmpty) {
        return fallback;
      }
      return <String>[cleaned];
    }
    final Set<String> out = <String>{};
    final List<String> tokens = rawInput
        .split(RegExp(r'[,/| ]+'))
        .map((String e) => e.trim())
        .where((String e) => e.isNotEmpty)
        .toList();
    for (final String token in tokens) {
      final String up = token.toUpperCase();
      if (RegExp(r'^[A-D]$').hasMatch(up)) {
        final int idx = up.codeUnitAt(0) - 65;
        if (idx >= 0 && idx < options.length) {
          out.add(options[idx]);
        }
        continue;
      }
      for (final String option in options) {
        if (option.trim().toLowerCase() == token.toLowerCase()) {
          out.add(option);
        }
      }
    }
    if (out.isEmpty) {
      return fallback;
    }
    if (upperType == 'MCQ') {
      return <String>[out.first];
    }
    return out.toList();
  }

  Future<void> _editTeacherQuestion(int index) async {
    if (index < 0 || index >= _questions.length) {
      return;
    }
    final Question q = _questions[index];
    String selectedType = q.type.trim().toUpperCase();
    if (selectedType != 'MCQ' &&
        selectedType != 'MULTI' &&
        selectedType != 'NUMERICAL') {
      selectedType = 'MCQ';
    }
    final TextEditingController qCtrl = TextEditingController(text: q.text);
    final TextEditingController solCtrl = TextEditingController(
      text: q.solution,
    );
    final TextEditingController corrCtrl = TextEditingController(
      text: q.correctAnswers.join(', '),
    );
    final TextEditingController sectionCtrl = TextEditingController(
      text: q.section,
    );
    final TextEditingController conceptCtrl = TextEditingController(
      text: q.concept,
    );
    final TextEditingController diffCtrl = TextEditingController(
      text: q.difficultyLabel,
    );
    final TextEditingController posCtrl = TextEditingController(
      text: q.posMark.toString(),
    );
    final TextEditingController negCtrl = TextEditingController(
      text: q.negMark.toString(),
    );
    final String existingReference =
        RegExp(
          r'(?i)reference\s*:\s*(.+)$',
          multiLine: true,
        ).firstMatch(q.solution)?.group(1)?.trim() ??
        '';
    final TextEditingController sourceCtrl = TextEditingController(
      text: existingReference,
    );
    final List<TextEditingController> optCtrls =
        List<TextEditingController>.generate(
          4,
          (int i) =>
              TextEditingController(text: q.options.elementAtOrNull(i) ?? ''),
        );
    final bool? save = await showModalBottomSheet<bool>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (BuildContext context) {
        final EdgeInsets insets = MediaQuery.of(context).viewInsets;
        return Padding(
          padding: EdgeInsets.fromLTRB(12, 0, 12, 12 + insets.bottom),
          child: LiquidGlass(
            borderRadius: BorderRadius.circular(24),
            padding: const EdgeInsets.fromLTRB(14, 14, 14, 12),
            child: StatefulBuilder(
              builder:
                  (
                    BuildContext context,
                    void Function(void Function()) setLocalState,
                  ) {
                    return SingleChildScrollView(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          Text(
                            'Edit Question ${index + 1}',
                            style: const TextStyle(
                              fontWeight: FontWeight.w800,
                              fontSize: 16,
                            ),
                          ),
                          const SizedBox(height: 10),
                          Row(
                            children: <Widget>[
                              Expanded(
                                child: DropdownButtonFormField<String>(
                                  value: selectedType,
                                  decoration: const InputDecoration(
                                    labelText: 'Question Type',
                                  ),
                                  items: const <DropdownMenuItem<String>>[
                                    DropdownMenuItem<String>(
                                      value: 'MCQ',
                                      child: Text('MCQ (Single Correct)'),
                                    ),
                                    DropdownMenuItem<String>(
                                      value: 'MULTI',
                                      child: Text('MULTI (Multi Correct)'),
                                    ),
                                    DropdownMenuItem<String>(
                                      value: 'NUMERICAL',
                                      child: Text('NUMERICAL'),
                                    ),
                                  ],
                                  onChanged: (String? value) {
                                    if (value == null) {
                                      return;
                                    }
                                    setLocalState(() {
                                      selectedType = value;
                                    });
                                  },
                                ),
                              ),
                              const SizedBox(width: 8),
                              SizedBox(
                                width: 92,
                                child: TextField(
                                  controller: posCtrl,
                                  keyboardType:
                                      const TextInputType.numberWithOptions(
                                        signed: true,
                                        decimal: true,
                                      ),
                                  decoration: const InputDecoration(
                                    labelText: '+Marks',
                                  ),
                                ),
                              ),
                              const SizedBox(width: 8),
                              SizedBox(
                                width: 92,
                                child: TextField(
                                  controller: negCtrl,
                                  keyboardType:
                                      const TextInputType.numberWithOptions(
                                        signed: true,
                                        decimal: true,
                                      ),
                                  decoration: const InputDecoration(
                                    labelText: '-Marks',
                                  ),
                                ),
                              ),
                            ],
                          ),
                          const SizedBox(height: 10),
                          TextField(
                            controller: qCtrl,
                            minLines: 3,
                            maxLines: 7,
                            decoration: const InputDecoration(
                              labelText: 'Question',
                            ),
                          ),
                          const SizedBox(height: 10),
                          if (selectedType != 'NUMERICAL')
                            ...List<Widget>.generate(4, (int i) {
                              return Padding(
                                padding: const EdgeInsets.only(bottom: 8),
                                child: TextField(
                                  controller: optCtrls[i],
                                  decoration: InputDecoration(
                                    labelText:
                                        'Option ${String.fromCharCode(65 + i)}',
                                  ),
                                ),
                              );
                            }),
                          TextField(
                            controller: corrCtrl,
                            decoration: InputDecoration(
                              labelText: selectedType == 'NUMERICAL'
                                  ? 'Correct Answer (integer allowed)'
                                  : selectedType == 'MULTI'
                                  ? 'Correct (e.g. A,C)'
                                  : 'Correct (A/B/C/D or text)',
                            ),
                          ),
                          const SizedBox(height: 10),
                          TextField(
                            controller: sectionCtrl,
                            decoration: const InputDecoration(
                              labelText: 'Section/Tags',
                            ),
                          ),
                          const SizedBox(height: 8),
                          TextField(
                            controller: conceptCtrl,
                            decoration: const InputDecoration(
                              labelText: 'Concept',
                            ),
                          ),
                          const SizedBox(height: 8),
                          TextField(
                            controller: diffCtrl,
                            decoration: const InputDecoration(
                              labelText: 'Difficulty Label',
                            ),
                          ),
                          const SizedBox(height: 8),
                          TextField(
                            controller: sourceCtrl,
                            decoration: const InputDecoration(
                              labelText: 'Source / Reference (optional)',
                            ),
                          ),
                          const SizedBox(height: 10),
                          TextField(
                            controller: solCtrl,
                            minLines: 5,
                            maxLines: 12,
                            decoration: const InputDecoration(
                              labelText: 'Detailed Solution',
                            ),
                          ),
                          const SizedBox(height: 12),
                          Row(
                            children: <Widget>[
                              Expanded(
                                child: OutlinedButton(
                                  onPressed: () =>
                                      Navigator.pop(context, false),
                                  child: const Text('Cancel'),
                                ),
                              ),
                              const SizedBox(width: 8),
                              Expanded(
                                child: ElevatedButton(
                                  onPressed: () => Navigator.pop(context, true),
                                  child: const Text('Save'),
                                ),
                              ),
                            ],
                          ),
                        ],
                      ),
                    );
                  },
            ),
          ),
        );
      },
    );
    final String nextText = qCtrl.text.trim();
    String nextSolution = solCtrl.text.trim();
    final String nextType = selectedType;
    final List<String> nextOptions = List<String>.generate(4, (int i) {
      final String token = optCtrls[i].text.trim();
      if (nextType == 'NUMERICAL') {
        return '';
      }
      return token;
    });
    final List<String> fallbackCorrect = q.correctAnswers.isEmpty
        ? (nextType == 'NUMERICAL'
              ? <String>['0']
              : <String>[
                  nextOptions.firstWhere(
                    (String e) => e.trim().isNotEmpty,
                    orElse: () => 'Option A',
                  ),
                ])
        : List<String>.from(q.correctAnswers);
    List<String> nextCorrect = _parseCorrectAnswersFromInput(
      corrCtrl.text,
      nextOptions,
      nextType,
      fallbackCorrect,
    );
    if (nextType == 'MCQ' && nextCorrect.isNotEmpty) {
      nextCorrect = <String>[nextCorrect.first];
    }
    if (nextType == 'MULTI' && nextCorrect.length < 2) {
      final List<String> nonEmpty = nextOptions
          .where((String e) => e.trim().isNotEmpty)
          .take(2)
          .toList();
      if (nonEmpty.length == 2) {
        nextCorrect = nonEmpty;
      }
    }
    if (nextType == 'NUMERICAL' && nextCorrect.isEmpty) {
      nextCorrect = <String>['0'];
    }
    final String sourceRef = sourceCtrl.text.trim();
    if (sourceRef.isNotEmpty &&
        !nextSolution.toLowerCase().contains(sourceRef.toLowerCase())) {
      nextSolution = nextSolution.trim().isEmpty
          ? 'Reference: $sourceRef'
          : '$nextSolution\nReference: $sourceRef';
    }
    final double nextPos = double.tryParse(posCtrl.text.trim()) ?? q.posMark;
    final double nextNeg = double.tryParse(negCtrl.text.trim()) ?? q.negMark;
    final String nextSection = sectionCtrl.text.trim().isEmpty
        ? q.section
        : sectionCtrl.text.trim();
    final String nextConcept = conceptCtrl.text.trim().isEmpty
        ? q.concept
        : conceptCtrl.text.trim();
    final String nextDifficulty = diffCtrl.text.trim().isEmpty
        ? q.difficultyLabel
        : diffCtrl.text.trim();
    qCtrl.dispose();
    solCtrl.dispose();
    corrCtrl.dispose();
    sectionCtrl.dispose();
    conceptCtrl.dispose();
    diffCtrl.dispose();
    posCtrl.dispose();
    negCtrl.dispose();
    sourceCtrl.dispose();
    for (final TextEditingController c in optCtrls) {
      c.dispose();
    }
    if (save != true || nextText.isEmpty || !mounted) {
      return;
    }
    setState(() {
      _questions[index] = Question(
        text: nextText,
        imageUrl: q.imageUrl,
        type: nextType,
        section: nextSection,
        posMark: nextPos,
        negMark: nextNeg,
        options: nextOptions,
        correctAnswers: nextCorrect,
        solution: nextSolution,
        concept: nextConcept,
        difficultyLabel: nextDifficulty,
        confidenceScore: q.confidenceScore,
        adaptiveScore: q.adaptiveScore,
      );
    });
  }

  Color _shardTint(String state) {
    final String normalized = state.trim().toLowerCase();
    if (normalized == 'done') {
      return const Color(0xFF059669);
    }
    if (normalized == 'failed') {
      return const Color(0xFFDC2626);
    }
    if (normalized == 'generating') {
      return const Color(0xFF2563EB);
    }
    return const Color(0xFF64748B);
  }

  IconData _shardIcon(String state) {
    final String normalized = state.trim().toLowerCase();
    if (normalized == 'done') {
      return Icons.check_circle_rounded;
    }
    if (normalized == 'failed') {
      return Icons.error_outline_rounded;
    }
    if (normalized == 'generating') {
      return Icons.auto_awesome_rounded;
    }
    return Icons.schedule_rounded;
  }

  Widget _buildShardCard(_AiQuestionShardProgress shard) {
    final String state = shard.state.trim().toLowerCase();
    final Color tint = _shardTint(state);
    final bool done = state == 'done';
    final String detail = shard.detail.trim().isEmpty
        ? (state == 'queued' ? 'Queued' : state)
        : shard.detail.trim();
    final String type = shard.targetType.trim().isEmpty
        ? const <String>['MCQ', 'MULTI', 'NUMERICAL'][shard.index % 3]
        : shard.targetType.trim().toUpperCase();
    final String scope = shard.subtopics.isEmpty
        ? 'General'
        : shard.subtopics.take(2).join(' • ');
    final String source = shard.source.trim().isEmpty
        ? ''
        : shard.source.trim();
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0.94, end: done ? 1.0 : 0.98),
      duration: Duration(milliseconds: done ? 420 : 260),
      curve: Curves.easeOutBack,
      builder: (_, double value, Widget? child) {
        return Opacity(
          opacity: value.clamp(0.0, 1.0),
          child: Transform.translate(
            offset: Offset(0, (1 - value) * 12),
            child: child,
          ),
        );
      },
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 280),
        curve: Curves.easeOutCubic,
        padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(18),
          color: tint.withOpacity(done ? 0.20 : 0.12),
          border: Border.all(color: tint.withOpacity(0.44)),
          boxShadow: <BoxShadow>[
            BoxShadow(
              color: tint.withOpacity(done ? 0.20 : 0.08),
              blurRadius: done ? 16 : 10,
              offset: const Offset(0, 5),
            ),
          ],
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: <Widget>[
            Row(
              children: <Widget>[
                AnimatedSwitcher(
                  duration: const Duration(milliseconds: 220),
                  child: Icon(
                    _shardIcon(state),
                    key: ValueKey<String>('shard_${shard.index}_$state'),
                    size: 16,
                    color: tint,
                  ),
                ),
                const SizedBox(width: 6),
                Text(
                  'Q${shard.index + 1}',
                  style: const TextStyle(
                    fontWeight: FontWeight.w800,
                    fontSize: 12,
                  ),
                ),
                const Spacer(),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 3,
                  ),
                  decoration: BoxDecoration(
                    borderRadius: BorderRadius.circular(999),
                    color: Colors.white.withOpacity(0.34),
                  ),
                  child: Text(
                    type,
                    style: TextStyle(
                      fontSize: 10.5,
                      fontWeight: FontWeight.w700,
                      color: tint,
                    ),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 8),
            Text(
              detail,
              maxLines: 2,
              overflow: TextOverflow.ellipsis,
              style: const TextStyle(
                fontSize: 11.5,
                fontWeight: FontWeight.w600,
              ),
            ),
            const SizedBox(height: 6),
            Text(
              scope,
              maxLines: 1,
              overflow: TextOverflow.ellipsis,
              style: const TextStyle(fontSize: 10.5, color: Colors.black54),
            ),
            if (source.isNotEmpty) ...<Widget>[
              const SizedBox(height: 4),
              Text(
                source,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                style: TextStyle(
                  fontSize: 10,
                  color: tint.withOpacity(0.9),
                  fontWeight: FontWeight.w700,
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }

  Widget _buildLoadingBody() {
    final double ratio = (_stage / 5).clamp(0.0, 1.0);
    return SafeArea(
      child: SingleChildScrollView(
