  Widget _buildStudentCard(Question q, int index) {
    final List<String> options = _optionRows(q);
    final String difficulty = q.difficultyLabel.trim();
    final double confidence = q.confidenceScore;
    final bool hasConfidence = confidence >= 0;
    return LiquidGlass(
      borderRadius: BorderRadius.circular(26),
      padding: const EdgeInsets.fromLTRB(16, 16, 16, 14),
      color: AppColors.primary.withOpacity(0.09),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Row(
            children: <Widget>[
              Text(
                'Q${index + 1}',
                style: const TextStyle(
                  fontWeight: FontWeight.w800,
                  fontSize: 15,
                ),
              ),
              const Spacer(),
              Container(
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 5,
                ),
                decoration: BoxDecoration(
                  color: AppColors.primary.withOpacity(0.12),
                  borderRadius: BorderRadius.circular(999),
                ),
                child: Text(
                  q.type.toUpperCase(),
                  style: const TextStyle(
                    fontWeight: FontWeight.w700,
                    fontSize: 11.5,
                    color: AppColors.primary,
                  ),
                ),
              ),
            ],
          ),
          if (difficulty.isNotEmpty || hasConfidence) ...<Widget>[
            const SizedBox(height: 8),
            Wrap(
              spacing: 8,
              runSpacing: 6,
              children: <Widget>[
                if (difficulty.isNotEmpty)
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: Colors.black.withOpacity(0.06),
                      borderRadius: BorderRadius.circular(999),
                    ),
                    child: Text(
                      difficulty,
                      style: const TextStyle(
                        fontWeight: FontWeight.w700,
                        fontSize: 11.5,
                      ),
                    ),
                  ),
                if (hasConfidence)
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: Colors.green.withOpacity(0.12),
                      borderRadius: BorderRadius.circular(999),
                    ),
                    child: Text(
                      '${(confidence * 100).round()}% confidence',
                      style: const TextStyle(
                        fontWeight: FontWeight.w700,
                        fontSize: 11.5,
                        color: Color(0xFF0F766E),
                      ),
                    ),
                  ),
              ],
            ),
          ],
          const SizedBox(height: 10),
          SmartText(
            q.text,
            style: const TextStyle(fontWeight: FontWeight.w600, height: 1.34),
          ),
          if (options.isNotEmpty) ...<Widget>[
            const SizedBox(height: 12),
            ...options.map(
              (String option) => Padding(
                padding: const EdgeInsets.only(bottom: 6),
                child: SmartText(option),
              ),
            ),
          ],
        ],
      ),
    );
  }

  Widget _buildTeacherCard(Question q, int index) {
    final AnswerKeyCardPayload payload = _teacherPayload(q, index);
    return Dismissible(
      key: ValueKey<String>('teacher_swipe_${payload.heroTag}'),
      direction: DismissDirection.startToEnd,
      confirmDismiss: (_) async {
        await _editTeacherQuestion(index);
        return false;
      },
      background: Container(
        alignment: Alignment.centerLeft,
        padding: const EdgeInsets.symmetric(horizontal: 18),
        decoration: BoxDecoration(
          color: const Color(0xFF0EA5E9).withOpacity(0.20),
          borderRadius: BorderRadius.circular(24),
        ),
        child: const Row(
          children: <Widget>[
            Icon(Icons.edit_rounded, color: Color(0xFF0369A1)),
            SizedBox(width: 8),
            Text(
              'Swipe right to edit',
              style: TextStyle(
                color: Color(0xFF075985),
                fontWeight: FontWeight.w700,
              ),
            ),
          ],
        ),
      ),
      child: SizedBox(
        height: 430,
        child: AnswerKeyFlipCard(
          payload: payload,
          teacherMode: true,
          showActionButtons: false,
          onAskAi: () {},
          onRaiseDoubt: () {},
        ),
      ),
    );
  }

  Widget _buildReadyBody() {
    final int total = _questions.length;
    final bool teacherMode = widget.teacherMode;
    return Column(
      children: <Widget>[
        Padding(
          padding: const EdgeInsets.fromLTRB(12, 10, 12, 0),
          child: LiquidGlass(
            padding: const EdgeInsets.all(12),
            child: Row(
              children: <Widget>[
                Expanded(
                  child: Text(
                    teacherMode
                        ? 'Teacher review mode • swipe right on any card to edit'
                        : 'Student preview mode • question + options only',
                    style: const TextStyle(
                      fontWeight: FontWeight.w700,
                      fontSize: 12.5,
                    ),
                  ),
                ),
                const SizedBox(width: 8),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 10,
                    vertical: 5,
                  ),
                  decoration: BoxDecoration(
                    color: AppColors.primary.withOpacity(0.12),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Text(
                    'Hardness ${_difficultyLabel()}',
                    style: const TextStyle(
                      color: AppColors.primary,
                      fontWeight: FontWeight.w700,
                      fontSize: 11.5,
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
        Expanded(
          child: ListView.separated(
            padding: const EdgeInsets.fromLTRB(12, 12, 12, 10),
            itemCount: total,
            separatorBuilder: (_, __) => const SizedBox(height: 10),
            itemBuilder: (_, int i) {
              if (i >= _visibleCards) {
                return LiquidGlass(
                  borderRadius: BorderRadius.circular(24),
                  padding: const EdgeInsets.all(14),
                  child: Row(
                    children: const <Widget>[
                      SizedBox(
                        width: 16,
                        height: 16,
                        child: CircularProgressIndicator(strokeWidth: 2),
                      ),
                      SizedBox(width: 10),
                      Text('Generating next question...'),
                    ],
                  ),
                );
              }
              final Question q = _questions[i];
              return TweenAnimationBuilder<double>(
                duration: const Duration(milliseconds: 280),
                tween: Tween<double>(begin: 0, end: 1),
                curve: Curves.easeOutCubic,
                builder: (_, double value, Widget? child) {
                  return Opacity(
                    opacity: value,
                    child: Transform.translate(
                      offset: Offset(0, (1 - value) * 12),
                      child: child,
                    ),
                  );
                },
                child: teacherMode
                    ? _buildTeacherCard(q, i)
                    : _buildStudentCard(q, i),
              );
            },
          ),
        ),
      ],
    );
  }

  Widget _buildBottomBar() {
    final bool ready = !_loading && _questions.isNotEmpty;
    final bool teacherMode = widget.teacherMode;
    return SafeArea(
      top: false,
      child: Padding(
        padding: const EdgeInsets.fromLTRB(12, 8, 12, 12),
        child: Row(
          children: <Widget>[
            Expanded(
              child: OutlinedButton.icon(
                onPressed: _loading ? null : () => _runGeneration(harder: true),
                icon: const Icon(Icons.trending_up_rounded),
                label: const Text('Regenerate Harder'),
              ),
            ),
            const SizedBox(width: 8),
            Expanded(
              child: ElevatedButton.icon(
                onPressed: !ready
                    ? null
                    : () => Navigator.pop(
                        context,
                        _AiGenerationStudioResult(
                          action: teacherMode
                              ? _AiGenerationAction.publish
                              : _AiGenerationAction.startExam,
                          data: _data!,
                          questions: List<Question>.from(_questions),
                        ),
                      ),
                icon: Icon(
                  teacherMode
                      ? Icons.publish_rounded
                      : Icons.play_arrow_rounded,
                ),
                label: Text(teacherMode ? 'Publish' : 'Start Exam'),
              ),
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        leading: IconButton(
          icon: const Icon(Icons.arrow_back),
          onPressed: () {
            if (!_loading &&
                widget.teacherMode &&
                _data != null &&
                _questions.isNotEmpty) {
              Navigator.pop(
                context,
                _AiGenerationStudioResult(
                  action: _AiGenerationAction.keepDraft,
                  data: _data!,
                  questions: List<Question>.from(_questions),
                ),
              );
              return;
            }
            Navigator.pop(context);
          },
        ),
        title: Text(
          widget.teacherMode ? 'AI Draft Studio' : 'AI Practice Studio',
        ),
        actions: <Widget>[
          Padding(
            padding: const EdgeInsets.only(right: 12),
            child: Center(
              child: Text(
                '${widget.initialQuestionCount} Q',
                style: const TextStyle(fontWeight: FontWeight.w700),
              ),
            ),
          ),
        ],
      ),
      body: _loading
          ? _buildLoadingBody()
          : _error.trim().isNotEmpty
          ? Center(
              child: Padding(
                padding: const EdgeInsets.all(16),
                child: LiquidGlass(
                  borderRadius: BorderRadius.circular(24),
                  padding: const EdgeInsets.all(16),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    children: <Widget>[
                      const Icon(Icons.error_outline_rounded, size: 30),
                      const SizedBox(height: 10),
                      Text(
                        _error,
                        textAlign: TextAlign.center,
                        style: const TextStyle(fontSize: 13),
                      ),
                      const SizedBox(height: 12),
                      ElevatedButton.icon(
                        onPressed: () => _runGeneration(harder: false),
                        icon: const Icon(Icons.refresh_rounded),
                        label: const Text('Retry'),
                      ),
                    ],
                  ),
                ),
              ),
            )
          : _buildReadyBody(),
      bottomNavigationBar: _buildBottomBar(),
    );
  }
}

class _DraftAnswerKeyPreviewScreen extends StatefulWidget {
  const _DraftAnswerKeyPreviewScreen({
    required this.title,
    required this.cards,
    required this.onAskAi,
    required this.onSendToTeacher,
    this.canEdit = false,
    this.onEditQuestion,
  });

  final String title;
  final List<AnswerKeyCardPayload> cards;
  final Future<void> Function(int index) onAskAi;
  final Future<void> Function(int index) onSendToTeacher;
  final bool canEdit;
  final Future<void> Function(int index)? onEditQuestion;

  @override
  State<_DraftAnswerKeyPreviewScreen> createState() =>
      _DraftAnswerKeyPreviewScreenState();
}

class _DraftAnswerKeyPreviewScreenState
    extends State<_DraftAnswerKeyPreviewScreen> {
  int _idx = 0;
  late final PageController _pageCtrl;

  @override
  void initState() {
    super.initState();
    _pageCtrl = PageController();
  }

  @override
  void dispose() {
    _pageCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final int total = widget.cards.length;
    return Scaffold(
      appBar: AppBar(
        title: const Text('Draft Answer Key'),
        actions: <Widget>[
          if (widget.canEdit && widget.onEditQuestion != null)
            IconButton(
              tooltip: 'Edit question',
              onPressed: () {
                final Future<void> Function(int index)? edit =
                    widget.onEditQuestion;
                if (edit == null) {
                  return;
                }
                final int target = _idx;
                Navigator.pop(context);
                unawaited(edit(target));
              },
              icon: const Icon(Icons.edit_rounded),
            ),
        ],
      ),
      body: Column(
        children: <Widget>[
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 12, 14, 0),
            child: LiquidGlass(
              padding: const EdgeInsets.all(14),
              child: Column(
                children: <Widget>[
                  Row(
                    children: <Widget>[
                      Expanded(
                        child: Text(
                          widget.title.trim().isEmpty
                              ? 'AI Draft'
                              : widget.title.trim(),
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            fontWeight: FontWeight.w800,
                            fontSize: 15,
                          ),
                        ),
                      ),
                      const SizedBox(width: 10),
                      Text(
                        'Q ${_idx + 1}/$total',
                        style: const TextStyle(fontWeight: FontWeight.w700),
                      ),
                    ],
                  ),
                  const SizedBox(height: 8),
                  LinearProgressIndicator(
                    value: total == 0 ? 0 : (_idx + 1) / total,
                    minHeight: 7,
                    borderRadius: BorderRadius.circular(10),
                  ),
                ],
              ),
            ),
          ),
          Expanded(
            child: PageView.builder(
              controller: _pageCtrl,
              itemCount: widget.cards.length,
              onPageChanged: (int value) => setState(() => _idx = value),
              itemBuilder: (_, int i) {
                return Padding(
                  padding: const EdgeInsets.all(12),
                  child: AnswerKeyFlipCard(
                    payload: widget.cards[i],
                    teacherMode: true,
                    onAskAi: () => unawaited(widget.onAskAi(i)),
                    onRaiseDoubt: () => unawaited(widget.onSendToTeacher(i)),
                  ),
                );
              },
            ),
          ),
          Padding(
            padding: const EdgeInsets.fromLTRB(12, 2, 12, 10),
            child: Row(
              children: <Widget>[
                Expanded(
                  child: OutlinedButton(
                    onPressed: _idx > 0
                        ? () {
                            _pageCtrl.previousPage(
                              duration: const Duration(milliseconds: 220),
                              curve: Curves.easeOutCubic,
                            );
                          }
                        : null,
                    child: const Text('Previous'),
                  ),
                ),
                const SizedBox(width: 8),
                Expanded(
                  child: ElevatedButton(
                    onPressed: _idx < widget.cards.length - 1
                        ? () {
                            _pageCtrl.nextPage(
                              duration: const Duration(milliseconds: 220),
                              curve: Curves.easeOutCubic,
                            );
                          }
                        : null,
                    child: const Text('Next'),
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

class TeacherAddMaterialScreen extends StatefulWidget {
  const TeacherAddMaterialScreen({super.key});

  @override
  State<TeacherAddMaterialScreen> createState() =>
      _TeacherAddMaterialScreenState();
}

class _TeacherAddMaterialScreenState extends State<TeacherAddMaterialScreen> {
  Uint8List? _pickedBytes;
  String? _pickedFileName;

  final TextEditingController _titleCtrl = TextEditingController();
  final TextEditingController _descriptionCtrl = TextEditingController();
  final TextEditingController _notesCtrl = TextEditingController();
  final TextEditingController _urlCtrl = TextEditingController();

  String _type = 'pdf';
  String _subject = 'Physics';
  bool _loading = false;

  String _selectedClass = 'Class 11';
  List<String> _selectedChapters = <String>[];

  Future<void> _pickFile() async {
    final FilePickerResult? result = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      allowedExtensions: <String>['pdf', 'jpg', 'jpeg', 'png', 'webp', 'heic'],
      withData: true,
    );

    if (result == null) {
      return;
    }

    final PlatformFile first = result.files.first;
    Uint8List? bytes = first.bytes;
    if (bytes == null && (first.path ?? '').trim().isNotEmpty) {
      try {
        bytes = await File(first.path!).readAsBytes();
      } catch (_) {
        bytes = null;
      }
    }
    if (bytes == null || bytes.isEmpty) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Unable to read selected file')),
      );
      return;
    }
    setState(() {
      _pickedBytes = bytes;
      _pickedFileName = first.name;
      _titleCtrl.text = _pickedFileName!;
      if (_pickedFileName!.toLowerCase().endsWith('.pdf')) {
        _type = 'pdf';
      } else {
        _type = 'image';
      }
    });
  }

  Future<String> _uploadPickedFile() async {
    if (_pickedBytes == null || _pickedFileName == null) {
      return '';
    }

    final String base64Data = base64Encode(_pickedBytes!);
    final String lowerName = _pickedFileName!.toLowerCase();
    final String mime = lowerName.endsWith('.pdf')
        ? 'application/pdf'
        : (lowerName.endsWith('.png') ? 'image/png' : 'image/jpeg');
    final String dataUrl = 'data:$mime;base64,$base64Data';
    return backendService.uploadFileData(
      fileName: _pickedFileName!,
      dataUrl: dataUrl,
    );
  }

  Future<void> _submit() async {
    if (Session.userRole != 'teacher') {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Only teachers can add study material')),
      );
      return;
    }
    if (_selectedChapters.isEmpty || _titleCtrl.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Select chapters and enter title')),
      );
      return;
    }

    setState(() => _loading = true);

    try {
      String url = _urlCtrl.text.trim();
      if (_type != 'note' && _pickedBytes != null) {
        url = await _uploadPickedFile();
        _urlCtrl.text = url;
      }

      if (_type != 'note' && url.isEmpty) {
        throw Exception('URL is empty');
      }
      if (_type == 'note' && _notesCtrl.text.trim().isEmpty) {
        throw Exception('Please enter notes content.');
      }

      final Map<String, dynamic> response = await backendService
          .addMaterial(<String, dynamic>{
            'class': _selectedClass,
            'subject': _subject,
            'chapters': _selectedChapters.join(', '),
            'title': _titleCtrl.text.trim(),
            'type': _type,
            'url': _type == 'note' ? 'inline://note' : url,
            'description': _descriptionCtrl.text.trim(),
            'notes': _notesCtrl.text.trim(),
            'role': Session.userRole,
          });

      if (!backendService.isSuccessfulResponse(response)) {
        throw Exception('Server rejected: ${jsonEncode(response)}');
      }

      if (!mounted) {
        return;
      }

      await notificationService.addAiNotification(
        title: 'Study Material Added',
        body: _titleCtrl.text.trim(),
        type: 'system',
      );
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(const SnackBar(content: Text('Uploaded successfully')));

      _titleCtrl.clear();
      _descriptionCtrl.clear();
      _notesCtrl.clear();
      _urlCtrl.clear();
      setState(() {
        _pickedBytes = null;
        _pickedFileName = null;
        _selectedChapters = <String>[];
      });
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Failed: $e')));
      }
    } finally {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  @override
  void dispose() {
    _titleCtrl.dispose();
    _descriptionCtrl.dispose();
    _notesCtrl.dispose();
    _urlCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Add Study Material')),
      body: SingleChildScrollView(
        padding: const EdgeInsets.fromLTRB(16, 14, 16, 22),
        child: Column(
          children: <Widget>[
            LiquidGlass(
              padding: const EdgeInsets.all(14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text(
                    'Target Class & Chapters',
                    style: TextStyle(fontWeight: FontWeight.w800, fontSize: 15),
                  ),
                  const SizedBox(height: 10),
                  Row(
                    children: <Widget>[
                      Expanded(
                        child: OutlinedButton.icon(
                          onPressed: () async {
                            final String? selected =
                                await showModalBottomSheet<String>(
                                  context: context,
                                  builder: (_) => ListView(
                                    children:
                                        <String>[
                                              'Class 11',
                                              'Class 12',
                                              '11 + 12',
                                            ]
                                            .map(
                                              (String e) => ListTile(
                                                title: Text(e),
                                                onTap: () =>
                                                    Navigator.pop(context, e),
                                              ),
                                            )
                                            .toList(),
                                  ),
                                );
                            if (selected == null) {
                              return;
                            }
                            setState(() {
                              _selectedClass = selected == '11 + 12'
                                  ? 'Class 11+12'
                                  : selected;
                              _selectedChapters.clear();
                            });
                          },
                          icon: const Icon(Icons.school_rounded),
                          label: Text(_selectedClass),
                        ),
                      ),
                      const SizedBox(width: 10),
                      Expanded(
                        child: OutlinedButton.icon(
                          onPressed: () async {
                            final Map<String, dynamic>? result =
                                await showClassChapterPicker(
                                  context,
                                  currentClass: _selectedClass == 'Class 11+12'
                                      ? '11 + 12'
                                      : _selectedClass,
                                  currentSubject: _subject,
                                  currentChapters: _selectedChapters,
                                );
                            if (result == null) {
                              return;
                            }
                            setState(() {
                              final String selected =
                                  (result['class'] ?? 'Class 11').toString();
                              _selectedClass = selected == '11 + 12'
                                  ? 'Class 11+12'
                                  : selected;
                              final String pickedSubject =
                                  (result['subject'] ?? '').toString().trim();
                              if (pickedSubject.isNotEmpty) {
                                _subject = pickedSubject;
                              }
                              _selectedChapters = List<String>.from(
                                result['chapters'] as List<dynamic>,
                              );
                            });
                          },
                          icon: const Icon(Icons.menu_book_rounded),
                          label: Text(
                            _selectedChapters.isEmpty
                                ? 'Select Chapters'
                                : '${_selectedChapters.length} Chapters',
                          ),
                        ),
                      ),
                    ],
                  ),
                  if (_selectedChapters.isNotEmpty) ...<Widget>[
                    const SizedBox(height: 8),
                    Wrap(
                      spacing: 6,
                      runSpacing: 6,
                      children: _selectedChapters
                          .map((String chapter) => Chip(label: Text(chapter)))
                          .toList(),
                    ),
                  ],
                  const SizedBox(height: 10),
                  DropdownButtonFormField<String>(
                    value: _subject,
                    decoration: const InputDecoration(labelText: 'Subject'),
                    items: const <DropdownMenuItem<String>>[
                      DropdownMenuItem(
                        value: 'Physics',
                        child: Text('Physics'),
                      ),
                      DropdownMenuItem(
                        value: 'Chemistry',
                        child: Text('Chemistry'),
                      ),
                      DropdownMenuItem(
                        value: 'Mathematics',
                        child: Text('Mathematics'),
                      ),
                      DropdownMenuItem(
                        value: 'Biology',
                        child: Text('Biology'),
                      ),
                      DropdownMenuItem(
                        value: 'General',
                        child: Text('General'),
                      ),
                    ],
                    onChanged: (String? v) =>
                        setState(() => _subject = v ?? 'Physics'),
                  ),
                ],
              ),
            ),
            const SizedBox(height: 12),
            LiquidGlass(
              padding: const EdgeInsets.all(14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text(
                    'Material Details',
                    style: TextStyle(fontWeight: FontWeight.w800, fontSize: 15),
                  ),
                  const SizedBox(height: 10),
                  TextField(
                    controller: _titleCtrl,
                    decoration: const InputDecoration(labelText: 'Title'),
                  ),
                  const SizedBox(height: 10),
                  TextField(
                    controller: _descriptionCtrl,
                    maxLines: 2,
                    decoration: const InputDecoration(labelText: 'Description'),
                  ),
                  const SizedBox(height: 10),
                  DropdownButtonFormField<String>(
                    value: _type,
                    decoration: const InputDecoration(labelText: 'Type'),
                    items: const <DropdownMenuItem<String>>[
                      DropdownMenuItem(value: 'pdf', child: Text('PDF')),
                      DropdownMenuItem(value: 'image', child: Text('Image')),
                      DropdownMenuItem(value: 'note', child: Text('Note')),
                    ],
                    onChanged: (String? v) =>
                        setState(() => _type = v ?? 'pdf'),
                  ),
                ],
              ),
            ),
            const SizedBox(height: 12),
            LiquidGlass(
              padding: const EdgeInsets.all(14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  Text(
                    _type == 'note' ? 'Notes Content' : 'File Source',
                    style: const TextStyle(
                      fontWeight: FontWeight.w800,
                      fontSize: 15,
                    ),
                  ),
                  const SizedBox(height: 10),
                  if (_type != 'note') ...<Widget>[
                    OutlinedButton.icon(
                      onPressed: _pickFile,
                      icon: const Icon(Icons.attach_file_rounded),
                      label: const Text('Pick PDF / Image'),
                    ),
                    if (_pickedFileName != null)
                      Padding(
                        padding: const EdgeInsets.only(top: 8),
                        child: Text('Selected: $_pickedFileName'),
                      ),
                    const SizedBox(height: 10),
                    TextField(
                      controller: _urlCtrl,
                      decoration: const InputDecoration(
                        labelText: 'File URL (auto-filled if file picked)',
                      ),
                    ),
                  ] else ...<Widget>[
                    TextField(
                      controller: _notesCtrl,
                      minLines: 6,
                      maxLines: 14,
                      decoration: const InputDecoration(
                        labelText: 'Notes Content',
                        hintText: 'Type or paste your chapter notes here...',
                      ),
                    ),
                  ],
                ],
              ),
            ),
            const SizedBox(height: 14),
            SizedBox(
              width: double.infinity,
              child: ElevatedButton.icon(
                onPressed: _loading ? null : _submit,
                icon: _loading
                    ? const SizedBox(
                        width: 16,
                        height: 16,
                        child: CircularProgressIndicator(strokeWidth: 2),
                      )
                    : const Icon(Icons.cloud_upload_rounded),
                label: Text(_loading ? 'Uploading...' : 'Upload Material'),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class StudyMaterialScreen extends StatefulWidget {
  const StudyMaterialScreen({
    super.key,
    required this.studentName,
    this.enableAiActions = true,
    this.initialClassFilter,
    this.initialSubjectFilter,
    this.onOpenAiHub,
    this.onQuickAskAi,
  });

  final String studentName;
  final bool enableAiActions;
  final String? initialClassFilter;
  final String? initialSubjectFilter;
  final VoidCallback? onOpenAiHub;
  final VoidCallback? onQuickAskAi;

  @override
  State<StudyMaterialScreen> createState() => _StudyMaterialScreenState();
}

class _StudyMaterialScreenState extends State<StudyMaterialScreen> {
  bool _loading = true;
  List<StudyMaterialItem> _items = <StudyMaterialItem>[];
  final TextEditingController _searchCtrl = TextEditingController();
  String _query = '';
  String _classFilter = 'Class 11';
  String _subjectFilter = 'Physics';
  List<String> _recentMaterialIds = <String>[];

  @override
  void initState() {
    super.initState();
    if ((widget.initialClassFilter ?? '').trim().isNotEmpty) {
      _classFilter = widget.initialClassFilter!.trim();
    }
    if ((widget.initialSubjectFilter ?? '').trim().isNotEmpty) {
      _subjectFilter = widget.initialSubjectFilter!.trim();
    }
    _loadRecent();
    _load();
  }

  Future<void> _load() async {
    setState(() => _loading = true);
    try {
      final List<dynamic> list = await backendService.fetchStudyMaterials();
      final List<StudyMaterialItem> temp = list
          .map(
            (dynamic e) =>
                StudyMaterialItem.fromJson(Map<String, dynamic>.from(e as Map)),
          )
          .where(
            (StudyMaterialItem e) =>
                e.title.isNotEmpty &&
                (e.url.isNotEmpty ||
                    (e.type.toLowerCase() == 'note' &&
                        e.notes.trim().isNotEmpty)),
          )
          .toList();
      if (mounted) {
        setState(() {
          _items = temp;
          _loading = false;
        });
      }
    } catch (_) {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  Future<void> _loadRecent() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final List<String> ids =
        prefs.getStringList('recent_material_ids') ?? <String>[];
    if (!mounted) {
      return;
    }
    setState(() => _recentMaterialIds = ids);
  }

  @override
  void dispose() {
    _searchCtrl.dispose();
    super.dispose();
  }

  Future<void> _markRecent(StudyMaterialItem item) async {
    final List<String> next = <String>[item.materialId];
    next.addAll(_recentMaterialIds.where((String id) => id != item.materialId));
    final List<String> bounded = next.take(8).toList();
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setStringList('recent_material_ids', bounded);
    if (!mounted) {
      return;
    }
    setState(() => _recentMaterialIds = bounded);
  }

  static const List<String> _classOptions = <String>[
    'Class 11',
    'Class 12',
    '11 + 12',
  ];

  String _normalizeClassName(String raw) {
    final String value = raw.trim().toLowerCase();
    if (value.contains('11+12') || value.contains('11 + 12')) {
      return '11 + 12';
    }
    if (value.contains('class 12') || value == '12') {
      return 'Class 12';
    }
    if (value.contains('class 11') || value == '11') {
      return 'Class 11';
    }
    return '';
  }

  String _normalizeSubject(String raw) {
    final String value = raw.trim();
    if (value.isEmpty) {
      return 'General';
    }
    final String lower = value.toLowerCase();
    if (lower == 'math' || lower == 'maths' || lower == 'mathematics') {
      return 'Mathematics';
    }
    if (lower == 'phy' || lower == 'physics') {
      return 'Physics';
    }
    if (lower == 'chem' || lower == 'chemistry') {
      return 'Chemistry';
    }
    if (lower == 'bio' || lower == 'biology') {
      return 'Biology';
    }
    return value;
  }

  List<String> _splitChapters(String raw) {
    final List<String> out = raw
        .split(RegExp(r'[,|;/\n]+'))
        .map((String e) => e.trim())
        .where((String e) => e.isNotEmpty)
        .toSet()
        .toList();
    return out;
  }

  bool _classMatchesMaterial(String selectedClass, String materialClass) {
    if (selectedClass == '11 + 12') {
      return true;
    }
    if (materialClass.isEmpty) {
      return true;
    }
    if (materialClass == selectedClass) {
      return true;
    }
    if (materialClass == '11 + 12') {
      return true;
    }
    return false;
  }

  List<String> _subjectOptionsForClass(String selectedClass) {
    final Set<String> out = <String>{};
    if (selectedClass == '11 + 12') {
      out.addAll(
        (syllabusByClassAndSubject['Class 11'] ?? <String, List<String>>{})
            .keys,
      );
      out.addAll(
        (syllabusByClassAndSubject['Class 12'] ?? <String, List<String>>{})
            .keys,
      );
    } else {
      out.addAll(
        (syllabusByClassAndSubject[selectedClass] ?? <String, List<String>>{})
            .keys,
      );
    }
    for (final StudyMaterialItem item in _items) {
      final String itemClass = _normalizeClassName(item.className);
      if (!_classMatchesMaterial(selectedClass, itemClass)) {
        continue;
      }
      out.add(_normalizeSubject(item.subject));
    }
    if (out.isEmpty) {
      out.add('General');
    }
    final List<String> list = out.toList()..sort();
    return list;
  }

  List<String> _syllabusChapters(String selectedClass, String selectedSubject) {
    final List<String> out = <String>[];
    final Set<String> seen = <String>{};
    void addAllOrdered(List<String> values) {
      for (final String value in values) {
        if (seen.add(value)) {
          out.add(value);
        }
      }
    }

    if (selectedClass == '11 + 12') {
      addAllOrdered(
        (syllabusByClassAndSubject['Class 11'] ??
                <String, List<String>>{})[selectedSubject] ??
            <String>[],
      );
      addAllOrdered(
        (syllabusByClassAndSubject['Class 12'] ??
                <String, List<String>>{})[selectedSubject] ??
            <String>[],
      );
    } else {
      addAllOrdered(
        (syllabusByClassAndSubject[selectedClass] ??
                <String, List<String>>{})[selectedSubject] ??
            <String>[],
      );
    }
    return out;
  }

  Future<void> _openExternalMaterial(String url) async {
    Uri? uri = Uri.tryParse(url.trim());
    if (uri == null || uri.scheme.isEmpty) {
      uri = Uri.tryParse('https://${url.trim()}');
    }
    if (uri == null || uri.host.trim().isEmpty) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Invalid material link: $url')));
      return;
    }
    final bool canOpen = await canLaunchUrl(uri);
    if (!canOpen) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Broken material link: $url')));
      return;
    }
    final bool opened = await launchUrl(
      uri,
      mode: LaunchMode.externalApplication,
    );
    if (opened || !mounted) {
      return;
    }
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text('Unable to open: $url')));
  }

  void _open(StudyMaterialItem item) {
    unawaited(_markRecent(item));
    if (_isNoteMaterial(item) && item.notes.trim().isNotEmpty) {
      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) =>
              NoteReaderScreen(title: item.title, content: item.notes),
        ),
      );
      return;
    }
    if (_isImageMaterial(item)) {
      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => FullscreenImageViewer(imageUrl: item.url),
        ),
      );
      return;
    }
    if (_isPdfMaterial(item) &&
        item.url.trim().isEmpty &&
        item.notes.trim().isNotEmpty) {
      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) =>
              NoteReaderScreen(title: item.title, content: item.notes),
        ),
      );
      return;
    }

    unawaited(_openExternalMaterial(item.url));
  }

  bool _isNoteMaterial(StudyMaterialItem item) {
    final String type = item.type.trim().toLowerCase();
    final String url = item.url.trim().toLowerCase();
    return type == 'note' || url.startsWith('inline://note');
  }

  bool _isImageMaterial(StudyMaterialItem item) {
    final String type = item.type.trim().toLowerCase();
    final String url = item.url.trim().toLowerCase();
    if (type == 'image') {
      return true;
    }
    if (type.contains('jpg') ||
        type.contains('jpeg') ||
        type.contains('png') ||
        type.contains('webp') ||
        type.contains('heic') ||
        type.contains('heif')) {
      return true;
    }
    return url.startsWith('data:image') ||
        url.endsWith('.jpg') ||
        url.endsWith('.jpeg') ||
        url.endsWith('.png') ||
        url.endsWith('.webp') ||
        url.endsWith('.heic') ||
        url.endsWith('.heif');
  }

  bool _isPdfMaterial(StudyMaterialItem item) {
    final String type = item.type.trim().toLowerCase();
    final String url = item.url.trim().toLowerCase();
    return type == 'pdf' ||
        type.contains('document') ||
        url.endsWith('.pdf') ||
        url.startsWith('data:application/pdf');
  }

  @override
  Widget build(BuildContext context) {
    if (_loading) {
      return const Center(child: CircularProgressIndicator());
    }

    final String selectedClass = _classOptions.contains(_classFilter)
        ? _classFilter
        : 'Class 11';
    final List<String> subjects = _subjectOptionsForClass(selectedClass);
    final String selectedSubject = subjects.contains(_subjectFilter)
        ? _subjectFilter
        : subjects.first;

    final List<StudyMaterialItem> scopedItems = _items.where((
      StudyMaterialItem item,
    ) {
      final String itemClass = _normalizeClassName(item.className);
      if (!_classMatchesMaterial(selectedClass, itemClass)) {
        return false;
      }
      final String subject = _normalizeSubject(item.subject);
      return subject == selectedSubject;
    }).toList();

    final List<String> syllabusChapters = _syllabusChapters(
      selectedClass,
      selectedSubject,
    );
    final Set<String> chapterSet = <String>{...syllabusChapters};
    for (final StudyMaterialItem item in scopedItems) {
      chapterSet.addAll(_splitChapters(item.chapter));
    }
    if (chapterSet.isEmpty) {
      chapterSet.add('General');
    }
    final List<String> chapterOrder = <String>[...syllabusChapters];
    final List<String> extraChapters =
        chapterSet.where((String c) => !syllabusChapters.contains(c)).toList()
          ..sort();
    chapterOrder.addAll(extraChapters);

    final String q = _query.trim().toLowerCase();
    final Map<String, List<StudyMaterialItem>> chapterToItems =
        <String, List<StudyMaterialItem>>{
          for (final String chapter in chapterOrder)
            chapter: <StudyMaterialItem>[],
        };
    final Set<String> visibleMaterialIds = <String>{};
    for (final StudyMaterialItem item in scopedItems) {
      final List<String> chapters = _splitChapters(item.chapter).isEmpty
          ? <String>['General']
          : _splitChapters(item.chapter);
      final String chapterSearch = chapters.join(', ').toLowerCase();
      final String type = item.type.trim().toUpperCase();
      final bool queryOk =
          q.isEmpty ||
          item.title.toLowerCase().contains(q) ||
          chapterSearch.contains(q) ||
          selectedSubject.toLowerCase().contains(q) ||
          type.toLowerCase().contains(q) ||
          item.description.toLowerCase().contains(q) ||
          item.notes.toLowerCase().contains(q);
      if (!queryOk) {
        continue;
      }
      visibleMaterialIds.add(item.materialId);
      for (final String chapter in chapters) {
        chapterToItems.putIfAbsent(chapter, () => <StudyMaterialItem>[]);
        chapterToItems[chapter]!.add(item);
      }
    }

    for (final String chapter in chapterToItems.keys) {
      if (!chapterOrder.contains(chapter)) {
        chapterOrder.add(chapter);
      }
    }
    chapterOrder.sort((String a, String b) {
      final int ai = syllabusChapters.indexOf(a);
      final int bi = syllabusChapters.indexOf(b);
      if (ai >= 0 && bi >= 0) {
        return ai.compareTo(bi);
      }
      if (ai >= 0) {
        return -1;
      }
      if (bi >= 0) {
        return 1;
      }
      return a.compareTo(b);
    });

    final Map<String, StudyMaterialItem> byId = <String, StudyMaterialItem>{
      for (final StudyMaterialItem item in _items) item.materialId: item,
    };
    final List<StudyMaterialItem> recentItems = _recentMaterialIds
        .map((String id) => byId[id])
        .whereType<StudyMaterialItem>()
        .toList();

    return RefreshIndicator(
      onRefresh: _load,
      child: ListView(
        padding: const EdgeInsets.all(16),
        children: <Widget>[
          LiquidGlass(
            padding: const EdgeInsets.all(16),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: <Widget>[
                const Text(
                  'Study Library',
                  style: TextStyle(fontSize: 22, fontWeight: FontWeight.w800),
                ),
                const SizedBox(height: 6),
                Text(
                  '$selectedClass • $selectedSubject • ${chapterOrder.length} chapters',
                  style: const TextStyle(color: Colors.grey),
                ),
                const SizedBox(height: 10),
                TextField(
                  controller: _searchCtrl,
                  onChanged: (String value) => setState(() => _query = value),
                  decoration: const InputDecoration(
                    hintText: 'Search assignment name, chapter, type...',
                    prefixIcon: Icon(Icons.search),
                  ),
                ),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 10,
                  runSpacing: 10,
                  children: <Widget>[
                    SizedBox(
                      width: 160,
                      child: DropdownButtonFormField<String>(
                        value: selectedClass,
                        decoration: const InputDecoration(labelText: 'Class'),
                        items: _classOptions
                            .map(
                              (String e) => DropdownMenuItem<String>(
                                value: e,
                                child: Text(e),
                              ),
                            )
                            .toList(),
                        onChanged: (String? value) {
                          if (value == null) {
                            return;
                          }
                          setState(() {
                            _classFilter = value;
                            final List<String> nextSubjects =
                                _subjectOptionsForClass(value);
                            if (!nextSubjects.contains(_subjectFilter)) {
                              _subjectFilter = nextSubjects.first;
                            }
                          });
                        },
                      ),
                    ),
                    SizedBox(
                      width: 160,
                      child: DropdownButtonFormField<String>(
                        value: selectedSubject,
                        decoration: const InputDecoration(labelText: 'Subject'),
                        items: subjects
                            .map(
                              (String e) => DropdownMenuItem<String>(
                                value: e,
                                child: Text(e),
                              ),
                            )
                            .toList(),
                        onChanged: (String? value) {
                          if (value == null) {
                            return;
                          }
                          setState(() => _subjectFilter = value);
                        },
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
          if (widget.enableAiActions &&
              (widget.onOpenAiHub != null ||
                  widget.onQuickAskAi != null)) ...<Widget>[
            const SizedBox(height: 12),
            LiquidGlass(
              padding: const EdgeInsets.all(14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text(
                    'LalaCore Study AI',
                    style: TextStyle(fontWeight: FontWeight.w800, fontSize: 16),
                  ),
                  const SizedBox(height: 6),
                  Text(
                    'Use AI directly within Study for chapter doubts, summaries, and JEE-focused revision.',
                    style: TextStyle(color: Colors.grey.shade700, height: 1.32),
                  ),
                  const SizedBox(height: 12),
                  Wrap(
                    spacing: 10,
                    runSpacing: 10,
                    children: <Widget>[
                      if (widget.onQuickAskAi != null)
                        FilledButton.icon(
                          onPressed: widget.onQuickAskAi,
                          icon: const Icon(Icons.smart_toy_outlined),
                          label: const Text('Quick Ask AI'),
                        ),
                      if (widget.onOpenAiHub != null)
                        OutlinedButton.icon(
                          onPressed: widget.onOpenAiHub,
                          icon: const Icon(Icons.auto_awesome),
                          label: const Text('Open AI Hub'),
                        ),
                    ],
                  ),
                ],
              ),
            ),
          ],
          if (recentItems.isNotEmpty) ...<Widget>[
            const SizedBox(height: 12),
            LiquidGlass(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  const Text(
                    'Recently Viewed',
                    style: TextStyle(fontWeight: FontWeight.w800),
                  ),
                  const SizedBox(height: 8),
                  SingleChildScrollView(
                    scrollDirection: Axis.horizontal,
                    child: Row(
                      children: recentItems.map((StudyMaterialItem item) {
                        return Padding(
                          padding: const EdgeInsets.only(right: 8),
                          child: ActionChip(
                            label: Text(
                              item.title,
                              maxLines: 1,
                              overflow: TextOverflow.ellipsis,
                            ),
                            onPressed: () => _open(item),
                          ),
                        );
                      }).toList(),
                    ),
                  ),
                ],
              ),
            ),
          ],
          const SizedBox(height: 12),
          if (visibleMaterialIds.isEmpty)
            const Padding(
              padding: EdgeInsets.only(top: 60),
              child: Center(
                child: Text(
                  'No teacher material found for selected class/subject',
                ),
              ),
            ),
          ...chapterOrder.map((String chapter) {
            final List<StudyMaterialItem> chapterItems =
                chapterToItems[chapter] ?? <StudyMaterialItem>[];
            return Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: LiquidGlass(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                child: ExpansionTile(
                  initiallyExpanded: _query.trim().isNotEmpty,
                  shape: const Border(),
                  collapsedShape: const Border(),
                  title: Text(
                    '$chapter (${chapterItems.length})',
                    style: const TextStyle(fontWeight: FontWeight.w800),
                  ),
                  children: chapterItems.isEmpty
                      ? const <Widget>[
                          Padding(
                            padding: EdgeInsets.fromLTRB(12, 4, 12, 12),
                            child: Align(
                              alignment: Alignment.centerLeft,
                              child: Text(
                                'No material uploaded by teacher for this chapter yet.',
                                style: TextStyle(color: Colors.grey),
                              ),
                            ),
                          ),
                        ]
                      : chapterItems.asMap().entries.map((
                          MapEntry<int, StudyMaterialItem> entry,
                        ) {
                          final StudyMaterialItem it = entry.value;
                          return FadeSlideIn(
                            index: entry.key,
                            child: Padding(
                              padding: const EdgeInsets.only(bottom: 10),
                              child: FlippableStudyCard(
                                item: it,
                                enableAiActions: widget.enableAiActions,
                                onOpen: () => _open(it),
                                onAskAI: () {
                                  if (!widget.enableAiActions) {
                                    return;
                                  }
                                  Navigator.push(
                                    context,
                                    MaterialPageRoute(
                                      builder: (_) => AIChatScreen(
                                        userId: widget.studentName,
                                        chatId: 'AI_STUDY_${it.materialId}',
                                        chatFunction: 'material_qa',
                                        showPersonaBanner: true,
                                        contextCard: <String, dynamic>{
                                          'material_id': it.materialId,
                                          'title': it.title,
                                          'chapter': chapter,
                                          'subject': selectedSubject,
                                          'type': it.type,
                                          'material_url': it.url,
                                          if (it.notes.trim().isNotEmpty)
                                            'material_notes':
                                                it.notes.length > 5000
                                                ? it.notes.substring(0, 5000)
                                                : it.notes,
                                          'enable_material_web_fusion': true,
                                          'enable_material_ocr': true,
                                        },
                                        initialPrompt: <String>[
                                          'Use this study material for JEE prep Q&A with OCR and web retrieval support.',
                                          'Title: ${it.title}',
                                          'Chapter: $chapter',
                                          'Subject: $selectedSubject',
                                          'Type: ${it.type}',
                                          'URL: ${it.url}',
                                          if (it.notes.trim().isNotEmpty)
                                            'Notes context: ${it.notes.length > 1500 ? it.notes.substring(0, 1500) : it.notes}',
                                          'For image/PDF follow strict OCR extraction first, then solve using verified reasoning.',
                                          'Respond in markdown with clear steps and LaTeX when needed.',
                                        ].join('\n'),
                                      ),
                                    ),
                                  );
                                },
                                onSummarize: () {
                                  if (!widget.enableAiActions) {
                                    return;
                                  }
                                  Navigator.push(
                                    context,
                                    MaterialPageRoute(
                                      builder: (_) => MaterialAIReaderScreen(
                                        materialId: it.materialId,
                                        title: it.title,
                                        mode: 'summarize',
                                        subject: selectedSubject,
                                        chapter: chapter,
                                        materialType: it.type,
                                        materialUrl: it.url,
                                        materialNotes: it.notes,
                                        aiOptions: <String, dynamic>{
                                          'detail_level': 'concise',
                                          'focus': 'revision',
                                          'format': 'structured',
                                          'summary_depth': 'high_accuracy',
                                          'ocr_mode': 'strict',
                                          'ocr_math_priority': true,
                                          'include_exam_patterns': true,
                                          'enable_pre_reasoning_context': true,
                                          'enable_web_retrieval': true,
                                          'enable_graph_of_thought': true,
                                          'enable_mcts_reasoning': true,
                                        },
                                      ),
                                    ),
                                  );
                                },
                                onNotes: () {
                                  if (!widget.enableAiActions) {
                                    return;
                                  }
                                  Navigator.push(
                                    context,
                                    MaterialPageRoute(
                                      builder: (_) => MaterialAIReaderScreen(
                                        materialId: it.materialId,
                                        title: it.title,
                                        mode: 'jee_notes',
                                        subject: selectedSubject,
                                        chapter: chapter,
                                        materialType: it.type,
                                        materialUrl: it.url,
                                        materialNotes: it.notes,
                                        aiOptions: <String, dynamic>{
                                          'detail_level': 'deep',
                                          'include_traps': true,
                                          'include_shortcuts': true,
                                          'ocr_mode': 'strict',
                                          'include_rank_booster_tips': true,
                                          'include_test_strategy': true,
                                          'enable_pre_reasoning_context': true,
                                          'enable_web_retrieval': true,
                                          'enable_graph_of_thought': true,
                                          'enable_mcts_reasoning': true,
                                        },
                                      ),
                                    ),
                                  );
                                },
                              ),
                            ),
                          );
                        }).toList(),
                ),
              ),
            );
          }),
        ],
      ),
    );
  }
}

class FlippableStudyCard extends StatefulWidget {
  const FlippableStudyCard({
    super.key,
    required this.item,
    required this.enableAiActions,
    required this.onOpen,
    required this.onAskAI,
    required this.onSummarize,
    required this.onNotes,
  });

  final StudyMaterialItem item;
  final bool enableAiActions;
  final VoidCallback onOpen;
  final VoidCallback onAskAI;
  final VoidCallback onSummarize;
  final VoidCallback onNotes;

  @override
  State<FlippableStudyCard> createState() => _FlippableStudyCardState();
}

class _FlippableStudyCardState extends State<FlippableStudyCard>
    with SingleTickerProviderStateMixin {
  bool _isFront = true;
  late final AnimationController _ctrl;

  @override
  void initState() {
    super.initState();
    _ctrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 420),
    );
  }

  @override
  void dispose() {
    _ctrl.dispose();
    super.dispose();
  }

  void _flip() {
    if (_isFront) {
      _ctrl.forward();
    } else {
      _ctrl.reverse();
    }
    _isFront = !_isFront;
  }

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: widget.onOpen,
      onLongPress: widget.enableAiActions ? _flip : null,
      child: AnimatedBuilder(
        animation: _ctrl,
        builder: (_, __) {
          final double eased = Curves.easeInOutCubic.transform(_ctrl.value);
          final double angle = eased * pi;
          final Matrix4 transform = Matrix4.identity()
            ..setEntry(3, 2, 0.001)
            ..rotateY(angle);

          return Transform(
            transform: transform,
            alignment: Alignment.center,
            child: _ctrl.value < 0.5
                ? _buildFront()
                : Transform(
                    transform: Matrix4.identity()..rotateY(pi),
                    alignment: Alignment.center,
                    child: _buildBack(),
                  ),
          );
        },
      ),
    );
  }

  Widget _buildFront() {
    final StudyMaterialItem it = widget.item;
    final String subject = it.subject.trim().isEmpty ? 'General' : it.subject;
    final String chapter = it.chapter.trim().isEmpty ? 'General' : it.chapter;
    final String className = it.className.trim();
    return Padding(
      padding: const EdgeInsets.all(8),
      child: LiquidGlass(
        padding: const EdgeInsets.all(18),
        color: Colors.white.withOpacity(0.10),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: <Widget>[
            Wrap(
              spacing: 6,
              runSpacing: 6,
              children: <Widget>[
                _smallPill(subject, AppColors.primary),
                _smallPill(chapter, Colors.teal),
                _smallPill(it.type.toUpperCase(), Colors.orange),
                if (className.isNotEmpty) _smallPill(className, Colors.indigo),
              ],
            ),
            const SizedBox(height: 10),
            Text(
              'Assignment: ${it.title}',
              maxLines: 2,
              overflow: TextOverflow.ellipsis,
              style: const TextStyle(fontWeight: FontWeight.w800, fontSize: 16),
            ),
            const SizedBox(height: 8),
            if (it.description.trim().isNotEmpty || it.notes.trim().isNotEmpty)
              Text(
                (it.description.trim().isNotEmpty
                        ? it.description
                        : it.notes.trim())
                    .trim(),
                maxLines: 3,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(
                  fontSize: 12.5,
                  color: Colors.grey,
                  height: 1.35,
                ),
              ),
            const Spacer(),
            Text(
              'Date Given: ${it.time.trim().isEmpty ? 'Not specified' : it.time}',
              style: const TextStyle(fontSize: 11, color: Colors.grey),
            ),
            const SizedBox(height: 8),
            Center(
              child: Text(
                widget.enableAiActions
                    ? 'Long press for AI options'
                    : 'Tap card to open material',
                style: const TextStyle(fontSize: 10.5, color: Colors.grey),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildBack() {
    if (!widget.enableAiActions) {
      return Padding(
        padding: const EdgeInsets.all(8),
        child: LiquidGlass(
          padding: const EdgeInsets.all(18),
          color: Colors.white.withOpacity(0.10),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: <Widget>[
              const Text(
                'Study Material',
                style: TextStyle(fontWeight: FontWeight.w800, fontSize: 16),
              ),
              const SizedBox(height: 10),
              Text(
                widget.item.title,
                style: const TextStyle(fontWeight: FontWeight.w700),
              ),
              const SizedBox(height: 8),
              Text(
                '${widget.item.subject.isEmpty ? 'General' : widget.item.subject} • ${widget.item.chapter.isEmpty ? 'General' : widget.item.chapter}${widget.item.className.trim().isEmpty ? '' : ' • ${widget.item.className.trim()}'}',
                style: const TextStyle(fontSize: 12, color: Colors.grey),
              ),
              const Spacer(),
              SizedBox(
                width: double.infinity,
                child: ElevatedButton.icon(
                  onPressed: widget.onOpen,
                  icon: const Icon(Icons.open_in_new_rounded),
                  label: const Text('Open Material'),
                ),
              ),
            ],
          ),
        ),
      );
    }
    final StudyMaterialItem item = widget.item;
    return Padding(
      padding: const EdgeInsets.all(8),
      child: LiquidGlass(
        padding: const EdgeInsets.all(18),
        color: Colors.white.withOpacity(0.12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: <Widget>[
            Row(
              children: <Widget>[
                const Icon(
                  Icons.auto_awesome,
                  size: 18,
