class AIChatScreen extends StatefulWidget {
  const AIChatScreen({
    super.key,
    required this.userId,
    required this.chatId,
    this.initialPrompt,
    this.chatFunction = 'general_chat',
    this.contextCard,
    this.showPersonaBanner = false,
    this.seedAssistantMessage,
    this.heroTag,
    this.heroCard,
  });

  final String userId;
  final String chatId;
  final String? initialPrompt;
  final String chatFunction;
  final Map<String, dynamic>? contextCard;
  final bool showPersonaBanner;
  final ChatMessage? seedAssistantMessage;
  final String? heroTag;
  final Map<String, dynamic>? heroCard;

  @override
  State<AIChatScreen> createState() => _AIChatScreenState();
}

class _AIChatScreenState extends State<AIChatScreen> {
  static const bool _enableCompanion = false;

  final List<ChatMessage> _messages = <ChatMessage>[];
  final TextEditingController _ctrl = TextEditingController();
  final ScrollController _scroll = ScrollController();
  final ImagePicker _picker = ImagePicker();
  final AICompanionController _companionController = AICompanionController();

  Timer? _typingTimer;
  int? _typingMessageIndex;
  int _typingVisibleChars = 0;
  bool _scrollFramePending = false;

  bool _loading = false;
  bool _initialConsumed = false;
  bool _personaEnabled = true;
  int _personaVariantTick = 0;
  int? _lastPersonaHeaderIdx;
  int? _lastPersonaMidIdx;
  int? _lastPersonaFinalIdx;
  int? _lastPersonaCloserIdx;
  double _companionSize = 156;
  bool _showCompanion = true;
  bool _showGfGuideCard = false;

  String get _storageKey => 'ai_chat_${widget.chatId}';
  String get _personaKey => 'ai_persona_enabled_${widget.userId}';
  String get _companionSizeKey => 'ai_companion_size_${widget.userId}';
  String get _gfGuideSeenKey => 'ai_gf_guide_seen_${widget.userId}';
  String get _sessionScopeAccountId =>
      (widget.contextCard?['account_id'] ?? Session.effectiveAccountId)
          .toString()
          .trim();
  bool get _busy => _loading || _typingMessageIndex != null;

  @override
  void initState() {
    super.initState();
    _personaEnabled = widget.showPersonaBanner;
    _showCompanion =
        _enableCompanion && widget.showPersonaBanner && _personaEnabled;
    performanceModeNotifier.addListener(_onPerfModeChanged);
    _loadCompanionPreference();
    _loadPersonaPreference();
    _loadGfGuideState();
    _persistLastOpenedChat();
    unawaited(_bootstrapChat());
  }

  @override
  void dispose() {
    performanceModeNotifier.removeListener(_onPerfModeChanged);
    _typingTimer?.cancel();
    _companionController.dispose();
    _ctrl.dispose();
    _scroll.dispose();
    super.dispose();
  }

  void _onPerfModeChanged() {
    if (!mounted) {
      return;
    }
    setState(() {});
  }

  Future<void> _loadCompanionPreference() async {
    if (!_enableCompanion || !widget.showPersonaBanner) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final double? size = prefs.getDouble(_companionSizeKey);
    if (!mounted || size == null) {
      return;
    }
    setState(() {
      _companionSize = size.clamp(110, 230).toDouble();
    });
  }

  Future<void> _loadPersonaPreference() async {
    if (!widget.showPersonaBanner) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final bool? saved = prefs.getBool(_personaKey);
    if (!mounted || saved == null) {
      return;
    }
    setState(() {
      _personaEnabled = saved;
      _showCompanion = _enableCompanion && saved;
    });
  }

  Future<void> _loadGfGuideState() async {
    if (!_enableCompanion || !widget.showPersonaBanner) {
      return;
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final bool seen = prefs.getBool(_gfGuideSeenKey) ?? false;
    if (!mounted) {
      return;
    }
    setState(() => _showGfGuideCard = !seen);
  }

  Future<void> _setPersonaEnabled(bool value) async {
    if (value == _personaEnabled) {
      return;
    }
    if (value) {
      setState(() {
        _personaEnabled = true;
        _showCompanion = _enableCompanion;
      });
      await Future<void>.delayed(
        Duration(milliseconds: _enableCompanion ? 260 : 80),
      );
      if (_enableCompanion && mounted && _showCompanion) {
        await _companionController.playHello();
      }
    } else {
      if (_enableCompanion) {
        await _companionController.playGoodbye();
      }
      if (!mounted) {
        return;
      }
      setState(() {
        _personaEnabled = false;
        _showCompanion = false;
      });
    }
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_personaKey, value);
  }

  Future<Map<String, dynamic>> _sendChatWithGuard({
    required String prompt,
    required String userId,
    required String chatId,
    required String function,
    required bool enablePersona,
    Map<String, dynamic>? card,
    String? base64Image,
  }) async {
    final Stopwatch sw = Stopwatch()..start();
    String activeFunction = function;
    Future<Map<String, dynamic>> runOnce({required String fn}) async {
      return aiService
          .sendChat(
            prompt: prompt,
            userId: userId,
            chatId: chatId,
            function: fn,
            responseStyle: 'structured_exam_solution',
            enablePersona: enablePersona,
            card: card,
            base64Image: base64Image,
          )
          .timeout(
            base64Image == null
                ? const Duration(seconds: 36)
                : const Duration(seconds: 48),
            onTimeout: () => <String, dynamic>{
              'ok': false,
              'status': 'AI_TIMEOUT',
              'error': 'Timed out while waiting for AI response',
            },
          );
    }

    Map<String, dynamic> response = await runOnce(fn: activeFunction);
    final String firstFailure = _aiFailureText(response);
    if (!_hasUsableAiResponse(response) &&
        activeFunction != 'general_chat' &&
        _looksUnsupportedFunctionFailure(firstFailure)) {
      activeFunction = 'general_chat';
      response = await runOnce(fn: activeFunction);
    }
    if (!_hasUsableAiResponse(response)) {
      final String err = (response['error'] ?? response['message'] ?? '')
          .toString()
          .trim();
      response = <String, dynamic>{
        ...response,
        'ok': false,
        'status': (response['status'] ?? 'AI_NO_ANSWER').toString(),
        'error': err.isEmpty ? 'AI engine returned no usable answer' : err,
      };
    }

    assert(() {
      final bool ok = response['ok'] == true;
      debugPrint(
        '[LATENCY][ai_chat] send ${sw.elapsedMilliseconds}ms ok=$ok fn=$activeFunction image=${base64Image != null} card=${card != null}',
      );
      return true;
    }());
    return response;
  }

  bool _hasUsableAiResponse(Map<String, dynamic> response) {
    final String answer = (response['answer'] ?? '').toString().trim();
    final String explanation = (response['explanation'] ?? '')
        .toString()
        .trim();
    final String combined = '$answer $explanation'.trim();
    if (combined.isEmpty) {
      return false;
    }
    if (_looksRefusalLikeText(combined)) {
      return false;
    }
    return response['ok'] == true ||
        answer.isNotEmpty ||
        explanation.isNotEmpty;
  }

  bool _looksRefusalLikeText(String text) {
    final String lower = text
        .toLowerCase()
        .replaceAll('’', "'")
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
    if (lower.trim().isEmpty) {
      return false;
    }
    const List<String> refusalPhrases = <String>[
      'i cannot solve',
      "i can't solve",
      'cannot solve this',
      'unable to solve',
      'cannot answer this',
      'unable to answer',
      "i'm unable to",
      'i am unable to',
      'as an ai',
      "can't assist",
      'cannot help with',
      'could not generate a valid answer',
      'cannot provide a solution',
      'i do not have enough information',
    ];
    for (final String phrase in refusalPhrases) {
      if (lower.contains(phrase)) {
        return true;
      }
    }
    if ((lower.contains("can't") || lower.contains('cannot')) &&
        (lower.contains('solve') ||
            lower.contains('answer') ||
            lower.contains('assist') ||
            lower.contains('help'))) {
      return true;
    }
    return false;
  }

  String? _tryLocalArithmeticSolve(String prompt) {
    String normalized = prompt
        .toLowerCase()
        .replaceAll('’', "'")
        .replaceAll(RegExp(r'\bwhat\s+is\b'), ' ')
        .replaceAll(RegExp(r'\bcalculate\b'), ' ')
        .replaceAll(RegExp(r'\bcompute\b'), ' ')
        .replaceAll(RegExp(r'\bsolve\b'), ' ')
        .replaceAll(RegExp(r'\bplus\b'), '+')
        .replaceAll(RegExp(r'\bminus\b'), '-')
        .replaceAll(RegExp(r'\bmultiplied\s+by\b'), '*')
        .replaceAll(RegExp(r'\btimes\b'), '*')
        .replaceAll(RegExp(r'\bdivided\s+by\b'), '/')
        .replaceAll(RegExp(r'\bover\b'), '/')
        .trim();
    normalized = normalized.replaceAllMapped(
      RegExp(r'(\d)\s*[xX]\s*(\d)'),
      (Match m) => '${m.group(1)}*${m.group(2)}',
    );
    normalized = normalized
        .replaceAll('=', ' ')
        .replaceAll('×', '*')
        .replaceAll('÷', '/')
        .replaceAll(RegExp(r'[?.!]+$'), '')
        .replaceAll(RegExp(r'[^0-9+\-x*/.\s]'), ' ')
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
    final Match? m = RegExp(
      r'^(-?\d+(?:\.\d+)?)\s*([+\-x*/])\s*(-?\d+(?:\.\d+)?)$',
    ).firstMatch(normalized);
    if (m == null) {
      return null;
    }
    final double? a = double.tryParse(m.group(1) ?? '');
    final double? b = double.tryParse(m.group(3) ?? '');
    final String op = m.group(2) ?? '';
    if (a == null || b == null || op.isEmpty) {
      return null;
    }
    double value;
    if (op == '+') {
      value = a + b;
    } else if (op == '-') {
      value = a - b;
    } else if (op == 'x' || op == '*') {
      value = a * b;
    } else {
      if (b == 0) {
        return null;
      }
      value = a / b;
    }
    final bool integerLike = (value - value.roundToDouble()).abs() < 1e-9;
    final String answerText = integerLike
        ? value.round().toString()
        : value
              .toStringAsFixed(4)
              .replaceAll(RegExp(r'0+$'), '')
              .replaceAll(RegExp(r'\.$'), '');
    return answerText;
  }

  String _aiFailureText(Map<String, dynamic> response) {
    return <String>[
      (response['error'] ?? '').toString(),
      (response['message'] ?? '').toString(),
      (response['status'] ?? '').toString(),
      (response['raw'] ?? '').toString(),
    ].join(' ').toLowerCase();
  }

  bool _looksUnsupportedFunctionFailure(String failureText) {
    if (failureText.isEmpty) {
      return false;
    }
    return failureText.contains('unknown action') ||
        failureText.contains('invalid action') ||
        failureText.contains('unknown function') ||
        failureText.contains('unsupported function') ||
        failureText.contains('not implemented');
  }

  bool _isRetryableAiFailure(String failureText) {
    if (failureText.isEmpty) {
      return true;
    }
    return failureText.contains('timed out') ||
        failureText.contains('timeout') ||
        failureText.contains('socket') ||
        failureText.contains('network') ||
        failureText.contains('failed host lookup') ||
        failureText.contains('dns') ||
        failureText.contains('temporarily unavailable') ||
        failureText.contains('connection reset') ||
        failureText.contains('connection refused') ||
        failureText.contains('backend error') ||
        failureText.contains(' 429') ||
        failureText.contains(' 502') ||
        failureText.contains(' 503');
  }

  bool _reducedEffects(BuildContext context) {
    return shouldUseReducedEffects(context);
  }

  double _effectiveCompanionSize(BuildContext context) {
    final double safe = _companionSize.clamp(110, 230).toDouble();
    return _reducedEffects(context) ? min(safe, 156) : safe;
  }

  Future<void> _openCompanionEditor() async {
    if (!_enableCompanion) {
      return;
    }
    final bool lowPower = _reducedEffects(context);
    final double? selected = await Navigator.of(context).push<double>(
      MaterialPageRoute<double>(
        builder: (_) => CompanionEditScreen(
          initialSize: _companionSize,
          lowPowerMode: lowPower,
        ),
      ),
    );
    if (!mounted || selected == null) {
      return;
    }
    final double next = selected.clamp(110, 230).toDouble();
    setState(() => _companionSize = next);
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setDouble(_companionSizeKey, next);
  }

  Future<void> _openGfCompanionGuide({bool markSeen = true}) async {
    if (!_enableCompanion || !widget.showPersonaBanner || !mounted) {
      return;
    }
    if (markSeen) {
      final SharedPreferences prefs = await SharedPreferences.getInstance();
      await prefs.setBool(_gfGuideSeenKey, true);
      if (mounted) {
        setState(() => _showGfGuideCard = false);
      }
    }
    await showModalBottomSheet<void>(
      context: context,
      useSafeArea: true,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (BuildContext context) {
        return Padding(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 12),
          child: LiquidGlass(
            borderRadius: BorderRadius.circular(30),
            color: const Color(0xFFFF6FAE).withValues(alpha: 0.16),
            padding: const EdgeInsets.fromLTRB(18, 18, 18, 16),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: const <Widget>[
                Text(
                  'GF Companion Mode Guide',
                  style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800),
                ),
                SizedBox(height: 10),
                Text(
                  '1. Keep the GF toggle ON in this chat to enable companion mode.',
                  style: TextStyle(fontSize: 14.3, height: 1.36),
                ),
                SizedBox(height: 6),
                Text(
                  '2. Ask your question normally (text or image). Companion reacts after each AI response.',
                  style: TextStyle(fontSize: 14.3, height: 1.36),
                ),
                SizedBox(height: 6),
                Text(
                  '3. Tap "Edit Companion" to tune size and behavior for your device.',
                  style: TextStyle(fontSize: 14.3, height: 1.36),
                ),
                SizedBox(height: 6),
                Text(
