  String _topicSeedFromMessage(String raw) {
    final String lowerRaw = raw.toLowerCase();
    String cleaned = raw
        .replaceAll(
          RegExp(
            r'\[(image sent|pdf sent:[^\]]+|voice sent:[^\]]+)\]',
            caseSensitive: false,
          ),
          ' ',
        )
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
    if (cleaned.length > 260) {
      cleaned = cleaned.substring(0, 260).trim();
    }
    if (cleaned.isEmpty) {
      if (lowerRaw.contains('[image sent]')) {
        return 'Image question discussion';
      }
      if (lowerRaw.contains('[pdf sent:')) {
        return 'PDF question discussion';
      }
      if (lowerRaw.contains('[voice sent:')) {
        return 'Voice note discussion';
      }
    }
    return cleaned;
  }

  String _latestMessageSeed(String role) {
    for (int i = _messages.length - 1; i >= 0; i--) {
      final ChatMessage m = _messages[i];
      if (m.role != role) {
        continue;
      }
      final String seed = _topicSeedFromMessage(m.text);
      if (seed.isNotEmpty) {
        return seed;
      }
    }
    return '';
  }

  String _fallbackSessionTitle() {
    final String seed = _latestMessageSeed('user');
    if (seed.isEmpty) {
      return 'New AI Chat';
    }
    final List<String> words = seed.split(RegExp(r'\s+'));
    final String compact = words.take(6).join(' ').trim();
    return _sanitizeSessionTitle(compact.isEmpty ? seed : compact);
  }

  String _sanitizeSessionTitle(String raw) {
    String title = raw.trim();
    if (title.isEmpty) {
      return '';
    }
    title = title.split('\n').first.trim();
    title = title.replaceAll(
      RegExp(r'^\s*(title|topic)\s*[:\-]\s*', caseSensitive: false),
      '',
    );
    title = title.replaceAll(RegExp(r'["`]+'), '').trim();
    title = title.replaceAll(RegExp(r'\s+'), ' ').trim();
    if (title.endsWith('.') || title.endsWith('!') || title.endsWith('?')) {
      title = title.substring(0, title.length - 1).trim();
    }
    if (title.length > 56) {
      title = '${title.substring(0, 56).trimRight()}...';
    }
    return title;
  }

  Future<String> _generateAiSessionTitle() async {
    final String userSeed = _latestMessageSeed('user');
    if (userSeed.isEmpty) {
      return '';
    }
    final String assistantSeed = _latestMessageSeed('assistant');
    final String prompt =
        '''
Generate a concise title for this AI chat.
Rules:
- Maximum 6 words
- No quotes
- No emojis
- Return title only

User message: $userSeed
Assistant response: ${assistantSeed.isEmpty ? 'N/A' : assistantSeed}
''';
    try {
      final Map<String, dynamic> response = await aiService
          .sendChat(
            prompt: prompt,
            userId: widget.userId,
            chatId: '${widget.chatId}_title',
            function: 'general_chat',
            responseStyle: 'exam_coach',
            enablePersona: false,
            card: <String, dynamic>{
              if (widget.contextCard != null) ...widget.contextCard!,
              'account_id': _sessionScopeAccountId,
              'source': 'ai_chat_title',
              'base_chat_id': widget.chatId,
            },
          )
          .timeout(
            const Duration(seconds: 12),
            onTimeout: () => <String, dynamic>{'ok': false},
          );
      final String rawTitle =
          (response['title'] ??
                  response['answer'] ??
                  response['explanation'] ??
                  response['message'] ??
                  '')
              .toString();
      return _sanitizeSessionTitle(rawTitle);
    } catch (_) {
      return '';
    }
  }

  Future<void> _upsertAiChatSession({required bool tryAiTitle}) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final List<_AiChatSessionRecord> sessions = _readAiChatSessions(
      prefs: prefs,
      userId: widget.userId,
      accountId: _sessionScopeAccountId,
    );
    final int existingIdx = sessions.indexWhere(
      (_AiChatSessionRecord e) => e.chatId == widget.chatId,
    );
    final _AiChatSessionRecord? existing = existingIdx >= 0
        ? sessions[existingIdx]
        : null;
    if (_messages.isEmpty && existing == null) {
      return;
    }

    final int nowMs = DateTime.now().millisecondsSinceEpoch;
    String title = existing?.title.trim() ?? '';
    if (title.isEmpty) {
      title = _fallbackSessionTitle();
    }
    bool aiGenerated = existing?.aiGeneratedTitle ?? false;
    if (tryAiTitle && !aiGenerated) {
      final String aiTitle = await _generateAiSessionTitle();
      if (aiTitle.isNotEmpty) {
        title = aiTitle;
        aiGenerated = true;
      }
    }
    if (title.isEmpty) {
      title = 'New AI Chat';
    }
    final _AiChatSessionRecord next = _AiChatSessionRecord(
      chatId: widget.chatId,
      title: title,
      createdAtMillis: _toSafeSessionMillis(
        existing?.createdAtMillis ?? nowMs,
        fallback: nowMs,
      ),
      updatedAtMillis: nowMs,
      messageCount: _messages.length,
      aiGeneratedTitle: aiGenerated,
      pinned: existing?.pinned ?? false,
      pinnedAtMillis: existing?.pinnedAtMillis ?? 0,
    );
    if (existingIdx >= 0) {
      sessions[existingIdx] = next;
    } else {
      sessions.add(next);
    }
    sessions.sort(
      (_AiChatSessionRecord a, _AiChatSessionRecord b) =>
          b.updatedAtMillis.compareTo(a.updatedAtMillis),
    );
    await _writeAiChatSessions(
      prefs: prefs,
      userId: widget.userId,
      accountId: _sessionScopeAccountId,
      sessions: sessions.take(250).toList(growable: false),
    );
  }

  Future<void> _bootstrapChat() async {
    await _loadHistory();
    await _injectSeedAssistantIfNeeded();
    await _upsertAiChatSession(tryAiTitle: false);
    final String prompt = (widget.initialPrompt ?? '').trim();
    if (prompt.isEmpty ||
        _initialConsumed ||
        widget.seedAssistantMessage != null) {
      return;
    }
    _initialConsumed = true;
    if (!mounted) {
      return;
    }
    _sendMessage(prompt);
  }

  Future<void> _injectSeedAssistantIfNeeded() async {
    final ChatMessage? seed = widget.seedAssistantMessage;
    if (seed == null || !mounted) {
      return;
    }
    final bool exists = _messages.any(
      (ChatMessage m) =>
          m.role == 'assistant' && m.text.trim() == seed.text.trim(),
    );
    if (exists) {
      return;
    }
    setState(() {
      _messages.add(
        _applyCosmeticMetaToMessage(_applyPersonaFallbackToMessage(seed)),
      );
    });
    await _persistHistory();
    await _upsertAiChatSession(tryAiTitle: false);
    _scrollToBottom();
  }

  Future<void> _loadHistory() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final String? raw = prefs.getString(_storageKey);
    if (raw == null || raw.isEmpty) {
      return;
    }

    try {
      final List<dynamic> decoded = jsonDecode(raw) as List<dynamic>;
      final List<ChatMessage> restored = decoded
          .map(
            (dynamic e) =>
                ChatMessage.fromJson(Map<String, dynamic>.from(e as Map)),
          )
          .map(_applyPersonaFallbackToMessage)
          .map(_applyCosmeticMetaToMessage)
          .toList();
      if (!mounted) {
        return;
      }
      setState(() {
        _messages
          ..clear()
          ..addAll(restored);
      });
      await _upsertAiChatSession(tryAiTitle: false);
      _scrollToBottom();
    } catch (_) {}
  }

  Future<void> _persistHistory() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString(
      _storageKey,
      jsonEncode(_messages.map((ChatMessage e) => e.toJson()).toList()),
    );
  }

  void _scrollToBottom({bool animate = true}) {
    if (_scrollFramePending) {
      return;
    }
    _scrollFramePending = true;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _scrollFramePending = false;
      if (!_scroll.hasClients) {
        return;
      }
      final double target = _scroll.position.maxScrollExtent + 160;
      if (animate) {
        _scroll.animateTo(
          target,
          duration: const Duration(milliseconds: 250),
          curve: Curves.easeOut,
        );
        return;
      }
      _scroll.jumpTo(_scroll.position.maxScrollExtent);
    });
  }

