  Future<String?> _askAttachmentCaption({
    required String title,
    required String initialValue,
  }) async {
    final TextEditingController captionCtrl = TextEditingController(
      text: initialValue,
    );
    final String? value = await showDialog<String>(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: Text(title),
          content: TextField(
            controller: captionCtrl,
            minLines: 2,
            maxLines: 5,
            decoration: const InputDecoration(
              hintText: 'Add caption/instructions before sending',
            ),
          ),
          actions: <Widget>[
            TextButton(
              onPressed: () => Navigator.pop(context, null),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context, captionCtrl.text.trim()),
              child: const Text('Send'),
            ),
          ],
        );
      },
    );
    captionCtrl.dispose();
    return value;
  }

  Future<void> _pickAndSendImage({required bool camera}) async {
    if (_busy) {
      return;
    }
    final XFile? img = await _picker.pickImage(
      source: camera ? ImageSource.camera : ImageSource.gallery,
      imageQuality: 92,
      maxWidth: 1760,
    );
    if (img == null) {
      return;
    }

    final String? caption = await _askAttachmentCaption(
      title: 'Image Caption',
      initialValue: _ctrl.text.trim(),
    );
    if (!mounted || caption == null) {
      return;
    }

    final Uint8List bytes = await img.readAsBytes();
    final String lower = img.name.toLowerCase();
    final String mime = lower.endsWith('.png')
        ? 'image/png'
        : (lower.endsWith('.webp') ? 'image/webp' : 'image/jpeg');
    await _sendImageAttachment(
      bytes: bytes,
      mimeType: mime,
      fileName: img.name,
      caption: caption.trim(),
    );
  }

  Future<void> _pickAndSendPdf() async {
    if (_busy) {
      return;
    }
    final FilePickerResult? result = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      withData: true,
      allowedExtensions: <String>['pdf'],
    );
    if (result == null || result.files.isEmpty) {
      return;
    }
    final PlatformFile file = result.files.first;
    Uint8List? bytes = file.bytes;
    if (bytes == null && file.path != null && file.path!.trim().isNotEmpty) {
      try {
        bytes = await File(file.path!).readAsBytes();
      } catch (_) {
        bytes = null;
      }
    }
    if (bytes == null || bytes.isEmpty) {
      return;
    }

    final String? caption = await _askAttachmentCaption(
      title: 'PDF Caption',
      initialValue: _ctrl.text.trim(),
    );
    if (!mounted || caption == null) {
      return;
    }

    await _sendPdfAttachment(
      bytes: bytes,
      fileName: file.name.trim().isEmpty ? 'document.pdf' : file.name.trim(),
      caption: caption.trim(),
    );
  }

  String _inferAudioMimeType(String fileName) {
    final String lower = fileName.toLowerCase();
    if (lower.endsWith('.wav')) {
      return 'audio/wav';
    }
    if (lower.endsWith('.mp3')) {
      return 'audio/mpeg';
    }
    if (lower.endsWith('.aac')) {
      return 'audio/aac';
    }
    if (lower.endsWith('.ogg') || lower.endsWith('.opus')) {
      return 'audio/ogg';
    }
    if (lower.endsWith('.webm')) {
      return 'audio/webm';
    }
    return 'audio/mp4';
  }

  Future<void> _pickAndSendAudio() async {
    if (_busy) {
      return;
    }
    final FilePickerResult? result = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      withData: true,
      allowedExtensions: <String>[
        'mp3',
        'wav',
        'aac',
        'm4a',
        'ogg',
        'opus',
        'webm',
      ],
    );
    if (result == null || result.files.isEmpty) {
      return;
    }
    final PlatformFile file = result.files.first;
    Uint8List? bytes = file.bytes;
    if (bytes == null && file.path != null && file.path!.trim().isNotEmpty) {
      try {
        bytes = await File(file.path!).readAsBytes();
      } catch (_) {
        bytes = null;
      }
    }
    if (bytes == null || bytes.isEmpty) {
      return;
    }

    final String? caption = await _askAttachmentCaption(
      title: 'Voice Caption',
      initialValue: _ctrl.text.trim(),
    );
    if (!mounted || caption == null) {
      return;
    }

    final String cleanName = file.name.trim().isEmpty
        ? 'voice_note.m4a'
        : file.name.trim();
    await _sendAudioAttachment(
      bytes: bytes,
      fileName: cleanName,
      mimeType: _inferAudioMimeType(cleanName),
      caption: caption.trim(),
    );
  }

  bool _isWeakImageResponse(Map<String, dynamic> response) {
    final String answer = (response['answer'] ?? '').toString().trim();
    final String explanation = (response['explanation'] ?? '')
        .toString()
        .trim();
    final String lowered = '$answer $explanation'.toLowerCase();
    if (answer.isEmpty && explanation.isEmpty) {
      return true;
    }
    return lowered.contains('could not process image') ||
        lowered.contains('failed to process image') ||
        lowered.contains('unable to process image');
  }

  Future<void> _sendImageAttachment({
    required Uint8List bytes,
    required String mimeType,
    required String fileName,
    required String caption,
  }) async {
    final String rawBase64 = base64Encode(bytes);
    final String dataUrl = 'data:$mimeType;base64,$rawBase64';
    final String combinedPrompt = caption.isEmpty
        ? 'Solve this question from the image. Extract all visible math text accurately and show full JEE-style steps.'
        : '$caption\n\nUse the attached image as primary context. Extract all visible text and solve step-by-step for JEE.';
    final String outgoingUserText = caption.isEmpty
        ? '[Image sent]'
        : '$caption\n[Image sent]';

    setState(() {
      _messages.add(
        ChatMessage(
          id: 'local_${DateTime.now().millisecondsSinceEpoch}',
          role: 'user',
          text: outgoingUserText,
        ),
      );
      _loading = true;
    });
    _ctrl.clear();
    await _persistHistory();
    await _upsertAiChatSession(tryAiTitle: false);
    _scrollToBottom();

    try {
      Map<String, dynamic> response = await _sendChatWithGuard(
        prompt: combinedPrompt,
        userId: widget.userId,
        chatId: widget.chatId,
        function: widget.chatFunction,
        enablePersona: _personaEnabled,
        card: <String, dynamic>{
          if (widget.contextCard != null) ...widget.contextCard!,
          'source': 'image',
          'image_name': fileName,
          'image_mime': mimeType,
          'image_size': bytes.length,
          'image_data_url': dataUrl,
          if (caption.isNotEmpty) 'image_text_prompt': caption,
        },
        base64Image: rawBase64,
      );

      if (_isWeakImageResponse(response)) {
        response = await _sendChatWithGuard(
          prompt:
              '$combinedPrompt\n\nRetry mode: OCR every symbol carefully and re-check equations before final answer.',
          userId: widget.userId,
          chatId: widget.chatId,
          enablePersona: _personaEnabled,
          function: widget.chatFunction,
          card: <String, dynamic>{
            if (widget.contextCard != null) ...widget.contextCard!,
            'source': 'image_retry',
            'image_name': fileName,
            'image_mime': mimeType,
            'image_size': bytes.length,
            'image_data_url': dataUrl,
            if (caption.isNotEmpty) 'image_text_prompt': caption,
          },
          base64Image: dataUrl,
        );
      }

      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantFromResponse(response);
    } catch (e) {
      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantAnimated(
        _AssistantPayload(
          text: _friendlyNetworkMessage(e, imageMode: true),
          meta: 'Image request error: $e',
        ),
      );
    }

    _scrollToBottom();
  }

  Future<void> _sendPdfAttachment({
    required Uint8List bytes,
    required String fileName,
    required String caption,
  }) async {
    final String prompt = caption.isEmpty
        ? 'Use the attached PDF as context and solve the relevant question with JEE-style steps.'
        : '$caption\n\nUse the attached PDF as primary context. Extract key text before solving.';
    final String outgoingUserText = caption.isEmpty
        ? '[PDF sent: $fileName]'
        : '$caption\n[PDF sent: $fileName]';

    setState(() {
      _messages.add(
        ChatMessage(
          id: 'local_${DateTime.now().millisecondsSinceEpoch}',
          role: 'user',
          text: outgoingUserText,
        ),
      );
      _loading = true;
    });
    _ctrl.clear();
    await _persistHistory();
    await _upsertAiChatSession(tryAiTitle: false);
    _scrollToBottom();

    try {
      final String pdfUrl = await backendService.uploadFileData(
        fileName: fileName,
        dataUrl: 'data:application/pdf;base64,${base64Encode(bytes)}',
      );
      final Map<String, dynamic> response = await _sendChatWithGuard(
        prompt: prompt,
        userId: widget.userId,
        chatId: widget.chatId,
        function: widget.chatFunction,
        enablePersona: _personaEnabled,
        card: <String, dynamic>{
          if (widget.contextCard != null) ...widget.contextCard!,
          'source': 'pdf',
          'pdf_name': fileName,
          'pdf_url': pdfUrl,
          if (caption.isNotEmpty) 'pdf_caption': caption,
        },
      );

      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantFromResponse(response);
    } catch (e) {
      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantAnimated(
        _AssistantPayload(
          text: 'Failed to process PDF right now. Please retry.',
          meta: 'PDF request error: $e',
        ),
      );
    }

    _scrollToBottom();
  }

