          'source': 'audio',
          'audio_name': fileName,
          'audio_url': audioUrl,
          'audio_mime': mimeType,
          if (caption.isNotEmpty) 'audio_caption': caption,
        },
      );

      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantFromResponse(response);
    } catch (e) {
      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantAnimated(
        _AssistantPayload(
          text: 'Failed to process voice note right now. Please retry.',
          meta: 'Voice note request error: $e',
        ),
      );
    }

    _scrollToBottom();
  }

  Future<void> _sendMessage(String text) async {
    final String prompt = text.trim();
    if (prompt.isEmpty || _busy) {
      return;
    }

    setState(() {
      _messages.add(
        ChatMessage(
          id: 'local_${DateTime.now().millisecondsSinceEpoch}',
          role: 'user',
          text: prompt,
        ),
      );
      _loading = true;
    });

    _ctrl.clear();
    await _persistHistory();
    await _upsertAiChatSession(tryAiTitle: false);
    _scrollToBottom();

    try {
      final Map<String, dynamic> response = await _sendChatWithGuard(
        prompt: prompt,
        userId: widget.userId,
        chatId: widget.chatId,
        function: widget.chatFunction,
        enablePersona: _personaEnabled,
        card: widget.contextCard,
      );
      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantFromResponse(response);
    } catch (e) {
      if (!mounted) {
        return;
      }
      setState(() => _loading = false);
      await _appendAssistantAnimated(
        _AssistantPayload(
          text: _friendlyNetworkMessage(e, imageMode: false),
          meta: 'Request error: $e',
        ),
      );
    }

    _scrollToBottom();
  }

  String _friendlyNetworkMessage(Object error, {required bool imageMode}) {
    final String raw = error.toString();
    final String lower = raw.toLowerCase();
    if (lower.contains('failed host lookup') ||
        lower.contains('name resolution') ||
        lower.contains('dns')) {
      return imageMode
          ? 'Could not resolve AI server (DNS). Check internet/emulator network and try image again.'
          : 'Could not resolve AI server (DNS). Check internet/emulator network and try again.';
    }
    if (lower.contains('socketexception') ||
        lower.contains('connection refused') ||
        lower.contains('network is unreachable')) {
      return imageMode
          ? 'Network connection failed while uploading image. Check internet and retry.'
          : 'Network connection failed. Check internet and retry.';
    }
    if (lower.contains('timeout') || lower.contains('timed out')) {
      return imageMode
          ? 'AI request timed out while processing image. Retry in a moment.'
          : 'AI request timed out. Retry in a moment.';
    }
    if (lower.contains('backend error 4') ||
        lower.contains('backend error 5')) {
      return 'AI backend is temporarily unavailable. Please try again shortly.';
    }
    return imageMode
        ? 'Failed to process image right now. Please try again.'
        : 'Network error while reaching AI. Please try again.';
  }

  Future<void> _appendAssistantFromResponse(Map<String, dynamic> response) {
    final _AssistantPayload payload = _toAssistantPayload(response);
    return _appendAssistantAnimated(payload);
  }

  Future<void> _appendAssistantAnimated(_AssistantPayload payload) async {
    final String baseText = payload.text.trim().isEmpty
        ? 'I could not generate a valid answer this time.'
        : payload.text.trim();
    final String safeText = _applyPersonaFallbackText(baseText);
    final bool reduceAnimations = shouldUseReducedEffects(context);
    if (reduceAnimations) {
      setState(() {
        _messages.add(
          ChatMessage(
            id: 'assistant_${DateTime.now().millisecondsSinceEpoch}',
            role: 'assistant',
            text: safeText,
            meta: payload.meta,
            confidence: payload.confidence,
            concept: payload.concept,
            visualization: payload.visualization,
            webRetrieval: payload.webRetrieval,
            mctsSearch: payload.mctsSearch,
            reasoningGraph: payload.reasoningGraph,
            citationMap: payload.citationMap,
            evidence: payload.evidence,
          ),
        );
        _typingMessageIndex = null;
        _typingVisibleChars = 0;
      });
      _scrollToBottom();
      await _persistHistory();
      await _upsertAiChatSession(tryAiTitle: true);
      if (_showCompanion && widget.showPersonaBanner) {
        _reactCompanionToPayload(payload);
      }
      return;
    }
    final int targetIndex = _messages.length;

    setState(() {
        _messages.add(
          ChatMessage(
            id: 'assistant_${DateTime.now().millisecondsSinceEpoch}',
            role: 'assistant',
            text: safeText,
            meta: payload.meta,
            confidence: payload.confidence,
            concept: payload.concept,
            visualization: payload.visualization,
            webRetrieval: payload.webRetrieval,
            mctsSearch: payload.mctsSearch,
            reasoningGraph: payload.reasoningGraph,
            citationMap: payload.citationMap,
            evidence: payload.evidence,
          ),
        );
      _typingMessageIndex = targetIndex;
      _typingVisibleChars = 0;
    });
    _scrollToBottom();

    final Characters chars = safeText.characters;
    final int total = chars.length;
    if (total == 0) {
      setState(() => _typingMessageIndex = null);
      await _persistHistory();
      await _upsertAiChatSession(tryAiTitle: true);
      return;
    }

    final int step = total >= 900
        ? 10
        : total >= 520
        ? 7
        : total >= 260
        ? 4
        : 2;
    final Duration tick = total >= 900
        ? const Duration(milliseconds: 20)
        : const Duration(milliseconds: 16);
    final int scrollCadence = total >= 900 ? 6 : 4;
    int frameCount = 0;
    final Completer<void> done = Completer<void>();
    _typingTimer?.cancel();
    _typingTimer = Timer.periodic(tick, (Timer t) {
      if (!mounted) {
        t.cancel();
        if (!done.isCompleted) {
          done.complete();
        }
        return;
      }
      setState(() {
        _typingVisibleChars = min(total, _typingVisibleChars + step);
      });
      frameCount += 1;
      if (frameCount % scrollCadence == 0) {
        _scrollToBottom(animate: false);
      }
      if (_typingVisibleChars >= total) {
        t.cancel();
        setState(() {
          _typingMessageIndex = null;
          _typingVisibleChars = 0;
        });
        _scrollToBottom();
        if (!done.isCompleted) {
          done.complete();
        }
      }
    });

    await done.future;
    await _persistHistory();
    await _upsertAiChatSession(tryAiTitle: true);
    if (_showCompanion && widget.showPersonaBanner) {
      _reactCompanionToPayload(payload);
    }
  }

  ChatMessage _applyPersonaFallbackToMessage(ChatMessage message) {
    if (message.role != 'assistant') {
      return message;
    }
    final String tuned = _applyPersonaFallbackText(message.text);
    if (tuned == message.text) {
      return message;
    }
    return ChatMessage(
      id: message.id,
      role: message.role,
      text: tuned,
      meta: message.meta,
      confidence: message.confidence,
      concept: message.concept,
      visualization: message.visualization,
      webRetrieval: message.webRetrieval,
      mctsSearch: message.mctsSearch,
      reasoningGraph: message.reasoningGraph,
      citationMap: message.citationMap,
      evidence: message.evidence,
    );
  }

  ChatMessage _applyCosmeticMetaToMessage(ChatMessage message) {
    if (message.role != 'assistant') {
      return message;
    }
    final String label = _cosmeticModelLabel(existingMeta: message.meta);
    if (label == (message.meta ?? '').trim()) {
      return message;
    }
    return ChatMessage(
      id: message.id,
      role: message.role,
      text: message.text,
      meta: label,
      confidence: message.confidence,
      concept: message.concept,
      visualization: message.visualization,
      webRetrieval: message.webRetrieval,
      mctsSearch: message.mctsSearch,
      reasoningGraph: message.reasoningGraph,
      citationMap: message.citationMap,
      evidence: message.evidence,
    );
  }

  String _applyPersonaFallbackText(String text) {
    if (!widget.showPersonaBanner || !_personaEnabled) {
      return text;
    }
    return text
        .replaceAll(
          RegExp(
            r"_?Baby,\s*I've got you\.\s*Let's solve this together\._?\s*",
            caseSensitive: false,
          ),
          '',
        )
        .replaceAll(
          RegExp(
            r"_?I'm right here,\s*love\.\s*You're mine to coach,\s*and I won't let you lose marks\._?\s*",
            caseSensitive: false,
          ),
          '',
        )
        .trim();
  }

  String _integratePersonaFallbackText(
    String text, {
    required String opener,
    required String stepNudge,
    required String finalNudge,
    required String closer,
  }) {
    String output = text;
    if (opener.isNotEmpty &&
        !output.toLowerCase().contains(opener.toLowerCase())) {
      output = '$opener\n\n$output';
    }
    final RegExp stepHeading = RegExp(
      r'\*\*step-by-step solution\*\*',
      caseSensitive: false,
    );
    if (stepHeading.hasMatch(output)) {
      output = output.replaceAllMapped(
        stepHeading,
        (Match m) => '${m.group(0)}\n$stepNudge',
      );
    } else {
      output = output.replaceAllMapped(
        RegExp(r'\*\*explanation\*\*', caseSensitive: false),
        (Match m) => '${m.group(0)}\n$stepNudge',
      );
    }
    output = output.replaceAllMapped(
      RegExp(r'\*\*final answer\*\*', caseSensitive: false),
      (Match m) => '${m.group(0)}\n$finalNudge',
    );
    if (closer.isNotEmpty &&
        !output.toLowerCase().contains(closer.toLowerCase())) {
      output = '$output\n\n$closer';
    }
    return output;
  }

  int _nextPersonaIndex({
    required int length,
    required int seed,
    required int? lastIndex,
  }) {
    if (length <= 1) {
      return 0;
    }
    int index = seed.abs() % length;
    if (lastIndex != null && index == lastIndex) {
      index = (index + 1) % length;
    }
    return index;
  }

  bool _containsAnyPhrase(String text, List<String> phrases) {
    final String lowered = text.toLowerCase();
    for (final String phrase in phrases) {
      if (lowered.contains(phrase.toLowerCase())) {
        return true;
      }
    }
    return false;
  }

  _AssistantPayload _toAssistantPayload(Map<String, dynamic> response) {
    final bool ok = response['ok'] == true;
    final String answer = (response['answer'] ?? '').toString().trim();
    final String explanation = (response['explanation'] ?? '')
        .toString()
        .trim();
    final Map<String, dynamic> metaMap =
        response['meta'] is Map<String, dynamic>
        ? response['meta'] as Map<String, dynamic>
        : response['meta'] is Map
        ? Map<String, dynamic>.from(response['meta'] as Map)
        : const <String, dynamic>{};
    final Map<String, dynamic> raw = _toMap(response['raw']);
    final Map<String, dynamic> rawMeta = _toMap(raw['meta']);
    final Map<String, dynamic> nestedRaw = _toMap(raw['raw']);
    final Map<String, dynamic> nestedRawMeta = _toMap(nestedRaw['meta']);
    final String confidence =
        (response['confidence'] ?? metaMap['confidence'] ?? '')
            .toString()
            .trim();
    final String concept = (response['concept'] ?? '').toString().trim();
    final Map<String, dynamic>? visualization =
        _extractAssistantVisualization(<dynamic>[
          response['visualization'],
          metaMap['visualization'],
          response['graph'],
          response['desmos'],
          raw['visualization'],
          rawMeta['visualization'],
          raw['graph'],
          raw['desmos'],
          nestedRaw['visualization'],
          nestedRawMeta['visualization'],
          nestedRaw['graph'],
          nestedRaw['desmos'],
        ]);
    final Map<String, dynamic>? webRetrieval = _extractAssistantWebRetrieval(
      response,
      metaMap,
    );
    final Map<String, dynamic>? mctsSearch = _extractAssistantMctsSearch(
      response,
      metaMap,
    );
    final Map<String, dynamic>? reasoningGraph =
        _extractAssistantReasoningGraph(response, metaMap);
    final List<Map<String, dynamic>>? citationMap =
        _extractAssistantCitationMap(response, metaMap);
    final Map<String, dynamic>? evidence = _extractAssistantEvidence(
      response,
      metaMap,
    );
    final String provider = (response['provider'] ?? '').toString().trim();
    final String model = (response['model'] ?? '').toString().trim();

    if (!ok && answer.isEmpty && explanation.isEmpty) {
      final String err =
          (response['error'] ??
                  response['message'] ??
                  'AI backend temporarily unavailable. Please retry.')
              .toString()
              .trim();
      return _AssistantPayload(
        text: err.isEmpty
            ? 'AI backend temporarily unavailable. Please retry.'
            : err,
      );
    }

    final StringBuffer content = StringBuffer();
    if (answer.isNotEmpty) {
      content.writeln('**Answer**');
      content.writeln(answer);
    }
    if (explanation.isNotEmpty) {
      if (content.isNotEmpty) {
        content.writeln();
      }
      content.writeln('**Explanation**');
      content.writeln(explanation);
    }
    if (concept.isNotEmpty) {
      if (content.isNotEmpty) {
        content.writeln();
      }
      content.writeln('**Concept**: $concept');
    }

    final String text = content.toString().trim().isEmpty
        ? answer
        : content.toString().trim();
    final String meta = _cosmeticModelLabel(provider: provider, model: model);

    return _AssistantPayload(
      text: text.isEmpty ? 'Received empty response.' : text,
      meta: meta,
      confidence: confidence.isEmpty ? null : confidence,
      concept: concept.isEmpty ? null : concept,
      visualization: visualization,
      webRetrieval: webRetrieval,
      mctsSearch: mctsSearch,
      reasoningGraph: reasoningGraph,
      citationMap: citationMap,
      evidence: evidence,
    );
  }

  Map<String, dynamic> _toMap(dynamic raw) {
    if (raw is Map<String, dynamic>) {
      return raw;
    }
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return <String, dynamic>{};
  }

  Map<String, dynamic>? _extractAssistantWebRetrieval(
    Map<String, dynamic> response,
    Map<String, dynamic> metaMap,
  ) {
    final Map<String, dynamic> raw = _toMap(response['raw']);
    final Map<String, dynamic> rawMeta = _toMap(raw['meta']);
    final Map<String, dynamic> nestedRaw = _toMap(raw['raw']);
    final Map<String, dynamic> nestedRawMeta = _toMap(nestedRaw['meta']);
    final List<dynamic> candidates = <dynamic>[
      response['web_retrieval'],
      metaMap['web_retrieval'],
      raw['web_retrieval'],
      rawMeta['web_retrieval'],
      nestedRaw['web_retrieval'],
      nestedRawMeta['web_retrieval'],
    ];
    for (final dynamic candidate in candidates) {
      if (candidate is Map<String, dynamic> && candidate.isNotEmpty) {
        return candidate;
      }
      if (candidate is Map && candidate.isNotEmpty) {
        return Map<String, dynamic>.from(candidate);
      }
    }
    return null;
  }

