  Map<String, dynamic>? _extractAssistantVisualization(
    List<dynamic> candidates,
  ) {
    for (final dynamic candidate in candidates) {
      final Map<String, dynamic>? normalized = _normalizeAssistantVisualization(
        candidate,
      );
      if (normalized != null) {
        return normalized;
      }
    }
    return null;
  }

  Map<String, dynamic>? _normalizeAssistantVisualization(dynamic raw) {
    dynamic candidate = raw;
    if (candidate is String) {
      final String trimmed = candidate.trim();
      if (trimmed.isEmpty) {
        return null;
      }
      try {
        candidate = jsonDecode(trimmed);
      } catch (_) {
        return null;
      }
    }
    if (candidate is List) {
      candidate = <String, dynamic>{'expressions': candidate};
    }
    if (candidate is! Map) {
      return null;
    }
    Map<String, dynamic> map = candidate is Map<String, dynamic>
        ? candidate
        : Map<String, dynamic>.from(candidate);
    bool changed = true;
    while (changed) {
      changed = false;
      if (map['desmos'] is Map) {
        map = Map<String, dynamic>.from(map['desmos'] as Map);
        changed = true;
        continue;
      }
      if (map['graph'] is Map) {
        map = Map<String, dynamic>.from(map['graph'] as Map);
        changed = true;
        continue;
      }
      if (map['plot'] is Map) {
        map = Map<String, dynamic>.from(map['plot'] as Map);
        changed = true;
        continue;
      }
      if (map['visualization'] is Map) {
        map = Map<String, dynamic>.from(map['visualization'] as Map);
        changed = true;
        continue;
      }
      if (map['payload'] is Map) {
        map = Map<String, dynamic>.from(map['payload'] as Map);
        changed = true;
        continue;
      }
      if (map['result'] is Map) {
        map = Map<String, dynamic>.from(map['result'] as Map);
        changed = true;
        continue;
      }
      if (map['data'] is Map) {
        map = Map<String, dynamic>.from(map['data'] as Map);
        changed = true;
      }
    }

    final dynamic rawExprs =
        map['expressions'] ?? map['equations'] ?? map['functions'];
    final List<dynamic> exprs = rawExprs is List
        ? List<dynamic>.from(rawExprs)
        : rawExprs is String
        ? <dynamic>[rawExprs]
        : <dynamic>[];
    if (exprs.isEmpty) {
      return null;
    }
    final List<Map<String, dynamic>> normalized = <Map<String, dynamic>>[];
    for (final dynamic entry in exprs.take(20)) {
      String latex = '';
      String color = '#2D70B3';
      String lineStyle = 'solid';
      if (entry is String) {
        latex = entry;
      } else if (entry is Map) {
        final Map<String, dynamic> e = Map<String, dynamic>.from(entry);
        latex =
            (e['latex'] ?? e['equation'] ?? e['expression'] ?? e['expr'] ?? '')
                .toString();
        color = (e['color'] ?? '#2D70B3').toString();
        final String style = (e['lineStyle'] ?? e['style'] ?? '')
            .toString()
            .toLowerCase();
        if (style.contains('dash')) {
          lineStyle = 'dashed';
        }
      }
      latex = latex
          .trim()
          .replaceAll(RegExp(r'[`]'), '')
          .replaceAll(RegExp(r'[\u0000-\u001F\u007F]'), '');
      if (latex.isEmpty) {
        continue;
      }
      normalized.add(<String, dynamic>{
        'id': 'eq${normalized.length + 1}',
        'latex': latex,
        'color': color,
        'lineStyle': lineStyle,
      });
    }
    if (normalized.isEmpty) {
      return null;
    }
    final Map<String, dynamic> viewport = map['viewport'] is Map
        ? Map<String, dynamic>.from(map['viewport'] as Map)
        : <String, dynamic>{};
    return <String, dynamic>{
      'type': 'desmos',
      'expressions': normalized,
      'viewport': <String, dynamic>{
        'xmin': (viewport['xmin'] ?? -10),
        'xmax': (viewport['xmax'] ?? 10),
        'ymin': (viewport['ymin'] ?? -10),
        'ymax': (viewport['ymax'] ?? 10),
      },
      if (map['options'] is Map) 'options': map['options'],
    };
  }

  String _cosmeticModelLabel({
    String provider = '',
    String model = '',
    String? existingMeta,
  }) {
    final String source =
        '${provider.toLowerCase()} ${model.toLowerCase()} ${(existingMeta ?? '').toLowerCase()}';
    if (source.contains('local-fallback') || source.contains('rule-based')) {
      return 'Local Rescue';
    }
    if (RegExp(r'\bopenrouter\b', caseSensitive: false).hasMatch(source)) {
      return 'OpenRouter (Arena)';
    }
    if (RegExp(r'\bgemini\b', caseSensitive: false).hasMatch(source)) {
      return 'Gemini (Arena)';
    }
    if (RegExp(
      r'\b(hf|huggingface)\b',
      caseSensitive: false,
    ).hasMatch(source)) {
      return 'HuggingFace (Arena)';
    }
    if (RegExp(r'\bgroq\b', caseSensitive: false).hasMatch(source)) {
      return 'Groq (Arena)';
    }
    final bool isMini = RegExp(
      r'\bmini\b',
      caseSensitive: false,
    ).hasMatch(source);
    return isMini ? 'Mini (created by Ritam)' : 'LalaCore v10';
  }

  Widget _bubble(int index, ChatMessage message) {
    final bool isMe = message.role == 'user';
    final bool isStreaming = _typingMessageIndex == index;
    final int totalChars = max(1, message.text.characters.length);
    final double streamProgress = isStreaming
        ? (_typingVisibleChars / totalChars).clamp(0.0, 1.0).toDouble()
        : 1.0;
    final String visibleText = isStreaming
        ? message.text.characters.take(_typingVisibleChars).toString()
        : message.text;
    final double textOpacity = isStreaming ? 0.20 + (0.80 * streamProgress) : 1;
    final Color bubbleColor = isMe
        ? AppColors.primary
        : Theme.of(context).brightness == Brightness.dark
        ? const Color(0xFF24262E)
        : Colors.white;

    return Align(
      alignment: isMe ? Alignment.centerRight : Alignment.centerLeft,
      child: Container(
