      ),
    );
  }

  Color _confidenceColor(String value) {
    final String lowered = value.toLowerCase();
    if (lowered.contains('high')) {
      return Colors.green;
    }
    if (lowered.contains('medium')) {
      return Colors.orange;
    }
    if (lowered.contains('low')) {
      return Colors.redAccent;
    }
    final double? n = double.tryParse(value);
    if (n == null) {
      return AppColors.primary;
    }
    if (n >= 0.75) {
      return Colors.green;
    }
    if (n >= 0.45) {
      return Colors.orange;
    }
    return Colors.redAccent;
  }

  double _confidenceToScore(String? value) {
    final String raw = (value ?? '').trim().toLowerCase();
    if (raw.isEmpty) {
      return 0.65;
    }
    final double? parsed = double.tryParse(raw);
    if (parsed != null) {
      return parsed.clamp(0, 1).toDouble();
    }
    if (raw.contains('high')) {
      return 0.88;
    }
    if (raw.contains('medium')) {
      return 0.62;
    }
    if (raw.contains('low')) {
      return 0.35;
    }
    return 0.65;
  }

  void _reactCompanionToPayload(_AssistantPayload payload) {
    if (!_enableCompanion) {
      return;
    }
    final String txt = payload.text.trim();
    if (txt.isEmpty || _reducedEffects(context)) {
      return;
    }
    final String lower = txt.toLowerCase();
    final bool looksCorrect =
        !lower.contains('error') &&
        !lower.contains('failed') &&
        !lower.contains('network');
    unawaited(
      _companionController.reactToAIResponse(
        text: txt,
        confidenceScore: _confidenceToScore(payload.confidence),
        isCorrectAnswer: looksCorrect,
      ),
    );
  }

