class _AssistantPayload {
  const _AssistantPayload({
    required this.text,
    this.meta,
    this.confidence,
    this.concept,
    this.visualization,
    this.webRetrieval,
    this.mctsSearch,
    this.reasoningGraph,
    this.citationMap,
    this.evidence,
  });

  final String text;
  final String? meta;
  final String? confidence;
  final String? concept;
  final Map<String, dynamic>? visualization;
  final Map<String, dynamic>? webRetrieval;
  final Map<String, dynamic>? mctsSearch;
  final Map<String, dynamic>? reasoningGraph;
  final List<Map<String, dynamic>>? citationMap;
  final Map<String, dynamic>? evidence;
}

class _SimilarProblemCard extends StatefulWidget {
  const _SimilarProblemCard({required this.retrieval});

  final Map<String, dynamic> retrieval;

  @override
  State<_SimilarProblemCard> createState() => _SimilarProblemCardState();
}

class _SimilarProblemCardState extends State<_SimilarProblemCard> {
  bool _showHint = false;
  bool _showSolution = false;
  bool _showAnswer = false;

  String _s(dynamic value) => (value ?? '').toString().trim();

  @override
  Widget build(BuildContext context) {
    final Map<String, dynamic> solution = widget.retrieval['solution'] is Map
        ? Map<String, dynamic>.from(widget.retrieval['solution'] as Map)
        : const <String, dynamic>{};
    final List<Map<String, dynamic>> matches =
        widget.retrieval['matches'] is List
        ? List<dynamic>.from(widget.retrieval['matches'] as List)
              .whereType<Map>()
              .map((Map row) => Map<String, dynamic>.from(row))
              .toList()
        : <Map<String, dynamic>>[];
    final List<Map<String, dynamic>> citations =
        widget.retrieval['citations'] is List
        ? List<dynamic>.from(widget.retrieval['citations'] as List)
              .whereType<Map>()
              .map((Map row) => Map<String, dynamic>.from(row))
              .toList()
        : <Map<String, dynamic>>[];
    final Map<String, dynamic> firstMatch = matches.isNotEmpty
        ? matches.first
        : const <String, dynamic>{};
    final bool enabled = widget.retrieval['enabled'] == true;
    final bool cacheHit = widget.retrieval['cache_hit'] == true;
    final bool contextInjected = widget.retrieval['context_injected'] == true;
    final Map<String, dynamic> evidence =
        widget.retrieval['evidence'] is Map<String, dynamic>
        ? Map<String, dynamic>.from(widget.retrieval['evidence'] as Map)
        : widget.retrieval['evidence'] is Map
        ? Map<String, dynamic>.from(widget.retrieval['evidence'] as Map)
        : const <String, dynamic>{};
    final String evidenceStrength = _s(evidence['strength']).isNotEmpty
        ? _s(evidence['strength'])
        : '';
    final double evidenceScore = evidence['score'] is num
        ? (evidence['score'] as num).toDouble()
        : double.tryParse(_s(evidence['score'])) ?? 0.0;
    final String query = _s(widget.retrieval['query']);
    final String hint = _s(solution['hint']);
    final String solutionText = _s(solution['solution_text']);
    final String possibleAnswer = _s(solution['answer']);
    final String sourceUrl = _s(solution['source_url']).isNotEmpty
        ? _s(solution['source_url'])
        : _s(firstMatch['url']);
    final String sourceTitle = _s(firstMatch['title']).isNotEmpty
        ? _s(firstMatch['title'])
        : _s(solution['source']);
    final double similarity = (firstMatch['similarity'] is num)
        ? (firstMatch['similarity'] as num).toDouble()
        : double.tryParse(_s(firstMatch['similarity'])) ?? 0.0;
    final Map<String, dynamic> latency =
        widget.retrieval['latency_s'] is Map<String, dynamic>
        ? Map<String, dynamic>.from(widget.retrieval['latency_s'] as Map)
        : widget.retrieval['latency_s'] is Map
        ? Map<String, dynamic>.from(widget.retrieval['latency_s'] as Map)
        : const <String, dynamic>{};
    final int searchMs =
        (((latency['search'] is num)
                        ? (latency['search'] as num).toDouble()
                        : double.tryParse(_s(latency['search'])) ?? 0.0)
                    .clamp(0.0, 99.0) *
                1000)
            .round();
    final int fetchMs =
        (((latency['fetch'] is num)
                        ? (latency['fetch'] as num).toDouble()
                        : double.tryParse(_s(latency['fetch'])) ?? 0.0)
                    .clamp(0.0, 99.0) *
                1000)
            .round();
    final List<Map<String, dynamic>> sourceRows = citations.isNotEmpty
        ? citations
        : matches;

    if (!enabled &&
        hint.isEmpty &&
        solutionText.isEmpty &&
        sourceUrl.isEmpty &&
        matches.isEmpty) {
      return const SizedBox.shrink();
    }

    return _InsightGlassCard(
      icon: Icons.travel_explore_rounded,
      accent: AppColors.primaryTone(context),
      title: 'Similar problem found online',
      subtitle: similarity > 0
          ? 'match ${(similarity * 100).toStringAsFixed(0)}% • ${sourceRows.length} sources'
          : '${sourceRows.length} sources',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              if (cacheHit)
                const _InsightPill(
                  label: 'cached',
                  icon: Icons.bolt_rounded,
                  color: Color(0xFF00A78E),
                ),
              if (contextInjected)
                const _InsightPill(
                  label: 'context injected',
                  icon: Icons.auto_awesome_rounded,
                  color: Color(0xFF3F8DFF),
                ),
              if (evidenceStrength.isNotEmpty)
                _InsightPill(
                  label: evidenceScore > 0
                      ? 'evidence $evidenceStrength • ${(evidenceScore * 100).round()}%'
                      : 'evidence $evidenceStrength',
                  icon: Icons.verified_rounded,
                  color: evidenceStrength == 'strong'
                      ? const Color(0xFF2ECC71)
                      : evidenceStrength == 'ok'
                      ? const Color(0xFF2D9CDB)
                      : const Color(0xFFF2994A),
                ),
              if (searchMs > 0 || fetchMs > 0)
                _InsightPill(
                  label: '${searchMs}ms search • ${fetchMs}ms fetch',
                  icon: Icons.timer_outlined,
                  color: Colors.blueGrey,
                ),
            ],
          ),
          if (query.isNotEmpty) ...<Widget>[
            const SizedBox(height: 8),
            Text(
              'Query: $query',
              maxLines: 2,
              overflow: TextOverflow.ellipsis,
              style: TextStyle(
                fontSize: 11,
                color: Theme.of(
                  context,
                ).textTheme.bodySmall?.color?.withOpacity(0.78),
              ),
            ),
          ],
          const SizedBox(height: 10),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              if (hint.isNotEmpty)
                _InsightGhostButton(
                  icon: _showHint
                      ? Icons.visibility_off_outlined
                      : Icons.lightbulb_outline_rounded,
                  label: _showHint ? 'Hide hint' : 'View hint',
                  active: _showHint,
                  onPressed: () => setState(() => _showHint = !_showHint),
                ),
              if (sourceUrl.isNotEmpty)
                _InsightGhostButton(
                  icon: Icons.open_in_new_rounded,
                  label: 'Open source',
                  onPressed: () async {
                    final Uri? uri = Uri.tryParse(sourceUrl);
                    if (uri == null) {
                      return;
                    }
                    await launchUrl(uri, mode: LaunchMode.externalApplication);
                  },
                ),
              if (solutionText.isNotEmpty)
                _InsightGhostButton(
                  icon: _showSolution
                      ? Icons.unfold_less_rounded
                      : Icons.menu_book_rounded,
                  label: _showSolution
                      ? 'Hide full solution'
                      : 'View full solution',
                  active: _showSolution,
                  onPressed: () =>
                      setState(() => _showSolution = !_showSolution),
                ),
            ],
          ),
          if (_showHint && hint.isNotEmpty) ...<Widget>[
            const SizedBox(height: 10),
            _InsightSection(
              title: 'Hint',
              icon: Icons.lightbulb_outline_rounded,
              child: SmartText(hint, style: const TextStyle(fontSize: 12.4)),
            ),
          ],
          if (_showSolution && solutionText.isNotEmpty) ...<Widget>[
            const SizedBox(height: 10),
            _InsightSection(
              title: 'Solution excerpt',
              icon: Icons.auto_stories_rounded,
              child: SmartText(
                solutionText,
                style: const TextStyle(fontSize: 12.4),
              ),
            ),
            if (possibleAnswer.isNotEmpty) ...<Widget>[
              const SizedBox(height: 8),
              _InsightGhostButton(
                icon: _showAnswer
                    ? Icons.visibility_off_outlined
                    : Icons.key_rounded,
                label: _showAnswer
                    ? 'Hide possible answer'
                    : 'Reveal possible answer',
                active: _showAnswer,
                onPressed: () => setState(() => _showAnswer = !_showAnswer),
              ),
              if (_showAnswer) ...<Widget>[
                const SizedBox(height: 8),
                _InsightSection(
                  title: 'Possible answer',
                  icon: Icons.check_circle_outline_rounded,
                  child: SmartText(
                    possibleAnswer,
                    style: const TextStyle(fontSize: 12.4),
                  ),
                ),
              ],
            ],
          ],
          if (sourceRows.isNotEmpty) ...<Widget>[
            const SizedBox(height: 10),
            _InsightSection(
              title: 'Sources consulted',
              icon: Icons.public_rounded,
              child: Column(
                children: <Widget>[
                  for (final Map<String, dynamic> row in sourceRows.take(3))
                    _SourceListTile(
                      title: _s(row['title']).isNotEmpty
                          ? _s(row['title'])
                          : _s(row['source']),
                      source: _s(row['source']),
                      url: _s(row['url']),
                      similarity: row['similarity'] is num
                          ? (row['similarity'] as num).toDouble()
                          : double.tryParse(_s(row['similarity'])) ?? 0.0,
                    ),
                ],
              ),
            ),
          ],
          if (sourceTitle.isNotEmpty && sourceRows.isEmpty) ...<Widget>[
            const SizedBox(height: 8),
            Text(
              sourceTitle,
              style: const TextStyle(
                fontSize: 12.2,
                fontWeight: FontWeight.w600,
              ),
            ),
          ],
        ],
      ),
    );
  }
}

class _CitationMapCard extends StatelessWidget {
  const _CitationMapCard({
    required this.citationMap,
    this.evidence,
  });

  final List<Map<String, dynamic>> citationMap;
  final Map<String, dynamic>? evidence;

  String _s(dynamic value) => (value ?? '').toString().trim();

  @override
  Widget build(BuildContext context) {
    if (citationMap.isEmpty) {
      return const SizedBox.shrink();
    }
    final Map<String, dynamic> evidenceMap = evidence ?? <String, dynamic>{};
    final String evidenceStrength = _s(evidenceMap['strength']);
    final double evidenceScore = evidenceMap['score'] is num
        ? (evidenceMap['score'] as num).toDouble()
        : double.tryParse(_s(evidenceMap['score'])) ?? 0.0;

    final Set<String> sources = <String>{};
    for (final Map<String, dynamic> section in citationMap) {
      final List<dynamic> rows = section['sources'] is List
          ? List<dynamic>.from(section['sources'] as List)
          : const <dynamic>[];
      for (final dynamic row in rows) {
        if (row is Map) {
          final String source = _s(row['source']);
          if (source.isNotEmpty) {
            sources.add(source);
          }
        }
      }
    }

    return _InsightGlassCard(
      icon: Icons.fact_check_rounded,
      accent: const Color(0xFF36A469),
      title: 'Answer evidence map',
      subtitle: '${citationMap.length} sections • ${sources.length} sources',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              if (evidenceStrength.isNotEmpty)
                _InsightPill(
                  label: evidenceScore > 0
                      ? 'evidence $evidenceStrength • ${(evidenceScore * 100).round()}%'
                      : 'evidence $evidenceStrength',
                  icon: Icons.verified_rounded,
                  color: evidenceStrength == 'strong'
                      ? const Color(0xFF2ECC71)
                      : evidenceStrength == 'ok'
                          ? const Color(0xFF2D9CDB)
                          : const Color(0xFFF2994A),
                ),
              if (sources.isNotEmpty)
                _InsightPill(
                  label: '${sources.length} sources',
                  icon: Icons.public_rounded,
                  color: const Color(0xFF1EA59C),
                ),
            ],
          ),
          const SizedBox(height: 10),
          for (final Map<String, dynamic> section in citationMap.take(2)) ...<Widget>[
            _InsightSection(
              title: _s(section['label']).isNotEmpty
                  ? _s(section['label'])
                  : 'Section',
              icon: Icons.bookmark_outline,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  if (_s(section['segment']).isNotEmpty)
                    Padding(
                      padding: const EdgeInsets.only(bottom: 8),
                      child: Text(
                        _s(section['segment']),
                        maxLines: 4,
                        overflow: TextOverflow.ellipsis,
                        style: TextStyle(
                          fontSize: 11.5,
                          color: Theme.of(context)
                              .textTheme
                              .bodySmall
                              ?.color
                              ?.withOpacity(0.8),
                        ),
                      ),
                    ),
                  if (section['sources'] is List)
                    ...List<dynamic>.from(section['sources'] as List)
                        .whereType<Map>()
                        .take(3)
                        .map(
                          (Map row) => _SourceListTile(
                            title: _s(row['title']),
                            source: _s(row['source']),
                            url: _s(row['url']),
                            similarity: row['similarity'] is num
                                ? (row['similarity'] as num).toDouble()
                                : double.tryParse(_s(row['similarity'])) ?? 0.0,
                          ),
                        )
                        .toList(),
                ],
              ),
            ),
            const SizedBox(height: 8),
          ],
        ],
      ),
    );
  }
}

class _MctsSearchCard extends StatefulWidget {
  const _MctsSearchCard({required this.search});

  final Map<String, dynamic> search;

  @override
  State<_MctsSearchCard> createState() => _MctsSearchCardState();
}

class _MctsSearchCardState extends State<_MctsSearchCard> {
  String _s(dynamic value) => (value ?? '').toString().trim();

  @override
  Widget build(BuildContext context) {
    final Map<String, dynamic> telemetry = widget.search['telemetry'] is Map
        ? Map<String, dynamic>.from(widget.search['telemetry'] as Map)
        : const <String, dynamic>{};
    final int iterations = telemetry['iterations'] is num
        ? (telemetry['iterations'] as num).toInt()
        : int.tryParse(_s(telemetry['iterations'])) ?? 0;
    final int nodes = telemetry['nodes_explored'] is num
        ? (telemetry['nodes_explored'] as num).toInt()
        : int.tryParse(_s(telemetry['nodes_explored'])) ?? 0;
    final int tools = telemetry['tool_calls'] is num
        ? (telemetry['tool_calls'] as num).toInt()
        : int.tryParse(_s(telemetry['tool_calls'])) ?? 0;
    final bool verified = telemetry['verification_pass'] == true;
    final String stopReason = _s(telemetry['stop_reason']);

    final List<dynamic> rawPath = widget.search['best_path'] is List
        ? List<dynamic>.from(widget.search['best_path'] as List)
        : <dynamic>[];
    final List<Map<String, dynamic>> path = rawPath
        .whereType<Map>()
        .map((Map row) => Map<String, dynamic>.from(row))
        .toList();

    if (iterations <= 0 && path.isEmpty && nodes <= 0) {
      return const SizedBox.shrink();
    }

    return _InsightGlassCard(
      icon: Icons.alt_route_rounded,
      accent: const Color(0xFF5F67FF),
      title: 'MCTS exploration',
      subtitle: '$iterations iterations • $nodes nodes',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              _InsightPill(
                label: verified ? 'verified path' : 'unverified path',
                icon: verified
                    ? Icons.verified_rounded
                    : Icons.warning_amber_rounded,
                color: verified
                    ? const Color(0xFF199E6D)
                    : const Color(0xFFFF8A3D),
              ),
              _InsightPill(
                label: '$tools tool calls',
                icon: Icons.precision_manufacturing_outlined,
                color: const Color(0xFF5F67FF),
              ),
              if (stopReason.isNotEmpty)
                _InsightPill(
                  label: stopReason.replaceAll('_', ' '),
                  icon: Icons.flag_outlined,
                  color: Colors.blueGrey,
                ),
            ],
          ),
          if (path.isNotEmpty) ...<Widget>[
            const SizedBox(height: 10),
            _InsightSection(
              title: 'Chosen reasoning path',
              icon: Icons.route_rounded,
              child: Column(
                children: <Widget>[
                  for (int i = 0; i < min(path.length, 4); i++)
                    Padding(
                      padding: EdgeInsets.only(
                        bottom: i == min(path.length, 4) - 1 ? 0 : 8,
                      ),
                      child: Row(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          Container(
                            width: 20,
                            height: 20,
                            alignment: Alignment.center,
                            decoration: BoxDecoration(
                              color: const Color(0xFF5F67FF).withOpacity(0.16),
                              borderRadius: BorderRadius.circular(8),
                            ),
                            child: Text(
                              '${i + 1}',
                              style: const TextStyle(
                                fontSize: 10,
                                fontWeight: FontWeight.w700,
                                color: Color(0xFF4A53EE),
                              ),
                            ),
                          ),
                          const SizedBox(width: 8),
                          Expanded(
                            child: SmartText(
                              '[${_s(_toMap(path[i]['action'])['type'])}] ${_s(_toMap(path[i]['action'])['content'])}',
                              style: const TextStyle(fontSize: 12.2),
                            ),
                          ),
                        ],
                      ),
                    ),
                ],
              ),
            ),
          ],
        ],
      ),
    );
  }

  Map<String, dynamic> _toMap(dynamic raw) {
    if (raw is Map<String, dynamic>) {
      return raw;
    }
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return const <String, dynamic>{};
  }
}

class _ReasoningStagesCard extends StatefulWidget {
  const _ReasoningStagesCard({required this.reasoningGraph});

  final Map<String, dynamic> reasoningGraph;

  @override
  State<_ReasoningStagesCard> createState() => _ReasoningStagesCardState();
}

class _ReasoningStagesCardState extends State<_ReasoningStagesCard> {
  String _s(dynamic value) => (value ?? '').toString().trim();

  List<Map<String, dynamic>> _nodesByType(String type) {
    final List<dynamic> rawNodes = widget.reasoningGraph['nodes'] is List
        ? List<dynamic>.from(widget.reasoningGraph['nodes'] as List)
        : <dynamic>[];
    final List<Map<String, dynamic>> out = <Map<String, dynamic>>[];
    for (final dynamic row in rawNodes) {
      if (row is! Map) {
        continue;
      }
      final Map<String, dynamic> map = Map<String, dynamic>.from(row);
      if (_s(map['type']).toLowerCase() != type.toLowerCase()) {
        continue;
      }
      out.add(map);
    }
    return out;
  }

  @override
  Widget build(BuildContext context) {
    final Map<String, dynamic> telemetry =
        widget.reasoningGraph['telemetry'] is Map
        ? Map<String, dynamic>.from(widget.reasoningGraph['telemetry'] as Map)
        : const <String, dynamic>{};
    final int nodeCount = telemetry['node_count'] is num
        ? (telemetry['node_count'] as num).toInt()
        : int.tryParse(_s(telemetry['node_count'])) ?? 0;
    final int toolCalls = telemetry['tool_calls'] is num
        ? (telemetry['tool_calls'] as num).toInt()
        : int.tryParse(_s(telemetry['tool_calls'])) ?? 0;
    final bool verificationPass = telemetry['verification_pass'] == true;
    final String stopReason = _s(telemetry['stop_reason']);

    final List<Map<String, dynamic>> hypotheses = _nodesByType('hypothesis');
    final List<Map<String, dynamic>> toolNodes = _nodesByType('tool_execution');
    final List<Map<String, dynamic>> verificationNodes = _nodesByType(
      'verification',
    );
    final List<Map<String, dynamic>> synthNodes = _nodesByType('synthesis');

    if (nodeCount <= 0 &&
        hypotheses.isEmpty &&
        toolNodes.isEmpty &&
        verificationNodes.isEmpty &&
        synthNodes.isEmpty) {
      return const SizedBox.shrink();
    }

    return _InsightGlassCard(
      icon: Icons.account_tree_rounded,
      accent: const Color(0xFF1EA59C),
      title: 'Reasoning stages',
      subtitle: '$nodeCount nodes • $toolCalls tool calls',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: <Widget>[
              _InsightPill(
                label: verificationPass ? 'verified' : 'unverified',
                icon: verificationPass
                    ? Icons.verified_rounded
                    : Icons.rule_folder_outlined,
                color: verificationPass
                    ? const Color(0xFF199E6D)
                    : const Color(0xFFFF8A3D),
              ),
              if (stopReason.isNotEmpty)
                _InsightPill(
                  label: stopReason.replaceAll('_', ' '),
                  icon: Icons.flag_outlined,
                  color: Colors.blueGrey,
                ),
            ],
          ),
          _ReasoningStageSection(
            title: 'Hypothesis',
            icon: Icons.lightbulb_outline_rounded,
            nodes: hypotheses,
          ),
          _ReasoningStageSection(
            title: 'Tool execution',
            icon: Icons.precision_manufacturing_outlined,
            nodes: toolNodes,
          ),
          _ReasoningStageSection(
            title: 'Verification',
            icon: Icons.verified_outlined,
            nodes: verificationNodes,
          ),
          _ReasoningStageSection(
            title: 'Final synthesis',
            icon: Icons.summarize_outlined,
            nodes: synthNodes,
          ),
        ],
      ),
    );
  }
}

class _InsightGlassCard extends StatelessWidget {
  const _InsightGlassCard({
    required this.icon,
    required this.accent,
    required this.title,
    required this.child,
    this.subtitle = '',
  });

  final IconData icon;
  final Color accent;
  final String title;
  final String subtitle;
  final Widget child;

  @override
  Widget build(BuildContext context) {
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    final Color surface = isDark
        ? AppColors.cardDark.withOpacity(0.68)
        : Colors.white.withOpacity(0.86);
    final Color border = accent.withOpacity(isDark ? 0.48 : 0.34);

    return TweenAnimationBuilder<double>(
      duration: const Duration(milliseconds: 520),
      curve: Curves.easeOutCubic,
      tween: Tween<double>(begin: 0.92, end: 1),
      child: ClipRRect(
        borderRadius: BorderRadius.circular(16),
        child: BackdropFilter(
          filter: ImageFilter.blur(sigmaX: 10, sigmaY: 10),
          child: Container(
            decoration: BoxDecoration(
              color: surface,
              borderRadius: BorderRadius.circular(16),
              border: Border.all(color: border, width: 1.05),
              boxShadow: <BoxShadow>[
                BoxShadow(
                  color: accent.withOpacity(isDark ? 0.16 : 0.12),
                  blurRadius: 18,
                  offset: const Offset(0, 10),
                ),
              ],
            ),
            padding: const EdgeInsets.fromLTRB(12, 10, 12, 12),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: <Widget>[
                Row(
                  children: <Widget>[
                    Container(
                      width: 30,
                      height: 30,
                      decoration: BoxDecoration(
                        borderRadius: BorderRadius.circular(10),
                        gradient: LinearGradient(
                          colors: <Color>[
                            accent.withOpacity(0.88),
                            accent.withOpacity(0.52),
                          ],
                          begin: Alignment.topLeft,
                          end: Alignment.bottomRight,
                        ),
                      ),
                      child: Icon(icon, size: 16, color: Colors.white),
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: <Widget>[
                          Text(
                            title,
                            style: const TextStyle(
                              fontSize: 12.8,
                              fontWeight: FontWeight.w800,
                              height: 1.15,
                            ),
                          ),
                          if (subtitle.trim().isNotEmpty)
                            Padding(
                              padding: const EdgeInsets.only(top: 2),
                              child: Text(
                                subtitle,
                                style: TextStyle(
                                  fontSize: 11,
                                  color: Theme.of(context)
                                      .textTheme
                                      .bodySmall
                                      ?.color
                                      ?.withOpacity(0.76),
                                ),
                              ),
                            ),
                        ],
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                child,
              ],
            ),
          ),
        ),
      ),
      builder: (BuildContext context, double value, Widget? card) {
        return Transform.scale(
          scale: value,
          child: Opacity(opacity: 0.45 + (0.55 * value), child: card),
        );
      },
    );
  }
}

