class _SourceListTile extends StatelessWidget {
  const _SourceListTile({
    required this.title,
    required this.source,
    required this.url,
    required this.similarity,
  });

  final String title;
  final String source;
  final String url;
  final double similarity;

  @override
  Widget build(BuildContext context) {
    if (title.trim().isEmpty && url.trim().isEmpty) {
      return const SizedBox.shrink();
    }
    final String cleanTitle = title.trim().isNotEmpty ? title.trim() : source;
    final String label = source.trim().isNotEmpty ? source.trim() : 'web';
    final String similarityText = similarity > 0
        ? '${(similarity * 100).round()}%'
        : '';
    final bool canOpen = url.trim().startsWith('http');
    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: InkWell(
        borderRadius: BorderRadius.circular(10),
        onTap: !canOpen
            ? null
            : () async {
                final Uri? uri = Uri.tryParse(url.trim());
                if (uri == null) {
                  return;
                }
                await launchUrl(uri, mode: LaunchMode.externalApplication);
              },
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 8),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(10),
            color: Theme.of(context).brightness == Brightness.dark
                ? Colors.white.withOpacity(0.035)
                : Colors.black.withOpacity(0.03),
            border: Border.all(
              color: Theme.of(context).dividerColor.withOpacity(0.08),
            ),
          ),
          child: Row(
            children: <Widget>[
              Icon(
                canOpen ? Icons.link_rounded : Icons.info_outline_rounded,
                size: 14,
                color: AppColors.primaryTone(context).withOpacity(0.86),
              ),
              const SizedBox(width: 8),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: <Widget>[
                    Text(
                      cleanTitle,
                      maxLines: 2,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        fontSize: 11.8,
                        fontWeight: FontWeight.w600,
                        height: 1.2,
                      ),
                    ),
                    const SizedBox(height: 2),
                    Text(
                      similarityText.isEmpty
                          ? label
                          : '$label • $similarityText',
                      style: TextStyle(
                        fontSize: 10.6,
                        color: Theme.of(
                          context,
                        ).textTheme.bodySmall?.color?.withOpacity(0.74),
                      ),
                    ),
                  ],
                ),
              ),
              if (canOpen)
                Icon(
                  Icons.open_in_new_rounded,
                  size: 13,
                  color: Theme.of(
                    context,
                  ).textTheme.bodySmall?.color?.withOpacity(0.62),
                ),
            ],
          ),
        ),
      ),
    );
  }
}

