            for (int i = 0; i < lines.length; i++)
              Padding(
                padding: EdgeInsets.only(bottom: i == lines.length - 1 ? 0 : 5),
                child: SmartText(
                  '• ${lines[i]}',
                  style: const TextStyle(fontSize: 12.2),
                ),
              ),
          ],
        ),
      ),
    );
  }
}

