class _MaterialAIReaderScreenState extends State<MaterialAIReaderScreen>
    with SingleTickerProviderStateMixin {
  bool _checking = true;
  bool _loading = false;
  bool _exporting = false;
  bool _attaching = false;
  String _content = '';
  String _error = '';
  int _statusPolls = 0;
  Map<String, dynamic>? _webRetrieval;
  Map<String, dynamic>? _mctsSearch;
  Map<String, dynamic>? _reasoningGraph;
  Map<String, dynamic>? _visualization;
  Map<String, dynamic>? _inputAnalysis;
  List<Map<String, dynamic>> _citationRows = <Map<String, dynamic>>[];
  List<String> _sourcesConsulted = <String>[];
  String _provider = '';
  String _model = '';
  String _qaAttachmentLabel = '';
  String? _qaImageDataUrl;
  String? _qaPdfUrl;

  final TextEditingController _questionCtrl = TextEditingController();
  final ImagePicker _picker = ImagePicker();
  late final AnimationController _prepCtrl;

  @override
  void initState() {
    super.initState();
    _prepCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1400),
    );
    if (!isLikelyWidgetTestMode()) {
      _prepCtrl.repeat();
    }
    _checkStatus();
  }

  @override
  void dispose() {
    _prepCtrl.dispose();
    _questionCtrl.dispose();
    super.dispose();
  }

  Future<void> _checkStatus() async {
    const int maxPolls = 8;
    while (mounted && _statusPolls < maxPolls) {
      _statusPolls += 1;
      try {
        final Map<String, dynamic> status = await aiService
            .materialStatus(widget.materialId)
            .timeout(const Duration(seconds: 8));
        final String value = (status['status'] ?? '').toString().toLowerCase();
        final bool ready =
            value.isEmpty ||
            value == 'ready' ||
            value == 'ok' ||
            value == 'completed';
        if (ready) {
          break;
        }
      } catch (_) {}
      await Future<void>.delayed(
        Duration(milliseconds: _statusPolls <= 3 ? 800 : 1200),
      );
    }
    if (!mounted) {
      return;
    }
    setState(() => _checking = false);
    if (widget.mode != 'qa') {
      await _generate();
    }
  }

  Future<void> _generate() async {
    if (_loading) {
      return;
    }
    setState(() {
      _loading = true;
      _error = '';
    });

    try {
      final String notes = widget.materialNotes.trim();
      final Map<String, dynamic> response = await aiService.materialGenerate(
        materialId: widget.materialId,
        mode: widget.mode,
        title: widget.title,
        options: <String, dynamic>{
          if (widget.aiOptions != null) ...widget.aiOptions!,
          'ui_profile': 'apple_health_light',
          'low_end_friendly': true,
          'subject': widget.subject,
          'chapter': widget.chapter,
          'source_type': widget.materialType,
          'source_style':
              (widget.materialType.toLowerCase() == 'image' ||
                  widget.materialType.toLowerCase() == 'pdf')
              ? 'handwritten'
              : 'typed',
          'handwritten_hint':
              widget.materialType.toLowerCase() == 'image' ||
              widget.materialType.toLowerCase() == 'pdf',
          'source_url': widget.materialUrl,
          if (notes.isNotEmpty)
            'source_notes': notes.length > 12000
                ? notes.substring(0, 12000)
                : notes,
          'ocr_required':
              widget.materialType.toLowerCase() == 'image' ||
              widget.materialType.toLowerCase() == 'pdf',
          'strict_ocr': true,
          'verify_equations': true,
          'jee_quality_pass': true,
        },
      );

      if (response['ok'] == true) {
        _content = (response['content'] ?? '').toString();
        _applyAiMetadata(response);
        await notificationService.addAiNotification(
          title: 'Material AI Output Ready',
          body: widget.title,
          type: 'ai',
        );
      } else {
        _error = (response['error'] ?? 'Generation failed').toString();
      }
    } catch (e) {
      _error = e.toString();
    }

    if (mounted) {
      setState(() => _loading = false);
    }
  }

  String _firstNonEmptyString(List<dynamic> candidates) {
    for (final dynamic value in candidates) {
      final String token = (value ?? '').toString().trim();
      if (token.isNotEmpty) {
        return token;
      }
    }
    return '';
  }

  Map<String, dynamic> _toMap(dynamic raw) {
    if (raw is Map<String, dynamic>) {
      return raw;
    }
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return <String, dynamic>{};
  }

  List<dynamic>? _firstList(List<dynamic> candidates) {
    for (final dynamic value in candidates) {
      if (value is List && value.isNotEmpty) {
        return List<dynamic>.from(value);
      }
    }
    return null;
  }

  List<Map<String, dynamic>> _toMapList(dynamic raw) {
    if (raw is! List) {
      return <Map<String, dynamic>>[];
    }
    return raw
        .whereType<Map>()
        .map((Map row) => Map<String, dynamic>.from(row))
        .toList();
  }

  Map<String, dynamic>? _firstMap(List<dynamic> candidates) {
    for (final dynamic value in candidates) {
      final Map<String, dynamic> map = _toMap(value);
      if (map.isNotEmpty) {
        return map;
      }
    }
    return null;
  }

  void _applyAiMetadata(Map<String, dynamic> response) {
    final Map<String, dynamic> raw = _toMap(response['raw']);
    final Map<String, dynamic> rawMeta = _toMap(raw['meta']);
    final Map<String, dynamic> nestedRaw = _toMap(raw['raw']);
    final Map<String, dynamic> nestedRawMeta = _toMap(nestedRaw['meta']);

    _webRetrieval = _firstMap(<dynamic>[
      response['web_retrieval'],
      raw['web_retrieval'],
      rawMeta['web_retrieval'],
      nestedRaw['web_retrieval'],
      nestedRawMeta['web_retrieval'],
    ]);
    _mctsSearch = _firstMap(<dynamic>[
      response['mcts_search'],
      raw['mcts_search'],
      rawMeta['mcts_search'],
      nestedRaw['mcts_search'],
      nestedRawMeta['mcts_search'],
    ]);
    _reasoningGraph = _firstMap(<dynamic>[
      response['reasoning_graph'],
      raw['reasoning_graph'],
      rawMeta['reasoning_graph'],
      nestedRaw['reasoning_graph'],
      nestedRawMeta['reasoning_graph'],
    ]);
    _visualization = _firstMap(<dynamic>[
      response['visualization'],
      raw['visualization'],
      rawMeta['visualization'],
      nestedRaw['visualization'],
      nestedRawMeta['visualization'],
    ]);
    _inputAnalysis = _firstMap(<dynamic>[
      response['input_analysis'],
      raw['input_analysis'],
      rawMeta['input_analysis'],
      nestedRaw['input_analysis'],
      nestedRawMeta['input_analysis'],
    ]);

    List<Map<String, dynamic>> citationRows = _toMapList(
      _firstList(<dynamic>[
        response['citations'],
        raw['citations'],
        rawMeta['citations'],
        nestedRaw['citations'],
      ]),
    );
    if (citationRows.isEmpty && _webRetrieval != null) {
      citationRows = _toMapList(
        _firstList(<dynamic>[
          _webRetrieval!['citations'],
          _webRetrieval!['matches'],
        ]),
      );
    }
    _citationRows = citationRows;

    final List<dynamic> rawSources =
        _firstList(<dynamic>[
          response['sources_consulted'],
          raw['sources_consulted'],
          rawMeta['sources_consulted'],
          nestedRaw['sources_consulted'],
        ]) ??
        <dynamic>[];
    final Set<String> sourceSet = <String>{};
    for (final dynamic row in rawSources) {
      final String token = row.toString().trim();
      if (token.isNotEmpty) {
        sourceSet.add(token);
      }
    }
    if (sourceSet.isEmpty && citationRows.isNotEmpty) {
      for (final Map<String, dynamic> row in citationRows) {
        final String source = (row['source'] ?? '').toString().trim();
        if (source.isNotEmpty) {
          sourceSet.add(source);
        }
      }
    }
    _sourcesConsulted = sourceSet.toList();

    _provider = _firstNonEmptyString(<dynamic>[
      response['provider'],
      raw['provider'],
      raw['winner_provider'],
      _toMap(raw['provider_diagnostics'])['winner_provider'],
    ]);
    _model = _firstNonEmptyString(<dynamic>[
      response['model'],
      raw['model'],
      _toMap(raw['engine'])['model'],
      _toMap(raw['engine'])['version'],
    ]);
  }

  String _composeAnswerContent(Map<String, dynamic> response) {
    final String answer = (response['answer'] ?? '').toString().trim();
    final String explanation = (response['explanation'] ?? '')
        .toString()
        .trim();
    final String confidence = (response['confidence'] ?? '').toString().trim();
    final String concept = (response['concept'] ?? '').toString().trim();
    final String content = (response['content'] ?? '').toString().trim();
    final String normalized = <String>[
      if (answer.isNotEmpty) '**Answer**\n$answer',
      if (explanation.isNotEmpty) '**Explanation**\n$explanation',
      if (concept.isNotEmpty) '**Concept**: $concept',
      if (confidence.isNotEmpty) '**Confidence**: $confidence',
    ].join('\n\n');
    if (normalized.trim().isNotEmpty) {
      return normalized.trim();
    }
    return content;
  }

  bool _hasMeaningfulResponse(Map<String, dynamic> response) {
    return _composeAnswerContent(response).trim().isNotEmpty;
  }

  Map<String, dynamic> _materialContextCard({String source = 'material_qa'}) {
    final String notes = widget.materialNotes.trim();
    return <String, dynamic>{
      'material_id': widget.materialId,
      'title': widget.title,
      'subject': widget.subject,
      'chapter': widget.chapter,
      'material_type': widget.materialType,
      'material_url': widget.materialUrl,
      if (notes.isNotEmpty)
        'material_notes': notes.length > 5000
            ? notes.substring(0, 5000)
            : notes,
      'source': source,
      'enable_material_web_fusion': true,
      'enable_material_ocr': true,
    };
  }

  Future<void> _ask() async {
    final String question = _questionCtrl.text.trim();
    if (question.isEmpty &&
        _qaImageDataUrl == null &&
        (_qaPdfUrl ?? '').trim().isEmpty) {
      return;
    }

    setState(() {
      _loading = true;
      _error = '';
    });

    try {
      final String resolvedQuestion = question.isEmpty
          ? 'Analyze the attached question in the context of this study material and answer for JEE preparation.'
          : question;
      final String qaPrompt = <String>[
        'Use the selected study material as primary context.',
        'Material: ${widget.title}',
        if (widget.subject.trim().isNotEmpty) 'Subject: ${widget.subject}',
        if (widget.chapter.trim().isNotEmpty) 'Chapter: ${widget.chapter}',
        'Student query: $resolvedQuestion',
        if (_qaImageDataUrl != null)
          'Attached image includes question text. Apply strict OCR and preserve all symbols exactly.',
        if ((_qaPdfUrl ?? '').trim().isNotEmpty)
          'Attached PDF includes context/problem. Extract key equations before reasoning.',
        'Return markdown with **Answer**, **Explanation**, key formulas, and confidence.',
      ].join('\n');

      final Map<String, dynamic> card = _materialContextCard(
        source: _qaImageDataUrl != null
            ? 'material_qa_image'
            : ((_qaPdfUrl ?? '').trim().isNotEmpty
                  ? 'material_qa_pdf'
                  : 'material_qa_text'),
      );
      if ((_qaPdfUrl ?? '').trim().isNotEmpty) {
        card['pdf_url'] = _qaPdfUrl!.trim();
      }
      if (_qaAttachmentLabel.trim().isNotEmpty) {
        card['attachment_label'] = _qaAttachmentLabel.trim();
      }

      Map<String, dynamic> response = await aiService.sendChat(
        prompt: qaPrompt,
        userId: 'material_reader',
        chatId: 'material_${widget.materialId}_qa',
        function: 'material_qa',
        responseStyle: 'exam_coach',
        enablePersona: false,
        card: card,
        base64Image: _qaImageDataUrl,
      );

      if ((response['ok'] != true || !_hasMeaningfulResponse(response)) &&
          _qaImageDataUrl == null &&
          (_qaPdfUrl ?? '').trim().isEmpty) {
        final Map<String, dynamic> fallback = await aiService.materialQuery(
          materialId: widget.materialId,
          question: resolvedQuestion,
          contextMode: widget.mode,
        );
        if (fallback['ok'] == true || _hasMeaningfulResponse(fallback)) {
          response = fallback;
        }
      }

      if (response['ok'] == true || _hasMeaningfulResponse(response)) {
        _content = _composeAnswerContent(response);
        _applyAiMetadata(response);
        _questionCtrl.clear();
        _clearQaAttachment(inSetState: false);
      } else {
        _error =
            (response['error'] ??
                    response['message'] ??
                    'Could not generate a response right now')
                .toString();
      }
    } catch (e) {
      _error = e.toString();
    }

    if (mounted) {
      setState(() => _loading = false);
    }
  }

  bool _materialLikelyOcrSource() {
    final String type = widget.materialType.trim().toLowerCase();
    final String url = widget.materialUrl.trim().toLowerCase();
    if (type.contains('image') || type.contains('pdf')) {
      return true;
    }
    return url.endsWith('.pdf') ||
        url.endsWith('.png') ||
        url.endsWith('.jpg') ||
        url.endsWith('.jpeg') ||
        url.endsWith('.webp') ||
        url.startsWith('data:image') ||
        url.startsWith('data:application/pdf');
  }

  String _inferImageMimeType(String fileName) {
    final String lower = fileName.toLowerCase();
    if (lower.endsWith('.png')) {
      return 'image/png';
    }
    if (lower.endsWith('.webp')) {
      return 'image/webp';
    }
    if (lower.endsWith('.heic')) {
      return 'image/heic';
    }
    if (lower.endsWith('.heif')) {
      return 'image/heif';
    }
    return 'image/jpeg';
  }

  Future<void> _pickQaImage({required bool camera}) async {
    if (_loading || _attaching) {
      return;
    }
    final XFile? img = await _picker.pickImage(
      source: camera ? ImageSource.camera : ImageSource.gallery,
      imageQuality: 92,
      maxWidth: 1760,
    );
    if (img == null) {
      return;
    }
    final Uint8List bytes = await img.readAsBytes();
    if (bytes.isEmpty) {
      return;
    }
    final String mime = _inferImageMimeType(img.name);
    final String dataUrl = 'data:$mime;base64,${base64Encode(bytes)}';
    if (!mounted) {
      return;
    }
    setState(() {
      _qaImageDataUrl = dataUrl;
      _qaPdfUrl = null;
      _qaAttachmentLabel =
          'Image: ${img.name.trim().isEmpty ? 'attachment' : img.name.trim()}';
      _error = '';
    });
  }

  Future<void> _pickQaPdf() async {
    if (_loading || _attaching) {
      return;
    }
    final FilePickerResult? result = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      withData: true,
      allowedExtensions: <String>['pdf'],
    );
    if (result == null || result.files.isEmpty) {
      return;
    }
    final PlatformFile file = result.files.first;
    Uint8List? bytes = file.bytes;
    if (bytes == null && file.path != null && file.path!.trim().isNotEmpty) {
      try {
        bytes = await File(file.path!).readAsBytes();
      } catch (_) {
        bytes = null;
      }
    }
    if (bytes == null || bytes.isEmpty) {
      return;
    }

    if (mounted) {
      setState(() => _attaching = true);
    }
    try {
      final String cleanName = file.name.trim().isEmpty
          ? 'material_question.pdf'
          : file.name.trim();
      final String pdfUrl = await backendService.uploadFileData(
        fileName: cleanName,
        dataUrl: 'data:application/pdf;base64,${base64Encode(bytes)}',
      );
      if (!mounted) {
        return;
      }
      setState(() {
        _qaPdfUrl = pdfUrl;
        _qaImageDataUrl = null;
        _qaAttachmentLabel = 'PDF: $cleanName';
        _error = '';
      });
    } catch (e) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('PDF attach failed: $e')));
    } finally {
      if (mounted) {
        setState(() => _attaching = false);
      }
    }
  }

  void _clearQaAttachment({bool inSetState = true}) {
    if (inSetState && mounted) {
      setState(() {
        _qaAttachmentLabel = '';
        _qaImageDataUrl = null;
        _qaPdfUrl = null;
      });
      return;
    }
    _qaAttachmentLabel = '';
    _qaImageDataUrl = null;
    _qaPdfUrl = null;
  }

  String _loadingLabel({required bool checking}) {
    if (checking) {
      return 'Preparing reader _';
    }
    if (widget.mode == 'jee_notes') {
      return 'Preparing JEE notes _';
    }
    if (widget.mode == 'summarize') {
      final bool ocrLikely = _materialLikelyOcrSource();
      return ocrLikely ? 'OCR + summary _' : 'Preparing summary _';
    }
    if (widget.mode == 'qa' &&
        (_qaImageDataUrl != null || (_qaPdfUrl ?? '').trim().isNotEmpty)) {
      return 'OCR + web reasoning _';
    }
    return 'Thinking _';
  }

  Widget _buildPreparingAnimation({
    required bool compact,
    required bool checking,
  }) {
    return AnimatedBuilder(
      animation: _prepCtrl,
      builder: (BuildContext context, Widget? _) {
        final double phase = _prepCtrl.value * 2 * pi;
        final int suffixCount = 1 + (_prepCtrl.value * 3).floor();
        final int clamped = suffixCount < 1
            ? 1
            : (suffixCount > 4 ? 4 : suffixCount);
        final String dynamicSuffix = List<String>.filled(clamped, '_').join();
        final String label = _loadingLabel(
          checking: checking,
        ).replaceAll('_', dynamicSuffix);
        final Widget wave = Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: List<Widget>.generate(5, (int i) {
            final double v = (sin(phase + (i * 0.55)) + 1) / 2;
            final double h = compact ? 5 + (v * 8) : 10 + (v * 18);
            return Container(
              width: compact ? 3.5 : 5,
              height: h,
              margin: EdgeInsets.symmetric(horizontal: compact ? 1.5 : 2.5),
              decoration: BoxDecoration(
                color: AppColors.primary.withOpacity(0.35 + (v * 0.55)),
                borderRadius: BorderRadius.circular(99),
              ),
            );
          }),
        );
        if (compact) {
          return Row(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              wave,
              const SizedBox(width: 8),
              Text(
                label,
                style: const TextStyle(
                  fontSize: 11,
                  color: Colors.grey,
                  fontWeight: FontWeight.w600,
                ),
              ),
            ],
          );
        }
        return LiquidGlass(
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              wave,
              const SizedBox(height: 12),
              Text(label, style: const TextStyle(fontWeight: FontWeight.w700)),
              const SizedBox(height: 4),
              const Text(
                'Analyzing chapter context and building structured output',
                style: TextStyle(fontSize: 11.5, color: Colors.grey),
                textAlign: TextAlign.center,
              ),
            ],
          ),
        );
      },
    );
  }

  String _fileStem() {
    final String modeName = widget.mode == 'jee_notes'
        ? 'jee_notes'
        : widget.mode == 'qa'
        ? 'qa'
        : 'summary';
    final String base = '${widget.title}_$modeName'
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9]+'), '_')
        .replaceAll(RegExp(r'_+'), '_')
        .replaceAll(RegExp(r'^_|_$'), '');
    return base.isEmpty ? 'material_ai_export' : base;
  }

  Future<String> _saveExportBytes({
    required List<int> bytes,
    required String extension,
  }) async {
    final String name =
        '${_fileStem()}_${DateTime.now().millisecondsSinceEpoch}.$extension';
    try {
      final String? path = await FilePicker.platform.saveFile(
        dialogTitle: 'Export $extension file',
        fileName: name,
        type: FileType.custom,
        allowedExtensions: <String>[extension],
      );
      if (path != null && path.trim().isNotEmpty) {
        final File file = File(path);
        await file.parent.create(recursive: true);
        await file.writeAsBytes(bytes, flush: true);
        return file.path;
      }
    } catch (_) {}
    final Directory docs = await getApplicationDocumentsDirectory();
    final File fallback = File('${docs.path}/$name');
    await fallback.writeAsBytes(bytes, flush: true);
    return fallback.path;
  }

  Future<void> _exportAsText() async {
    if (_loading || _exporting || _content.trim().isEmpty) {
      return;
    }
    setState(() => _exporting = true);
    try {
      final String path = await _saveExportBytes(
        bytes: utf8.encode(_content),
        extension: 'txt',
      );
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Text exported: $path')));
    } catch (e) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Text export failed: $e')));
    } finally {
      if (mounted) {
        setState(() => _exporting = false);
      }
    }
  }

  Future<void> _exportAsPdf() async {
    if (_loading || _exporting || _content.trim().isEmpty) {
      return;
    }
    setState(() => _exporting = true);
    try {
      final pw.Document doc = pw.Document();
      final String title = widget.mode == 'jee_notes' ? 'JEE Notes' : 'Summary';
      doc.addPage(
        pw.MultiPage(
          margin: const pw.EdgeInsets.all(24),
          build: (_) => <pw.Widget>[
            pw.Text(
              '$title • ${widget.title}',
              style: pw.TextStyle(fontSize: 18, fontWeight: pw.FontWeight.bold),
            ),
            if (widget.subject.trim().isNotEmpty ||
                widget.chapter.trim().isNotEmpty)
              pw.Padding(
                padding: const pw.EdgeInsets.only(top: 6, bottom: 12),
                child: pw.Text(
                  '${widget.subject.trim()}${widget.chapter.trim().isEmpty ? '' : ' • ${widget.chapter.trim()}'}',
                  style: const pw.TextStyle(fontSize: 11),
                ),
              ),
            pw.Text(_content),
          ],
        ),
      );
      final List<int> bytes = await doc.save();
      final String path = await _saveExportBytes(
        bytes: bytes,
        extension: 'pdf',
      );
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('PDF exported: $path')));
      await Printing.sharePdf(
        bytes: Uint8List.fromList(bytes),
        filename: '${_fileStem()}_${DateTime.now().millisecondsSinceEpoch}.pdf',
      );
    } catch (e) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('PDF export failed: $e')));
    } finally {
      if (mounted) {
        setState(() => _exporting = false);
      }
    }
  }

