    final String title = widget.mode == 'qa'
        ? 'Ask AI'
        : widget.mode == 'summarize'
        ? 'Summary'
        : 'JEE Advanced Notes';

    return Scaffold(
      appBar: AppBar(title: Text(title)),
      body: _checking
          ? Center(
              child: _buildPreparingAnimation(compact: false, checking: true),
            )
          : Column(
              children: <Widget>[
                Padding(
                  padding: const EdgeInsets.fromLTRB(14, 10, 14, 6),
                  child: LiquidGlass(
                    padding: const EdgeInsets.all(12),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: <Widget>[
                        Row(
                          children: <Widget>[
                            Icon(
                              widget.mode == 'jee_notes'
                                  ? Icons.edit_note
                                  : widget.mode == 'summarize'
                                  ? Icons.summarize
                                  : Icons.question_answer,
                              color: AppColors.primary,
                            ),
                            const SizedBox(width: 10),
                            Expanded(
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: <Widget>[
                                  Text(
                                    widget.title,
                                    maxLines: 1,
                                    overflow: TextOverflow.ellipsis,
                                    style: const TextStyle(
                                      fontWeight: FontWeight.w700,
                                    ),
                                  ),
                                  const SizedBox(height: 2),
                                  Text(
                                    widget.mode == 'jee_notes'
                                        ? 'Deep JEE notes with traps, shortcuts, revision points'
                                        : widget.mode == 'summarize'
                                        ? 'Fast chapter summary for revision'
                                        : 'Context-aware Q&A with OCR and web reasoning',
                                    style: const TextStyle(
                                      fontSize: 11,
                                      color: Colors.grey,
                                    ),
                                  ),
                                ],
                              ),
                            ),
