class LoadingScreen extends StatefulWidget {
  const LoadingScreen({
    super.key,
    required this.item,
    required this.studentName,
    required this.isResume,
  });

  final QuizItem item;
  final String studentName;
  final bool isResume;

  @override
  State<LoadingScreen> createState() => _LoadingScreenState();
}

class _LoadingScreenState extends State<LoadingScreen>
    with SingleTickerProviderStateMixin {
  late final AnimationController _pulseCtrl;

  @override
  void initState() {
    super.initState();
    _pulseCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1200),
    );
    if (!isLikelyWidgetTestMode()) {
      _pulseCtrl.repeat(reverse: true);
    }
    _load();
  }

  @override
  void dispose() {
    _pulseCtrl.dispose();
    super.dispose();
  }

  Future<void> _load() async {
    try {
      final String? localFromUrl = localQuizStore.quizIdFromUrl(
        widget.item.url,
      );
      final String localQuizId = (localFromUrl ?? widget.item.id).trim();
      final bool forceLocal = localQuizStore.isLocalQuizUrl(widget.item.url);
      if (forceLocal && localQuizId.isNotEmpty) {
        final List<Question> localQuestions = await localQuizStore
            .loadQuestions(localQuizId);
        if (localQuestions.isNotEmpty) {
          if (!mounted) {
            return;
          }
          Navigator.pushReplacement(
            context,
            MaterialPageRoute(
              builder: (_) => ExamScreen(
                questions: localQuestions,
                item: widget.item,
                studentName: widget.studentName,
                isResume: widget.isResume,
              ),
            ),
          );
          return;
        }
      }

      final Uri base = Uri.parse(widget.item.url);
      final Uri url = base.replace(
        queryParameters: <String, String>{
          ...base.queryParameters,
          'ts': DateTime.now().millisecondsSinceEpoch.toString(),
        },
      );
      final String csvResponse = await _fetchRaw(url);

      final List<List<dynamic>> rows = await parseCsvInBackground(csvResponse);
      final List<Question> questions = <Question>[];

      for (int i = 1; i < rows.length; i++) {
        final List<dynamic> row = rows[i];
        if (row.isEmpty) {
          continue;
        }

        String col(int index) =>
            index < row.length ? row[index].toString().trim() : '';

        questions.add(
          Question(
            text: col(0),
            imageUrl: col(1),
            type: col(2).isEmpty ? 'MCQ' : col(2),
            section: col(3).isEmpty ? 'General' : col(3),
            posMark: double.tryParse(col(4)) ?? 4,
            negMark: double.tryParse(col(5)) ?? 1,
            options: <String>[col(6), col(7), col(8), col(9)],
            correctAnswers: col(10)
                .split(',')
                .map((String e) => e.trim())
                .where((String e) => e.isNotEmpty)
                .toList(),
            solution: col(11),
            concept: col(12),
          ),
        );
      }

      unawaited(
        aiPrecomputeService.enqueueQuiz(
          quizId: widget.item.id,
          questions: questions,
          userId: Session.effectiveAccountId.isNotEmpty
              ? Session.effectiveAccountId
              : widget.studentName,
        ),
      );

      if (!mounted) {
        return;
      }

      Navigator.pushReplacement(
        context,
        MaterialPageRoute(
          builder: (_) => ExamScreen(
            questions: questions,
            item: widget.item,
            studentName: widget.studentName,
            isResume: widget.isResume,
          ),
        ),
      );
      unawaited(
        localQuizStore.saveQuiz(
          item: widget.item,
          questions: questions,
          ownerAccountId: Session.effectiveAccountId,
          ownerRole: Session.userRole,
          visibility: 'published',
          includeInIndex: false,
        ),
      );
    } catch (e) {
      try {
        final List<Question> fallbackQuestions = await localQuizStore
            .loadQuestions(widget.item.id);
        if (fallbackQuestions.isNotEmpty && mounted) {
          Navigator.pushReplacement(
            context,
            MaterialPageRoute(
              builder: (_) => ExamScreen(
                questions: fallbackQuestions,
                item: widget.item,
                studentName: widget.studentName,
                isResume: widget.isResume,
              ),
            ),
          );
          return;
        }
      } catch (_) {}
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Failed to load exam: $e')));
      Navigator.pop(context);
    }
  }

  Future<String> _fetchRaw(Uri uri) async {
    final http.Response response = await http
        .get(uri)
        .timeout(const Duration(seconds: 20));
    if (response.statusCode != 200) {
      throw Exception('HTTP ${response.statusCode}');
    }
    return response.body;
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: LiquidGlass(
          padding: const EdgeInsets.symmetric(horizontal: 40, vertical: 36),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              AnimatedBuilder(
                animation: _pulseCtrl,
                builder: (_, __) {
                  final double scale = 0.85 + (_pulseCtrl.value * 0.15);
                  return Transform.scale(
                    scale: scale,
                    child: const Icon(
                      Icons.hourglass_top_rounded,
                      size: 64,
                      color: AppColors.primary,
                    ),
                  );
                },
              ),
              const SizedBox(height: 24),
              const Text(
                'Preparing Your Exam',
                style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
              ),
              const SizedBox(height: 8),
              Text(
                widget.isResume
                    ? 'Restoring your previous attempt...'
                    : 'Loading questions and setting up the environment...',
                textAlign: TextAlign.center,
                style: const TextStyle(color: Colors.grey),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class ExamScreen extends StatefulWidget {
  const ExamScreen({
    super.key,
    required this.questions,
    required this.item,
    required this.studentName,
    required this.isResume,
  });

  final List<Question> questions;
  final QuizItem item;
  final String studentName;
  final bool isResume;

  @override
  State<ExamScreen> createState() => _ExamScreenState();
}

class _ExamScreenState extends State<ExamScreen> with WidgetsBindingObserver {
  static const List<int> _elapsedMilestones = <int>[20, 40, 60, 80, 100];

  int _idx = 0;
  Map<int, List<String>> _answers = <int, List<String>>{};
  Set<int> _review = <int>{};
  Set<int> _visited = <int>{0};

  Timer? _timer;
  Timer? _autoSaveTimer;

  late PageController _pageCtrl;
  late ValueNotifier<int> _timeNotifier;

  bool _submitting = false;
  int _secondsLeft = 0;
  bool _ready = false;
  Timer? _assistantTimer;
  Timer? _assistantHideTimer;
  bool _assistantVisible = false;
  String _assistantMessage = '';
  final Set<int> _elapsedMilestonesSent = <int>{};
  bool _sentFiveMinuteAlert = false;
  bool _sentTwoMinuteAlert = false;
  late final DateTime _sessionStartedAt;

  @override
  void initState() {
    super.initState();
    _sessionStartedAt = DateTime.now();
    WidgetsBinding.instance.addObserver(this);
    _restoreOrStart();
  }

  bool get _isUnlimitedTimeMode =>
      widget.item.isUnlimitedTime || widget.item.durationMinutes <= 0;

  Map<String, dynamic> _asMap(dynamic raw) {
    if (raw is Map<String, dynamic>) {
      return raw;
    }
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return <String, dynamic>{};
  }

  bool _asBool(dynamic raw, {required bool fallback}) {
    if (raw is bool) {
      return raw;
    }
    final String text = raw.toString().trim().toLowerCase();
    if (text == 'true') {
      return true;
    }
    if (text == 'false') {
      return false;
    }
    return fallback;
  }

  Map<String, dynamic> get _questionCardFrontSpec {
    final Map<String, dynamic> questionCard = _asMap(
      _asMap(widget.item.uiSpec)['question_card'],
    );
    return _asMap(questionCard['front']);
  }

  double get _questionCardRadius {
    final Map<String, dynamic> layout = _asMap(
      _asMap(widget.item.uiSpec)['layout'],
    );
    final double radius = _asDouble(layout['card_corner_radius'], fallback: 24);
    return radius.clamp(16.0, 36.0);
  }

  bool get _showDifficultyDot =>
      _asBool(_questionCardFrontSpec['difficulty_dot'], fallback: true);

  bool get _showConfidencePill =>
      _asBool(_questionCardFrontSpec['confidence_pill'], fallback: true);

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    _timer?.cancel();
    _autoSaveTimer?.cancel();
    _assistantTimer?.cancel();
    _assistantHideTimer?.cancel();
    if (_ready) {
      _pageCtrl.dispose();
      _timeNotifier.dispose();
    }
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (state == AppLifecycleState.paused ||
        state == AppLifecycleState.inactive) {
      unawaited(_autoSave());
    }
  }

  Future<void> _autoSave() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final AutoSaveExam save = AutoSaveExam(
      quizId: widget.item.id,
      currentIndex: _idx,
      remainingSeconds: _secondsLeft,
      answers: _answers,
      review: _review,
      visited: _visited,
    );
    await prefs.setString('auto_${widget.item.id}', jsonEncode(save.toJson()));
  }

  Future<void> _restoreOrStart() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    bool restored = false;

    if (widget.isResume) {
      final String? raw = prefs.getString('auto_${widget.item.id}');
      if (raw != null) {
        try {
          final AutoSaveExam save = AutoSaveExam.fromJson(
            jsonDecode(raw) as Map<String, dynamic>,
          );
          _idx = save.currentIndex;
          _secondsLeft = save.remainingSeconds;
          _answers = save.answers;
          _review = save.review;
          _visited = save.visited.isEmpty ? <int>{_idx} : save.visited;
          restored = true;
        } catch (_) {}
      }
    }

    if (!restored) {
      _idx = 0;
      _secondsLeft = _isUnlimitedTimeMode
          ? 0
          : widget.item.durationMinutes * 60;
      _visited = <int>{0};
    } else if (_isUnlimitedTimeMode) {
      _secondsLeft = 0;
    }

    _primeTimedAlertsFromRestoredState();
    _timeNotifier = ValueNotifier<int>(_secondsLeft);
    _pageCtrl = PageController(initialPage: _idx);
    _startTimer();

    if (mounted) {
      setState(() => _ready = true);
    }
  }

  void _startTimer() {
    _timer?.cancel();
    _autoSaveTimer?.cancel();

    if (!_isUnlimitedTimeMode) {
      _timer = Timer.periodic(const Duration(seconds: 1), (_) {
        if (_submitting) {
          return;
        }
        if (_secondsLeft > 0) {
          _secondsLeft--;
          _timeNotifier.value = _secondsLeft;
          _evaluateTimedSignals();
        } else {
          _submit();
        }
      });
    } else {
      _timer = null;
      _timeNotifier.value = 0;
    }

    _autoSaveTimer = Timer.periodic(
      const Duration(seconds: 12),
      (_) => _autoSave(),
    );
    _startAssistantTicker();
  }

  int get _totalExamSeconds => max(1, widget.item.durationMinutes * 60);

  int get _answeredCount =>
      _answers.values.where((List<String> e) => e.isNotEmpty).length;

  int get _unansweredCount => max(0, widget.questions.length - _answeredCount);

  int get _skippedCount => _visited
      .where((int i) => (_answers[i] ?? const <String>[]).isEmpty)
      .length;

  void _primeTimedAlertsFromRestoredState() {
    if (_isUnlimitedTimeMode) {
      _elapsedMilestonesSent.clear();
      _sentFiveMinuteAlert = false;
      _sentTwoMinuteAlert = false;
      return;
    }
    _elapsedMilestonesSent.clear();
    final int elapsedPercent =
        (((_totalExamSeconds - _secondsLeft) / _totalExamSeconds) * 100)
            .floor()
            .clamp(0, 100);
    for (final int mark in _elapsedMilestones) {
      if (elapsedPercent >= mark) {
        _elapsedMilestonesSent.add(mark);
      }
    }
    _sentFiveMinuteAlert = _secondsLeft <= 300;
    _sentTwoMinuteAlert = _secondsLeft <= 120;
  }

  void _evaluateTimedSignals() {
    if (_isUnlimitedTimeMode) {
      return;
    }
    final int elapsedPercent =
        (((_totalExamSeconds - _secondsLeft) / _totalExamSeconds) * 100)
            .floor()
            .clamp(0, 100);

    for (final int mark in _elapsedMilestones) {
      if (elapsedPercent >= mark && !_elapsedMilestonesSent.contains(mark)) {
        _elapsedMilestonesSent.add(mark);
        _pushAssistantMessage(milestoneLabel: '$mark% time used');
        break;
      }
    }

    if (!_sentFiveMinuteAlert && _secondsLeft <= 300 && _secondsLeft > 120) {
      _sentFiveMinuteAlert = true;
      _pushAssistantMessage(milestoneLabel: '5 minutes left');
    }
    if (!_sentTwoMinuteAlert && _secondsLeft <= 120 && _secondsLeft > 0) {
      _sentTwoMinuteAlert = true;
      _pushAssistantMessage(milestoneLabel: '2 minutes left');
    }
  }

  void _startAssistantTicker() {
    _assistantTimer?.cancel();
    _assistantTimer = Timer.periodic(const Duration(seconds: 34), (_) {
      if (!mounted || _submitting) {
        return;
      }
      _pushAssistantMessage();
    });
  }

  void _pushAssistantMessage({String? milestoneLabel}) {
    _showAssistantMessage(
      _buildAssistantMessage(milestoneLabel: milestoneLabel),
    );
  }

  String _buildAssistantMessage({String? milestoneLabel}) {
    final int total = widget.questions.length;
    final int answered = _answeredCount;
    final int marked = _review.length;
    final int unanswered = total - answered;
    if (_isUnlimitedTimeMode) {
      if (unanswered > 0 && answered < max(2, total ~/ 3)) {
        return 'Practice mode is untimed. Build accuracy first, then speed.';
      }
      if (marked > 0) {
        return '$marked marked question${marked == 1 ? '' : 's'} pending. Resolve them before submit.';
      }
      if (unanswered > 0) {
        return '$answered/$total done. Keep momentum and finish the remaining set.';
      }
      return 'All questions attempted. Quick review, then submit when ready.';
    }
    final int mins = _secondsLeft ~/ 60;
    final int secs = _secondsLeft % 60;
    final double elapsedRatio =
        ((_totalExamSeconds - _secondsLeft) / _totalExamSeconds)
            .clamp(0.0, 1.0)
            .toDouble();
    final int expectedByNow = (elapsedRatio * total).round().clamp(0, total);
    final int paceGap = expectedByNow - answered;
    final String prefix = (milestoneLabel ?? '').trim().isEmpty
        ? ''
        : '${milestoneLabel!.trim()}: ';

    String msg = '';
    if (_secondsLeft <= 120 && unanswered > 0) {
      msg =
          '$unanswered left in ${mins}m ${secs.toString().padLeft(2, '0')}s. Lock quick wins and avoid guesses.';
    } else if (_secondsLeft <= 300 && unanswered > 0) {
      final int targetNow = min(total, answered + max(2, unanswered ~/ 2));
      msg =
          '$answered/$total done. Push to $targetNow attempts before final 2 minutes.';
    } else if (paceGap >= max(2, total ~/ 10)) {
      msg =
          'Behind pace by $paceGap question${paceGap == 1 ? '' : 's'}. Take direct ones now.';
    } else if (paceGap <= -max(2, total ~/ 12)) {
      msg =
          'Ahead by ${paceGap.abs()} question${paceGap.abs() == 1 ? '' : 's'}. Use buffer to clean marked items.';
    } else if (marked > 0 && answered >= (total * 0.55).round()) {
      msg =
          '$marked marked question${marked == 1 ? '' : 's'} pending. Reserve final pass time.';
    } else if (answered >= (total * 0.8).round()) {
      msg = "Strong pace. Protect marks and avoid negative attempts.";
    }
    if (mins <= 5 && unanswered > 0 && paceGap > 0) {
      msg =
          '$unanswered remaining and pace is short by $paceGap. Solve shortest questions first.';
    }
    if (msg.isEmpty) {
      msg = 'Steady pace. Keep section flow and finish confident attempts.';
    }
    return '$prefix$msg';
  }

  void _showAssistantMessage(String message) {
    if (message.trim().isEmpty || !mounted) {
      return;
    }
    HapticFeedback.selectionClick();
    setState(() {
      _assistantMessage = message.trim();
      _assistantVisible = true;
    });
    _assistantHideTimer?.cancel();
    _assistantHideTimer = Timer(const Duration(seconds: 6), () {
      if (mounted) {
        setState(() => _assistantVisible = false);
      }
    });
  }

  void _jumpToQuestion(int index, {bool animate = true}) {
    if (index < 0 || index >= widget.questions.length || !_ready) {
      return;
    }
    setState(() {
      _idx = index;
      _visited.add(index);
    });
    if (animate) {
      _pageCtrl.animateToPage(
        index,
        duration: const Duration(milliseconds: 240),
        curve: Curves.easeOutCubic,
      );
    } else {
      _pageCtrl.jumpToPage(index);
    }
    unawaited(_autoSave());
  }

  void _jumpToFirstQuestion() {
    _jumpToQuestion(0);
  }

  void _jumpToLastQuestion() {
    _jumpToQuestion(max(0, widget.questions.length - 1));
  }

  void _jumpToFirstReview() {
    if (_review.isEmpty) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('No marked questions yet.')),
        );
      }
      return;
    }
    final List<int> ordered = _review.toList()..sort();
    final int ahead = ordered.firstWhere(
      (int i) => i > _idx,
      orElse: () => ordered.first,
    );
    _jumpToQuestion(ahead);
  }

  void _jumpToNearestUnanswered({required bool forward}) {
    final int total = widget.questions.length;
    if (total <= 0) {
      return;
    }
    for (int step = 1; step <= total; step++) {
      final int candidate = forward
          ? (_idx + step) % total
          : (_idx - step + total) % total;
      if ((_answers[candidate] ?? const <String>[]).isEmpty) {
        _jumpToQuestion(candidate);
        return;
      }
    }
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('All questions are attempted.')),
      );
    }
  }

  void _openPalette() {
    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      builder: (_) => GlassQuestionPaletteSheet(
        total: widget.questions.length,
        current: _idx,
        answeredCount: _answeredCount,
        reviewCount: _review.length,
        skippedCount: _skippedCount,
        stateFor: _paletteStateFor,
        onPrevUnanswered: () {
          _jumpToNearestUnanswered(forward: false);
          Navigator.pop(context);
        },
        onNextUnanswered: () {
          _jumpToNearestUnanswered(forward: true);
          Navigator.pop(context);
        },
        onFirstReview: () {
          _jumpToFirstReview();
          Navigator.pop(context);
        },
        onJumpFirst: () {
          _jumpToFirstQuestion();
          Navigator.pop(context);
        },
        onJumpLast: () {
          _jumpToLastQuestion();
          Navigator.pop(context);
        },
        onJump: (int i) {
          _jumpToQuestion(i, animate: false);
          Navigator.pop(context);
        },
      ),
    );
  }

  PageRouteBuilder<void> _buildSmoothRoute(Widget child) {
    return PageRouteBuilder<void>(
      transitionDuration: const Duration(milliseconds: 360),
      reverseTransitionDuration: const Duration(milliseconds: 240),
      pageBuilder:
          (
            BuildContext context,
            Animation<double> animation,
            Animation<double> secondaryAnimation,
          ) => child,
      transitionsBuilder:
          (
            BuildContext context,
            Animation<double> animation,
            Animation<double> secondaryAnimation,
            Widget routeChild,
          ) {
            final Animation<double> fade = CurvedAnimation(
              parent: animation,
              curve: Curves.easeOutCubic,
            );
            final Animation<Offset> slide = Tween<Offset>(
              begin: const Offset(0, 0.025),
              end: Offset.zero,
            ).animate(fade);
            return FadeTransition(
              opacity: fade,
              child: SlideTransition(position: slide, child: routeChild),
            );
          },
    );
  }

  QuestionPaletteState _paletteStateFor(int i) {
    if (i == _idx) {
      return QuestionPaletteState.current;
    }
    if (_review.contains(i)) {
      return QuestionPaletteState.review;
    }
    if ((_answers[i] ?? <String>[]).isNotEmpty) {
      return QuestionPaletteState.answered;
    }
    if (_visited.contains(i)) {
      return QuestionPaletteState.skipped;
    }
    return QuestionPaletteState.unseen;
  }

  void _confirmSubmit() {
    final int answered = _answers.values
        .where((List<String> e) => e.isNotEmpty)
        .length;
    final int review = _review.length;
    final int total = widget.questions.length;

    showDialog<void>(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: const Text('Submit Exam?'),
          content: Text(
            'Answered: $answered\\nMarked for Review: $review\\nUnattempted: ${total - answered}\\n\\nSubmit anyway?',
          ),
          actions: <Widget>[
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Cancel'),
            ),
            TextButton(
              onPressed: () {
                Navigator.pop(context);
                _submit();
              },
              child: const Text('Submit'),
            ),
          ],
        );
      },
    );
  }

  Map<String, dynamic> _normalizeExamAIResult(Map<String, dynamic> raw) {
    if (raw.containsKey('analytics') && raw['analytics'] is Map) {
      raw = Map<String, dynamic>.from(raw['analytics'] as Map);
    }
    if (raw.containsKey('strengths') ||
        raw.containsKey('weaknesses') ||
        raw.containsKey('strategy') ||
        raw.containsKey('next_steps')) {
      return <String, dynamic>{
        'summary': raw['summary'] ?? '',
        'strengths': raw['strengths'] ?? <dynamic>[],
        'weaknesses': raw['weaknesses'] ?? <dynamic>[],
        'strategy': raw['strategy'] ?? <dynamic>[],
        'next_steps': raw['next_steps'] ?? <dynamic>[],
      };
    }
    return <String, dynamic>{
      'summary': raw['summary'] ?? '',
      'strengths': raw['insights'] ?? <dynamic>[],
      'weaknesses': <dynamic>[],
      'strategy': raw['actions'] ?? <dynamic>[],
      'next_steps': raw['actions'] ?? <dynamic>[],
    };
  }

  int _asInt(dynamic value, {int fallback = 0}) {
    if (value is int) {
      return value;
    }
    if (value is num) {
      return value.toInt();
    }
    return int.tryParse((value ?? '').toString()) ?? fallback;
  }

  double _asDouble(dynamic value, {double fallback = 0}) {
    if (value is num) {
      return value.toDouble();
    }
    return double.tryParse((value ?? '').toString()) ?? fallback;
  }

  Map<String, double> _toSectionAccuracy(dynamic raw) {
    if (raw is! Map) {
      return <String, double>{};
    }
    final Map<String, dynamic> map = Map<String, dynamic>.from(raw);
    final Map<String, double> out = <String, double>{};
    map.forEach((String key, dynamic value) {
      out[key] = _asDouble(value).clamp(0, 100).toDouble();
    });
    return out;
  }

  List<Question> _evaluatedQuestionsFromAnswerKey(
    List<Question> baseQuestions,
    dynamic answerKeyRaw,
  ) {
    if (answerKeyRaw is! List) {
      return baseQuestions;
    }
    final Map<int, Map<String, dynamic>> byIndex =
        <int, Map<String, dynamic>>{};
    for (final dynamic raw in answerKeyRaw) {
      if (raw is! Map) {
        continue;
      }
      final Map<String, dynamic> row = Map<String, dynamic>.from(raw);
      final int idx = _asInt(
        row['question_index'] ?? row['index'] ?? row['question_no'],
        fallback: -1,
      );
      if (idx < 0) {
        continue;
      }
      byIndex[idx] = row;
    }
    final List<Question> out = <Question>[];
    for (int i = 0; i < baseQuestions.length; i++) {
      final Question q = baseQuestions[i];
      final Map<String, dynamic>? row = byIndex[i];
      if (row == null) {
        out.add(q);
        continue;
      }
      final String correctAnswerRaw = (row['correct_answer'] ?? '')
          .toString()
          .trim();
      String correctAnswer = correctAnswerRaw;
      if (correctAnswer.contains(')')) {
        final List<String> parts = correctAnswer.split(')');
        if (parts.length > 1) {
          correctAnswer = parts.sublist(1).join(')').trim();
        }
      }
      if (correctAnswer.isEmpty) {
        final String letter = (row['correct_option'] ?? '')
            .toString()
            .trim()
            .toUpperCase();
        if (letter.length == 1) {
          final int idx = letter.codeUnitAt(0) - 65;
          if (idx >= 0 && idx < q.options.length) {
            correctAnswer = q.options[idx];
          }
        }
      }
      final List<String> conceptTags = (row['concept_tags'] is List)
          ? (row['concept_tags'] as List<dynamic>)
                .map((dynamic e) => e.toString().trim())
                .where((String e) => e.isNotEmpty)
                .toList()
          : <String>[];
      out.add(
        Question(
          text: (row['question_text'] ?? q.text).toString().trim(),
          imageUrl: q.imageUrl,
          type: q.type,
          section: conceptTags.isEmpty
              ? q.section
              : (q.section.trim().isEmpty ? conceptTags.join(', ') : q.section),
          posMark: q.posMark,
          negMark: q.negMark,
          options: q.options,
          correctAnswers: correctAnswer.isEmpty
              ? q.correctAnswers
              : <String>[correctAnswer],
          solution: (row['solution_explanation'] ?? q.solution)
              .toString()
              .trim(),
          concept: conceptTags.isEmpty ? q.concept : conceptTags.join(', '),
        ),
      );
    }
    return out;
  }

  Future<void> _syncResultToBackend(ResultData result) async {
    try {
      await backendService.submitResult(<String, dynamic>{
        'quiz_id': result.quizId,
        'quiz_title': result.quizTitle,
        'topic': result.quizTitle,
        'name': widget.studentName,
        'student_name': widget.studentName,
        'student_id': Session.studentId,
        'account_id': Session.effectiveAccountId,
        'score': result.score,
        'total': result.maxScore,
        'max_score': result.maxScore,
        'correct': result.correct,
        'wrong': result.wrong,
        'skipped': result.skipped,
        'section_accuracy': result.sectionAccuracy,
        'type': widget.item.type,
        'ts': DateTime.now().millisecondsSinceEpoch,
        'submitted_at': DateTime.now().toIso8601String(),
      });
    } catch (_) {}
  }

  ResultData _buildLocalResult({required int timeTaken}) {
    double score = 0;
    int correct = 0;
    int wrong = 0;
    final Map<String, int> sectionTotal = <String, int>{};
    final Map<String, int> sectionCorrect = <String, int>{};

    for (int i = 0; i < widget.questions.length; i++) {
      final Question q = widget.questions[i];
      final List<String> user = _answers[i] ?? <String>[];
      final String section = q.section.trim().isEmpty ? 'General' : q.section;
      sectionTotal[section] = (sectionTotal[section] ?? 0) + 1;

      bool ok = false;
      if (user.isNotEmpty) {
        if (q.type == 'NUMERICAL') {
          final double? userVal = double.tryParse(user.first);
          final double? correctVal = q.correctAnswers.isNotEmpty
              ? double.tryParse(q.correctAnswers.first)
              : null;
          if (userVal != null &&
              correctVal != null &&
              (userVal - correctVal).abs() < 0.01) {
            ok = true;
          }
        } else {
          final Set<String> u = user.map((String e) => e.trim()).toSet();
          final Set<String> c = q.correctAnswers
              .map((String e) => e.trim())
              .where((String e) => e.isNotEmpty)
              .toSet();
          if (c.isNotEmpty && u.length == c.length && u.containsAll(c)) {
            ok = true;
          }
        }
      }

      if (ok) {
        score += q.posMark;
        correct++;
        sectionCorrect[section] = (sectionCorrect[section] ?? 0) + 1;
      } else if (user.isNotEmpty) {
        score -= q.negMark;
        wrong++;
      }
    }

    final double totalScore = widget.questions.fold(
      0.0,
      (double p, Question e) => p + e.posMark,
    );
    final Map<String, double> sectionAccuracy = <String, double>{};
    sectionTotal.forEach((String section, int total) {
      final int secCorrect = sectionCorrect[section] ?? 0;
      sectionAccuracy[section] = ((secCorrect / max(1, total)) * 100)
          .clamp(0, 100)
          .toDouble();
    });
    return ResultData(
      quizId: widget.item.id,
      quizTitle: widget.item.title,
      score: score,
      maxScore: totalScore,
      correct: correct,
      wrong: wrong,
      skipped: widget.questions.length - (correct + wrong),
      totalTime: timeTaken,
      sectionAccuracy: sectionAccuracy,
      userAnswers: _answers,
    );
  }

  Future<void> _submit() async {
    if (_submitting) {
      return;
    }
    setState(() => _submitting = true);

    _timer?.cancel();
    _autoSaveTimer?.cancel();

    try {
      final int timeTaken = _isUnlimitedTimeMode
          ? max(0, DateTime.now().difference(_sessionStartedAt).inSeconds)
          : max(0, (widget.item.durationMinutes * 60) - _secondsLeft);
      ResultData result;
      List<Question> evaluatedQuestions = widget.questions;
      final ResultData localResult = _buildLocalResult(timeTaken: timeTaken);

      if (widget.item.isAiGenerated) {
        bool usedBackendEvaluation = false;
        try {
          final Map<String, dynamic> response = await backendService
              .evaluateQuizSubmission(<String, dynamic>{
                'quiz_id': widget.item.id,
                'quiz_title': widget.item.title,
                'name': widget.studentName,
                'student_name': widget.studentName,
                'student_id': Session.studentId,
                'user_id': Session.effectiveAccountId,
                'account_id': Session.effectiveAccountId,
                'answers': _answers.map(
                  (int k, List<String> v) => MapEntry(k.toString(), v),
                ),
                'time_taken_seconds': timeTaken,
                'include_answer_key': true,
              });
          if (!backendService.isSuccessfulResponse(response)) {
            throw Exception('Submission rejected: ${jsonEncode(response)}');
          }
          final Map<String, dynamic> eval =
              response['evaluation_result'] is Map<String, dynamic>
              ? response['evaluation_result'] as Map<String, dynamic>
              : response['evaluation_result'] is Map
              ? Map<String, dynamic>.from(response['evaluation_result'] as Map)
              : <String, dynamic>{};
          final double score = _asDouble(
            eval['score'] ?? response['score'],
            fallback: 0,
          );
          final double maxScore = _asDouble(
            eval['max_score'] ?? response['max_score'] ?? response['total'],
            fallback: widget.questions.length * 4,
          );
          final int correct = _asInt(
            eval['correct'] ?? response['correct'],
            fallback: 0,
          );
          final int wrong = _asInt(
            eval['wrong'] ?? response['wrong'],
            fallback: 0,
          );
          final int skipped = _asInt(
            eval['skipped'] ?? response['skipped'],
            fallback: max(0, widget.questions.length - (correct + wrong)),
          );
          final Map<String, double> sectionAccuracy = _toSectionAccuracy(
            eval['section_accuracy'] ?? response['section_accuracy'],
          );

          evaluatedQuestions = _evaluatedQuestionsFromAnswerKey(
            widget.questions,
            response['answer_key'],
          );
          result = ResultData(
            quizId: widget.item.id,
            quizTitle: widget.item.title,
            score: score,
            maxScore: maxScore,
            correct: correct,
            wrong: wrong,
            skipped: skipped,
            totalTime: timeTaken,
            sectionAccuracy: sectionAccuracy,
            userAnswers: _answers,
          );
          usedBackendEvaluation = true;
        } catch (_) {
          result = localResult;
        }
        if (!usedBackendEvaluation) {
          unawaited(_syncResultToBackend(result));
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(
                content: Text(
                  'Submitted with local evaluation (backend unavailable).',
                ),
              ),
            );
          }
        }
      } else {
        result = localResult;
        unawaited(_syncResultToBackend(result));
      }

      final SharedPreferences prefs = await SharedPreferences.getInstance();
      final int resultTs = DateTime.now().millisecondsSinceEpoch;
      final Map<String, dynamic> persisted = result.toJson();
      persisted['studentName'] = widget.studentName;
      persisted['studentId'] = Session.studentId;
      persisted['accountId'] = Session.effectiveAccountId;
      persisted['savedAt'] = resultTs;
      await prefs.setString(
        'res_${widget.item.id}_$resultTs',
        jsonEncode(persisted),
      );
      await prefs.remove('auto_${widget.item.id}');

      if (!mounted) {
        return;
      }

      Map<String, dynamic>? aiResult;
      bool aiAvailable = false;

      Navigator.push(
        context,
        _buildSmoothRoute(
          AnalyticsLoadingScreen(
            task: () async {
              try {
                final Map<String, dynamic> res = await aiService.analyzeExam(
                  result.toJson(),
                );
                if (res['ok'] == true && res['ai_available'] == true) {
                  aiAvailable = true;
                  aiResult = _normalizeExamAIResult(res);
                } else {
                  aiAvailable = false;
                  aiResult = null;
                }
              } catch (_) {
                aiAvailable = false;
                aiResult = null;
              }
            },
            onDone: () async {
              try {
                await notificationService.addAiNotification(
                  title: 'Exam Submitted',
                  body:
                      '${widget.item.title.split('|').first}: ${result.score.toStringAsFixed(1)}/${result.maxScore.toStringAsFixed(1)}',
                  type: 'ai',
                  payload: <String, dynamic>{'quizId': widget.item.id},
                );
              } catch (_) {}

              if (!mounted) {
                return;
              }

              Navigator.of(context).pushAndRemoveUntil(
                _buildSmoothRoute(
                  AnalyticsScreen(
                    data: result,
                    studentName: widget.studentName,
                    title: widget.item.title,
                    item: widget.item,
                    aiAvailable: aiAvailable,
                    aiResult: aiResult,
                    questions: evaluatedQuestions,
                  ),
                ),
                (Route<dynamic> route) => false,
              );
            },
          ),
        ),
      );
    } catch (e) {
      if (!mounted) {
        return;
      }
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Submission failed: $e')));
      setState(() => _submitting = false);
      _startTimer();
    }
  }

  void _clearCurrentAnswer() {
    setState(() => _answers.remove(_idx));
    unawaited(_autoSave());
  }

  void _toggleCurrentReview() {
    setState(() {
      if (_review.contains(_idx)) {
        _review.remove(_idx);
      } else {
        _review.add(_idx);
      }
    });
    unawaited(_autoSave());
  }

  Widget _minimalExamAction({
    required BuildContext context,
    required IconData icon,
    required String tooltip,
    required VoidCallback onPressed,
    bool active = false,
    Color accent = AppColors.primary,
  }) {
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    final Color bg = active
        ? accent.withValues(alpha: isDark ? 0.28 : 0.14)
        : (isDark
              ? Colors.white.withValues(alpha: 0.10)
              : Colors.black.withValues(alpha: 0.05));
    final Color border = active
        ? accent.withValues(alpha: isDark ? 0.55 : 0.26)
        : Colors.transparent;
    final Color iconColor = active
        ? accent
        : (isDark ? const Color(0xFFE6EEF9) : const Color(0xFF273444));
    return Padding(
      padding: const EdgeInsets.only(right: 6),
      child: IconButton(
        tooltip: tooltip,
        onPressed: onPressed,
        icon: Icon(icon, size: 18, color: iconColor),
        style: IconButton.styleFrom(
          visualDensity: VisualDensity.compact,
          padding: const EdgeInsets.all(7),
          minimumSize: const Size(34, 34),
          backgroundColor: bg,
          side: BorderSide(color: border, width: 0.9),
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(12),
          ),
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    if (!_ready) {
      return const Scaffold(body: Center(child: CircularProgressIndicator()));
    }

    final int answeredCount = _answeredCount;
    final int reviewCount = _review.length;
    final int unansweredCount = _unansweredCount;
    final Size viewport = MediaQuery.of(context).size;
    final bool compactWidth = viewport.width < 430;
    final int expectedAttemptsNow = _isUnlimitedTimeMode
        ? answeredCount
        : (((_totalExamSeconds - _secondsLeft) / _totalExamSeconds) *
                  widget.questions.length)
              .round()
              .clamp(0, widget.questions.length);
    final int paceDelta = answeredCount - expectedAttemptsNow;
    final String paceLabel = _isUnlimitedTimeMode
        ? 'N/A'
        : (paceDelta >= 0 ? '+$paceDelta' : '$paceDelta');
    final double attemptedRatio = widget.questions.isEmpty
        ? 0
        : answeredCount / widget.questions.length;

    return WillPopScope(
      onWillPop: () async {
        _confirmSubmit();
        return false;
      },
      child: Scaffold(
        appBar: AppBar(
          title: _isUnlimitedTimeMode
              ? Row(
                  children: <Widget>[
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: AppColors.primary.withValues(alpha: 0.12),
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: const Text(
                        'Unlimited',
                        style: TextStyle(
                          fontWeight: FontWeight.w700,
                          fontSize: 12,
                          color: AppColors.primary,
                        ),
                      ),
                    ),
                    const SizedBox(width: 10),
                    Expanded(
                      child: Text(
                        'Q ${_idx + 1}/${widget.questions.length}',
                        style: const TextStyle(fontWeight: FontWeight.w700),
                      ),
                    ),
                  ],
                )
              : ValueListenableBuilder<int>(
                  valueListenable: _timeNotifier,
                  builder: (_, int value, __) {
                    return Row(
                      children: <Widget>[
                        PremiumExamTimer(
                          secondsLeft: _timeNotifier,
                          totalSeconds: widget.item.durationMinutes * 60,
                          onTimesUp: _submit,
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: Text(
                            'Q ${_idx + 1}/${widget.questions.length}',
                            style: const TextStyle(fontWeight: FontWeight.w700),
                          ),
                        ),
                      ],
                    );
                  },
                ),
          actions: compactWidth
              ? <Widget>[
                  _minimalExamAction(
                    context: context,
                    icon: _review.contains(_idx)
                        ? Icons.bookmark_rounded
                        : Icons.bookmark_border_rounded,
                    tooltip: _review.contains(_idx)
                        ? 'Unmark review'
                        : 'Mark for review',
                    onPressed: _toggleCurrentReview,
                    active: _review.contains(_idx),
                    accent: const Color(0xFFE58A00),
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: Icons.task_alt_rounded,
                    tooltip: 'Submit',
                    onPressed: _confirmSubmit,
                    active: true,
                    accent: Colors.redAccent,
                  ),
                  PopupMenuButton<String>(
                    icon: const Icon(Icons.more_horiz_rounded),
                    onSelected: (String value) {
                      if (value == 'first') {
                        _jumpToFirstQuestion();
                      } else if (value == 'prev_unanswered') {
                        _jumpToNearestUnanswered(forward: false);
                      } else if (value == 'next_unanswered') {
                        _jumpToNearestUnanswered(forward: true);
                      } else if (value == 'last') {
                        _jumpToLastQuestion();
                      } else if (value == 'review_jump') {
                        _jumpToFirstReview();
                      } else if (value == 'palette') {
                        _openPalette();
                      } else if (value == 'clear') {
                        _clearCurrentAnswer();
                      } else if (value == 'submit') {
                        _confirmSubmit();
                      }
                    },
                    itemBuilder: (BuildContext context) =>
                        const <PopupMenuEntry<String>>[
                          PopupMenuItem<String>(
                            value: 'palette',
                            child: Text('Question palette'),
                          ),
                          PopupMenuItem<String>(
                            value: 'clear',
                            child: Text('Clear answer'),
                          ),
                          PopupMenuItem<String>(
                            value: 'prev_unanswered',
                            child: Text('Previous unanswered'),
                          ),
                          PopupMenuItem<String>(
                            value: 'next_unanswered',
                            child: Text('Next unanswered'),
                          ),
                          PopupMenuItem<String>(
                            value: 'first',
                            child: Text('Go to first question'),
                          ),
                          PopupMenuItem<String>(
                            value: 'last',
                            child: Text('Go to last question'),
                          ),
                          PopupMenuItem<String>(
                            value: 'review_jump',
                            child: Text('Jump to review'),
                          ),
                          PopupMenuItem<String>(
                            value: 'submit',
                            child: Text('Submit exam'),
                          ),
                        ],
                  ),
                ]
              : <Widget>[
                  _minimalExamAction(
                    context: context,
                    icon: Icons.skip_previous_rounded,
                    tooltip: 'Previous unanswered',
                    onPressed: () => _jumpToNearestUnanswered(forward: false),
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: Icons.skip_next_rounded,
                    tooltip: 'Next unanswered',
                    onPressed: () => _jumpToNearestUnanswered(forward: true),
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: Icons.grid_view_rounded,
                    tooltip: 'Question palette',
                    onPressed: _openPalette,
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: Icons.backspace_outlined,
                    tooltip: 'Clear answer',
                    onPressed: _clearCurrentAnswer,
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: _review.contains(_idx)
                        ? Icons.bookmark_rounded
                        : Icons.bookmark_border_rounded,
                    tooltip: _review.contains(_idx)
                        ? 'Unmark review'
                        : 'Mark for review',
                    onPressed: _toggleCurrentReview,
                    active: _review.contains(_idx),
                    accent: const Color(0xFFE58A00),
                  ),
                  _minimalExamAction(
                    context: context,
                    icon: Icons.task_alt_rounded,
                    tooltip: 'Submit',
                    onPressed: _confirmSubmit,
                    active: true,
                    accent: Colors.redAccent,
                  ),
                  PopupMenuButton<String>(
                    icon: const Icon(Icons.more_horiz_rounded),
                    onSelected: (String value) {
                      if (value == 'first') {
                        _jumpToFirstQuestion();
                      } else if (value == 'last') {
                        _jumpToLastQuestion();
                      } else if (value == 'review_jump') {
                        _jumpToFirstReview();
                      }
                    },
                    itemBuilder: (BuildContext context) =>
                        const <PopupMenuEntry<String>>[
                          PopupMenuItem<String>(
                            value: 'first',
                            child: Text('Go to first question'),
                          ),
                          PopupMenuItem<String>(
                            value: 'last',
                            child: Text('Go to last question'),
                          ),
                          PopupMenuItem<String>(
                            value: 'review_jump',
                            child: Text('Jump to review'),
                          ),
                        ],
                  ),
                ],
        ),
        body: Padding(
          padding: const EdgeInsets.all(16),
          child: Stack(
            children: <Widget>[
              Column(
                children: <Widget>[
                  LiquidGlass(
                    padding: const EdgeInsets.all(12),
                    child: Column(
                      children: <Widget>[
                        if (!compactWidth)
                          Row(
                            children: <Widget>[
                              Text(
                                'Question ${_idx + 1}/${widget.questions.length}',
                                style: const TextStyle(
                                  fontWeight: FontWeight.w800,
                                ),
                              ),
                              const Spacer(),
                              Text(
                                'Attempted $answeredCount/${widget.questions.length}',
                                style: const TextStyle(
                                  fontSize: 12,
                                  color: Colors.grey,
                                  fontWeight: FontWeight.w600,
                                ),
                              ),
                            ],
                          )
                        else
                          Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: <Widget>[
                              Text(
                                'Question ${_idx + 1}/${widget.questions.length}',
                                style: const TextStyle(
                                  fontWeight: FontWeight.w800,
                                ),
                              ),
                              const SizedBox(height: 4),
                              Text(
                                'Attempted $answeredCount/${widget.questions.length}',
                                style: const TextStyle(
                                  fontSize: 12,
                                  color: Colors.grey,
                                  fontWeight: FontWeight.w600,
                                ),
                              ),
                            ],
                          ),
                        const SizedBox(height: 8),
                        LinearProgressIndicator(
                          value: attemptedRatio,
                          minHeight: 8,
                          borderRadius: BorderRadius.circular(10),
                        ),
                        const SizedBox(height: 10),
                        Wrap(
                          spacing: 8,
                          runSpacing: 8,
                          children: <Widget>[
                            _ExamStatChip(
                              label: 'Answered',
                              value: '$answeredCount',
                              color: const Color(0xFF1BA784),
                            ),
                            _ExamStatChip(
                              label: 'Review',
                              value: '$reviewCount',
                              color: const Color(0xFFE58A00),
                            ),
                            _ExamStatChip(
                              label: 'Left',
                              value: '$unansweredCount',
                              color: const Color(0xFF5C6BC0),
                            ),
                            if (_isUnlimitedTimeMode)
                              const _ExamStatChip(
                                label: 'Mode',
                                value: 'Unlimited',
                                color: AppColors.primary,
                              )
                            else ...<Widget>[
                              _ExamStatChip(
                                label: 'Time Left',
                                value:
                                    '${((_secondsLeft / _totalExamSeconds) * 100).ceil().clamp(0, 100)}%',
                                color: AppColors.primary,
                              ),
                              _ExamStatChip(
                                label: 'Pace',
                                value: paceLabel,
                                color: paceDelta >= 0
                                    ? const Color(0xFF1BA784)
                                    : const Color(0xFFE05858),
                              ),
                            ],
                          ],
                        ),
                        const SizedBox(height: 2),
                      ],
                    ),
                  ),
                  const SizedBox(height: 10),
                  Expanded(
                    child: PageView.builder(
                      controller: _pageCtrl,
                      physics: const BouncingScrollPhysics(),
                      onPageChanged: (int i) {
                        setState(() {
                          _idx = i;
                          _visited.add(i);
                        });
                        _autoSave();
                      },
                      itemCount: widget.questions.length,
                      itemBuilder: (_, int i) {
                        final Question q = widget.questions[i];
                        return _QuestionView(
                          q: q,
                          index: i,
                          answers: _answers,
                          cardCornerRadius: _questionCardRadius,
