class _QuestionView extends StatelessWidget {
  const _QuestionView({
    required this.q,
    required this.index,
    required this.answers,
    required this.cardCornerRadius,
    required this.showDifficultyDot,
    required this.showConfidencePill,
    required this.onChanged,
  });

  final Question q;
  final int index;
  final Map<int, List<String>> answers;
  final double cardCornerRadius;
  final bool showDifficultyDot;
  final bool showConfidencePill;
  final void Function(List<String>) onChanged;

  String _cleanQuestionText(String raw) {
    String text = raw.trim();
    if (text.isEmpty) {
      return text;
    }
    text = text.replaceFirst(RegExp(r'^\[[^\]]+\]\s*'), '').trim();
    final List<String> subjectPrefixes = <String>[
      'physics',
      'chemistry',
      'biology',
      'math',
      'mathematics',
      'maths',
    ];
    final String lowered = text.toLowerCase();
    for (final String prefix in subjectPrefixes) {
      if (lowered.startsWith('$prefix:')) {
        return text.substring(prefix.length + 1).trim();
      }
      if (lowered.startsWith('$prefix -')) {
        return text.substring(prefix.length + 1).trim();
      }
    }
    return text;
  }

  String _difficultyLabel() {
    final String direct = q.difficultyLabel.trim();
    if (direct.isNotEmpty) {
      return direct;
    }
    final Match? levelMatch = RegExp(
      r'Difficulty\s*L\s*([1-5])',
      caseSensitive: false,
    ).firstMatch(q.concept);
    final int level = int.tryParse(levelMatch?.group(1) ?? '') ?? 0;
    if (level <= 0) {
      return '';
    }
    if (level <= 2) {
      return 'Basic';
    }
    if (level == 3) {
      return 'Main';
    }
    return 'Advanced';
  }

  Color _difficultyColor(String label) {
    final String lower = label.toLowerCase();
    if (lower.contains('adv') || lower.contains('hard')) {
      return const Color(0xFFB91C1C);
    }
    if (lower.contains('main') || lower.contains('medium')) {
      return const Color(0xFFEA580C);
    }
    return const Color(0xFF0284C7);
  }

  Color _confidenceColor(double score) {
    if (score >= 0.75) {
      return const Color(0xFF0F766E);
    }
    if (score >= 0.5) {
      return const Color(0xFFB45309);
    }
    return const Color(0xFFB91C1C);
  }

  @override
  Widget build(BuildContext context) {
    final List<String> selected = answers[index] ?? <String>[];
    final String questionText = _cleanQuestionText(q.text);
    final String difficultyLabel = _difficultyLabel();
    final bool hasDifficulty =
        showDifficultyDot && difficultyLabel.trim().isNotEmpty;
    final bool hasConfidence = showConfidencePill && q.confidenceScore >= 0;
    final Color difficultyColor = _difficultyColor(difficultyLabel);
    final Color confidenceColor = _confidenceColor(q.confidenceScore);

    return LiquidGlass(
      borderRadius: BorderRadius.circular(cardCornerRadius),
      padding: const EdgeInsets.all(22),
      child: LayoutBuilder(
        builder: (BuildContext context, BoxConstraints constraints) {
          return SingleChildScrollView(
            physics: const BouncingScrollPhysics(),
            child: ConstrainedBox(
              constraints: BoxConstraints(minHeight: constraints.maxHeight),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: <Widget>[
                      Expanded(
                        child: SmartText(
                          'Q${index + 1}. $questionText',
                          style: const TextStyle(
                            fontSize: 18,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                      ),
                      const SizedBox(width: 10),
                      Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 4,
                        ),
                        decoration: BoxDecoration(
                          color: AppColors.primary.withOpacity(0.12),
                          borderRadius: BorderRadius.circular(999),
                        ),
                        child: Text(
                          q.type.toUpperCase(),
                          style: const TextStyle(
                            fontSize: 11.5,
                            fontWeight: FontWeight.w700,
                            color: AppColors.primary,
                          ),
                        ),
                      ),
                    ],
                  ),
                  if (hasDifficulty || hasConfidence) ...<Widget>[
                    const SizedBox(height: 10),
                    Wrap(
                      spacing: 8,
                      runSpacing: 6,
                      children: <Widget>[
                        if (hasDifficulty)
                          Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 10,
                              vertical: 4,
                            ),
                            decoration: BoxDecoration(
                              color: difficultyColor.withOpacity(0.14),
                              borderRadius: BorderRadius.circular(999),
                              border: Border.all(
                                color: difficultyColor.withOpacity(0.35),
                              ),
                            ),
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: <Widget>[
                                Container(
                                  width: 7,
                                  height: 7,
                                  decoration: BoxDecoration(
                                    shape: BoxShape.circle,
                                    color: difficultyColor,
                                  ),
                                ),
                                const SizedBox(width: 6),
                                Text(
                                  difficultyLabel,
                                  style: TextStyle(
                                    fontSize: 11.5,
                                    fontWeight: FontWeight.w700,
                                    color: difficultyColor,
                                  ),
                                ),
                              ],
                            ),
                          ),
                        if (hasConfidence)
                          Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 10,
                              vertical: 4,
                            ),
                            decoration: BoxDecoration(
                              color: confidenceColor.withOpacity(0.14),
                              borderRadius: BorderRadius.circular(999),
                              border: Border.all(
                                color: confidenceColor.withOpacity(0.35),
                              ),
                            ),
                            child: Text(
                              '${(q.confidenceScore * 100).round()}% confidence',
                              style: TextStyle(
                                fontSize: 11.5,
                                fontWeight: FontWeight.w700,
                                color: confidenceColor,
                              ),
                            ),
                          ),
                      ],
                    ),
                  ],
                  const SizedBox(height: 12),
                  if (q.imageUrl.isNotEmpty)
                    Center(
                      child: ClipRRect(
                        borderRadius: BorderRadius.circular(12),
                        child: SmartImage(
                          q.imageUrl,
                          height: 180,
                          width: double.infinity,
                        ),
                      ),
                    ),
                  const SizedBox(height: 20),
                  if (q.type == 'NUMERICAL')
                    TextField(
                      key: ValueKey<String>('num_$index'),
                      controller: TextEditingController.fromValue(
                        TextEditingValue(
                          text: selected.isEmpty ? '' : selected.first,
                          selection: TextSelection.collapsed(
                            offset:
                                (selected.isEmpty ? '' : selected.first).length,
                          ),
                        ),
                      ),
                      keyboardType: const TextInputType.numberWithOptions(
                        decimal: true,
                      ),
                      decoration: const InputDecoration(
                        hintText: 'Enter answer',
                      ),
                      onChanged: (String v) => onChanged(<String>[v.trim()]),
                    )
                  else if (q.type == 'MCQ')
                    ...q.options.map((String opt) {
                      final String? groupValue = selected.isEmpty
                          ? null
                          : selected.first;
                      return RadioListTile<String>(
                        key: ValueKey<String>('mcq_${index}_$opt'),
                        value: opt,
                        groupValue: groupValue,
                        title: SmartText(opt),
                        onChanged: (String? v) {
                          if (v != null) {
                            onChanged(<String>[v]);
                          }
                        },
                      );
                    })
                  else
                    ...q.options.map((String opt) {
                      final bool sel = selected.contains(opt);
                      return CheckboxListTile(
                        key: ValueKey<String>('multi_${index}_$opt'),
                        value: sel,
                        title: SmartText(opt),
                        onChanged: (_) {
                          final List<String> copy = List<String>.from(selected);
                          if (sel) {
                            copy.remove(opt);
                          } else {
                            copy.add(opt);
                          }
                          onChanged(copy);
                        },
                      );
                    }),
                ],
              ),
            ),
          );
        },
      ),
    );
  }
}

class _QuestionPaletteSheet extends StatelessWidget {
  const _QuestionPaletteSheet({
    required this.total,
    required this.current,
    required this.answers,
    required this.review,
    required this.visited,
    required this.onJump,
  });

  final int total;
  final int current;
  final Map<int, List<String>> answers;
  final Set<int> review;
  final Set<int> visited;
  final void Function(int) onJump;

  Color _colorFor(int i) {
    if (i == current) {
      return Colors.blue;
    }
    if (review.contains(i)) {
      return Colors.orange;
    }
    if (answers.containsKey(i)) {
      if ((answers[i] ?? <String>[]).isEmpty) {
        return visited.contains(i) ? Colors.deepPurple : Colors.grey;
      }
      return Colors.green;
    }
    if (visited.contains(i)) {
      return Colors.deepPurple;
    }
    return Colors.grey;
  }

  @override
  Widget build(BuildContext context) {
    final double h = MediaQuery.of(context).size.height;
    return Container(
      height: h * 0.65,
      padding: const EdgeInsets.all(16),
      decoration: const BoxDecoration(
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      child: Column(
        children: <Widget>[
          const Text(
            'Question Palette',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
          ),
          const SizedBox(height: 12),
          Expanded(
            child: GridView.builder(
              itemCount: total,
              gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
                crossAxisCount: 5,
                mainAxisSpacing: 12,
                crossAxisSpacing: 12,
              ),
              itemBuilder: (_, int i) {
                final Color base = _colorFor(i);
                return InkWell(
                  onTap: () => onJump(i),
                  child: Container(
                    decoration: BoxDecoration(
                      borderRadius: BorderRadius.circular(12),
                      border: Border.all(color: base, width: 2),
                      color: base.withOpacity(0.12),
                    ),
                    child: Center(
                      child: Text(
                        '${i + 1}',
                        style: TextStyle(
                          fontWeight: FontWeight.bold,
                          color: base,
                        ),
                      ),
                    ),
                  ),
                );
              },
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 10,
            runSpacing: 8,
            alignment: WrapAlignment.center,
            children: const <Widget>[
              _LegendDot(color: Colors.green, text: 'Attempted'),
              _LegendDot(color: Colors.grey, text: 'Not Visited'),
              _LegendDot(color: Colors.deepPurple, text: 'Visited'),
              _LegendDot(color: Colors.orange, text: 'Marked'),
            ],
          ),
        ],
      ),
    );
  }
}

class AnalyticsLoadingScreen extends StatefulWidget {
  const AnalyticsLoadingScreen({
    super.key,
    required this.task,
    required this.onDone,
  });

  final Future<void> Function() task;
  final VoidCallback onDone;

  @override
  State<AnalyticsLoadingScreen> createState() => _AnalyticsLoadingScreenState();
}

class _AnalyticsLoadingScreenState extends State<AnalyticsLoadingScreen> {
  final List<String> messages = <String>[
    'Analyzing your performance…',
    'Finding your strengths…',
    'Detecting weak areas…',
    'Building your improvement plan…',
  ];

  int idx = 0;
  Timer? _timer;

  @override
  void initState() {
    super.initState();

    _timer = Timer.periodic(const Duration(seconds: 2), (_) {
      if (!mounted) {
        return;
      }
      setState(() => idx = (idx + 1) % messages.length);
    });

    () async {
      try {
        await widget.task().timeout(const Duration(seconds: 30));
      } catch (_) {}

      if (!mounted) {
        return;
      }
      _timer?.cancel();
      widget.onDone();
    }();
  }

  @override
  void dispose() {
    _timer?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: <Widget>[
            const SizedBox(
              width: 44,
              height: 44,
              child: CircularProgressIndicator(strokeWidth: 3),
            ),
            const SizedBox(height: 24),
            AnimatedSwitcher(
              duration: const Duration(milliseconds: 300),
              child: Text(
                messages[idx],
                key: ValueKey<int>(idx),
                style: const TextStyle(
                  fontSize: 18,
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class AnalyticsScreen extends StatefulWidget {
  const AnalyticsScreen({
    super.key,
    required this.data,
    required this.studentName,
    required this.title,
    required this.item,
    required this.aiAvailable,
    required this.aiResult,
    this.questions,
  });

  final ResultData data;
  final String studentName;
  final String title;
  final QuizItem item;
  final bool aiAvailable;
  final Map<String, dynamic>? aiResult;
  final List<Question>? questions;

  @override
  State<AnalyticsScreen> createState() => _AnalyticsScreenState();
}

class _AnalyticsScreenState extends State<AnalyticsScreen> {
  List<ResultData> _history = <ResultData>[];
  List<Map<String, dynamic>> _leaderboard = <Map<String, dynamic>>[];
  bool _loadingHistory = true;
  StudentIntelSnapshot? _studentIntel;
  bool _loadingIntel = true;
  int _rank = 1;
  double _percentile = 100;

  @override
  void initState() {
    super.initState();
    _loadHistory();
  }

  int _resultTimestampFromKey(String key) {
    final RegExpMatch? m = RegExp(r'^res_.+_(\d+)$').firstMatch(key.trim());
    if (m == null) {
      return 0;
    }
    return int.tryParse(m.group(1) ?? '') ?? 0;
  }

  Future<void> _loadHistory() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    final List<String> keys =
        prefs
            .getKeys()
            .where((String key) => key.startsWith('res_${widget.item.id}_'))
            .toList()
          ..sort(
            (String a, String b) => _resultTimestampFromKey(
              b,
            ).compareTo(_resultTimestampFromKey(a)),
          );
    final List<ResultData> temp = <ResultData>[];
    final List<Map<String, dynamic>> rows = <Map<String, dynamic>>[];

    for (final String key in keys) {
      try {
        final String? raw = prefs.getString(key);
        if (raw != null) {
          final Map<String, dynamic> row =
              jsonDecode(raw) as Map<String, dynamic>;
          rows.add(row);
          temp.add(ResultData.fromJson(row));
        }
      } catch (_) {}
    }

    _buildLeaderboard(rows);

    if (mounted) {
      setState(() {
        _history = temp;
        _loadingHistory = false;
      });
    }

    await _loadStudentIntel(temp);
  }

  void _buildLeaderboard(List<Map<String, dynamic>> rows) {
    final String currentAccountId = Session.effectiveAccountId.trim().isNotEmpty
        ? Session.effectiveAccountId.trim()
        : (Session.studentId.trim().isNotEmpty
              ? Session.studentId.trim()
              : widget.studentName.trim());

    final Map<String, Map<String, dynamic>> bestByStudent =
        <String, Map<String, dynamic>>{};

    for (final Map<String, dynamic> row in rows) {
      final String accountId =
          (row['accountId'] ??
                  row['studentId'] ??
                  row['account_id'] ??
                  row['student_id'] ??
                  row['studentName'] ??
                  row['student_name'] ??
                  '')
              .toString()
              .trim();
      if (accountId.isEmpty) {
        continue;
      }
      final String displayName =
          (row['studentName'] ??
                  row['student_name'] ??
                  row['name'] ??
                  'Student')
              .toString()
              .trim();
      final double score = _toDoubleNum(row['score']);
      final double maxScore = max(1.0, _toDoubleNum(row['maxScore']));
      final double scorePercent = ((score / maxScore) * 100).clamp(0.0, 100.0);
      final int totalTime = _toIntNum(row['totalTime']);
      final int savedAt = _toIntNum(
        row['savedAt'] ?? row['timestamp'] ?? row['ts'] ?? 0,
      );

      final Map<String, dynamic> entry = <String, dynamic>{
        'accountId': accountId,
        'name': displayName.isEmpty ? 'Student' : displayName,
        'score': score,
        'maxScore': maxScore,
        'scorePercent': scorePercent,
        'time': totalTime,
        'savedAt': savedAt,
      };

      final Map<String, dynamic>? prev = bestByStudent[accountId];
      if (prev == null || _isLeaderboardEntryBetter(entry, prev)) {
        bestByStudent[accountId] = entry;
      }
    }

    if (!bestByStudent.containsKey(currentAccountId)) {
      final double maxScore = max(1.0, widget.data.maxScore);
      bestByStudent[currentAccountId] = <String, dynamic>{
        'accountId': currentAccountId,
        'name': widget.studentName,
        'score': widget.data.score,
        'maxScore': maxScore,
        'scorePercent': ((widget.data.score / maxScore) * 100).clamp(
          0.0,
          100.0,
        ),
        'time': widget.data.totalTime,
        'savedAt': DateTime.now().millisecondsSinceEpoch,
      };
    }

    final List<Map<String, dynamic>> board = bestByStudent.values.toList()
      ..sort((Map<String, dynamic> a, Map<String, dynamic> b) {
        final int byPercent = _toDoubleNum(
          b['scorePercent'],
        ).compareTo(_toDoubleNum(a['scorePercent']));
        if (byPercent != 0) {
          return byPercent;
        }
        final int byScore = _toDoubleNum(
          b['score'],
        ).compareTo(_toDoubleNum(a['score']));
        if (byScore != 0) {
          return byScore;
        }
        final int byTime = _toIntNum(a['time']).compareTo(_toIntNum(b['time']));
        if (byTime != 0) {
          return byTime;
        }
        return _toIntNum(a['savedAt']).compareTo(_toIntNum(b['savedAt']));
      });

    final int idx = board.indexWhere(
      (Map<String, dynamic> entry) =>
          (entry['accountId'] ?? '').toString() == currentAccountId,
    );
    final int rank = idx >= 0 ? idx + 1 : 1;
    final double percentile = board.length <= 1
        ? 100.0
        : (((board.length - rank) / (board.length - 1)) * 100)
              .clamp(0.0, 100.0)
              .toDouble();

    if (!mounted) {
      return;
    }
    setState(() {
      _leaderboard = board;
      _rank = rank;
      _percentile = percentile;
    });
  }

  bool _isLeaderboardEntryBetter(
    Map<String, dynamic> candidate,
    Map<String, dynamic> previous,
  ) {
    final double cPct = _toDoubleNum(candidate['scorePercent']);
    final double pPct = _toDoubleNum(previous['scorePercent']);
    if ((cPct - pPct).abs() > 0.0001) {
      return cPct > pPct;
    }
    final double cScore = _toDoubleNum(candidate['score']);
    final double pScore = _toDoubleNum(previous['score']);
    if ((cScore - pScore).abs() > 0.0001) {
      return cScore > pScore;
    }
    final int cTime = _toIntNum(candidate['time']);
    final int pTime = _toIntNum(previous['time']);
    if (cTime != pTime) {
      return cTime < pTime;
    }
    return _toIntNum(candidate['savedAt']) > _toIntNum(previous['savedAt']);
  }

  int _toIntNum(dynamic value) {
    if (value is int) {
      return value;
    }
    if (value is num) {
      return value.toInt();
    }
    return int.tryParse((value ?? '').toString()) ?? 0;
  }

  double _toDoubleNum(dynamic value) {
    if (value is num) {
      return value.toDouble();
    }
    return double.tryParse((value ?? '').toString()) ?? 0;
  }

  Future<void> _loadStudentIntel(List<ResultData> history) async {
    if (mounted) {
      setState(() => _loadingIntel = true);
    }

    final String accountId = Session.effectiveAccountId.isNotEmpty
        ? Session.effectiveAccountId
        : widget.studentName;

    try {
      final StudentIntelSnapshot snapshot = await studentIntelService
          .buildAndStore(
            accountId: accountId,
            latest: widget.data,
            history: history,
            quizDurationMinutes: widget.item.durationMinutes > 0
                ? widget.item.durationMinutes
                : max(1, (widget.data.totalTime ~/ 60) + 1),
          );
      if (mounted) {
        setState(() {
          _studentIntel = snapshot;
          _loadingIntel = false;
        });
      }
      await notificationService.runPremiumStudentActivityScan(
        accountId: accountId,
        studentName: widget.studentName,
        quizzes: <QuizItem>[widget.item],
        history: history,
        intel: snapshot,
        force: true,
        interval: const Duration(minutes: 6),
      );
      return;
    } catch (_) {}

    try {
      final StudentIntelSnapshot? cached = await studentIntelService.load(
        accountId,
      );
      if (mounted) {
        setState(() {
          _studentIntel = cached;
          _loadingIntel = false;
        });
      }
    } catch (_) {
      if (mounted) {
        setState(() => _loadingIntel = false);
      }
    }
  }

  Map<String, dynamic> _normalizeAIResult(Map<String, dynamic> raw) {
    if (raw.containsKey('analytics') && raw['analytics'] is Map) {
      raw = Map<String, dynamic>.from(raw['analytics'] as Map);
    }

    if (raw.containsKey('strengths') ||
        raw.containsKey('weaknesses') ||
        raw.containsKey('strategy') ||
        raw.containsKey('next_steps')) {
      return <String, dynamic>{
        'summary': raw['summary'] ?? '',
        'strengths': raw['strengths'] ?? <dynamic>[],
        'weaknesses': raw['weaknesses'] ?? <dynamic>[],
        'strategy': raw['strategy'] ?? <dynamic>[],
        'next_steps': raw['next_steps'] ?? <dynamic>[],
      };
    }

    return <String, dynamic>{
      'summary': raw['summary'] ?? '',
      'strengths': raw['insights'] ?? <dynamic>[],
      'weaknesses': <dynamic>[],
      'strategy': raw['actions'] ?? <dynamic>[],
      'next_steps': raw['actions'] ?? <dynamic>[],
    };
  }

  Widget _analyticsCard({
    required Widget child,
    EdgeInsets padding = const EdgeInsets.all(20),
    Color? tint,
    BorderRadius borderRadius = const BorderRadius.all(Radius.circular(30)),
    VoidCallback? onTap,
  }) {
    final bool isDark = Theme.of(context).brightness == Brightness.dark;
    return LiquidGlass(
      onTap: onTap,
      quality: LiquidGlassQuality.low,
      enableRipple: onTap != null,
      enableHaptics: onTap != null,
      borderRadius: borderRadius,
      color: tint?.withValues(alpha: isDark ? 0.20 : 0.09),
      padding: padding,
      child: child,
    );
  }

