              color: const Color(0xFF1BA784).withValues(alpha: 0.14),
              borderRadius: BorderRadius.circular(999),
            ),
            child: const Text(
              'Apple Analytics',
              style: TextStyle(
                fontSize: 11,
                fontWeight: FontWeight.w700,
                color: Color(0xFF1B7F63),
              ),
            ),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final ResultData d = widget.data;
    final int attempted = d.correct + d.wrong;
    final double accuracy = attempted == 0 ? 0.0 : d.correct / attempted;
    final double percent =
        (d.score / (d.maxScore == 0 ? 1 : d.maxScore)) * 100.0;
    final bool unlimitedMode =
        widget.item.isUnlimitedTime || widget.item.durationMinutes <= 0;
    final int totalSeconds = unlimitedMode
        ? max(1, d.totalTime)
        : max(1, widget.item.durationMinutes * 60);

    int anim = 0;

    return Scaffold(
      appBar: AppBar(title: const Text('Student Analytics')),
      body: ListView(
        padding: const EdgeInsets.fromLTRB(20, 16, 20, 40),
        children: <Widget>[
          FadeSlideIn(index: anim++, child: _analyticsHeader()),
          const SizedBox(height: 14),
          FadeSlideIn(index: anim++, child: _heroAIAndScore(percent, d)),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _rankAndPercentileCard(percent)),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _leaderboardCard()),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _aiInsightsCard()),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _studentIntelCard()),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _quickStatsRow(d)),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _sectionBreakdownCard(d)),
          const SizedBox(height: 20),
          FadeSlideIn(
            index: anim++,
            child: _accuracyAndTime(
              accuracy,
              d.totalTime,
              totalSeconds,
              unlimitedMode: unlimitedMode,
            ),
          ),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _attemptPie(d)),
          const SizedBox(height: 20),
          if (!_loadingHistory && _history.length >= 2)
            FadeSlideIn(index: anim++, child: _historyTrend()),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _insightGrid(accuracy, d)),
          const SizedBox(height: 20),
          FadeSlideIn(index: anim++, child: _performanceVerdict(percent)),
          const SizedBox(height: 24),
          FadeSlideIn(index: anim++, child: _actionButtons()),
        ],
      ),
    );
  }

  Widget _heroAIAndScore(double percent, ResultData d) {
    final Map<String, dynamic>? ai = widget.aiResult != null
        ? _normalizeAIResult(widget.aiResult!)
        : null;

    String grade;
    Color gradeColor;
    String verdict;

    if (percent >= 85) {
      grade = 'A';
      gradeColor = Colors.green;
      verdict = 'Outstanding performance. You\'re in top form.';
    } else if (percent >= 70) {
      grade = 'B';
      gradeColor = Colors.lightGreen;
      verdict =
          'Very good performance. A little polish will make it excellent.';
    } else if (percent >= 50) {
      grade = 'C';
      gradeColor = Colors.orange;
      verdict = 'Decent attempt. There is clear room for improvement.';
    } else {
      grade = 'D';
      gradeColor = Colors.redAccent;
      verdict = 'Needs serious improvement. Let\'s rebuild fundamentals.';
    }

    final String aiSummary = (widget.aiAvailable && ai != null)
        ? (ai['summary'] ?? '').toString()
        : '';

    return _analyticsCard(
      tint: gradeColor,
      padding: const EdgeInsets.fromLTRB(22, 20, 22, 22),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          Row(
            children: <Widget>[
              const Text(
                'Performance Overview',
                style: TextStyle(fontSize: 20, fontWeight: FontWeight.w800),
              ),
              const Spacer(),
              Container(
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 5,
                ),
                decoration: BoxDecoration(
                  color:
                      (widget.aiAvailable
                              ? const Color(0xFF1BA784)
                              : const Color(0xFFFF8C42))
                          .withValues(alpha: 0.14),
                  borderRadius: BorderRadius.circular(999),
                ),
                child: Text(
                  widget.aiAvailable ? 'AI Synced' : 'Rule-Based',
                  style: TextStyle(
                    fontSize: 11,
                    fontWeight: FontWeight.w700,
                    color: widget.aiAvailable
                        ? const Color(0xFF197A61)
                        : const Color(0xFFB4691C),
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 18),
          Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: <Widget>[
              Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  Text(
                    '${percent.toStringAsFixed(1)}%',
                    style: const TextStyle(
                      fontSize: 56,
                      fontWeight: FontWeight.w900,
                      letterSpacing: -1.2,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    '${d.score.toStringAsFixed(1)} / ${d.maxScore.toStringAsFixed(1)}',
                    style: const TextStyle(
                      fontSize: 15,
                      color: Colors.grey,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ],
              ),
              const Spacer(),
              Container(
                width: 82,
                height: 82,
                decoration: BoxDecoration(
                  gradient: LinearGradient(
                    begin: Alignment.topLeft,
                    end: Alignment.bottomRight,
                    colors: <Color>[
                      gradeColor.withValues(alpha: 0.26),
                      gradeColor.withValues(alpha: 0.10),
                    ],
                  ),
                  borderRadius: BorderRadius.circular(24),
                  border: Border.all(
                    color: gradeColor.withValues(alpha: 0.24),
                    width: 1.0,
                  ),
                ),
                child: Center(
                  child: Text(
                    grade,
                    style: TextStyle(
                      fontSize: 38,
                      fontWeight: FontWeight.w900,
                      color: gradeColor,
                    ),
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 18),
          ClipRRect(
            borderRadius: BorderRadius.circular(14),
            child: LinearProgressIndicator(
              value: percent / 100.0,
              minHeight: 11,
              backgroundColor: Colors.grey.withValues(alpha: 0.22),
              color: gradeColor,
            ),
          ),
          const SizedBox(height: 16),
