  Widget _rankAndPercentileCard(double percent) {
    final int totalLearners = max(1, _leaderboard.length);
    final double topPercent = _leaderboard.isEmpty
        ? percent
        : _toDoubleNum(_leaderboard.first['scorePercent']);
    final double gapToTop = (topPercent - percent).clamp(0.0, 100.0);

    return _analyticsCard(
      tint: const Color(0xFF5B7BFF),
      padding: const EdgeInsets.all(18),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          const Text(
            'Rank Intelligence',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 10),
          Row(
            children: <Widget>[
              _intelPill(
                label: 'Rank',
                value: '#$_rank',
                color: const Color(0xFF3F8CFF),
              ),
              const SizedBox(width: 8),
              _intelPill(
                label: 'Percentile',
                value: '${_percentile.toStringAsFixed(1)}%',
                color: const Color(0xFF1BA784),
              ),
              const SizedBox(width: 8),
              _intelPill(
                label: 'Learners',
                value: '$totalLearners',
                color: const Color(0xFF5C6BC0),
              ),
            ],
          ),
          const SizedBox(height: 12),
          Text(
            gapToTop <= 0.01
                ? 'You are leading this quiz leaderboard.'
                : '${gapToTop.toStringAsFixed(1)}% behind the top score. One stronger attempt can shift rank quickly.',
            style: const TextStyle(
              fontSize: 13.8,
              height: 1.35,
              fontWeight: FontWeight.w600,
            ),
          ),
        ],
      ),
    );
  }

  Widget _leaderboardCard() {
    if (_leaderboard.isEmpty) {
      return _analyticsCard(
        tint: const Color(0xFF6A7BFF),
        padding: const EdgeInsets.all(18),
        child: const Text(
          'Leaderboard will appear after more attempts are available.',
          style: TextStyle(fontWeight: FontWeight.w600),
        ),
      );
    }

    final String currentAccountId = Session.effectiveAccountId.trim().isNotEmpty
        ? Session.effectiveAccountId.trim()
        : (Session.studentId.trim().isNotEmpty
              ? Session.studentId.trim()
              : widget.studentName.trim());

    return _analyticsCard(
      tint: const Color(0xFF6A7BFF),
      padding: const EdgeInsets.all(18),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          const Text(
            'Leaderboard (Best Attempt)',
            style: TextStyle(fontSize: 17.5, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 10),
          ..._leaderboard.take(8).toList().asMap().entries.map((
            MapEntry<int, Map<String, dynamic>> item,
          ) {
            final int rank = item.key + 1;
            final Map<String, dynamic> row = item.value;
            final bool isCurrent =
                (row['accountId'] ?? '').toString() == currentAccountId;
            final Color rankColor = rank <= 3
                ? const Color(0xFFE58A00)
                : const Color(0xFF486581);
            return Container(
              margin: const EdgeInsets.only(bottom: 8),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(12),
                color:
                    (isCurrent
                            ? const Color(0xFF1BA784)
                            : const Color(0xFF3F8CFF))
                        .withValues(alpha: isCurrent ? 0.12 : 0.06),
                border: Border.all(
                  color:
                      (isCurrent
                              ? const Color(0xFF1BA784)
                              : const Color(0xFF3F8CFF))
                          .withValues(alpha: isCurrent ? 0.32 : 0.14),
                ),
              ),
              child: Row(
                children: <Widget>[
                  SizedBox(
                    width: 26,
                    child: Text(
                      '#$rank',
                      style: TextStyle(
                        fontWeight: FontWeight.w800,
                        color: rankColor,
                      ),
                    ),
                  ),
                  const SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      (row['name'] ?? 'Student').toString(),
                      overflow: TextOverflow.ellipsis,
                      style: TextStyle(
                        fontWeight: isCurrent
                            ? FontWeight.w800
                            : FontWeight.w600,
                      ),
                    ),
                  ),
                  const SizedBox(width: 8),
                  Text(
                    '${_toDoubleNum(row['scorePercent']).toStringAsFixed(1)}%',
                    style: const TextStyle(
                      fontWeight: FontWeight.w800,
                      color: Color(0xFF102A43),
                    ),
                  ),
                  const SizedBox(width: 8),
                  Text(
                    '${(_toIntNum(row['time']) ~/ 60)}m',
                    style: const TextStyle(
                      fontSize: 12,
                      color: Color(0xFF486581),
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

  Widget _sectionBreakdownCard(ResultData d) {
    if (d.sectionAccuracy.isEmpty) {
      return const SizedBox.shrink();
    }
    final List<MapEntry<String, double>> entries =
        d.sectionAccuracy.entries.toList()..sort(
          (MapEntry<String, double> a, MapEntry<String, double> b) =>
              b.value.compareTo(a.value),
        );

    return _analyticsCard(
      tint: const Color(0xFF2F91F7),
      padding: const EdgeInsets.all(18),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          const Text(
            'Section Accuracy',
            style: TextStyle(fontSize: 17.5, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 12),
          ...entries.map((MapEntry<String, double> entry) {
            final double normalized = (entry.value / 100).clamp(0.0, 1.0);
            final Color c = entry.value >= 75
                ? const Color(0xFF1BA784)
                : entry.value >= 50
                ? const Color(0xFFE58A00)
                : const Color(0xFFE05858);
            return Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  Row(
                    children: <Widget>[
                      Expanded(
                        child: Text(
                          entry.key.trim().isEmpty ? 'General' : entry.key,
                          style: const TextStyle(fontWeight: FontWeight.w700),
                        ),
                      ),
                      Text(
                        '${entry.value.toStringAsFixed(1)}%',
                        style: TextStyle(fontWeight: FontWeight.w800, color: c),
                      ),
                    ],
                  ),
                  const SizedBox(height: 6),
                  ClipRRect(
                    borderRadius: BorderRadius.circular(8),
                    child: LinearProgressIndicator(
                      value: normalized,
                      minHeight: 8,
                      color: c,
                      backgroundColor: Colors.black12,
                    ),
                  ),
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

