  Widget _studentIntelCard() {
    if (_loadingIntel) {
      return _analyticsCard(
        tint: const Color(0xFF3F8CFF),
        padding: const EdgeInsets.all(18),
        child: Row(
          children: const <Widget>[
            SizedBox(
              width: 18,
              height: 18,
              child: CircularProgressIndicator(strokeWidth: 2),
            ),
            SizedBox(width: 10),
            Text('Building student intelligence...'),
          ],
        ),
      );
    }

    final StudentIntelSnapshot? intel = _studentIntel;
    if (intel == null) {
      return const SizedBox.shrink();
    }

    final Color burnoutColor = intel.burnoutProbability > 0.62
        ? Colors.red
        : intel.burnoutProbability > 0.4
        ? Colors.orange
        : Colors.green;
    final Color improvementColor = intel.improvementProbability > 0.65
        ? Colors.green
        : intel.improvementProbability > 0.4
        ? Colors.orange
        : Colors.redAccent;

    return _analyticsCard(
      tint: const Color(0xFF3F8CFF),
      padding: const EdgeInsets.all(18),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          const Text(
            'Student Intelligence Engine',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 12),
          Row(
            children: <Widget>[
              _intelPill(
                label: 'Trend EMA',
                value: '${intel.performanceTrendEma.toStringAsFixed(1)}%',
                color: AppColors.primary,
              ),
              const SizedBox(width: 8),
              _intelPill(
                label: 'Consistency',
                value: '${(intel.consistencyScore * 100).toStringAsFixed(0)}%',
                color: Colors.teal,
              ),
              const SizedBox(width: 8),
              _intelPill(
                label: 'Difficulty',
                value:
                    '${(intel.difficultyHandlingScore * 100).toStringAsFixed(0)}%',
                color: Colors.blue,
              ),
            ],
          ),
          const SizedBox(height: 10),
          Row(
            children: <Widget>[
              Expanded(
                child: _probabilityTile(
                  title: 'Burnout Probability',
                  value: intel.burnoutProbability,
                  color: burnoutColor,
                ),
              ),
              const SizedBox(width: 10),
              Expanded(
                child: _probabilityTile(
                  title: 'Improvement Prediction',
                  value: intel.improvementProbability,
                  color: improvementColor,
                ),
              ),
            ],
          ),
          if (intel.weakConcepts.isNotEmpty) ...<Widget>[
            const SizedBox(height: 12),
            const Text(
              'Weak Concepts',
              style: TextStyle(fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 6),
            Wrap(
              spacing: 6,
              runSpacing: 6,
              children: intel.weakConcepts
                  .map(
                    (String c) => Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 6,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.orange.withOpacity(0.14),
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Text(c, style: const TextStyle(fontSize: 12)),
                    ),
                  )
                  .toList(),
            ),
          ],
          if (intel.recommendations.isNotEmpty) ...<Widget>[
            const SizedBox(height: 12),
            const Text(
              'Recommendations',
              style: TextStyle(fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 6),
            ...intel.recommendations
                .take(3)
                .map(
                  (String e) => Padding(
                    padding: const EdgeInsets.only(bottom: 4),
                    child: Text('• $e'),
                  ),
                ),
          ],
        ],
      ),
    );
  }

