  Widget _historyTrend() {
    final List<FlSpot> spots = <FlSpot>[];
    for (int i = 0; i < _history.length; i++) {
      final ResultData h = _history[_history.length - 1 - i];
      final double pct = (h.score / (h.maxScore == 0 ? 1 : h.maxScore)) * 100;
      spots.add(FlSpot(i.toDouble(), pct));
    }

    return _analyticsCard(
      tint: const Color(0xFF1BA784),
      padding: const EdgeInsets.all(20),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: <Widget>[
          const Text(
            'Performance Trend',
            style: TextStyle(fontWeight: FontWeight.bold, fontSize: 17),
          ),
          const SizedBox(height: 16),
          SizedBox(
            height: 200,
            child: LineChart(
              LineChartData(
                minY: 0,
                maxY: 100,
                gridData: FlGridData(
                  show: true,
                  drawVerticalLine: false,
                  getDrawingHorizontalLine: (_) => FlLine(
                    color: Colors.black.withValues(alpha: 0.06),
                    strokeWidth: 1,
                  ),
                ),
                titlesData: const FlTitlesData(show: false),
                borderData: FlBorderData(show: false),
                lineBarsData: <LineChartBarData>[
                  LineChartBarData(
                    spots: spots,
                    isCurved: true,
                    color: const Color(0xFF3F8CFF),
                    barWidth: 3.2,
                    dotData: const FlDotData(show: false),
                    belowBarData: BarAreaData(
                      show: true,
                      color: const Color(0xFF3F8CFF).withValues(alpha: 0.16),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _insightGrid(double accuracy, ResultData d) {
    final int attempted = d.correct + d.wrong;
    final int total = max(1, attempted + d.skipped);
    final double coverage = (attempted / total) * 100;
    final double minutesUsed = max(1.0, d.totalTime / 60.0);
    final double speed = attempted / minutesUsed;

    return GridView.count(
      crossAxisCount: 2,
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      mainAxisSpacing: 12,
      crossAxisSpacing: 12,
      childAspectRatio: 1.4,
      children: <Widget>[
        _miniInsight('Accuracy', '${(accuracy * 100).toStringAsFixed(1)}%'),
        _miniInsight('Coverage', '${coverage.toStringAsFixed(1)}%'),
        _miniInsight('Attempt Speed', '${speed.toStringAsFixed(1)} q/min'),
        _miniInsight('Percentile', '${_percentile.toStringAsFixed(1)}%'),
      ],
    );
  }

