      ),
    );
  }

  Widget _performanceVerdict(double percent) {
    String text;
    IconData icon;

    if (percent >= 75) {
      text = 'Excellent Performance';
      icon = Icons.emoji_events;
    } else if (percent >= 45) {
      text = 'Good Progress';
      icon = Icons.trending_up;
    } else {
      text = 'Needs Improvement';
      icon = Icons.warning_amber;
    }

    return _analyticsCard(
      tint: percent >= 75
          ? Colors.green
          : percent >= 45
          ? Colors.orange
          : Colors.redAccent,
      padding: const EdgeInsets.all(20),
      child: Row(
        children: <Widget>[
          Icon(icon, size: 32),
          const SizedBox(width: 12),
          Expanded(
            child: Text(
              text,
              style: const TextStyle(fontSize: 17, fontWeight: FontWeight.bold),
            ),
          ),
        ],
      ),
    );
  }

  Widget _actionButtons() {
    return Row(
      children: <Widget>[
        Expanded(
          child: _analyticsCard(
            tint: const Color(0xFF3F8CFF),
            onTap: () {
              Navigator.push(
                context,
                MaterialPageRoute(
                  builder: (_) => AnswerKeyScreen(
                    quizId: widget.data.quizId,
                    quizTitle: widget.title,
                    studentName: widget.studentName,
                    userAns: widget.data.userAnswers,
                    item: widget.item,
                    providedQuestions: widget.questions,
                  ),
                ),
              );
            },
            padding: const EdgeInsets.all(16),
            child: const Center(child: Text('View Answer Key')),
          ),
        ),
        const SizedBox(width: 12),
        Expanded(
          child: LiquidGlass(
            onTap: () async {
              final SharedPreferences prefs =
                  await SharedPreferences.getInstance();
              await prefs.remove('auto_${widget.item.id}');
              if (!mounted) {
                return;
              }
              Navigator.pushReplacement(
                context,
                MaterialPageRoute(
                  builder: (_) => InstructionScreen(
                    item: widget.item,
                    studentName: widget.studentName,
                    isResume: false,
                  ),
                ),
              );
            },
            color: AppColors.primary,
            padding: const EdgeInsets.all(16),
            child: const Center(
              child: Text(
                'Reattempt',
                style: TextStyle(
                  color: Colors.white,
                  fontWeight: FontWeight.bold,
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }
