    required this.item,
    this.providedQuestions,
  });

  final String quizId;
  final String quizTitle;
  final String studentName;
  final Map<int, List<String>> userAns;
  final QuizItem item;
  final List<Question>? providedQuestions;

  @override
  State<AnswerKeyScreen> createState() => _AnswerKeyScreenState();
}

class _AnswerKeyScreenState extends State<AnswerKeyScreen> {
  List<Question> _questions = <Question>[];
  List<AnswerKeyCardPayload> _cards = <AnswerKeyCardPayload>[];
  bool _loading = true;
  int _idx = 0;
  late final PageController _pageCtrl;

  bool get _teacherAksMode => Session.userRole == 'teacher';

  @override
  void initState() {
    super.initState();
    _pageCtrl = PageController();
    _load();
  }

  @override
  void dispose() {
    _pageCtrl.dispose();
    super.dispose();
  }

  Future<void> _load() async {
    if (widget.providedQuestions != null &&
        widget.providedQuestions!.isNotEmpty) {
      setState(() {
        _questions = widget.providedQuestions!;
        _cards = _buildCardPayloads(widget.providedQuestions!);
        _loading = false;
      });
      unawaited(
        aiPrecomputeService.enqueueQuiz(
          quizId: widget.quizId,
          questions: widget.providedQuestions!,
          userId: Session.effectiveAccountId,
        ),
      );
      return;
    }

    if (widget.item.isAiGenerated) {
      try {
        final Map<String, dynamic> evaluated = await backendService
            .evaluateQuizSubmission(<String, dynamic>{
              'quiz_id': widget.quizId,
              'quiz_title': widget.quizTitle,
              'name': widget.studentName,
              'student_name': widget.studentName,
              'student_id': Session.studentId,
              'user_id': Session.effectiveAccountId,
              'account_id': Session.effectiveAccountId,
              'answers': widget.userAns.map(
                (int k, List<String> v) => MapEntry(k.toString(), v),
              ),
              'include_answer_key': true,
              'preview_only': true,
            });
        if (backendService.isSuccessfulResponse(evaluated)) {
          final List<Question> aiQuestions = _questionsFromAnswerKeyPayload(
            evaluated['answer_key'],
          );
          if (aiQuestions.isNotEmpty) {
            if (mounted) {
              setState(() {
                _questions = aiQuestions;
                _cards = _buildCardPayloads(aiQuestions);
                _loading = false;
              });
            }
            unawaited(
              aiPrecomputeService.enqueueQuiz(
                quizId: widget.quizId,
                questions: aiQuestions,
                userId: Session.effectiveAccountId,
              ),
            );
            return;
          }
        }
      } catch (_) {}
    }

    try {
      final String? localFromUrl = localQuizStore.quizIdFromUrl(
        widget.item.url,
      );
      final String localQuizId = (localFromUrl ?? widget.quizId).trim();
      final bool forceLocal = localQuizStore.isLocalQuizUrl(widget.item.url);
      if (forceLocal && localQuizId.isNotEmpty) {
        final List<Question> localQuestions = await localQuizStore
            .loadQuestions(localQuizId);
        if (localQuestions.isNotEmpty) {
          if (mounted) {
            setState(() {
              _questions = localQuestions;
              _cards = _buildCardPayloads(localQuestions);
              _loading = false;
            });
          }
          unawaited(
            aiPrecomputeService.enqueueQuiz(
              quizId: widget.quizId,
              questions: localQuestions,
              userId: Session.effectiveAccountId,
            ),
          );
          return;
        }
      }
    } catch (_) {}

    try {
      final Uri base = Uri.parse(widget.item.url);
      final Uri uri = base.replace(
        queryParameters: <String, String>{
          ...base.queryParameters,
          'ts': DateTime.now().millisecondsSinceEpoch.toString(),
        },
      );
      final String raw = await _fetchRaw(uri);
      final List<List<dynamic>> rows = await parseCsvInBackground(raw);

      final List<Question> temp = <Question>[];
      for (int i = 1; i < rows.length; i++) {
        final List<dynamic> row = rows[i];
        if (row.isEmpty) {
          continue;
        }

        String col(int idx) =>
            idx < row.length ? row[idx].toString().trim() : '';

        temp.add(
          Question(
            text: col(0),
            imageUrl: col(1),
            type: col(2).isEmpty ? 'MCQ' : col(2),
            section: col(3).isEmpty ? 'General' : col(3),
            posMark: double.tryParse(col(4)) ?? 4,
            negMark: double.tryParse(col(5)) ?? 1,
            options: <String>[col(6), col(7), col(8), col(9)],
            correctAnswers: col(10)
                .split(',')
                .map((String e) => e.trim())
                .where((String e) => e.isNotEmpty)
                .toList(),
            solution: col(11),
            concept: col(12),
          ),
        );
      }

      if (mounted) {
        setState(() {
          _questions = temp;
          _cards = _buildCardPayloads(temp);
          _loading = false;
        });
      }
      unawaited(
        localQuizStore.saveQuiz(
          item: widget.item,
          questions: temp,
          ownerAccountId: Session.effectiveAccountId,
          ownerRole: Session.userRole,
          visibility: 'published',
          includeInIndex: false,
        ),
      );
      unawaited(
        aiPrecomputeService.enqueueQuiz(
          quizId: widget.quizId,
          questions: temp,
          userId: Session.effectiveAccountId,
        ),
      );
    } catch (_) {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  List<AnswerKeyCardPayload> _buildCardPayloads(List<Question> questions) {
    return List<AnswerKeyCardPayload>.generate(questions.length, (int i) {
      final Question q = questions[i];
      final List<String> user = widget.userAns[i] ?? <String>[];
      final bool skipped = user.isEmpty;
      final bool correct = _isCorrect(q, user);
      final double delta = _markDelta(q, user);
      final Color statusColor = skipped
          ? Colors.blueGrey
          : correct
          ? Colors.green
          : Colors.redAccent;
      final String status = skipped
          ? 'SKIPPED'
          : correct
          ? 'CORRECT'
          : 'WRONG';
      final List<String> opts = q.options
          .asMap()
          .entries
          .map(
            (MapEntry<int, String> e) =>
                '${String.fromCharCode(65 + e.key)}) ${e.value}',
          )
          .toList();
      return AnswerKeyCardPayload(
        heroTag: 'ak_${widget.quizId}_$i',
        questionIndex: i,
        questionText: q.text,
        options: _teacherAksMode ? opts : const <String>[],
        correctAnswer: q.correctAnswers.join(', '),
        studentAnswer: _teacherAksMode
            ? (user.isEmpty ? 'Skipped' : user.join(', '))
            : '',
        solution: q.solution,
        concept: q.concept,
        marksDelta: delta,
        statusLabel: status,
        statusColor: statusColor,
        imageUrl: q.imageUrl,
      );
    });
  }

  String _normalizeAnswerKeyQuestionType(dynamic rawType) {
    final String normalized = rawType.toString().trim().toLowerCase();
    final bool singleCorrectSignal =
        normalized.contains('single correct') ||
        normalized.contains('single answer') ||
        normalized.contains('mcq_single') ||
        normalized == 'single';
    final bool multiSignal =
        normalized == 'multi' ||
        normalized == 'mcq_multi' ||
        normalized == 'multicorrect' ||
        normalized == 'multi_correct' ||
        normalized == 'multi-correct' ||
        normalized == 'multiple' ||
        normalized == 'multiple_correct' ||
        normalized == 'multiple correct' ||
        normalized == 'multiple_choice_multiple_answer' ||
        normalized == 'msq' ||
        normalized == 'mcma' ||
        normalized == 'select_all_that_apply' ||
        normalized.contains('multiple correct') ||
        normalized.contains('multi correct') ||
        normalized.contains('select all') ||
        (normalized.contains('multiple') && !singleCorrectSignal);
    if (multiSignal) {
      return 'MULTI';
    }
    if (normalized == 'numerical' ||
        normalized == 'integer' ||
        normalized == 'numeric' ||
        normalized == 'num') {
      return 'NUMERICAL';
    }
    return 'MCQ';
  }

  List<Question> _questionsFromAnswerKeyPayload(dynamic raw) {
    if (raw is! List) {
      return <Question>[];
    }
    final List<Question> out = <Question>[];
    for (final dynamic entry in raw) {
      if (entry is! Map) {
        continue;
      }
      final Map<String, dynamic> row = Map<String, dynamic>.from(entry);
      final String text = (row['question_text'] ?? '').toString().trim();
      if (text.isEmpty) {
        continue;
      }
      final List<String> options = (row['options'] is List)
          ? (row['options'] as List<dynamic>)
                .map((dynamic e) => e.toString().trim())
                .where((String e) => e.isNotEmpty)
                .take(4)
                .toList()
          : <String>[];
      final String questionType = _normalizeAnswerKeyQuestionType(
        row['question_type'] ?? row['type'],
      );
      while (options.length < 4) {
        options.add('');
      }
      List<String> correctAnswers = const <String>[];
      if (questionType == 'NUMERICAL') {
        final String correct =
            (row['correct_numerical'] ??
                    row['numerical_answer'] ??
                    row['correct_answer'] ??
                    '')
                .toString()
                .trim();
        correctAnswers = correct.isEmpty ? const <String>[] : <String>[correct];
      } else if (questionType == 'MULTI') {
        if (row['correct_answers'] is List) {
          correctAnswers = (row['correct_answers'] as List<dynamic>)
              .map((dynamic e) => e.toString().trim())
              .where((String e) => e.isNotEmpty)
              .toList();
        } else {
          final String rawMulti =
              (row['correct_answers'] ?? row['correct_answer'] ?? '')
                  .toString()
                  .trim();
          if (rawMulti.isNotEmpty) {
            correctAnswers = rawMulti
                .split(RegExp(r'[,/|&;]+'))
                .map((String e) => e.trim())
                .where((String e) => e.isNotEmpty)
                .toList();
          }
        }
      } else {
        String correct = (row['correct_answer'] ?? '').toString().trim();
        if (correct.contains(')')) {
          final List<String> parts = correct.split(')');
          if (parts.length > 1) {
            correct = parts.sublist(1).join(')').trim();
          }
        }
        if (correct.isEmpty) {
          final String letter = (row['correct_option'] ?? '')
              .toString()
              .trim()
              .toUpperCase();
          if (letter.length == 1) {
            final int idx = letter.codeUnitAt(0) - 65;
            if (idx >= 0 && idx < options.length) {
              correct = options[idx];
            }
          }
        }
        correctAnswers = correct.isEmpty ? const <String>[] : <String>[correct];
      }
      final List<String> tags = (row['concept_tags'] is List)
          ? (row['concept_tags'] as List<dynamic>)
                .map((dynamic e) => e.toString().trim())
                .where((String e) => e.isNotEmpty)
                .toList()
          : <String>[];
      out.add(
        Question(
          text: text,
          imageUrl: '',
          type: questionType,
          section: tags.isEmpty ? 'General' : tags.join(', '),
          posMark: 4,
          negMark: 1,
          options: options,
          correctAnswers: correctAnswers,
          solution: (row['solution_explanation'] ?? '').toString().trim(),
          concept: tags.join(', '),
        ),
      );
    }
    return out;
  }

  Future<String> _fetchRaw(Uri uri) async {
    final http.Response response = await http
        .get(uri)
        .timeout(const Duration(seconds: 20));
    if (response.statusCode != 200) {
      throw Exception('HTTP ${response.statusCode}');
    }
    return response.body;
  }

  Future<void> _askAIFor(int idx) async {
    final Question q = _questions[idx];
    final List<String> myAnsList = widget.userAns[idx] ?? <String>[];
    final String myAns = myAnsList.isEmpty ? 'Skipped' : myAnsList.join(', ');
    final double marks = _markDelta(q, myAnsList);
    final AnswerKeyCardPayload payload = _cards[idx];
    final Map<String, dynamic> cardMap = payload.toCardMap();

    final AiCacheEntry? cached = await aiPrecomputeService.cached(
      quizId: widget.quizId,
      questionIndex: idx,
    );
    final bool canUseCache =
        cached != null &&
        cached.questionHash == AiCacheManager.hashQuestion(q.text) &&
        (cached.answer.trim().isNotEmpty ||
            cached.explanation.trim().isNotEmpty);
    if (canUseCache && mounted) {
      final String confidence = cached.confidence >= 0.75
          ? 'High'
          : cached.confidence >= 0.45
          ? 'Medium'
          : 'Low';
      final String content =
          '''
**Answer**
${cached.answer}

**Explanation**
${cached.explanation}
''';
      Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => AIChatScreen(
            userId: widget.studentName,
            chatId: 'AI_${widget.studentName}_${widget.quizId}',
            chatFunction: 'aks_answer_review',
            showPersonaBanner: true,
            heroTag: payload.heroTag,
            heroCard: cardMap,
            seedAssistantMessage: ChatMessage(
              role: 'assistant',
              text: content.trim(),
              confidence: confidence,
              concept: cached.concept.isEmpty ? null : cached.concept,
            ),
            contextCard: <String, dynamic>{
              'quiz_id': widget.quizId,
              'question_index': idx,
              'question': q.text,
              'correct': q.correctAnswers,
              'student': myAnsList,
              'solution': q.solution,
              'concept': q.concept,
              'marks': marks,
              'cache_hit': true,
              'answer_key_card': cardMap,
            },
          ),
        ),
      );
      return;
    }

    final String prompt =
        '''
Question:
${q.text}

Options:
A) ${q.options.elementAtOrNull(0) ?? ''}
B) ${q.options.elementAtOrNull(1) ?? ''}
C) ${q.options.elementAtOrNull(2) ?? ''}
D) ${q.options.elementAtOrNull(3) ?? ''}

Correct Answer: ${q.correctAnswers.join(', ')}
Student Answer: $myAns
Marks: ${marks >= 0 ? '+' : ''}${marks.toStringAsFixed(2)}
${q.solution.trim().isEmpty ? '' : 'Official Solution:\\n${q.solution.trim()}\\n'}

Tasks:
1) Explain why the student answer is right or wrong.
2) Teach the correct method step by step.
3) Give one exam-oriented tip.
4) Return markdown with LaTeX where needed.
''';

    if (!mounted) {
      return;
    }
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => AIChatScreen(
          userId: widget.studentName,
          chatId: 'AI_${widget.studentName}_${widget.quizId}',
          chatFunction: 'aks_answer_review',
          showPersonaBanner: true,
          heroTag: payload.heroTag,
          heroCard: cardMap,
          contextCard: <String, dynamic>{
            'quiz_id': widget.quizId,
            'question_index': idx,
            'question': q.text,
            'correct': q.correctAnswers,
            'student': myAnsList,
            'solution': q.solution,
            'concept': q.concept,
            'marks': marks,
            'answer_key_card': cardMap,
          },
          initialPrompt: prompt,
        ),
      ),
    );
  }

  bool _isCorrect(Question q, List<String> user) {
    if (user.isEmpty) {
      return false;
    }
    if (q.type.toUpperCase() == 'NUMERICAL') {
      final double? userVal = double.tryParse(user.first);
      final double? correctVal = double.tryParse(q.correctAnswers.first);
      return userVal != null &&
          correctVal != null &&
          (userVal - correctVal).abs() < 0.01;
    }
    final Set<String> userSet = user.map((String e) => e.trim()).toSet();
    final Set<String> correctSet = q.correctAnswers
        .map((String e) => e.trim())
        .toSet();
    return userSet.length == correctSet.length &&
        userSet.containsAll(correctSet);
  }

  double _markDelta(Question q, List<String> user) {
    if (user.isEmpty) {
      return 0;
    }
    return _isCorrect(q, user) ? q.posMark : -q.negMark;
  }

  void _openPalette() {
    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      builder: (_) => _AnswerKeyPaletteSheet(
        total: _questions.length,
        current: _idx,
        answers: widget.userAns,
        questions: _questions,
        onJump: (int next) {
          setState(() => _idx = next);
          _pageCtrl.animateToPage(
            next,
            duration: const Duration(milliseconds: 220),
            curve: Curves.easeOutCubic,
          );
          Navigator.pop(context);
        },
      ),
    );
  }

  Future<void> _raiseDoubtFor(int idx) async {
    final Question q = _questions[idx];
    final AnswerKeyCardPayload payload = _cards[idx];
    final TextEditingController doubtCtrl = TextEditingController();

    await showDialog<void>(
      context: context,
      builder: (BuildContext context) {
        return AlertDialog(
          title: const Text('Raise Doubt'),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            children: <Widget>[
              Text(
                q.text,
                maxLines: 3,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(fontSize: 12, color: Colors.grey),
              ),
              const SizedBox(height: 10),
              TextField(
                controller: doubtCtrl,
                minLines: 2,
                maxLines: 4,
                decoration: const InputDecoration(
                  hintText: 'Describe your doubt for teacher',
                  border: OutlineInputBorder(),
                ),
              ),
            ],
          ),
          actions: <Widget>[
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Send'),
            ),
          ],
        );
      },
    );

    final String doubt = doubtCtrl.text.trim();
    doubtCtrl.dispose();
    if (doubt.isEmpty || !mounted) {
      return;
    }

    try {
      await backendService.enqueueTeacherReview(<String, dynamic>{
        'quiz_id': widget.quizId,
        'question_id': idx + 1,
        'question_index': idx,
        'student_answer':
            (widget.userAns[idx] ?? <String>[]).join(', ').trim().isEmpty
            ? 'Skipped'
            : (widget.userAns[idx] ?? <String>[]).join(', '),
        'correct_answer': q.correctAnswers.join(', '),
        'student_id': Session.effectiveAccountId,
        'message': doubt,
        'timestamp': DateTime.now().millisecondsSinceEpoch,
      });
    } catch (_) {}

    try {
      final ChatThreadSummary thread = await chatService.raiseDoubtFromQuestion(
        quizId: widget.quizId,
        quizTitle: widget.quizTitle,
        questionText: q.text,
        myUserId: Session.effectiveChatId,
        myName: Session.effectiveDisplayName,
        initialMessage: doubt,
        imageUrl: q.imageUrl,
        card: payload.toCardMap(),
      );

      if (!mounted) {
        return;
      }
      await Navigator.push(
        context,
        MaterialPageRoute(
          builder: (_) => ChatThreadScreen(
            thread: thread,
            myUserId: Session.effectiveChatId,
            myName: Session.effectiveDisplayName,
            role: Session.userRole,
            chatService: chatService,
          ),
        ),
      );
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Failed to raise doubt: $e')));
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final int total = _questions.length;
    return Scaffold(
      appBar: AppBar(
        title: const Text('Answer Key'),
        actions: <Widget>[
          IconButton(
            icon: const Icon(Icons.grid_view_rounded),
            onPressed: _loading ? null : _openPalette,
          ),
        ],
      ),
      body: _loading
          ? const Center(child: CircularProgressIndicator())
          : Column(
              children: <Widget>[
                Padding(
                  padding: const EdgeInsets.fromLTRB(14, 12, 14, 0),
                  child: LiquidGlass(
                    padding: const EdgeInsets.all(14),
                    child: Column(
                      children: <Widget>[
                        Row(
                          children: <Widget>[
                            Text(
                              'Question ${_idx + 1} / $total',
                              style: const TextStyle(
                                fontWeight: FontWeight.w800,
                              ),
                            ),
                            const Spacer(),
                            TextButton.icon(
                              onPressed: _openPalette,
                              icon: const Icon(
                                Icons.grid_view_rounded,
                                size: 18,
                              ),
                              label: const Text('Palette'),
                            ),
                          ],
                        ),
                        const SizedBox(height: 8),
                        LinearProgressIndicator(
                          value: total == 0 ? 0 : (_idx + 1) / total,
                          minHeight: 8,
                          borderRadius: BorderRadius.circular(10),
                        ),
                      ],
                    ),
                  ),
                ),
                ValueListenableBuilder<AiPrecomputeProgress>(
                  valueListenable: aiPrecomputeService.progress,
                  builder: (_, AiPrecomputeProgress p, __) {
                    if (p.quizId != widget.quizId || p.total == 0) {
                      return const SizedBox.shrink();
                    }
                    return Padding(
                      padding: const EdgeInsets.fromLTRB(14, 10, 14, 0),
                      child: LiquidGlass(
                        padding: const EdgeInsets.all(10),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: <Widget>[
                            Text(
                              p.running
                                  ? 'Preparing AI hints: ${p.completed}/${p.total}'
                                  : 'AI hints ready',
                              style: const TextStyle(
                                fontSize: 12,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                            const SizedBox(height: 6),
                            LinearProgressIndicator(
                              value: p.fraction,
                              minHeight: 6,
                              borderRadius: BorderRadius.circular(8),
                            ),
                          ],
                        ),
                      ),
                    );
                  },
                ),
                Expanded(
                  child: PageView.builder(
                    controller: _pageCtrl,
                    itemCount: _questions.length,
                    onPageChanged: (int i) => setState(() => _idx = i),
                    itemBuilder: (_, int i) {
                      final AnswerKeyCardPayload payload = _cards[i];
                      return Padding(
                        padding: const EdgeInsets.all(12),
                        child: AnswerKeyFlipCard(
                          payload: payload,
                          teacherMode: _teacherAksMode,
                          onAskAi: () => _askAIFor(i),
                          onRaiseDoubt: () => _raiseDoubtFor(i),
                        ),
                      );
                    },
                  ),
                ),
                Padding(
                  padding: const EdgeInsets.fromLTRB(12, 2, 12, 10),
                  child: Row(
                    children: <Widget>[
                      Expanded(
                        child: OutlinedButton(
                          onPressed: _idx > 0
                              ? () {
                                  _pageCtrl.previousPage(
                                    duration: const Duration(milliseconds: 220),
                                    curve: Curves.easeOutCubic,
                                  );
                                }
                              : null,
                          child: const Text('Previous'),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Expanded(
                        child: ElevatedButton(
                          onPressed: _idx < _questions.length - 1
                              ? () {
                                  _pageCtrl.nextPage(
                                    duration: const Duration(milliseconds: 220),
                                    curve: Curves.easeOutCubic,
                                  );
                                }
                              : null,
                          child: const Text('Next'),
                        ),
                      ),
                    ],
                  ),
                ),
              ],
            ),
    );
  }
}

class _AnswerKeyPaletteSheet extends StatelessWidget {
  const _AnswerKeyPaletteSheet({
    required this.total,
    required this.current,
    required this.answers,
    required this.questions,
    required this.onJump,
  });

  final int total;
  final int current;
  final Map<int, List<String>> answers;
  final List<Question> questions;
  final void Function(int) onJump;

  Color _colorFor(int idx) {
    if (idx == current) {
      return AppColors.primary;
    }
    final List<String> user = answers[idx] ?? <String>[];
    if (user.isEmpty) {
      return Colors.blueGrey;
    }
    final Question q = questions[idx];
    if (q.type.toUpperCase() == 'NUMERICAL') {
      final double? userVal = double.tryParse(user.first);
      final double? correctVal = double.tryParse(q.correctAnswers.first);
      if (userVal != null &&
          correctVal != null &&
          (userVal - correctVal).abs() < 0.01) {
        return Colors.green;
      }
      return Colors.redAccent;
    }
    final Set<String> userSet = user.map((String e) => e.trim()).toSet();
    final Set<String> correctSet = q.correctAnswers
        .map((String e) => e.trim())
        .toSet();
    final bool correct =
        userSet.length == correctSet.length && userSet.containsAll(correctSet);
    return correct ? Colors.green : Colors.redAccent;
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      height: MediaQuery.of(context).size.height * 0.66,
      padding: const EdgeInsets.all(16),
      child: Column(
        children: <Widget>[
          const Text(
            'Question Palette',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 10),
          Expanded(
            child: GridView.builder(
              itemCount: total,
              gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
                crossAxisCount: 5,
                mainAxisSpacing: 10,
                crossAxisSpacing: 10,
              ),
              itemBuilder: (_, int idx) {
                final Color c = _colorFor(idx);
                return InkWell(
                  onTap: () => onJump(idx),
                  borderRadius: BorderRadius.circular(10),
                  child: Container(
                    decoration: BoxDecoration(
                      borderRadius: BorderRadius.circular(10),
                      border: Border.all(color: c, width: 2),
                      color: c.withOpacity(0.12),
                    ),
                    child: Center(
                      child: Text(
                        '${idx + 1}',
                        style: TextStyle(fontWeight: FontWeight.w800, color: c),
                      ),
                    ),
                  ),
                );
              },
            ),
          ),
          const SizedBox(height: 8),
          Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: <Widget>[
              _LegendDot(color: Colors.green, text: 'Correct'),
              const SizedBox(width: 12),
              _LegendDot(color: Colors.redAccent, text: 'Wrong'),
              const SizedBox(width: 12),
              _LegendDot(color: Colors.blueGrey, text: 'Skipped'),
            ],
          ),
        ],
      ),
    );
  }
}

class _LegendDot extends StatelessWidget {
  const _LegendDot({required this.color, required this.text});

  final Color color;
  final String text;

  @override
  Widget build(BuildContext context) {
    return Row(
      children: <Widget>[
        Container(
          width: 9,
          height: 9,
          decoration: BoxDecoration(color: color, shape: BoxShape.circle),
        ),
        const SizedBox(width: 4),
        Text(text, style: const TextStyle(fontSize: 12)),
      ],
    );
  }
}

extension _ElementAtOrNull<E> on List<E> {
  E? elementAtOrNull(int index) {
    if (index < 0 || index >= length) {
      return null;
    }
    return this[index];
  }
}
